    // Circumference Calculator
	function circumference($request){
	
		if (is_numeric($request->radius) || is_numeric($request->diameter) || is_numeric($request->circumference) || is_numeric($request->area) || is_numeric($request->s_area) || is_numeric($request->vol)) {
			if(is_numeric($request->radius)){
				if (empty($request->diameter) && empty($request->circumference) && empty($request->area) && empty($request->s_area) && empty($request->vol)) {
					$Radius=$request->radius;
					if ($request->unit_r=='mm') {
						$Radius=$Radius / 10;
					}
					if ($request->unit_r=='m') {
						$Radius=$Radius * 100;
					}
					if ($request->unit_r=='ft') {
						$Radius=$Radius * 30.48;
					}
					if ($request->unit_r=='in') {
						$Radius=$Radius * 2.54;
					}
					if ($request->unit_r=='km') {
						$Radius=$Radius * 100000;
					}
					if ($request->unit_r=='yd') {
						$Radius=$Radius * 91.44;
					}
					if ($request->unit_r=='mi') {
						$Radius=$Radius * 160934;
					}
					$Diameter= 2 * $Radius;
					$Circumference= 2 * 3.14159 * $Radius;
					$Area=3.14159 * pow($Radius,2);
					$this->param['Radius'] = round($Radius,5);
					$this->param['Diameter'] = round($Diameter,5);
					$this->param['Circumference'] = round($Circumference,5);
					$this->param['Area'] = round($Area,5);
					$this->param['RESULT'] = 1;
					return $this->param;
				} else {
                    $this->param['error'] = 'You can enter only one value.';
                    return $this->param;
				}
			}elseif(is_numeric($request->diameter)){
				if (empty($request->radius) && empty($request->circumference) && empty($request->area) && empty($request->s_area) && empty($request->vol)) {
					$Diameter=$request->diameter;
					if ($request->unit_d=='mm') {
						$Diameter=$Diameter / 10;
					}
					if ($request->unit_d=='m') {
						$Diameter=$Diameter * 100;
					}
					if ($request->unit_d=='ft') {
						$Diameter=$Diameter * 30.48;
					}
					if ($request->unit_d=='in') {
						$Diameter=$Diameter * 2.54;
					}
					if ($request->unit_d=='km') {
						$Diameter=$Diameter * 100000;
					}
					if ($request->unit_d=='yd') {
						$Diameter=$Diameter * 91.44;
					}
					if ($request->unit_d=='mi') {
						$Diameter=$Diameter * 160934;
					}
					$Radius=$Diameter / 2;
					$Circumference= 2 * 3.14159 * $Radius;
					$Area=3.14159 * pow($Radius,2);
					$this->param['Radius'] = round($Radius,5);
					$this->param['Diameter'] = round($Diameter,5);
					$this->param['Circumference'] = round($Circumference,5);
					$this->param['Area'] = round($Area,5);
					$this->param['RESULT'] = 1;
					return $this->param;
				} else {
                    $this->param['error'] = 'You can enter only one value.';
                    return $this->param;
				}
				
			}elseif(is_numeric($request->circumference)){
				if (empty($request->radius) && empty($request->diameter) && empty($request->area) && empty($request->s_area) && empty($request->vol)) {
					$Circumference=$request->circumference;
					if ($request->unit_c=='mm') {
						$Circumference=$Circumference / 10;
					}
					if ($request->unit_c=='m') {
						$Circumference=$Circumference * 100;
					}
					if ($request->unit_c=='ft') {
						$Circumference=$Circumference * 30.48;
					}
					if ($request->unit_c=='in') {
						$Circumference=$Circumference * 2.54;
					}
					if ($request->unit_c=='km') {
						$Circumference=$Circumference * 100000;
					}
					if ($request->unit_c=='yd') {
						$Circumference=$Circumference * 91.44;
					}
					if ($request->unit_c=='mi') {
						$Circumference=$Circumference * 160934;
					}
					$Radius=$Circumference / (2 * 3.14159);
					$Diameter= 2 * $Radius;
					$Area=3.14159 * pow($Radius,2);
					$this->param['Radius'] = round($Radius,5);
					$this->param['Diameter'] = round($Diameter,5);
					$this->param['Circumference'] = round($Circumference,5);
					$this->param['Area'] = round($Area,5);
					$this->param['RESULT'] = 1;
					return $this->param;
				} else {
                    $this->param['error'] = 'You can enter only one value.';
                    return $this->param;
				}
				
			}elseif(is_numeric($request->area)){
				if (empty($request->radius) && empty($request->diameter) && empty($request->circumference) && empty($request->s_area) && empty($request->vol)) {
					$Area=$request->area;
					if ($request->unit_a=='mm²') {
						$Area=$Area / 100;
					}
					if ($request->unit_a=='m²') {
						$Area=$Area * 10000;
					}
					if ($request->unit_a=='ft²') {
						$Area=$Area * 929.03;
					}
					if ($request->unit_a=='km²') {
						$Area=$Area * 1e+10;
					}
					if ($request->unit_a=='in²') {
						$Area=$Area * 6.452;
					}
					if ($request->unit_a=='mi²') {
						$Area=$Area * 2.59e+10;
					}
					if ($request->unit_a=='yd²') {
						$Area=$Area * 8361.27;
					}
					$Radius=sqrt($Area / 3.14159);
					$Diameter= 2 * $Radius;
					$Circumference= 2 * 3.14159 * $Radius;
					$this->param['Radius'] = round($Radius,5);
					$this->param['Diameter'] = round($Diameter,5);
					$this->param['Circumference'] = round($Circumference,5);
					$this->param['Area'] = round($Area,5);
					$this->param['RESULT'] = 1;
					return $this->param;
				} else {
					$this->param['error'] = 'You can enter only one value.';
                    return $this->param;
				}
				
			}elseif(is_numeric($request->s_area)){
				if (empty($request->radius) && empty($request->diameter) && empty($request->circumference) && empty($request->area) && empty($request->vol)) {
					$S_Area=$request->s_area;
					if ($request->unit_sa=='mm²') {
						$S_Area=$S_Area / 100;
					}
					if ($request->unit_sa=='m²') {
						$S_Area=$S_Area * 10000;
					}
					if ($request->unit_sa=='ft²') {
						$S_Area=$S_Area * 929.03;
					}
					if ($request->unit_sa=='km²') {
						$S_Area=$S_Area * 1e+10;
					}
					if ($request->unit_sa=='in²') {
						$S_Area=$S_Area * 6.452;
					}
					if ($request->unit_sa=='mi²') {
						$S_Area=$S_Area * 2.59e+10;
					}
					if ($request->unit_sa=='yd²') {
						$S_Area=$S_Area * 8361.27;
					}
					$Radius=sqrt($S_Area / (4*3.14159));
					$this->param['Radius'] = round($Radius,5);
					$this->param['RESULT'] = 1;
					return $this->param;
				} else {
					$this->param['error'] = 'You can enter only one value.';
                    return $this->param;
				}
				
			}elseif(is_numeric($request->vol)){
				if (empty($request->radius) && empty($request->diameter) && empty($request->circumference) && empty($request->area) && empty($request->s_area)) {
					$vol=$request->vol;
					if ($request->unit_v=='m³') {
						$vol=$vol * 1e+6;
					}
					if ($request->unit_v=='ft³') {
						$vol=$vol * 28316.8;
					}
					if ($request->unit_v=='in³') {
						$vol=$vol * 16.387;
					}
					if ($request->unit_v=='km³') {
						$vol=$vol * 1000000000000000;
					}
					if ($request->unit_v=='yd³') {
						$vol=$vol * 764555;
					}
					if ($request->unit_v=='mi³') {
						$vol=$vol * 4168181818124979;
					}
					$Radius=pow((($vol * 3) / (4*3.14159)), 1/3);
					$this->param['Radius'] = round($Radius,5);
					$this->param['RESULT'] = 1;
					return $this->param;
				} else {
					$this->param['error'] = 'You can enter only one value.';
                    return $this->param;
				}
			}
		} else {
            $this->param['error'] = 'Please enter any one value.';
            return $this->param;
		}
		
	}

