	// Fibonacci Calculator
	function fibonacci($request){
		$n = $request->n;
		$units = $request->units;
		$first_term = $request->first_term;
		$second_term = $request->second_term;  
		function generateFibonacci($start, $end) {
			$fibonacci = array();
			$fibonacci[0] = 0;
			$fibonacci[1] = 1;
			for ($i = 2; $i <= $end; $i++) {
				$fibonacci[$i] = $fibonacci[$i - 1] + $fibonacci[$i - 2];
			}
			return array_slice($fibonacci, $start, $end - $start + 1);
		}
		if($units === "A Sequence"){
			if($first_term > $second_term){
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;

			}
			if(is_numeric($first_term) && is_numeric($second_term)){
				$fibonacci_sequence = generateFibonacci($first_term, $second_term);
				$this->param['fibonacci_sequence'] = $fibonacci_sequence;
			}else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param; 
			}
		} else { 
			if ($n < -250) {
				$this->param['error'] = 'n Value is less than -250';
            	return $this->param;
			} 
			if ($n >= 251) {
				$this->param['error'] = 'n Value is greater than or equal to 250';
            	return $this->param;
			} 
			if (is_numeric($n)) {
				$phi = (1 + sqrt(5)) / 2;
				$psi = 1 - $phi;
				$answer = (pow($phi, $n) - pow($psi, $n)) / sqrt(5);
				$this->param['answer'] = $answer;
			} else {
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
			} 
		} 
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Circumference to Diameter Calculator
	function circumference_diamter($request)
	{
		$conversionType = $request->conversionType;
		$value = $request->value;
		$unit = $request->unit;
		function convert_unit($unit,$value){
			if (isset($unit)) {
				if ($unit == 'cm') {
					$value = $value;
				} else if ($unit == 'mm') {
					$value = $value * 10;
				} else if ($unit == 'm') {
					$value = $value * 0.01;
				} else if ($unit == 'km') {
					$value = $value * 0.00001;
				} else if ($unit == 'in') {
					$value = $value * 0.3937;
				}else if ($unit == 'ft') {
					$value = $value * 0.0328084;
				}else if ($unit == 'yd') {
					$value = $value * 0.0109361;
				}else if ($unit == 'mi') {
					$value = $value * 0.0000062137;
				}
				return $value;
			}
		}
		if(is_numeric($value)){		
			if ($conversionType === "circumferenceToDiameter") {
				$value = convert_unit($unit,$value);
				$result = $value / pi();
			} else {
				$value = convert_unit($unit,$value);
				$result = $value * pi();
			}
			$this->param[ 'result' ] = $result;
			$this->param[ 'unit' ] = $unit;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please Check Your Input.';
            return $this->param;
		}
    }

	// Volume of a Square Calculator
	function square_volume($request){
		$length = $request->length;
		$length_unit = $request->length_unit;
		$height = $request->height;
		$height_unit = $request->height_unit;
		$width = $request->width;
		$width_unit = $request->width_unit;
		function convert_in($unit,$value){
			if($unit === "mm"){
				$val1 = $value / 25.4;
			}else if($unit === "cm"){
				$val1 = $value / 2.54;
			}else if($unit === "m"){
				$val1 = $value * 39.37;
			}else if($unit === "km"){
				$val1 = $value * 39370;
			}else if($unit === "in"){
				$val1 = $value * 1;
			}else if($unit === "ft"){
				$val1 = $value * 12;
			}else if($unit === "yd"){
				$val1 = $value * 36;
			}else if($unit === "mi"){
				$val1 = $value * 63360;
			}
			return $val1;	
		}
	    if (is_numeric($length) && is_numeric($height) && is_numeric($width)) {
			$length = convert_in($length_unit,$length);
			$height = convert_in($height_unit,$height);
			$width = convert_in($width_unit,$width);
			$answer = $length * $height * $width;
			$this->param['answer'] = $answer;
			$this->param[ 'RESULT' ] = 1;
            return $this->param;
		}else{
			$this->param['error'] = 'Please Check Your Input.';
            return $this->param;
		}
	}

