	// Equilateral Triangle Calculator
	function equilateral($request){
		$operations = $request->operations;
		$first = $request->first;
		$unit1 = $request->unit1;
	    if ($operations == "side") {
			if (is_numeric($first)) {
	            $a = $first;
	            $p = $a * 3;
	            $s = (3 * $first) / 2;
	            $k = (1/4) * sqrt(3) * pow($first, 2);
	            $h = (1/2) * sqrt(3) * $first;
	        }else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
	        }
	    }elseif ($operations == "perimeter") {
			if (is_numeric($first)) {
	            $a = $first / 3;
	            $p = $first;
	            $s = (3 * $a) / 2;
	            $k = (1/4) * sqrt(3) * pow($a, 2);
	            $h = (1/2) * sqrt(3) * $a; 
	        }else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
	        }
	    }elseif ($operations == "semiperimeter") {
			if (is_numeric($first)) {
				$a = ($first * 2) / 3;
	            $p = 3 * $a;
	            $s = $first;
	            $k = (1/4) * sqrt(3) * pow($a, 2);
	            $h = (1/2) * sqrt(3) * $a; 
	        }else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
	        }
		}elseif ($operations == "area") {
			if (is_numeric($first)) {
				$a = 2 * sqrt($first / sqrt(3));
	            $p = 3 * $a;
	            $s = (3 * $a) / 2;
	            $k = $first;
	            $h = (1/2) * sqrt(3) * $a; 
	        }else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
	        }
		}elseif ($operations == "altitude") {
			if (is_numeric($first)) {
				$a = (2 * sqrt(3)) * $first;
	            $p = 3 * $a;
	            $s = (3 * $a) / 2;
	            $k = (1/4) * sqrt(3) * pow($a, 2);
	            $h = $first; 
	        }else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
	        }
		}
		$this->param['a'] = $a;
		$this->param['k'] = $k;
		$this->param['p'] = $p;
		$this->param['s'] = $s;
		$this->param['h'] = $h;
		$this->param['unit'] = $unit1;
	    $this->param['RESULT'] = 1;
	    return $this->param;
	}

	// Radius of a Circle Calculator  
    function rad_cir($request){
		$operations = $request->operations;
		$first = $request->first;
		$unit1 = $request->unit1;
		$second = $request->second;
		$unit2 = $request->unit2;
        function con_cm($a,$b){
            if($a == "mm"){
                $centi = $b / 10;
            }elseif ($a == "cm"){
                $centi = $b * 1;
            }elseif ($a == "dm"){
                $centi = $b * 10;
            }elseif ($a == "m"){
                $centi = $b * 100;
            }elseif ($a == "km"){
                $centi = $b * 100000;
            }elseif ($a == "in"){
                $centi = $b * 2.54;
            }elseif ($a == "ft"){
                $centi = $b * 30.48;
            }elseif ($a == "yd"){
                $centi = $b * 91.44;
            }elseif ($a == "mi"){
                $centi = $b * 160900;
            }elseif ($a == "nmi"){
                $centi = $b * 185200;
            }
            return $centi;
        }
        function con_cm_sq($a,$b){
            if($a == "mm²"){
                $foot = $b / 10;
            }elseif ($a == "cm²"){
                $foot = $b * 1;
            }elseif ($a == "dm²"){
                $foot = $b * 10;
            }elseif ($a == "m²"){
                $foot = $b * 100;
            }elseif ($a == "km²"){
                $foot = $b * 100000;
            }elseif ($a == "in²"){
                $foot = $b * 2.54;
            }elseif ($a == "ft²"){
                $foot = $b * 30.48;
            }elseif ($a == "yd²"){
                $foot = $b * 91.44;
            }elseif ($a == "mi²"){
                $foot = $b * 160900;
            }elseif ($a == "a"){
                $foot = $b * 1000000;
            }elseif ($a == "da"){
                $foot = $b * 1000;
            }elseif ($a == "ha"){
                $foot = $b * 100000000;
            }elseif ($a == "ac"){
                $foot = $b * 40468564.224;
            }elseif ($a == "sf"){
                $foot = $b * 71224673.03424;
            }
            return $foot;
        }
        if ($operations == "1") {
			if (is_numeric($first)) {
				$first = con_cm($unit1,$first);
				$radius = $first / (2 * 3.14);
				$diameter = 2 * $radius;
				$area = (pow($radius, 2)) * 3.14;
				$this->param['diameter'] = $diameter;
				$this->param['area'] = $area;
            }else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
            }
        }elseif ($operations == "2") {
			if (is_numeric($second)) {
				$second = con_cm_sq($unit2,$second);
				$radius = sqrt($second / 3.14);
				$diameter = 2 * $radius;
				$circum = 2 * 3.14 * $radius;
				$this->param['diameter'] = $diameter;
				$this->param['circum'] = $circum;
            }else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
            }
        }elseif ($operations == "3") {
			if (is_numeric($first)) {
				$first = con_cm($unit1,$first);
				$radius = $first / 2;
				$circum = 2 * 3.14 * $radius;
				$area = (pow($radius, 2)) * 3.14;
				$this->param['circum'] = $circum;
				$this->param['area'] = $area;
            }else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
            }
		}
		$this->param['radius'] = $radius;
        $this->param['RESULT'] = 1;
        return $this->param;
    }

	// Volume of a Circle Calculator
	function volume($request){
		$radius= $request->radius;
		$radius_unit= $request->radius_unit;
		$circle= $request->circle;
		$circle_unit= $request->circle_unit;
		$pi= 3.14159265359;
		function sigFig($value, $digits)
		{
		    if ($value == 0) {
		        $decimalPlaces = $digits - 1;
		    } elseif ($value < 0) {
		        $decimalPlaces = $digits - floor(log10($value * -1)) - 1;
		    } else {
		        $decimalPlaces = $digits - floor(log10($value)) - 1;
		    }
		    $answer = round($value, $decimalPlaces);
		    return $answer;
		}
		function unitConvert($input,$unit){
			if($unit == 'cm'){
				$input = $input * 0.3937;
			}else if($unit == 'm'){
				$input = $input * 39.37;
			}else if($unit == 'ft'){
				$input = $input * 12;
			}else if($unit == 'yd'){
				$input = $input * 36;
			}
			return $input;
		}

		if(is_numeric($radius) && is_numeric($circle)  && !empty($pi)){
			
			if(isset($radius_unit)){
				$radius = unitConvert($radius,$radius_unit);
			}
			if(isset($circle_unit)){
				$circle = unitConvert($circle,$circle_unit);
			}
			$p_radius = pow($radius,2);
			$cv = $pi * $p_radius * $circle;

			$this->param[ 'radius' ] = $radius;
			$this->param[ 'circle' ] = $circle;
			$this->param[ 'pi' ] = $pi;
			$this->param[ 'p_radius' ] = $p_radius;
			$this->param[ 'cv' ] = sigfig($cv,6);
			$this->param[ 'RESULT' ] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please Check Your Input.';
            return $this->param;
		}
	}

    // SAS Triangle Calculator
    function sas($request){

		$first = $request->first;
		$unit1 = $request->unit1;
		$second = $request->second;
		$unit2 = $request->unit2;
		$third = $request->third;
		$unit3 = $request->unit3;
        function cm($a,$b){
            if($a == "mm"){
                $convert1 = $b / 10;
            }elseif ($a == "cm"){
                $convert1 = $b * 1;
            }elseif ($a == "m"){
                $convert1 = $b * 100;
            }elseif ($a == "in"){
                $convert1 = $b * 2.54;
            }elseif ($a == "ft"){
                $convert1 = $b * 30.48;
            }
            return $convert1;
        }
        function deg($a,$b){
            if($a == "pi"){
                $convert1 = $b * 57.2958;
            }elseif ($a == "deg"){
                $convert1 = $b * 1;
            }
            return $convert1;
        }
        $first = cm($unit1,$first);
        $second = cm($unit2,$second);
        $third = deg($unit3,$third);
        if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
            $c = round(sqrt(pow($first, 2) + pow($second, 2) - (2 * $first * $second * cos(deg2rad($third)))), 3);
            $p = $first + $second + $c;
            $s = $p / 2;
            $t = round(sqrt($s * ($s - $first) * ($s - $second) * ($s - $c)), 4);
            $h_a = (2 * $t) / $first;
            $h_b = (2 * $t) / $second;
            $h_c = (2 * $t) / $c;
            $alpha = rad2deg(acos((pow($second, 2) + pow($c, 2) - pow($first, 2)) / (2 * $second * $c)));
            $beta = rad2deg(acos((pow($first, 2) + pow($c, 2) - pow($second, 2)) / (2 * $first * $c)));
            $gema = 180 - $alpha - $beta;
            $r = $t / $s;
            $R = ($first * $second * $c) / (4 * $r * $s);
            $m_a = round(sqrt((2 * pow($second, 2)) + (2 * pow($c, 2)) - pow($first, 2)) / 2, 4);    
            $m_b = round(sqrt((2 * pow($c, 2)) + (2 * pow($first, 2)) - pow($second, 2)) / 2, 4);    
            $m_c = round(sqrt((2 * pow($first, 2)) + (2 * pow($second, 2)) - pow($c, 2)) / 2, 4);
        }else{
			$this->param['error'] = 'Please Check Your Input.';
            return $this->param;
        }
        $this->param['a'] = $first;
        $this->param['b'] = $second;
        $this->param['c'] = $c;
        $this->param['t'] = $t;
        $this->param['s'] = $s;
        $this->param['p'] = $p;
        $this->param['alpha'] = $alpha;
        $this->param['beta'] = $beta;
        $this->param['gema'] = $gema;
        $this->param['h_a'] = $h_a;
        $this->param['h_b'] = $h_b;
        $this->param['h_c'] = $h_c;
        $this->param['m_a'] = $m_a;
        $this->param['m_b'] = $m_b;
        $this->param['m_c'] = $m_c;
        $this->param['r'] = $r;
        $this->param['R'] = $R;
        $this->param['RESULT'] = 1;
		return $this->param;
    }

	// Trigonometry Calculator
	function trigonometry($request){
		$find= $request->find;
		$angle= $request->angle;
		$angle_unit= $request->angle_unit;
		if($find=="sin" || $find=="cos" || $find=="tan" || $find=="cot" || $find=="sec" || $find=="csc"){
			if(is_numeric($angle)){
				$method=1;
				if($angle_unit=="deg"){
					if($find=="sin"){
						$ans1=sin(deg2rad($angle));		
					}else if($find=="cos"){
						$ans1=cos(deg2rad($angle));
					}else if($find=="tan"){
						$ans1=tan(deg2rad($angle));
					}else if($find=="csc"){
						$ans1=1/(sin(deg2rad($angle)));			
					}else if($find=="sec"){
						$ans1=1/(cos(deg2rad($angle)));			
					}else if($find=="cot"){
						$ans1=1/(tan(deg2rad($angle)));			
					}
					$ans2=deg2rad($angle);
				}else if($angle_unit=="rad"){
					if($find=="sin"){
						$ans1=sin($angle);
					}else if($find=="cos"){
						$ans1=cos($angle);
					}else if($find=="tan"){
						$ans1=tan($angle);
					}else if($find=="cot"){
						$ans1=1/(tan($angle));
					}else if($find=="csc"){
						$ans1=1/sin($angle);
					}else if($find=="sec"){
						$ans1=1/cos($angle);
					}
					$ans2=rad2deg($angle);
				}
				$this->param['ans1']=$ans1;
				$this->param['ans2']=$ans2;
			}else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
			}
		}else if($find=="All"){
			if(is_numeric($angle)){
				$method=2;
				if($angle_unit=="deg"){
					$sin=sin(deg2rad($angle));
					$cos=cos(deg2rad($angle));
					$tan=tan(deg2rad($angle));
					$csc=1/sin(deg2rad($angle));
					$sec=1/cos(deg2rad($angle));
					$cot=1/tan(deg2rad($angle));
					$asin=asin($angle);
					$acos=acos($angle);
					$atan=atan($angle);
					$acsc=asin(1/$angle);
					$asec=acos(1/$angle);
					$acot=atan(1/$angle);
					$fns=deg2rad($angle);
				}else if($angle_unit=="rad"){
					$sin=sin($angle);
					$cos=cos($angle);
					$tan=tan($angle);
					$csc=1/sin($angle);
					$sec=1/cos($angle);
					$cot=1/tan($angle);
					$asin=asin($angle);
					$acos=acos($angle);
					$atan=atan($angle);
					$acsc=asin(1/$angle);
					$asec=acos(1/$angle);
					$acot=atan(1/$angle);
					$fns=rad2deg($angle);
				}
			}else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
			}
			$this->param['sin']=$sin;
			$this->param['cos']=$cos;
			$this->param['tan']=$tan;
			$this->param['csc']=$csc;
			$this->param['cot']=$cot;
			$this->param['sec']=$sec;
			$this->param['asin']=$asin;
			$this->param['acos']=$acos;
			$this->param['atan']=$atan;
			$this->param['acsc']=$acsc;
			$this->param['acot']=$acot;
			$this->param['asec']=$asec;
			$this->param['fns']=$fns;	
		}else if($find=="arcsin" || $find=="arccos" || $find=="arctan" || $find=="arccsc" || $find=="arcsec" || $find=="arccot"){
			$method=3; 
		    $vars=explode(".",$angle);
		    if(count($vars)<2){
				$deg=$vars[0];
			    $min=0;
			    $sec=0;
		    }else{
			    $deg=$vars[0];
			    $tempma="0.".$vars[1];
			    $tempma=$tempma*3600;
			    $min=floor($tempma/60);
			    $sec=round($tempma-($min*60),3);
			 }
			 if($find=="arcsin"){
			 	$rad=asin($angle);
			 }else if($find=="arccos"){
			 	$rad=acos($angle);
			 }else if($find=="arctan"){
			 	$rad=atan($angle);
			 }else if($find=="arccsc"){
			 	$rad=(asin(1/$angle));
			 }else if($find=="arcsec"){
			 	$rad=(acos(1/$angle));
			 }else if($find=="arccot"){
			 	$rad=(atan(1/$angle));
			 }
			$deg=rad2deg($rad);
			$this->param['rad']=$rad;
			$this->param['deg']=$deg;
		}
		if($find=="sin"){
			$naam="Group 4";
		}else if($find=="cos"){
			$naam="Group 3";
		}else if($find=="tan"){
			$naam="Group 2";
		}else if($find=="sec"){
			$naam="Group 6";
		}else if($find=="csc"){
			$naam="Group 5";
		}else if($find=="cot"){
			$naam="Group 1";
		}
		if(isset($naam)){
			$this->param['naam']=$naam;
		}
		$this->param['find']=$find;
		$this->param['angle']=$angle;
		$this->param['angle_unit']=$angle_unit;
		$this->param['method']=$method;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

    // Test Calculator
    function test($request){
		$grades = $request->grades;
		$first = $request->first;
		$second = $request->second;
		$increment = $request->increment;
		$aplus = $request->aplus;
		$a = $request->a;
		$aminus = $request->aminus;
		$bplus = $request->bplus;
		$b = $request->b;
		$bminus = $request->bminus;
		$cplus = $request->cplus;
		$c = $request->c;
		$cminus = $request->cminus;
		$dplus = $request->dplus;
		$d = $request->d;
		$dminus = $request->dminus;
        if (is_numeric($first) && is_numeric($second) && is_numeric($increment)) {
            $increment = floor($increment);
            for($j=$first; $j >= 0; $j-=$increment) {
                $q_array[] = $j;
            }
            for($i=0; $i <= $first; $i++) {
                if ($i != 0) {
                    $i = $i + ($increment-1);
                }
                $i_array[] = $i;
            }
            $first = floor($first);
            $correct = $first - $second;
            $per = (100 * $correct / $first);
            $per = round($per);
            if ($grades == 1) {
                if (is_numeric($a) && is_numeric($b) && is_numeric($c) && is_numeric($d)) {
                    if ($a < $b) {
						$this->param['error'] = 'A limit must be higher or equal to B limit';
            			return $this->param;
                    }elseif ($b < $c) {
						$this->param['error'] = 'B limit must be higher or equal to C limit';
            			return $this->param;
                    }elseif ($c < $d) {
						$this->param['error'] = 'C limit must be higher or equal to D limit';
            			return $this->param;
                    }
                    $lettertbl=['A','B','C','D','F'];
                    $percenttbl=[$a,$b,$c,$d,0];
                }else{
					$this->param['error'] = 'Please Check Your Input.';
            		return $this->param;
                }
            }else if ($grades == 2) {
                if (is_numeric($aplus) && is_numeric($a) && is_numeric($aminus) && is_numeric($bplus) && is_numeric($b) && is_numeric($bminus) && is_numeric($cplus) && is_numeric($c) && is_numeric($cminus) && is_numeric($dplus) && is_numeric($d) && is_numeric($dminus)) {
                    if ($aplus < $a) {
						$this->param['error'] = 'A+ limit must be higher or equal to A limit';
            			return $this->param;
                    }elseif ($a < $aminus) {
						$this->param['error'] = 'A limit must be higher or equal to A- limit';
            			return $this->param;
                    }elseif ($aminus < $bplus) {
						$this->param['error'] = 'A- limit must be higher or equal to B+ limit';
            			return $this->param;
                    }elseif ($bplus < $b) {
						$this->param['error'] = 'B+ limit must be higher or equal to B limit';
            			return $this->param;
                    }elseif ($b < $bminus) {
						$this->param['error'] = 'B limit must be higher or equal to B- limit';
            			return $this->param;
                    }elseif ($bminus < $cplus) {
						$this->param['error'] = 'B- limit must be higher or equal to C+ limit';
            			return $this->param;
                    }elseif ($cplus < $c) {
						$this->param['error'] = 'C+ limit must be higher or equal to C limit';
            			return $this->param;
                    }elseif ($c < $cminus) {
						$this->param['error'] = 'C limit must be higher or equal to C- limit';
            			return $this->param;
                    }elseif ($cminus < $dplus) {
						$this->param['error'] = 'C- limit must be higher or equal to D+ limit';
            			return $this->param;
                    }elseif ($dplus < $d) {
						$this->param['error'] = 'D+ limit must be higher or equal to D limit';
            			return $this->param;
                    }elseif ($d < $dminus) {
						$this->param['error'] = 'D limit must be higher or equal to D- limit';
            			return $this->param;
                    }
                    $lettertbl = ['A+','A','A-','B+','B','B-','C+','C','C-','D+','D','D-','F'];
                    $percenttbl = [$aplus,$a,$aminus,$bplus,$b,$bminus,$cplus,$c,$cminus,$dplus,$d,$dminus,0];
                }else{
					$this->param['error'] = 'Please Check Your Input.';
            		return $this->param;
                }
            }
			$letter = '';
            for($i=0; $i < count($percenttbl); $i++){
                if($per >= $percenttbl[$i] ){
                    $letter = $lettertbl[$i];
                    break;
                }
            }
            $letter_ans = $letter;
            for($k=0; $k <= count($q_array)-1; $k++) {
                $grade = 100 * ($q_array[$k] / $first);
                $grade = round($grade);
                for($i=0; $i < count($percenttbl); $i++){
                    if($grade >= $percenttbl[$i] ){
                        $letter = $lettertbl[$i];
                        break;
                    }
                }
                $g_array[] = $grade;
                $l_array[] = $letter;
            }
        }else{
			$this->param['error'] = 'Please Check Your Input.';
            return $this->param;
        }
        $this->param['first'] = $first;
        $this->param['correct'] = $correct;
        $this->param['per'] = $per;
        $this->param['letter_ans'] = $letter_ans;
        $this->param['q_array'] = $q_array;
        $this->param['i_array'] = $i_array;
        $this->param['g_array'] = $g_array;
        $this->param['l_array'] = $l_array;
        $this->param['RESULT'] = 1;
        return $this->param;
    }

	// Cofunction Calculator
	function cofunction($request){
		$func= $request->func;
		$angle= $request->angle;
		$unit= $request->unit;
		if (is_numeric($func) && is_numeric($angle)) {
			$ang=$angle;
			if ($unit=="rad") {
				$angle=rad2deg($angle);
			}
			if ($angle<0 || $angle>90) {
				$this->param['error'] = 'Angle for cofunction identities is 0-90 degrees (or 0 - π/2 in radians).';
            	return $this->param;
			}
			$ang1=90 - $angle;
			if ($unit=="rad") {
				$ang1=deg2rad($ang1);
			}
			if ($func==1) {
				$ans = sin(deg2rad($angle));
				if ($angle==30) {
					$ans1=' = 1/2';
					$this->param['ans1'] = $ans1;
				}elseif ($angle==45) {
					$ans1=' = √2/2';
					$this->param['ans1'] = $ans1;
				}elseif ($angle==60) {
					$ans1=' = √3/2';
					$this->param['ans1'] = $ans1;
				}
			}elseif ($func==2) {
				$ans = cos(deg2rad($angle));
				if ($angle==30) {
					$ans1=' = √3/2';
					$this->param['ans1'] = $ans1;
				}elseif ($angle==45) {
					$ans1=' = √2/2';
					$this->param['ans1'] = $ans1;
				}elseif ($angle==60) {
					$ans1=' = 1/2';
					$this->param['ans1'] = $ans1;
				}
			}elseif ($func==3) {
				$ans = tan(deg2rad($angle));
				if ($angle==30) {
					$ans1=' = 1/√3 = √3/3';
					$this->param['ans1'] = $ans1;
				}elseif ($angle==60) {
					$ans1=' = √3';
					$this->param['ans1'] = $ans1;
				}
			}elseif ($func==4) {
				$ans = 1/tan(deg2rad($angle));
				if ($angle==30) {
					$ans1=' = √3';
					$this->param['ans1'] = $ans1;
				}elseif ($angle==60) {
					$ans1=' = 1/√3 = √3/3';
					$this->param['ans1'] = $ans1;
				}
			}elseif ($func==5) {
				$ans = 1/cos(deg2rad($angle));
				if ($angle==30) {
					$ans1=' = 2√3/3';
					$this->param['ans1'] = $ans1;
				}elseif ($angle==45) {
					$ans1=' = √2';
					$this->param['ans1'] = $ans1;
				}
			}elseif ($func==6) {
				$ans = 1/sin(deg2rad($angle));
				if ($angle==45) {
					$ans1=' = √2';
					$this->param['ans1'] = $ans1;
				}elseif ($angle==60) {
					$ans1=' = 2√3/3';
					$this->param['ans1'] = $ans1;
				}
			}
			$this->param['ans'] = round($ans,8);
			$this->param['ang'] = round($ang,8);
			$this->param['ang1'] = round($ang1,8);
			$this->param['RESULT'] = 1;
            return $this->param;
		}else{
			$this->param['error'] = 'Please Check Your Input.';
            return $this->param;
		}
	}

	// Doubling Time Calculator
	function doubling($request){
		// dd($request->all());
		$x= $request->x;
		$want= $request->want;
  		if (is_numeric($x) && is_numeric($want)) {
  			if ($want==1) {
  				$ans=log(2)/(log(1+($x/100)));
  			}else{
  				$ans=log(2)/($x);
  				$ans=pow(2.71828, $ans)-1;
  				$ans=$ans*100;
			}
			$this->param['ans'] = $ans;
			$this->param['RESULT'] = 1;
			return $this->param;
  		}else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
  		}
	}

	// Golden Ratio Calculator
	function golden($request){
		$selection= $request->selection;
		$a= $request->a;
		$value=1.6180339887498;
		if (is_numeric($a)){
			if($selection == '1'){
				$longer_section=$a;
				$shorter_section=$a / $value;
				$sum=$shorter_section + $a;
			}
			if($selection == '2'){
				$shorter_section=$a;
				$longer_section=$value * $a;
				$sum=$longer_section + $a;
			}
			if($selection == '3'){
				$sum=$a;
				$longer_section=$a / $value;
				$shorter_section=$longer_section / $value;
			}
			$this->param['value'] = $value;
			$this->param['a'] = round($a,5);
			$this->param['sum'] = round($sum,5);
			$this->param['longer_section'] = round($longer_section,5);
			$this->param['shorter_section'] = round($shorter_section,5);
  			$this->param['RESULT'] = 1;
            return $this->param;
		}else{
			$this->param['error'] = 'Please Check Your Input.';
            return $this->param;
		}
	}

	// Reference Angle Calculator
	function reference($request){
		$angle= $request->angle;
		$angle_unit= $request->angle_unit;
		if($angle_unit=="deg"){
			if(is_numeric($angle)){
				$angle_convert=$angle*1;
				if($angle_convert>=0 && $angle_convert<=90){
					$ans=$angle_convert;
					$src= "11.svg";
				}elseif ($angle_convert>90 && $angle_convert<=180) {
					$ans=180-$angle_convert;
					$src= "22.svg";
				}elseif ($angle_convert>180 && $angle_convert<=270){
					$ans=$angle_convert-180;
					$src= "33.svg";
				}elseif ($angle_convert>270 && $angle_convert<=360) {
					$ans=360-$angle_convert;
					$src= "44.svg";
				}elseif ($angle_convert>360){
					while($angle_convert>360) {
						$angle_convert=$angle_convert-360;
					}
					if($angle_convert>=0 && $angle_convert<=90){
						$ans=$angle_convert;
						$src= "11.svg";
					}elseif ($angle_convert>90 && $angle_convert<=180) {
						$ans=180-$angle_convert;
						$src= "22.svg";
					}elseif ($angle_convert>180 && $angle_convert<=270){
						$ans=$angle_convert-180;
						$src= "33.svg";
					}elseif ($angle_convert>270 && $angle_convert<=360) {
						$ans=360-$angle_convert;
						$src= "44.svg";
					}
				}elseif ($angle_convert<=0 && $angle_convert>=-90) {
					$mul=-1;
					$ans=$angle_convert*$mul;
					$src= "44.svg";
				}elseif($angle_convert<-90 && $angle_convert>=-180){
					$mul=-1;
					$converting=$angle_convert*(-1);
					$ans=180-$converting;
					$src= "33.svg";
				}elseif($angle_convert<-180 && $angle_convert>=-270){
					$mul=-1;
					$converting=$angle_convert*(-1);
					$ans=($converting-180);
					$src= "22.svg";
				}elseif($angle_convert<-270 && $angle_convert>=-360){
					$mul=-1;
					$converting=$angle_convert*(-1);
					$ans=$converting-360;
					$src= "11.svg";
				}	
				elseif ($angle_convert<-360) {
					while($angle_convert<-360){
						$angle_convert=($angle_convert)+360;
					}
					if ($angle_convert<=0 && $angle_convert>=-90) {
						$mul=-1;
						$ans=$angle_convert*$mul;
						$src= "44.svg";
					}elseif($angle_convert<-90 && $angle_convert>=-180){
						$mul=-1;
						$converting=$angle_convert*$mul;
						$ans=(180-$converting);
						$src= "33.svg";
					}elseif($angle_convert<-180 && $angle_convert>=-270){
						$mul=-1;
						$converting=$angle_convert*$mul;
						$ans=($angle_convert-$converting);
						$src= "22.svg";
					}elseif($angle_convert<-270 && $angle_convert>=-360){
						$mul=-1;
						$converting=$angle_convert*$mul;
