					}	
				}
					$this->param['pi']=$ans*0.005556;
			}else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
			}
		}elseif($angle_unit=="rad") {
			if(is_numeric($angle)){
				$convert=$angle*57.2958;
				if($convert>=0 && $convert<=90) {
					$ans=$convert;
					$src= "11.svg";
				}elseif ($convert>90 && $convert<=180) {
					$ans=180-$convert;
					$src= "22.svg";
				}elseif ($convert>180 && $convert<=270) {
					$ans=($convert-180);
					$src= "33.svg";
				}elseif ($convert>270 && $convert<=360) {
					$ans=360-$convert;
					$src= "44.svg";
				}elseif ($convert>360){
					while($convert>360) {
						$convert=$convert-360;
					}
					if($convert>=0 && $convert<=90){
						$ans=$convert;
						$src= "11.svg";
					}elseif ($convert>90 && $convert<=180) {
						$ans=180-$convert;
						$src= "22.svg";
					}elseif ($convert>180 && $convert<=270){
						$ans=$convert-180;
						$src= "33.svg";
					}elseif ($convert>270 && $convert<=360) {
						$ans=360-$convert;
						$src= "44.svg";
					}
				
				}elseif ($convert<=0 && $convert>=-90) {
					$mul=-1;
					$ans=$convert*$mul;
					$src= "44.svg";
				}elseif ($convert<-90 && $convert>=-180) {
					$src= "33.svg";
					$mul=-1;
					$converting=$convert*$mul;
					$ans=(180-$converting);
				}elseif ($convert<-180 && $convert>=-270) {
					$mul=-1;
					$src= "22.svg";
					$converting=$convert*$mul;
					$ans=($converting-180);
				}elseif ($convert<-270 && $convert>=-360) {
					$src= "11.svg";
					$mul=-1;
					$converting=$convert*$mul;
					$ans=(360-$converting);
				}
				elseif ($convert<-360) {
					while($convert<-360){
						$convert=$convert+360;	
					}
					if ($convert<=0 && $convert>=-90) {
						$mul=-1;
						$ans=$convert*$mul;
						$src= "44.svg";
					}elseif ($convert<-90 && $convert>=-180) {
						$src= "33.svg";
						$mul=-1;
						$converting=$convert*$mul;
						$ans=(180-$converting);
					}elseif ($convert<-180 && $convert>=-270) {
						$mul=-1;
						$converting=$convert*$mul;
						$src= "22.svg";
						$ans=($converting-180);
					}elseif ($convert<-270 && $convert>=-360) {
						$src= "11.svg";
						$mul=-1;
						$converting=$convert*$mul;
						$ans=(360-$converting);
					}
				}
				$this->param['pi']=($ans*0.3183)*(0.017453);
			}else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
			}
				
		}else{
			if(is_numeric($angle)){
				$ans=$angle*0;
				$src="";
			}else{
				$this->param['error'] = 'Please Check Your Input.';
            	return $this->param;
			}
		}
		$this->param['ans'] = $ans;
		$this->param['src']=$src;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

	// Exponent Calculator
	function exponent($request){
		$b= $request->b;
		$x= $request->x;
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $x)) {
			$this->param['error'] = 'Please Enter Valid Input.';
            return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $b)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if(!empty($b) && !empty($x)){
			if (strlen($b) <= 7) {
				if ($x <= 2000) {
					$base=eval('return '.$b.';');
					$exp=eval('return '.$x.';');
					$result=pow($base, $exp);
					$this->param['result'] = $result;
					$this->param['b'] = $base;
					$this->param['x'] = $exp;
					$this->param['RESULT'] = 1;
					return $this->param;
				}else{
					$this->param['error'] = 'Use exponents less than 2000.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Enter base less than 7 characters.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please Enter Numbers.';
			return $this->param;
		}	
	}
	
	// Coterminal Angle Calculator
	function coterminal($request){
		$want= $request->want;
		$unit= $request->unit;
		$angle= $request->angle;
		$angle2= $request->angle2;
		function gcd($a,$b) 
		{
			$a = abs($a); $b = abs($b);

			if( $a < $b)
			{ 
				list($b,$a) = Array($a,$b);
			}
			if( $b == 0){
				return 1;
			}
			$r = $a % $b;
			while($r > 0): 
				$a = $b;
				$b = $r;
				$r = $a % $b;
			endwhile;
			return $b;
	
		}
		function reduce($num,$den) 
		{
			$g = gcd($num,$den);
			return array($num/$g,$den/$g);
		}
		if ($unit==1 && $want==1) {
			list ($upr , $btm) = reduce($angle,180);
			$rad=round($upr/$btm,3);
			$this->param['want'] = $want;
			$this->param['rad'] = $rad;
			$this->param['upr'] = $upr;
			$this->param['btm'] = $btm;
			$this->param['unit'] = $unit;
			$this->param['angle'] = $angle;
			$this->param['angle2'] = $angle2;
			$this->param['RESULT'] = 1;
			return $this->param;
		}elseif ($unit==2 && $want==1) {
			$deg=round($angle*180,3);
			$two=$angle;
			while ($two>=2) {
				$two=$two-2;
			}
			if ($angle>=2) {
				$pos=($two).' π,'.($two+2).' π,'.($two+4).' π,'.($two+6).' π,'.($two+8).' .....';
				$neg=($two-2).' π,'.($two-4).' π,'.($two-6).' π,'.($two-8).' π,'.($two-10).' .....';
			}else{
				$pos=($angle+2).' π,'.($angle+4).' π,'.($angle+6).' π,'.($angle+8).' π,'.($angle+10).' .....';
				$neg=($angle-2).' π,'.($angle-4).' π,'.($angle-6).' π,'.($angle-8).' π,'.($angle-10).' .....';
			}
			$rem=$deg%360;
			if ($rem>0 && $rem<90) {
				$q='first quadrant';
			}elseif ($rem==90) {
				$q='positive y-axis';
			}elseif ($rem>90 && $rem<180) {
				$q='second quadrant';
			}elseif ($rem==180) {
				$q='negative x-axis';
			}elseif ($rem>180 && $rem<270) {
				$q='third quadrant';
			}elseif ($rem==270) {
				$q='negative y-axis';
			}elseif ($rem>270) {
				$q='fourth quadrant';
			}elseif ($rem==0) {
				$q='positive x-axis';
			}
			$this->param['want'] = $want;
			$this->param['two'] = $two;
			$this->param['pos'] = $pos;
			$this->param['neg'] = $neg;
			$this->param['deg'] = $deg;
			$this->param['q'] = $q;
			$this->param['unit'] = $unit;
			$this->param['angle'] = $angle;
			$this->param['angle2'] = $angle2;
			$this->param['RESULT'] = 1;
			return $this->param;
		}elseif ($unit==1 && $want==2) {
			$angle_=$angle%360;
			$angle2_=$angle2%360;
			if ($angle_==$angle2_) {
				$check=1;
			}else{
				$check=0;
			}
			$this->param['check'] = $check;
			$this->param['want'] = $want;
			$this->param['unit'] = $unit;
			$this->param['angle'] = $angle;
			$this->param['angle2'] = $angle2;
			$this->param['RESULT'] = 1;
			return $this->param;
		}elseif ($unit==2 && $want==2) {
			$angle11=$angle*180;
			$angle22=$angle2*180;
			$angle_=$angle11%360;
			$angle2_=$angle22%360;
			if ($angle_==$angle2_) {
				$check=1;
			}else{
				$check=0;
			}
			$this->param['check'] = $check;
			$this->param['want'] = $want;
			$this->param['unit'] = $unit;
			$this->param['angle'] = $angle;
			$this->param['angle2'] = $angle2;
			$this->param['RESULT'] = 1;
			return $this->param;
		}
	}

