  				$angle=asin(sqrt($sin2x));
  			}elseif (empty($sinx) && empty($cosx) && empty($tanx) && empty($sin2x) && is_numeric($cos2x) && empty($tan2x)) {
  				$angle=acos(sqrt($cos2x));
  			}elseif (empty($sinx) && empty($cosx) && empty($tanx) && empty($sin2x) && empty($cos2x) && is_numeric($tan2x)) {
  				$angle=atan(sqrt($tan2x));
  			}else{
				$this->param['error'] = 'Please Enter any one of the know function value.';
				return $this->param;
