  			$sin3=(3*sin(deg2rad($angle)) - sin(3*deg2rad($angle)))/4;
  			$cos3=(1/4)*cos(3*deg2rad($angle)) + (3/4)* cos(deg2rad($angle));
  			$tan3=$sin3/$cos3;
  			$sin4=(3 - (4*cos(2*deg2rad($angle))) + cos(4*deg2rad($angle)))/8;
  			$cos4=(3 + (4*cos(2*deg2rad($angle))) + cos(4*deg2rad($angle)))/8;
  			$tan4=$sin4/$cos4;
  			$this->param['sin'] = $sin;
  			$this->param['cos'] = $cos;
