	// Rounding Calculator
	function rounding($request){
		$number = $request->number;
		$mode = $request->mode;
		$per = $request->per;
		if (is_numeric($number)) {
			$ans=round($number, $per, PHP_ROUND_HALF_UP);
			$one=round($number, 0, PHP_ROUND_HALF_UP);
			$two=round($number, -1, PHP_ROUND_HALF_UP);
			$three=round($number, -2, PHP_ROUND_HALF_UP);
			$four=round($number, -3, PHP_ROUND_HALF_UP);
			$this->param['ans'] = $ans;
			$this->param['one'] = $one;
			$this->param['two'] = $two;
			$this->param['three'] = $three;
			$this->param['four'] = $four;
			$this->param['RESULT'] = 1;

			return $this->param;
		} else {
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
		
	}

	// Arcsin Calculator
	function arcsin($request){
		$arcsin= $request->arcsin;
		$round= $request->round;
		if(is_numeric($arcsin) && is_numeric($round)){
			function DDtoDMS($dec){
				$vars=explode(".",$dec);
				if(count($vars)<2){
					$deg=$vars[0];
					$min=0;
					$sec=0;
				}else{
					$deg=$vars[0];
					$tempma="0.".$vars[1];
					$tempma=$tempma*3600;
					$min=floor($tempma/60);
					$sec=round($tempma-($min*60),3);
				}
				return array("deg"=>$deg,"min"=>$min,"sec"=>$sec);
			}
			$rad=asin($arcsin);
			$deg=rad2deg($rad);
			$gon=$rad*63.66;
			$tr=$rad*0.15915;
			$arcmin=$rad*3438;
			$arcsec=$rad*206265;
			$mrad=$rad*1000;
			$urad=$rad*1000000;
			$pirad=$rad*0.3183;
			$DMS=DDtoDMS($deg);
			$d=$DMS['deg'];
			$m=$DMS['min'];
			$s=$DMS['sec'];
			$this->param['angle']=round($deg,$round);
			$this->param['rad']=round($rad,$round);
			$this->param['gon']=round($gon,$round);
			$this->param['tr']=round($tr,$round);
			$this->param['arcmin']=round($arcmin,$round);
			$this->param['arcsec']=round($arcsec,$round);
			$this->param['mrad']=round($mrad,$round);
			$this->param['urad']=round($urad,$round);
			$this->param['pirad']=round($pirad,$round);
			$this->param['deg']=round($d,$round);
			$this->param['min']=round($m,$round);
			$this->param['sec']=round($s,$round);
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

