	function hemisphere($request){
		$to_calculate = $request->to_calculate;
		$val = $request->value;
		$unit = $request->unit;
		$rof = $request->rof;
		if (is_numeric($val)) {
			if ($to_calculate == 'rad') {
				$r=$val." ".$unit;
				$c=round(2*pi()*$val,$rof)." ".$unit;
				$v=round((2/3)*pi()*pow($val,3),$rof)." ".$unit."<sup class='font-s-14'>3</sup>";
				$a=round(2*pi()*pow($val,2),$rof)." ".$unit."<sup class='font-s-14'>2</sup>";
				$b=round(pi()*pow($val,2),$rof)." ".$unit."<sup class='font-s-14'>2</sup>";
				$tsa=round(3*pi()*pow($val,2),$rof)." ".$unit."<sup class='font-s-14'>2</sup>";
				$pc=round(2*$val,$rof)." "."π"." ".$unit;
				$pv=round((2/3)*pow($val,3),$rof)." "."π"." ".$unit."<sup class='font-s-14'>3</sup>";
				$pa=round(2*pow($val,2),$rof)." "."π"." ".$unit."<sup class='font-s-14'>2</sup>";
				$pb=round(pow($val,2),$rof)." "."π"." ".$unit."<sup class='font-s-14'>2</sup>";
				$ptsa=round(3*pow($val,2),$rof)." "."π"." ".$unit."<sup class='font-s-14'>2</sup>";  
			}elseif ($to_calculate == 'vol'){
				$r=round(pow((3*$val)/(2*pi()),1.0/3.0),$rof);
				$c=round(2*pi()*$r,$rof)." ".$unit;
				$v=round($val,$rof)." ".$unit."<sup class='font-s-14'>3</sup>";
				$a=round(2*pi()*pow($r,2),$rof)." ".$unit."<sup class='font-s-14'>2</sup>";
				$b=round(pi()*pow($r,2),$rof)." ".$unit."<sup class='font-s-14'>2</sup>";
				$tsa=round(3*pi()*pow($r,2),$rof)." ".$unit."<sup class='font-s-14'>2</sup>";
				$pc=round(2*$r,$rof)." "."π"." ".$unit;
				$pv=round((2/3)*pow($r,3),$rof)." "."π"." ".$unit."<sup class='font-s-14'>3</sup>";
				$pa=round(2*pow($r,2),$rof)." "."π"." ".$unit."<sup class='font-s-14'>2</sup>";
				$pb=round(pow($r,2),$rof)." "."π"." ".$unit."<sup class='font-s-14'>2</sup>";
