				$this->param['chrd_len'] = round($chrd_len,3);
				$this->param['area'] = round($area,3);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
			
		}elseif($find==='3'){
			if (is_numeric($rad) && is_numeric($chrd_len)) {
				$area=(pow($rad,2))*($angle/2);
