				$arc_len=$rad*$angle;
				if($angle_unit==='deg'){
					$angle=$angle*57.2958;
				}
				$this->param['arc_len'] = round($arc_len,5);
				$this->param['angle'] = round($angle,4);
				$this->param['diameter'] = round($diameter,3);
				$this->param['area'] = round($area,4);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
			
		}elseif($find==='4'){
			if (is_numeric($angle) && is_numeric($diameter)) {
				$rad=$diameter/2;
				$area=(pow($rad,2))*($angle/2);
				$arc_len=$rad*$angle;
				$this->param['arc_len'] = round($arc_len,5);
				$this->param['rad'] = round($rad,4);
				$this->param['diameter'] = round($diameter,3);
