				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}elseif($find==='5'){
			if (is_numeric($angle) && is_numeric($area)) {
				$rad=sqrt(((2*$area)/$angle));
				$diameter=$rad*2;
				$arc_len=$rad*$angle;
				$chrd_len=2*$rad*sin(($angle/2));
				$this->param['arc_len'] = round($arc_len,5);
				$this->param['rad'] = round($rad,4);
				$this->param['diameter'] = round($diameter,3);
				$this->param['chrd_len'] = round($chrd_len,3);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}elseif($find==='6'){
			if (is_numeric($angle) && is_numeric($chrd_len)) {
				$rad=$chrd_len/(2*(sin($angle/2)));
				$diameter=$rad*2;
				$area=(pow($rad,2))*($angle/2);
				$arc_len=$rad*$angle;
				$this->param['arc_len'] = round($arc_len,5);
				$this->param['rad'] = round($rad,4);
				$this->param['diameter'] = round($diameter,3);
				$this->param['area'] = round($area,4);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			if (is_numeric($chrd_len) && is_numeric($seg_height)) {
				$rad=($seg_height/2)+((pow($chrd_len,2))/(8*$seg_height));
				$angle=2*asin(($chrd_len/(2*$rad)));
				$diameter=$rad*2;
				$area=(pow($rad,2))*($angle/2);
				$arc_len=$rad*$angle;
				$this->param['arc_len'] = round($arc_len,5);
