				$this->param['rad'] = round($rad,4);
				$this->param['diameter'] = round($diameter,3);
				$this->param['area'] = round($area,4);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		$this->param['RESULT'] = 1;

		return $this->param;
	}

	// Arctan Calculator
	function arctan($request){
		$arctan= $request->arctan;
		$round= $request->round;
		if(is_numeric($arctan) && is_numeric($round)){
			function DDtoDMS($dec){
				$vars=explode(".",$dec);
				if(count($vars)<2){
						$deg=$vars[0];
					$min=0;
					$sec=0;
				}else{
					$deg=$vars[0];
					$tempma="0.".$vars[1];
					$tempma=$tempma*3600;
					$min=floor($tempma/60);
					$sec=round($tempma-($min*60),3);
				}
				return array("deg"=>$deg,"min"=>$min,"sec"=>$sec);
			}
			$rad=atan($arctan);
			$deg=rad2deg($rad);
			$gon=$rad*63.66;
			$tr=$rad*0.15915;
			$arcmin=$rad*3438;
			$arcsec=$rad*206265;
			$mrad=$rad*1000;
			$urad=$rad*1000000;
			$pirad=$rad*0.3183;
			$DMS=DDtoDMS($deg);
			$d=$DMS['deg'];
			$m=$DMS['min'];
			$s=$DMS['sec'];
			$this->param['angle']=round($deg,$round);
			$this->param['rad']=round($rad,$round);
			$this->param['gon']=round($gon,$round);
			$this->param['tr']=round($tr,$round);
			$this->param['arcmin']=round($arcmin,$round);
			$this->param['arcsec']=round($arcsec,$round);
			$this->param['mrad']=round($mrad,$round);
			$this->param['urad']=round($urad,$round);
			$this->param['pirad']=round($pirad,$round);
			$this->param['deg']=round($d,$round);
			$this->param['min']=round($m,$round);
			$this->param['sec']=round($s,$round);
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Sphere Calculator
	function sphere($request){
		$with= $request->slct1;	
		$rad= $request->rad;
		$pi= $request->pi;
		if (is_numeric($rad) && is_numeric($pi)) {
			if ($with=='1') {
				$volume=(4/3*$pi*$rad*$rad*$rad);
				$surfacearea=($pi*$rad*$rad);
				$circumference=2*$pi*$rad;
				$v1=(4/3*$rad*$rad*$rad);
				$c1=2*$rad;
				$s1=$c1*$c1;
			}elseif ($with=='2') {
				$radius=(3*$rad/(4*$pi))**(1/3)."<br>";
				$circumference=($pi**(2/3)*(6*$rad)**(1/3));
				$surfacearea=($pi**(1/3)*(6*$rad)**(2/3));
				$volume=$rad;
				$v1=$rad/$pi;
				$c1=$circumference/$pi;
				$s1=$surfacearea/$pi; 
				$rad=$radius;
			}elseif ($with=='3') {
				$radius=sqrt($rad/(4*$pi));
				$circumference=sqrt($pi*$rad);
				$volume=($rad**(3/2)/(6*sqrt($pi)));
				$surfacearea=$rad;
				$v1=$volume/$pi;
				$c1=$circumference/$pi;
				$s1=$rad/$pi; 
				$rad=$radius;
			}elseif ($with=='4') {
				$radius=($rad/(2*$pi));
				$circumference=$rad;
				$surfacearea=($rad*$rad/$pi);
				$volume=($rad*$rad*$rad/(6*$pi*$pi));
				$v1=$volume/$pi;
				$c1=$rad/$pi;
				$s1=$surfacearea/$pi; 
				$rad=$radius;
			}
			$this->param['rad'] = round($rad,5);
			$this->param['vol'] = round($volume,5);
			$this->param['v1'] = round($v1,5);
			$this->param['c1'] = round($c1,5);
			$this->param['s1'] = round($s1,5);
			$this->param['area'] = round($surfacearea,5);
			$this->param['c'] = round($circumference,5);
			$this->param['RESULT'] = 1;


			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Area of A Sector Calculator
	function sector($request){
		// dd($request->all());
		$angle= $request->angle;	
		$angle_unit= $request->angle_unit;
		$rad= $request->rad;
		$rad_unit= $request->rad_unit;
		$diameter= $request->diameter;
		$diameter_unit= $request->diameter_unit;
		$area= $request->area;
		$area_unit= $request->area_unit;
		$arc= $request->arc;
		$arc_unit= $request->arc_unit;
		$c= $request->c;
		$c_unit= $request->c_unit;
		if (is_numeric($angle) && is_numeric($rad) && empty($diameter) && empty($area) && empty($arc) && empty($c)) {
			if ($angle_unit=='deg') {
				$angle=deg2rad($angle);
			}
			$area=$angle*pow($rad, 2)/2;
			$dia=$rad*2;
			$arc=$angle*$rad;
			$c=2*$rad*sin($angle/2);
			$this->param['mode'] = 1;
			$this->param['area'] = $area;
			$this->param['unit'] = $rad_unit;
			$this->param['dia'] = $dia;
			$this->param['arc'] = $arc;
			$this->param['c'] = $c;
			$this->param['RESULT'] = 1;
			return $this->param;
		}elseif (is_numeric($angle) && empty($rad) && is_numeric($diameter) && empty($area) && empty($arc) && empty($c)) {
			if ($angle_unit=='deg') {
				$angle=deg2rad($angle);
			}
			$rad=$diameter/2;
			$area=$angle*pow($rad, 2)/2;
			$arc=$angle*$rad;
			$c=2*$rad*sin($angle/2);
			$this->param['mode'] = 2;
			$this->param['area'] = $area;
			$this->param['unit'] = $diameter_unit;
			$this->param['rad'] = $rad;
			$this->param['arc'] = $arc;
			$this->param['c'] = $c;
			$this->param['RESULT'] = 1;
			return $this->param;
		}elseif (empty($angle) && is_numeric($rad) && empty($diameter) && is_numeric($area) && empty($arc) && empty($c)) {
			$check_unit=str_replace('²', '', $area_unit);
			if ($check_unit===$rad_unit) {
				$unit=$rad_unit;
			}else{
				$unit='cm';
				if($rad_unit=='in'){
					$rad=$rad*2.54;
				}elseif($rad_unit=='m'){
					$rad=$rad*100;
				}elseif($rad_unit=='ft'){
					$rad=$rad*30.48;
				}elseif($rad_unit=='yd'){
					$rad=$rad*91.44;
				}
