	// Variation Calculator
	function variation($request){
		$x=$request->x;
		$y=$request->y;
		$select=$request->select;
		if (is_numeric($x) && is_numeric($y)) {
			if ($select==='1') {
				$ans=$y/$x;
			}elseif ($select==='2') {
				$ans=$y*$x;
			}elseif ($select==='3') {
				$ans=$y/pow($x,2);
			}elseif ($select==='4') {
				$ans=$y/pow($x,3);
			}elseif ($select==='5') {
				$ans=$y/sqrt($x);
			}elseif ($select==='6') {
				$ans=$y*pow($x,2);
			}elseif ($select==='7') {
				$ans=$y*pow($x,3);
			}elseif ($select==='8') {
				$ans=$y*sqrt($x);
			}
			$this->param['ans'] = $ans;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

