	// Point Slope Form Calculator
	function point($request){
		$point_unit = $request->point_unit;
		$x1 = $request->x1;
		$y1 = $request->y1;
		$m = $request->m;
		$sec_x1 = $request->sec_x1;
		$sec_y1 = $request->sec_y1;
		$sec_x2 = $request->sec_x2;
		$sec_y2 = $request->sec_y2;
		if($point_unit ==='1'){
			if (is_numeric($x1) && is_numeric($y1) && is_numeric($m)) {
				$x1=$x1*(-1);
				$y1=$y1*(-1);
				$mn=$x1*$m;
				$s=" y ".(($y1<0)?'- '.abs($y1):'+ '.$y1)."  = ".$m."( x ".(($x1<0)?'- '.abs($x1):'+ '.$x1)." )";
				$s1="( y ".(($y1<0)?'- '.abs($y1):'+ '.$y1).") = ".$m."x ".(($mn<0)?'- '.abs($mn):'+ '.$mn);
				$s2="y = ".$m."x ".(($mn<0)?'- '.abs($mn):'+ '.$mn)." ".(($y1<0)?'+ '.abs($y1):'- '.$y1);
				$val=$mn+$y1;
				$s3="y = ".$m."x ".(($val<0)?'- '.abs($val):'+ '.$val);
				$val=$mn+$y1;
				$s4=$m."x - y ".(($val<0)?'- '.abs($val):'+ '.$val)." = 0";
				$this->param['s'] = $s;
				$this->param['s1'] = $s1;
				$this->param['s2'] = $s2;
				$this->param['s3'] = $s3;
				$this->param['s4'] = $s4;
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			if(is_numeric($sec_x1) && is_numeric($sec_y1) && is_numeric($sec_x2) && is_numeric($sec_y2)){
				if ($sec_x2 == "0" && $sec_x1 == "0" ) {
					$this->param['error'] = 'Please Check Your Input value cannot be equal to or less then zero.';
					return $this->param;
				}
				$m = ($sec_y2 - $sec_y1) / ($sec_x2 - $sec_x1);
				$slope = $m;
				$sec_x1=$sec_x1*(-1);
				$sec_y1=$sec_y1*(-1);
				$mn=$sec_x1*$m;
				$s="( y ".(($sec_y1<0)?'- '.abs($sec_y1):'+ '.$sec_y1)." ) = ".$m."( x ".(($sec_x1<0)?'- '.abs($sec_x1):'+ '.$sec_x1)." )";
				$s1="( y ".(($sec_y1<0)?'- '.abs($sec_y1):'+ '.$sec_y1).") = ".$m."x ".(($mn<0)?'- '.abs($mn):'+ '.$mn);
				$s2="y = ".$m."x ".(($mn<0)?'- '.abs($mn):'+ '.$mn)." ".(($sec_y1<0)?'+ '.abs($sec_y1):'- '.$sec_y1);
				$val=$mn+$sec_y1;
				$s3="y = ".$m."x ".(($val<0)?'- '.abs($val):'+ '.$val);
				$s4=$m."x - y ".(($val<0)?'- '.abs($val):'+ '.$val)." = 0";
				$this->param['s'] = $s;
				$this->param['s1'] = $s1;
				$this->param['s2'] = $s2;
				$this->param['s3'] = $s3;
				$this->param['s4'] = $s4;
				$this->param['slope'] = $slope;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		$this->param[ 'RESULT' ] = 1;
		return $this->param;
	}

	// Discriminant Calculator
	function discriminant($request){
		$to_calculate = $request->to_calculate;
		$value = $request->value;
		$value1 = $request->value1;
		$value2 = $request->value2;
		$value3 = $request->value3;
		$value4 = $request->value4;
		if ($to_calculate=='2d'){
			if (is_numeric($value) && is_numeric($value1) && is_numeric($value2)){
				$A=$value;
				$B=$value1;
				$C=$value2;
				$ds=pow($B,2)-4*$A*$C;
				if ($ds==0) {
				$nr="The polynomial has a double root.";}
				else if ($ds>0) {
				$nr="The polynomial has two distinct real roots";}
				else if ($ds<0) {
				$nr="The polynomial has a pair of conjugate complex roots";}
				$this->param['sd'] = $ds;
				$this->param['nrs']=$nr;		
				$this->param['RESULT'] = 1;
				return $this->param;
			}
			else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		elseif ($to_calculate=='3d') {
			if (is_numeric($value) && is_numeric($value1) && is_numeric($value2)){
				$A=$value;
				$B=$value1;
				$C=$value2;
				$D=$value3;
				$ds=pow($B,2)*pow($C,2)-4*$A*pow($C,3)-4*pow($B,3)*$D-27*pow($A,2)*pow($D,2)+18*$A*$B*$C*$D;
				if ($ds==0) {
				$nr="At least two roots are equal (one root of multiplicity 3 or two distinct real roots)one of which is a double root";}
				else if ($ds>0) {
				$nr="The roots are three distinct real numbers";}
				else if ($ds<0) {
				$nr="There is one real root and two complex conjugate roots";}
				$this->param['sd'] = $ds;
				$this->param['nrs']=$nr;		
				$this->param['RESULT'] = 1;
				return $this->param;
			}
			else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		elseif ($to_calculate=='4d') {
			if (is_numeric($value) && is_numeric($value1) && is_numeric($value2) && is_numeric($value3) && is_numeric($value4)){
				$A=$value;
				$B=$value1;
				$C=$value2;
				$D=$value3;
				$E=$value4;
				$ds=256*pow($A,3)*pow($E,3)-192*pow($A,2)*$B*$D*pow($E,2)-128*pow($A,2)*pow($C,2)*pow($E,2)+144*pow($A,2)*$C*pow($D,2)*$E-27*pow($A,2)*pow($D,4)+144*$A*pow($B,2)*$C*pow($E,2)-6*$A*pow($B,2)*pow($D,2)*$E-80*$A*$B*pow($C,2)*$D*$E+18*$A*$B*$C*pow($D,3)+16*$A*pow($C,4)*$E-4*$A*pow($C,3)*pow($D,2)-27*pow($B,4)*pow($E,2)+18*pow($B,3)*$C*$D*$E-4*pow($B,3)*pow($D,3)-4*pow($B,2)*pow($C,3)*$E+pow($B,2)*pow($C,2)*pow($D,2);
				if ($ds==0) {
				$nr="There are two or more equal roots";}
				else if ($ds>0){
					$nr="There are four distinct real roots or four distinct non-real roots";}
				else if ($ds<0){
				$nr="There are two distinct real roots and two distinct non-real roots";}
				$this->param['sd'] = $ds;
				$this->param['nrs']=$nr;		
				$this->param['RESULT'] = 1;
				return $this->param;
			}else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
	}

	// Power Set Calculator
	function power($request){
		$set = $request->set;
		if(preg_match("/\<|\>|\&|\+|\-|\(|\)|\{|\}|\[|\]|\||php|print_r|print|echo|sin|cos|tan|arcsin|arccos|arctan|script|=|&|%/i",$set)){
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if(!empty($set)){
			$set=str_replace(' ', '', $set);
			$set=explode(',',$set);
			if (count($set) >= 10) {
				$this->param['error'] = 'Please Enter maximum 10 numbers.';
				return $this->param;
			}
			// Powerset Function
			function power_set($array){
				$results = [[]];
				foreach($array as $key => $value){
					foreach($results as $combination){
					$results[] = $combination + [$key => $value];
					}
				}
				# array_shift($results); # uncomment if you don't want the empty set in your results
				$order = array_map('count', $results);
				uksort($results, function($key_a, $key_b) use ($order){
					# change only this to $order[$key_b] - $order[$key_a] for descending size
					$comp = $order[$key_a] - $order[$key_b];
					if($comp == 0){
					$comp = $key_a - $key_b;
					}
					return $comp;
				});
				return array_values($results);
			}
			$size=count($set);
			$powset=power_set($set,$size);
			$count=count($powset);
			$comma=',';
			$arr='';
			foreach($powset as $key => $value){
				$counter=0;
				$arr.='{';
				foreach($value as $key1 => $value1){
					if(count($value)-1==$counter){
					$arr.=$value1;
					}else{
					$arr.=$value1.$comma;
					}
					$counter++;
				}
				if($key===$count-1){
					$comma='';
				}
				$arr.='}'.$comma;
			}
			$this->param['size'] = $size;
			$this->param['powerset'] = $arr;
			$this->param['subsets'] = $count;
			$this->param['pro_subsets'] = $count-1;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Subset Calculator
	function subset($request){
		$cal_by = $request->cal_by;
		$set = $request->set;
		$cardinal = $request->cardinal;
		if(preg_match("/\<|\>|\&|\+|\-|\(|\)|\{|\}|\[|\]|\||php|print_r|print|echo|sin|cos|tan|arcsin|arccos|arctan|script|=|&|%/i",$set)){
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		$check=false;
		if($cal_by==='elements'){
			if(!empty($set)) {
				$check=true;
				$set=str_replace(' ', '', $set);
				$set=explode(',',$set);
				if (count($set)>10) {
					$this->param['error'] = 'Number of Elements must be less than or equal to 10.';
					return $this->param;
				}
				// Powerset Function
				function power_set($array){
					$results = [[]];
					foreach($array as $key => $value){
						foreach($results as $combination){
							$results[] = $combination + [$key => $value];
						}
					}
					# array_shift($results); # uncomment if you don't want the empty set in your results
					$order = array_map('count', $results);
					uksort($results, function($key_a, $key_b) use ($order){
						# change only this to $order[$key_b] - $order[$key_a] for descending size
						$comp = $order[$key_a] - $order[$key_b];
						if($comp == 0){
							$comp = $key_a - $key_b;
						}
						return $comp;
					});
					return array_values($results);
				}
				$size=count($set);
				$powset=power_set($set,$size);
				$count=count($powset);
				$comma=',';
				$arr='';
				foreach($powset as $key => $value){
					$counter=0;
					$arr.='{';
					foreach($value as $key1 => $value1){
						if(count($value)-1==$counter){
							$arr.=$value1;
						}else{
							$arr.=$value1.$comma;
						}
						$counter++;
					}
					if($key===$count-1){
						$comma='';
					}
					$arr.='}'.$comma;
				}
				$this->param['pw'] = $arr;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}elseif($cal_by==='cardinality'){
			if(is_numeric($cardinal)) {
				$check=true;
				if ($cardinal>100) {
					$this->param['error'] = 'Elements must be less than or equal to 100.';
					return $this->param;
				}
				$size=$cardinal;
				$count=pow(2,$size);
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		if($check===true){
			$ne=array();
			$size1=$size;
			function myFactorial($n) {
				if ($n === 0 || $n === 1) {
					return 1;
				}
				$result = 1;
				for ($i = 2; $i <= $n; $i++) {
					$result *= $i;
				}
				return $result;
			}
			for($i=0; $i <= $size; $i++){
				$ne[].= myFactorial($size) / (myFactorial($i) * myFactorial($size1));
				$size1--;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$this->param['subsets'] = $count;
		$this->param['pro_subsets'] = $count-1;
		$this->param['ne'] = $ne;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Orthocenter Calculator
	function orthocenter($request){
		$x1= $request->x1;
		$y1= $request->y1;
		$x2= $request->x2;
		$y2= $request->y2;
		$x3= $request->x3;
		$y3= $request->y3;
		if(is_numeric($x1) && is_numeric($y1) && is_numeric($x2) && is_numeric($y2) && is_numeric($x3) && is_numeric($y3)){
			$a=$y2-$y1;
			$a1=$x2-$x1;
			if($a!=0 && $a1!=0){
				$ab = $a/$a1;
				$ab1=-1/$ab;
				$ab2=($y3)-($ab1*$x3);
				if($ab2>0){
					$xx="y"."=".$ab1."x".".".$ab2;
				}else{
					$xx ="y"."=".$ab1."x".$ab2;
				}
			}
			$b=$y3-$y2;
			$b1=$x3-$x2;
			if($b!=0 && $b1!=0){ 
				$bc = $b/$b1;
				$bc1=-1/$bc;
				$bc2=($y1)-($bc1*$x1);
				if($bc2>0){
					$xx="y"."=".$bc1."x".".".$bc2;
				}else{
					$xx ="y"."=".$bc1."x".$bc2;
				}
			}
			$c=$y3-$y1;
			$c1=$x3-$x1;
			if($c!=0 && $c1 !=0){
				$ca = $c/$c1;
