	// Circumcenter Calculator
	function circumcenter($request){
		$x1 = $request->x1;
		$x2 = $request->x2;
		$x3 = $request->x3;
		$y1 = $request->y1;
		$y2 = $request->y2;
		$y3 = $request->y3;
		if (is_numeric($x1) && is_numeric($y1) && is_numeric($x2) && is_numeric($y2) && is_numeric($x3) && is_numeric($y3)) {
			$xa=$x1;
			$ya=$y1;
			$xb=$x2;
			$yb=$y2;
			$xc=$x3;
			$yc=$y3;
			$m=(+$xa)+(+$xb);
			$m1=$m/2;
			$m2=(+$ya)+(+$yb);
			$m3=$m2/2;
			$a=$yb-$ya;
			$a1=$xb-$xa;
			if($a!=0 && $a1!=0){
				$ab = $a/$a1;
				$ab1=-1/$ab;
				$ab2=($m3)-($ab1*$m1);
				if($ab2>0){
					$xx="y"."=".$ab1."x"."+".$ab2;
				}else{
					$xx ="y"."=".$ab1."x".$ab2;
				}
			}	
			$m5=(+$xc)+(+$xb);
			$m6=$m5/2;
			$m7=(+$yc)+(+$yb);
			$m8=$m7/2;
			$b=$yc-$yb;
			$b1=$xc-$xb;
			if($b!=0 && $b1!=0){	
				$bc = $b/$b1;
				$bc1=-1/$bc;
				$bc2=($m8)-($bc1*$m6);
				if($bc2>0){
					$xx="y"."=".$bc1."x"."+".$bc2;
				}else{
					$xx ="y"."=".$bc1."x".$bc2;
				}
			}
			$m9=(+$xc)+(+$xa);
			$m10=$m9/2;
			$m11=(+$yc)+(+$ya);
			$m12=$m11/2;
			$c=$yc-$ya;
			$c1=$xc-$xa;
			if($c!=0 && $c1 !=0){
				$ca = $c/$c1;
				$ca1=-1/$ca;
				$ca2=($m12)-($ca1*$m10);
				if($ca2>0){
					$xx="y"."=".$ca1."x"."+".$ca2;
				}else{
					$xx ="y"."=".$ca1."x".$ca2;
				}
			}
			if($a!=0&&$a1!=0&&$b!=0&&$b1!=0&&$c!=0&&$c1!=0){
				$con=-$bc1;
				$con1=-$bc2;
				$ad=$con+$ab1;
				$ad1=$ab2+$con1;
				$di=$ad1/$ad;
				$di1=-$di;
				$y8=($bc1*$di1)+$bc2;
				$x=$di1;
				$y=$y8;

			}else if($a!=0 && $a1!=0 && $b!=0 && $b1 !=0){
				$con=-$bc1;
				$con1=-$bc2;
				$ad=$con+$ab1;
				$ad1=$ab2+$con1;
				$di=$ad1/$ad;
				$di1=-$di;
				$y8=($bc1*$di1)+$bc2;
				$x=$di1;
				$y=$y8;
			}else if($b!=0 && $b1!=0 && $c!=0 && $c1 !=0){
				$con2=-$ca1;
				$con3=-$ca2;
				$ad2=$con2+$bc1;
				$ad3=$bc2+$con3;
				$di=$ad3/$ad2;
				$di1=-$di;
				$y8=($ca1*$di1)+$ca2;
				$x=$di1;
				$y=$y8;

			}else if($a!=0 && $a1!=0 && $c!=0 && $c1 !=0){
				$con2=-$ab1;
				$con3=-$ab2;
				$ad2=$con2+$ca1;
				$ad3=$ca2+$con3;
				$di=$ad3/$ad2;
				$di1=-$di;
				$y8=($ab1*$di1)+$ab2;
				$x=$di1;
				$y=$y8;
			}
			$this->param['x'] = $x;
			$this->param['y'] = $y;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
