	// Percentage Increase Calculator
	function per_inc($request){
		$start = $request->start;	
		$final = $request->final;
		if (is_numeric($start) && is_numeric($final)) {
			$ans=($final-$start)/abs($start);
			$this->param['ans1'] = round($ans,3);
			$ans=$ans*100;
			$this->param['ans'] = $ans;
			$this->param['dif'] = $final-$start;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Truncated Pyramid Calculator
	function truncated($request){
		$ubl = $request->ubl;
		$ubw = $request->ubw;
		$lbl = $request->lbl;
		$lbw = $request->lbw;
		$height = $request->height;
	    if (is_numeric($ubl) && is_numeric($ubw) && is_numeric($ubl) && is_numeric($lbl) && is_numeric($height)) {
			$DL = round((sqrt(pow($lbl, 2) + pow($lbw, 2))), 2);
			$DT = round((sqrt(pow($ubl, 2) + pow($ubw, 2))), 2);
			$dia = ($DL/2) - ($DT/2);
			$HL = round((sqrt(pow(($dia), 2) + pow($height, 2))), 2);
			$sL = $lbl / 2;
			$sW = $lbw / 2;
			$si = $ubl / 2;
			$sw = $ubw / 2;
			$c1 = $sW - $sw;
			$c2 = $sL - $si;
			$slA = round((sqrt(pow($c1, 2) + pow($height, 2))), 2);
			$slB = round((sqrt(pow($c2, 2) + pow($height, 2))), 2);
			$a = round((asin($height / $HL)) * (180/3.14), 2);
			$b = round((atan($height / $c1)) * (180/3.14), 2);
			$c = round((atan($height / $c2)) * (180/3.14), 2);
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$this->param['DL'] = $DL;
		$this->param['DT'] = $DT;
		$this->param['HL'] = $HL;
		$this->param['slA'] = $slA;
		$this->param['slB'] = $slB;
		$this->param['a'] = $a;
		$this->param['b'] = $b;
		$this->param['c'] = $c;
	    $this->param[ 'RESULT' ] = 1;
		return $this->param;
	}

