	// Cube Root Calculator
	function cube($request){
		$number = $request->number;
		if (is_numeric($number)) {
            $number = floatval($number);
            $cube_root = pow(abs($number), 1/3);
            if ($number < 0) {
                $cube_root = -$cube_root;
