			return $this->param;
		}
    }

	// Amplitude and Period Calculator
	function amplitude($request){
		$trigonometric_unit= $request->trigonometric_unit;
		$first_number= $request->first_number;
		$second_number= $request->second_number;
		$third_number= $request->third_number;
		$fourth_number= $request->fourth_number;
		if(is_numeric($first_number) && is_numeric($second_number) && is_numeric($third_number) && is_numeric($fourth_number)){
			if($first_number==0){
				$this->param['error'] = 'For A=0, this is not a trigometric function!';
				return $this->param;
			}else if($second_number==0){
				$this->param['error'] = 'For B=0, this is not a trigometric function!';
				return $this->param;
			}
			else{
				$this->param['first_number']=$first_number;
				$this->param['second_number']=2/$second_number;
				$this->param['third_number']=$third_number/$second_number;
				$this->param['fourth_number']=$fourth_number;
				$this->param['fifth_number']=$second_number;
				$this->param['sixth_number']=$third_number;
				$this->param['operation']=$trigonometric_unit;
				$this->param['RESULT'] = 1;
				return $this->param;	
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Angle Of Elevation Calculator
	function angle_of($request){
		$to_cal= $request->to_cal;
		$vertical= $request->vertical;
		$vertical_unit= $request->vertical_unit;
		$hori= $request->hori;
		$hori_unit= $request->hori_unit;
		$angle= $request->angle;
		$angle_unit= $request->angle_unit;
		function unit_meter($a,$b){
			if ($b==='cm') {
				$convertedVal = $a * 0.01;
			}elseif ($b==='km') {
				$convertedVal = $a * 1000;
			}elseif ($b==='in') {
				$convertedVal = $a * 0.0254;
			}elseif ($b==='ft') {
				$convertedVal = $a * 0.3048;
			}elseif ($b==='yd') {
				$convertedVal = $a * 0.9144;
			}elseif ($b==='mi') {
				$convertedVal = $a * 1609.3;
			}else{
				$convertedVal = $a * 1;
			}
			return $convertedVal;
		}
		if ($to_cal==='1') {
			if(is_numeric($vertical) && is_numeric($hori)){
				$vertical = unit_meter($vertical,$vertical_unit);
				$hori = unit_meter($hori,$hori_unit);
				$angle=atan($vertical/$hori);
				$grade=$vertical/$hori;
				$gradep=$vertical/$hori*100;
				$ang_deg=rad2deg($angle);
				$this->param['angle'] = $angle;
				$this->param['ang_deg'] = $ang_deg;
				$this->param['grade'] = $grade;
				$this->param['gradep'] = $gradep;
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}elseif($to_cal==='2'){
			if(is_numeric($angle) && is_numeric($hori)){
				$hori = unit_meter($hori,$hori_unit);
				if ($angle_unit==='deg') {
					$vertical=$hori*tan(deg2rad($angle));
				}else{
					$vertical=$hori*tan($angle);
				}
				$grade=$vertical/$hori;
				$gradep=$vertical/$hori*100;
				$this->param['vertical'] = round($vertical,4).' '.$hori_unit;
				$this->param['grade'] = $grade;
				$this->param['gradep'] = $gradep;
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			if(is_numeric($vertical) && is_numeric($angle)){
				$vertical = unit_meter($vertical,$vertical_unit);
				if ($angle_unit==='deg') {
					$hori=$vertical/tan(deg2rad($angle));
				}else{
					$hori=$vertical/tan($angle);
				}
				$grade=$vertical/$hori;
				$gradep=$vertical/$hori*100;
				$this->param['hori'] = round($hori,4).' '.$vertical_unit;
				$this->param['grade'] = $grade;
				$this->param['gradep'] = $gradep;
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
	}

	// Arithmetic Sequences Calculator
	function arithmetic($request){
		$first= $request->first;
		$diff= $request->diff;
		$nth= $request->nth;
		if (is_numeric($first) && is_numeric($diff) && is_numeric($nth)){
        	$nth_v=$first+(($nth-1)*$diff);
        	$sum=$first;
        	$res="$first";
        	for ($i=1; $i < 10; $i++) { 
        		$sum = $sum + $diff;
        		if ($i<9) {
        			$res.=", $sum";
        		}
        		if ($i==9) {
        			$res.=" ....";
        		}
        	}
        	$total=($nth/2)*((2*$first)+($nth-1)*$diff);
        	$this->param['first'] = $first;
        	$this->param['diff'] = $diff;
        	$this->param['nth'] = $nth;
        	$this->param['total'] = $total;
        	$this->param['res'] = $res;
        	$this->param['nth_v'] = $nth_v;
			$this->param['RESULT'] = 1;
			return $this->param;
        }else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

    //Perfect Square Trinomial Calculator
    function perfect($request){
		$A= $request->A;
		$B= $request->B;
		$C= $request->C;
        if (is_numeric($A) && is_numeric($B) && is_numeric($C)){
			$ds=pow($B,2)-4*$A*$C;
			$this->param['sd'] = $ds;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
    }

	// Comparing Fractions Calculator
	function comparing($request){
		$first= $request->first;
		$second= $request->second;
  		if (!empty($first) && !empty($second)) {
  			if (preg_match("/%/i", $first)) {
				$nbr1=str_replace('%', '', $first);
				if (is_numeric($nbr1)) {
					$nbr1=$nbr1 / 100;
				}else{
					$this->param['error'] = 'Please Enter Valid Input.';
					return $this->param;
				}
			}else{
				$fraction_check=explode('/', trim($first));
				if (count($fraction_check)==2) {
					$mixed_check=explode(' ',trim($fraction_check[0]));
					if (count($mixed_check)==2) {
						if (is_numeric(trim($mixed_check[0])) && is_numeric(trim($mixed_check[1])) && is_numeric(trim($fraction_check[1]))) {
							$up=(trim($mixed_check[0])*trim($fraction_check[1]))+trim($mixed_check[1]);
							$nbr1=$up/trim($fraction_check[1]);
						}else{
							$this->param['error'] = 'Please Enter Valid Input.';
							return $this->param;
						}
					}elseif(count($mixed_check)>2){
						$this->param['error'] = 'Please Enter Valid Input.';
						return $this->param;
					}else{
						if (is_numeric(trim($fraction_check[0])) && is_numeric(trim($fraction_check[1]))) {
							$nbr1=trim($fraction_check[0])/trim($fraction_check[1]);
						}else{
							$this->param['error'] = 'Please Enter Valid Input.';
							return $this->param;
						}
					}
				}elseif (count($fraction_check)>2) {
					$this->param['error'] = 'Please Enter Valid Input.';
					return $this->param;
				}else{
					if (is_numeric(trim($first))) {
						$nbr1=trim($first);
					}else{
						$this->param['error'] = 'Please Enter Valid Input.';
						return $this->param;
					}
				}
			}
			if (preg_match("/%/i", $second)) {
				$nbr2=str_replace('%', '', $second);
				if (is_numeric($nbr2)) {
					$nbr2=$nbr2 / 100;
				}else{
					$this->param['error'] = 'Please Enter Valid Input.';
					return $this->param;
				}
			}else{
