			if($angle_unit==='rad'){
				$angle=rad2deg($angle);
			}elseif($angle_unit==='pirad'){
				$angle=rad2deg($angle*pi());
			}
			$sin=sin(deg2rad($angle));
			$cos=cos(deg2rad($angle));
