	// 45 45 90 Triangle Calculator
	function forty_five($request){
	
		$sides = $request->sides;
		$input = $request->input;
		$linear_unit = $request->linear_unit;
		$square_unit = $request->square_unit;
		function unit_convert($unit,$value){
			if($unit === "mm"){
				$val1 = $value*0.1;
			}else if($unit === "cm"){
				$val1 = $value * 1;
			}else if($unit === "m"){
				$val1 = $value * 100;
			}else if($unit === "km"){
				$val1 = $value * 1000;
			}else if($unit === "in"){
				$val1 = $value * 2.54;
			}else if($unit === "ft"){
				$val1 = $value * 30.48;
			}else if($unit === "yd"){
				$val1 = $value * 91.44;
			}else if($unit === "mi"){
				$val1 = $value * 160934;
			}
			return $val1;	
		}
		function centi($unit3,$value3){
			if($unit3 === "mm²"){
				$val3 = $value3 * 0.01;
			}else if($unit3 === "cm²"){
				$val3 = $value3 * 1;
			}else if($unit3 === "m²"){
				$val3 = $value3 * 10000;
			}else if($unit3 === "km²"){
				$val3 = $value3 * 10000000000;
			}else if($unit3 === "in²"){
				$val3 = $value3 * 6.452;
			}else if($unit3 === "ft²"){
				$val3 = $value3 * 929;
			}else if($unit3 === "yd²"){
				$val3 = $value3 * 8361;
			}else if($unit3 === "mi²"){
				$val3 = $value3 * 25899881103;
			}
			return $val3;
		}
		if(is_numeric($input)){
			if ($sides === "a") {
				$user_input = unit_convert($linear_unit,$input);
				$a_ans = $user_input; 
				$b_ans = $user_input; 
				$c_ans = $user_input * sqrt(2);
				$area_ans = pow($user_input, 2) / 2;
				$perimeter_ans = $user_input * 3.41421356;
			}else if ($sides === "b"){
				$user_input = unit_convert($linear_unit,$input);
				$c_ans = $user_input * sqrt(2);
				$a_ans = $user_input; 
				$b_ans = $user_input; 
				$area_ans = pow($user_input, 2) / 2;
				$perimeter_ans = $user_input * 3.41421356;
			}else if ($sides === "c"){
				$user_input = unit_convert($linear_unit,$input);
				$c_ans = $user_input;
				$a_ans = $user_input / 1.4142135;
				$b_ans = $a_ans; 
				$area_ans = pow($a_ans, 2) / 2;
				$perimeter_ans = $a_ans * 3.41421356;
			}else if ($sides === "area"){
				$user_input = centi($square_unit,$input);
				$area_ans = $user_input;
				$a_ans = sqrt($user_input * 2);
				$b_ans = $a_ans; 
				$c_ans = $a_ans * sqrt(2);
				$perimeter_ans = $a_ans * 3.41421356;
			}else if ($sides === "perimeter"){
				$user_input = unit_convert($linear_unit,$input);
				$perimeter_ans = $user_input;
				$a_ans = $user_input / 3.41421356;
				$b_ans = $a_ans; 
				$c_ans = $a_ans * sqrt(2);
				$area_ans = pow($a_ans, 2) / 2;
			}
			$height = $c_ans / 2;
			$radius = $a_ans - $height;
	   	}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
	   	}
		$this->param['a_ans'] = $a_ans;
		$this->param['b_ans'] = $b_ans;
		$this->param['c_ans'] = $c_ans;
		$this->param['area_ans'] = $area_ans;
		$this->param['perimeter_ans'] = $perimeter_ans;
		$this->param['height'] = $height;
		$this->param['radius'] = $radius;
		$this->param['RESULT'] = 1;
		//  dd($this->param);
	    return $this->param;
	}

