	  			$b=$check_b[0]/$check_b[1];
	  		}
	  		$check_c=explode('/', $c);
	  		if (count($check_c)==2) {
	  			$c=$check_c[0]/$check_c[1];
	  		}
	  		if (is_numeric($a) && is_numeric($b) && is_numeric($c) && $b!=0) {
				$m=((-1)*$a)/$b;
