	  		}
  		}else{
  			$m=$a;
  			$c=$b;
  			$check_a=explode('/', $a);
	  		if (count($check_a)==2) {
	  			$a=$check_a[0]/$check_a[1];
	  		}
	  		$check_b=explode('/', $b);
	  		if (count($check_b)==2) {
	  			$b=$check_b[0]/$check_b[1];
	  		}
	  		if (is_numeric($a) && is_numeric($b)) {
				/****
				** Reduce value
				****/
				function gcd($a,$b) 
				{
					$a = abs($a); $b = abs($b);

					if( $a < $b)
					{ 
						list($b,$a) = Array($a,$b);
					}
					if( $b == 0){
						return 1;
					}
					$r = $a % $b;
					while($r > 0): 
						$a = $b;
						$b = $r;
						$r = $a % $b;
					endwhile;
					return $b;
			
				}

				function reduce($num,$den) 
				{
					$g = gcd($num,$den);
					return array($num/$g,$den/$g);
				}
				function to_frac($num){
					$nbr=$num;
					$nbr=explode('.', $nbr);
					$div='1';
					$count=0;
					if (count($nbr)>1) {
						$count=strlen($nbr[1]);
					}
					for ($i=1; $i <= $count ; $i++) { 
						$div.='0';
					}
					if (count($nbr)>1) {
						$upr=$nbr[0].$nbr[1];
					}else{
						$upr=$num;
					}
					list ($upr,$div) = reduce($upr,$div);
					return array($upr,$div);
				}
				function lcmofn($numbers, $n)
				{
					$ans = $numbers[0];
					for ($i = 1; $i < $n; $i++)
					$ans = ((($numbers[$i] * $ans)) / (gcd($numbers[$i], $ans)));
					return $ans;
				}
				if (count($check_a)==1 && count($check_b)==1) {
					list($upr,$btm)=to_frac($a);
					list($upr1,$btm1)=to_frac($b);
					$g = gcd($btm,$btm1);
					$lcm=lcmofn(array($btm,$btm1), 2);
				}elseif(count($check_a)==2 && count($check_b)==1){
					$upr=$check_a[0];
					$btm=$check_a[1];
					list($upr1,$btm1)=to_frac($b);
					$g = gcd($btm,$btm1);
					$lcm=lcmofn(array($btm,$btm1), 2);
				}elseif (count($check_a)==1 && count($check_b)==2) {
					$upr1=$check_b[0];
					$btm1=$check_b[1];
					list($upr,$btm)=to_frac($a);
					$g = gcd($btm,$btm1);
					$lcm=lcmofn(array($btm,$btm1), 2);
				}elseif (count($check_a)==2 && count($check_b)==2) {
					$upr=$check_a[0];
					$btm=$check_a[1];
					$upr1=$check_b[0];
					$btm1=$check_b[1];
					$g = gcd($btm,$btm1);
					$lcm=lcmofn(array($btm,$btm1), 2);
				}
				$A=(-1)*$a*$lcm;
				$B=1*$lcm;
				$C=$b*$lcm;
				$this->param['A'] = $A;
				$this->param['B'] = $B;
				$this->param['C'] = $C;
	  			$this->param['RESULT'] = 1;
				return $this->param;
	  		}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
	  		}
  		}
	}

	// Decimal Calculator
	function decimalCal($request){
		$method= $request->method;
		$rounding= $request->rounding;
		$a= $request->a;
		$b= $request->b;
		if (is_numeric($a) && is_numeric($b)) {
			if ($method=='1') {
				$ans = $a + $b;
				$res = "<p class='mt-2'>a + b = ?</p> <p class='mt-2'>$a + $b = $ans</p>";
			}elseif ($method=='2') {
				$ans = $a - $b;
				$res = "<p class='mt-2'>a - b = ?</p> <p class='mt-2'>$a - $b = $ans</p>";
			}elseif ($method=='3') {
				$ans = $a * $b;
				$res = "<p class='mt-2'>a x b = ?</p> <p class='mt-2'>$a x $b = $ans</p>";
			}elseif ($method=='4') {
				$ans = $a / $b;
				$res = "<p class='mt-2'>a ÷ b = ?</p> <p class='mt-2'>$a ÷ $b = $ans</p>";
			}elseif ($method=='5') {
				$floatChkA = explode('.',$a);
				$floatChkB = explode('.',$b);
				if (count($floatChkA)==2 && count($floatChkB)==2) {
					$count = strlen($floatChkA[1]);
					$divideA='1';
					for ($i=0; $i < $count ; $i++) { 
						$divideA.='0';
					}
					$divideA = intval($divideA);

					$count = strlen($floatChkB[1]);
					$divideB='1';
					for ($i=0; $i < $count ; $i++) { 
						$divideB.='0';
					}
					$divideB = intval($divideB);
					$newA = $a*$divideA;
					$newB = $b*$divideB;
					$upper = pow(pow($newA,$newB),(1/$divideB));
					$bottom = pow(pow($divideA,$newB),(1/$divideB));
				}
				$ans = pow($a, $b);
				$res = "a<sup class='font-s-14'>b</sup> = ?";
			}elseif ($method=='6') {
				$ans = pow($a, 1/$b);
				$res = "<sup class='font-s-14'>b</sup>√a = ?";
			}elseif ($method=='7') {
				$ans=log($b,$a);
				$res = "log<sub class='font-s-14'>a</sub>b = ?";
			}
			if ($rounding!='not') {
				$this->param['round_ans'] = round($ans,$rounding);
			}
			$this->param['ans'] = $ans;
			$this->param['res'] = $res;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}	
	}

