	// Convolution Calculator
	function convolution($request){
		$seq1= $request->seq1;
		$seq2= $request->seq2;
		if(!empty($seq1) && !empty($seq2)){
			$check=true;
			$set1=array_map("trim",array_filter(explode(",",$seq1)));
			$set2=array_map("trim",array_filter(explode(",",$seq2)));
			foreach($set1 as $value){
				if(!is_numeric($value)){
					$check=false;
				}
			}
			foreach($set2 as $value){
				if(!is_numeric($value)){
					$check=false;
				}
			}
			if ($check === true) {
				try{
					$response = Http::timeout(120)->get('http://167.172.134.148/convolution', [
						'seq1' => $seq1,
						'seq2' => $seq2,
					]);
					$buffer = $response->body();
					$conv = explode('###', $buffer);
					array_pop($conv);
					return [
						'conv' => $conv,
						'RESULT' => 1,
					];
				} catch (\Exception $response) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}

		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Diagonal Calculator
	function diagonal($request){
		$given= $request->given;
		$ls= $request->ls;
		$ls_unit= $request->ls_unit;
		$ss= $request->ss;
		$ss_unit= $request->ss_unit;
		$perimeter= $request->perimeter;
