		$angle_unit= $request->angle_unit;
		$circum= $request->circum;
		$circum_unit= $request->circum_unit;
		function myunitConvert($unit,$value){
			if($unit=="mm"){
				$val1=$value*0.1;
			}else if($unit=="cm"){
				$val1=$value*1;
			}else if($unit=="m"){
				$val1=$value*100;
			}else if($unit=="km"){
				$val1=$value*1000;
			}else if($unit=="in"){
				$val1=$value*2.54;
