		function centimeter($unit3,$value3){
			if($unit3=="mm²"){
				$val3=$value3*0.01;
			}else if($unit3=="cm²"){
				$val3=$value3*1;
			}else if($unit3=="m²"){
				$val3=$value3*10000;
			}else if($unit3=="km²"){
				$val3=$value3*10000000000;
			}else if($unit3=="in²"){
				$val3=$value3*6.452;
			}else if($unit3=="ft²"){
				$val3=$value3*929;
			}else if($unit3=="yd²"){
				$val3=$value3*8361;
			}else if($unit3=="mi²"){
				$val3=$value3*25899881103;
			}else if($unit3=="mi²"){
				$val3=$value3*25899881103;
			}else if($unit3=="a"){
				$val3=$value3*1000000;
			}else if($unit3=="da"){
				$val3=$value3*10000000;
			}else if($unit3=="ha"){
				$val3=$value3*100000000;
			}else if($unit3=="ac"){
				$val3=$value3*40468560;
			}
			return $val3;
		}
		if($given=="1"){//Longer Side and Shorter Side
			if(is_numeric($ls) && is_numeric($ss)){
				$lsv=myunitConvert($ls_unit,$ls);
				$ssv=myunitConvert($ss_unit,$ss);
				if($ls>$ss){
					$area=$lsv*$ssv;
					$perimeter= 2 * $ss + 2 * $lsv;
					$diagonal=sqrt($lsv*$lsv+$ssv*$ssv);
					$radius=$diagonal/2;
					$δ =atan($ssv/$lsv);
				   	$angle_α =3.141592653589793238-(2*$δ);
				   	$lsv="";
				   	$ssv="";
				}else{
					$this->param['error'] = 'Please! Longer side should be greater than shorter side.';
					return $this->param;	
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($given=="2"){//Longer Side and Area
			if(is_numeric($ls) && is_numeric($area)){
				$lsv=myunitConvert($ls_unit,$ls);
				$av=centimeter($area_unit,$area);
				$ssv=$av/$lsv;
				$perimeter= 2 * $ssv + 2 * $lsv;
				$δ =atan($ssv/$lsv);
				$angle_α =3.141592653589793238-(2*$δ);
				$diagonal=sqrt($lsv*$lsv+$ssv*$ssv);
				$radius=$diagonal/2;
				$lsv="";
				$area="";
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($given=="3"){//Longer Side and Perimeter
			if(is_numeric($ls) && is_numeric($perimeter)){
				if(($ls*2+1)<=$perimeter){
					$lsv=myunitConvert($ls_unit,$ls);
					$pv=myunitConvert($perimeter_unit,$perimeter);
					$ssv=($pv-(2*$lsv))/2;
					$area=$lsv*$ssv;
					$δ =atan($ssv/$lsv);
					$angle_α =3.141592653589793238-(2*$δ);
					$diagonal=sqrt($lsv*$lsv+$ssv*$ssv);
					$radius=$diagonal/2;
					$lsv="";
					$perimeter="";
				}else{
					$this->param['error'] = 'Perimeter is too small.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($given=="4"){//Longer Side and Angle alpha
			if(is_numeric($ls) && is_numeric($angle)){
				if($angle<=90){
					$this->param['error'] = 'Angle between diagonals must be greater than 90°.';
					return $this->param;
