						$angle_α= 0.9 * $angle;
					}else{
						$angle_α= 180 * $angle;
					}
					$angle_α=$angle_α/2;
					$ssv=$lsv/tan(deg2rad($angle_α));
					$area=$lsv*$ssv;
					$perimeter= 2 * $ssv + 2 * $lsv;
					$diagonal=sqrt($lsv*$lsv+$ssv*$ssv);
					$radius=$diagonal/2;
					$lsv="";
					$angle_α="";
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
