				$lsv=$av/$ssv;
				$perimeter= 2 * $ssv + 2 * $lsv;
				$δ =atan($ssv/$lsv);
				$angle_α =3.141592653589793238-(2*$δ);
				$diagonal=sqrt($lsv*$lsv+$ssv*$ssv);
				$radius=$diagonal/2;
				$ssv="";
				$area="";
