			}
		}else if($given=="7"){//Shorter Side and Perimeter
			if(is_numeric($ss) && is_numeric($angle)){
				$ssv=myunitConvert($ss_unit,$ss);
				if($angle_unit === "deg"){
					$angle_α= 1 * $angle;
				}elseif($angle_unit === "rad"){
