		return $this->param;
	}

	// Equation of a Circle Calculator
	function equation($request){
		$from= $request->from;
		$a= $request->a;
		$b= $request->b;
		$c= $request->c;
		$x1= $request->x1;
		$y1= $request->y1;
		$r= $request->r;
		$h1= $request->h1;
		$k1= $request->k1;
        if ($from=="1") {
            if (is_numeric($a) && is_numeric($b) && is_numeric($c)) {
                if ($c > 0) {
                    $radius=sqrt($c);
                    $diameter=2 * $radius;
                    $sq_radius=pow($radius, 2);
                    $area=$sq_radius * 3.14;
                    $circumference=$diameter * 3.14;
                    $A=$a;
                    $B=$b;
                    $C=$c;
                    $D=$a * -2;
                    $E=$b * -2;
                    $F_f1=pow($a, 2);
                    $F_f2=pow($b, 2);
                    $F_f3=$F_f1 + $F_f2;
                    $F=$F_f3 - $c;
                    $d1=$a - $radius;
                    $d2=$a + $radius;
                    $r1=$b - $radius;
                    $r2=$b + $radius;
                    $eccentricity=0;
                }else{
					$this->param['error'] = 'Such circle (C) does not exist.';
					return $this->param;
                }
            }else{
                $this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
            }
        }else if ($from=="2") {
            if (is_numeric($a) && is_numeric($b) && is_numeric($c)) {
				$radius=$c;
				$diameter=2 * $radius;
				$sq_radius=pow($radius, 2);
				$area=$sq_radius * 3.14;
				$circumference=$diameter * 3.14;
				$eccentricity=0;
				$A=$a;
				$B=$b;
				$C=$c;
				$D=$a * -2;
				$E=$b * -2;
				$F_f1=pow($a, 2);
				$F_f2=pow($b, 2);
				$F_f3=$F_f1 + $F_f2;
				$F=$F_f3 - $c;
				$d1=$a - $radius;
				$d2=$a + $radius;
				$r1=$b - $radius;
				$r2=$b + $radius;
            }else{
				$this->param['error'] = 'Please check your input.';
				return $this->param;
            }
        }else if ($from=="3") {
            if (is_numeric($a) && is_numeric($b) && is_numeric($c)) {
                    $A=$a / -2;
                    $B=$b / -2;
                    $C=$c;
                    $D=$a;
                    $E=$b;
                    $F=$c;
                    $D2=$D / 2;
                    $D2_sq=pow($D2, 2);
                    $E2=$E / 2;
                    $E2_sq=pow($E2, 2);
                    $plus=$D2_sq + $E2_sq;
                    $sq_root=$plus - $F;
                    $radius=sqrt($sq_root);
                    $diameter=2 * $radius;
                    $sq_radius=pow($radius, 2);
                    $area=$sq_radius * 3.14;
                    $circumference=$diameter * 3.14;
                    $eccentricity=0;
                    $d1=$a - $radius;
                    $d2=$a + $radius;
                    $r1=$b - $radius;
                    $r2=$b + $radius;
                }else{
                    $this->param['error'] = 'Please check your input.';
					return $this->param;
                }
        }else if ($from=="4") {
            if (is_numeric($x1) && is_numeric($y1)) {
                if ($r > 0) {
                    $A=$x1;
                    $B=$y1;
                    $radius=$r;
                    $sq_radius=pow($radius, 2);
                    $C=$c;
                    $D=$A * -2;
                    $E=$B * -2;
                    $F_f1=pow($x1, 2);
                    $F_f2=pow($y1, 2);
                    $F_f3=$F_f1 + $F_f2;
                    $F=$F_f3 - $sq_radius;
                    $diameter=2 * $radius;
                    $area=$sq_radius * 3.14;
                    $circumference=$diameter * 3.14;
                    $eccentricity=0;
                    $d1=$x1 - $radius;
                    $d2=$y1 + $radius;
                    $r1=$x1 - $radius;
                    $r2=$y1 + $radius;
                }else{
					$this->param['error'] = 'Such circle (r) does not exist.';
					return $this->param;
                }
            }else{
                $this->param['error'] = 'Please check your input.';
				return $this->param;
            }
        }else if ($from=="5") {
            if (is_numeric($x1) && is_numeric($y1) && is_numeric($h1) && is_numeric($k1)) {
                $A=$x1;
                $B=$y1;
                $ans1=$x1 - $h1;
                $ans1_sq=pow($ans1, 2);
                $ans2=$y1 - $k1;
                $ans2_sq=pow($ans2, 2);
                $plus=$ans1_sq + $ans2_sq;
                $radius=sqrt($plus);
                $sq_radius=pow($radius, 2);
                $C=$c;
                $D=$A * -2;
                $E=$B * -2;
                $F_f1=pow($x1, 2);
                $F_f2=pow($y1, 2);
                $F_f3=$F_f1 + $F_f2;
                $F=$F_f3 - $sq_radius;
                $diameter=2 * $radius;
                $area=$sq_radius * 3.14;
                $circumference=$diameter * 3.14;
                $eccentricity=0;
                $d1=$x1 - $radius;
                $d2=$y1 + $radius;
                $r1=$h1 - $radius;
                $r2=$k1 + $radius;
            }else{
                $this->param['error'] = 'Please check your input.';
				return $this->param;
            }
        }
        if (is_float($radius)) {
            $radius=number_format($radius, 2);
        }
        if (is_float($area)) {
            $area=number_format($area, 2);
        }
        if (is_float($diameter)) {
            $diameter=number_format($diameter, 2);
        }
        if (is_float($circumference)) {
            $circumference=number_format($circumference, 2);
        }
        $d1=number_format($d1, 2);
        $d2=number_format($d2, 2);
        $r1=number_format($r1, 2);
        $r2=number_format($r2, 2);
        $this->param['A'] = $A;
        $this->param['B'] = $B;
        $this->param['C'] = $C;
        $this->param['E'] = $E;
        $this->param['D'] = $D;
        $this->param['F'] = $F;
        $this->param['d1'] = $d1;
        $this->param['d2'] = $d2;
        $this->param['r1'] = $r1;
        $this->param['r2'] = $r2;
        $this->param['radius'] = $radius;
        $this->param['area'] = $area;
        $this->param['diameter'] = $diameter;
        $this->param['circumference'] = $circumference;
        $this->param['eccentricity']= $eccentricity;
        $this->param['RESULT'] = 1;
        return $this->param;
    }

	// Least To Greatest Calculator
	function least($request){
		$x= $request->x;
		$order= $request->order;
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|[a-zA-Z]|&/i", $x)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (!empty($x)) {
			$x=str_replace('plus','+',$x);
			$input=explode(',', $x);
			$filter=[];
			$filter1=[];
			foreach ($input as $key => $value) {
				$value=trim($value);
				$index=$value;
				$chech_frac = explode('/',$value);
				if(count($chech_frac)>1){
					$up = $chech_frac[0];
					$btm = $chech_frac[1];
					$check_up = explode(' ',$up);
					if(count($check_up)>1){
						$up = $check_up[1];
						$sahi = $check_up[0];
						if($sahi<0 && $up>0){
							$up = $up * (-1);
						}
						$up=($btm * $sahi) + $up;
						$ans = $up / $btm;
					}else{
						$ans = $up / $btm;
					}
				}else{
					$value=str_replace('%','/100',$value);
					$value=str_replace(' ','+',$value);
					$ans=eval('return '.$value.';');
				}
				if (is_numeric($ans)) {
					$filter1["$ans"]=$index;
					$filter[$index]=$ans;
				}else{
					$this->param['error'] = 'Please Enter Valid Input.';
					return $this->param;
					break;
				}
			}
			$solve=$filter;
			if ($order==='1') {
				asort($filter);
			}else{
				arsort($filter);
			}
			$this->param['solve'] = $solve;
			$this->param['order'] = $order;
			$this->param['ans'] = $filter;
			$this->param['filter1'] = $filter1;
			$this->param['RESULT'] = 1;

			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// One's Complement Calculator
	function ones($request){
		$cal = $request->cal;
		$dec = $request->dec;
		$bnry = $request->bnry;
		$hex = $request->hex;
		$bits = $request->bits;
		$no_of_bits = $request->no_of_bits;
		if (preg_match("/\<|\>|\&|\/|\\\\|\-|php|print_r|print|echo|script|=|sin|cos|tan|arcsin|arccos|arctan|&|%/i", $hex)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		$check = true;
		if ($cal === 'bnry_cal') {
			if (!is_numeric($dec)) {
				$check = false;
			}
		} elseif ($cal === 'dec_cal') {
			if (!is_numeric($bnry)) {
				$check = false;
			}
		} elseif ($cal === 'hex_cal') {
			if ($hex === '') {
				$check = false;
			}
		}
		function onesComplement($str)
		{
			function flip($c)
			{
				return ($c == '0') ? '1' : '0';
			}
			$n = strlen($str);
			$i = '';
			$ones = '';
			for ($i = 0; $i < $n; $i++)
				$ones .= flip($str[$i]);
			return $ones;
		}
		function addspace($binary)
		{
			$bit_len = strlen($binary);
			$s1 = floor($bit_len / 4);
			$s2 = $s1 * 4;
			$s3 = $bit_len - $s2;
			$res = '';
			$rem = $bit_len % 4;
			if ($rem != 0) {
				$len = $s1 + 1;
			} else {
				$len = $s1;
			}
			$space = 0;
			for ($i = 0; $i < $len; $i++) {
				if ($i == 0 && $s3 != 0) {
					$mins = 1;
					for ($j = 0; $j <= $s3; $j++) {
						if ($j != $s3) {
							$res .= $binary[$j];
						} else {
							$res .= ' ';
							$space++;
						}
					}
				} else {
					$s4 = strlen($res) - $space;
					for ($j = 0; $j <= 4; $j++) {
						if ($j != 4) {
							$res .= $binary[$s4 + $j];
						} else {
							$res .= ' ';
							$space++;
						}
					}
				}
			}
			return $res;
		}
		function bnry_cal($dec, $bits)
		{
			$binary = decbin($dec);
			$hex = base_convert($binary, 2, 16);
			$bit_len = strlen($binary);
			$n = $bits - $bit_len;
			if ($dec < 0) {
				for ($i = 0; $i < $n; $i++) {
					if ($n < $bits) {
						$binary = '1' . $binary;
					}
				}
			} else {
				for ($i = 0; $i < $n; $i++) {
					if ($n < $bits) {
						$binary = '0' . $binary;
					}
				}
			}
			$binary = substr($binary, -$bits);
			$_1s = onesComplement($binary);
			$_1s = addspace($_1s);
			$binary = addspace($binary);
			$result = array('bits' => $bits, 'dec' => $dec, 'binary' => $binary, 'hex' => $hex, '_1s' => $_1s);
			return $result;
		}
		function dec_cal($bnry, $bits)
		{
			$dec = bindec($bnry);
			$hex = base_convert($bnry, 2, 16);
			$bit_len = strlen($bnry);
			$n = $bits - $bit_len;
			if ($dec < 0) {
				for ($i = 0; $i < $n; $i++) {
					if ($n < $bits) {
						$bnry = '1' . $bnry;
					}
				}
			} else {
				for ($i = 0; $i < $n; $i++) {
					if ($n < $bits) {
						$bnry = '0' . $bnry;
					}
				}
			}
			$bnry = substr($bnry, -$bits);
			$_1s = onesComplement($bnry);
			$_1s = addspace($_1s);
			$bnry = addspace($bnry);
			$result = array('bits' => $bits, 'dec' => $dec, 'binary' => $bnry, 'hex' => $hex, '_1s' => $_1s);
			return $result;
		}
		function hex_cal($hex, $bits)
		{
			$binary = base_convert($hex, $bits, 2);
			$dec = bindec($binary);
			$bit_len = strlen($hex);
			$n = $bits - $bit_len;
			for ($i = 0;
				$i < $n;
				$i++
			) {
				if ($n < $bits) {
					$binary = '0' . $binary;
				}
			}
			$binary = substr($binary, -$bits);
			$_1s = onesComplement($binary);
			$binary = addspace($binary);
			$_1s = addspace($_1s);
			$result = array('bits' => $bits, 'dec' => $dec, 'binary' => $binary, 'hex' => $hex, '_1s' => $_1s);
			return $result;
		}
		if ($check === true) {
			if ($cal === 'bnry_cal') {
				$check = false;
				if ($bits === '4') {
					if ($dec >= -8 && $dec <= 7) {
						$check = true;
						$result = bnry_cal($dec, $bits);
					} else {
						$check = false;
					}
				} elseif ($bits === '8') {
					if ($dec >= -128 && $dec <= 127) {
						$check = true;
						$result = bnry_cal($dec, $bits);
					} else {
						$check = false;
					}
				} elseif ($bits === '12') {
					if ($dec >= -2048 && $dec <= 2047) {
						$check = true;
						$result = bnry_cal($dec, $bits);
					} else {
						$check = false;
					}
				} elseif ($bits === '16') {
					if ($dec >= -32768 && $dec <= 32767) {
						$check = true;
						$result = bnry_cal($dec, $bits);
					} else {
						$check = false;
					}
				} else {
					if ($no_of_bits > 1 && $no_of_bits < 71
					) {
						$min = pow(2, $no_of_bits - 1) * (-1);
						$max = pow(2, $no_of_bits - 1) - 1;
						if ($dec >= $min && $dec <= $max) {
							$check = true;
							$result = bnry_cal($dec, $no_of_bits);
						} else {
							$check = false;
						}
					} else {
						$this->param['error'] = 'Please! Enter Number in Range (2-70).';
						return $this->param;
					}
				}
			} elseif ($cal === 'dec_cal') {
				$check = false;
				$bnry_len = strlen($bnry);
				if ($bits === '4') {
					if ($bnry_len <= 4) {
						$check = true;
						$result = dec_cal($bnry, $bits);
					} else {
						$check = false;
					}
				} elseif ($bits === '8') {
					if ($bnry_len <= 8) {
						$check = true;
						$result = dec_cal($bnry, $bits);
					} else {
						$check = false;
					}
				} elseif ($bits === '12') {
					if ($bnry_len <= 12) {
						$check = true;
						$result = dec_cal($bnry, $bits);
					} else {
						$check = false;
					}
				} elseif ($bits === '16') {
					if ($bnry_len <= 16) {
						$check = true;
						$result = dec_cal($bnry, $bits);
					} else {
						$check = false;
					}
				} else {
					if ($no_of_bits > 1 && $no_of_bits < 71) {
						if (strlen($bnry) > 0 && strlen($bnry) <= $no_of_bits) {
							$check = true;
							$result = dec_cal($bnry, $no_of_bits);
						} else {
							$check = false;
						}
					} else {
						$this->param['error'] = 'Please! Enter Number in Range (2-70).';
						return $this->param;
					}
				}
			} elseif ($cal === 'hex_cal') {
				if ($hex === '0') {
					$this->param['error'] = 'Undefined Value!';
					return $this->param;
				}
				$hex_len = strlen($hex);
				if ($hex_len > 16) {
					$check = false;
					$this->param['error'] = 'Please! Enter Number in Range.';
					return $this->param;
				} else {
					$check = true;
					$result = hex_cal($hex, '16');
				}
			} else {
				$this->param['error'] = 'Please Check Your Input.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
		if ($check === true) {
			$this->param['bit'] = $result['bits'];
			$this->param['dec'] = $result['dec'];
			$this->param['binary'] = $result['binary'];
			$this->param['hex'] = $result['hex'];
			$this->param['_1s'] = $result['_1s'];
		} else {
			$this->param['error'] = 'Please! Enter Number in Range.';
			return $this->param;
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Volume of a Rectangle Calculator
	function rectangle_volume($request){
		$choose = $request->choose;
		$first = $request->first;
		$first_unit = $request->first_unit;
		$second = $request->second;
		$second_unit = $request->second_unit;
		$third = $request->third;
		$third_unit = $request->third_unit;
		$units = $request->units;
		function convert_into_cm($unit,$value){
			if($unit === "mm"){
				$val1 = $value*0.1;
			}else if($unit === "cm"){
				$val1 = $value * 1;
			}else if($unit === "m"){
				$val1 = $value * 100;
			}else if($unit === "km"){
				$val1 = $value * 1000;
			}else if($unit === "in"){
				$val1 = $value * 2.54;
			}else if($unit === "ft"){
				$val1 = $value * 30.48;
			}else if($unit === "yd"){
				$val1 = $value * 91.44;
			}else if($unit === "mi"){
				$val1 = $value * 160934;
			}
			return $val1;	
		}
	    if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
			$first = convert_into_cm($first_unit,$first);
			$second = convert_into_cm($second_unit,$second);
			$third = convert_into_cm($third_unit,$third);
			if ($choose === "hlw") {
				$length = $first;
				$width = $second;
				$height = $third;
				$diagonal = sqrt((pow($first, 2)) + (pow($second, 2)) + (pow($third, 2)));
				$s_tot = 2 * (($first * $second) + ($first * $third) + ($second * $third));
				$s_lat = 2 * $third * ($first + $second);
				$s_top = $first * $second;
				$s_btm = $first * $second;
				$volume_ans = $first * $second * $third;
			}elseif ($choose === "slw") {
				$length = $first;
				$width = $second;
				$height = (($third / 2) - ($first * $second)) / ($first + $second);
				$diagonal = sqrt((pow($first, 2)) + (pow($second, 2)) + (pow($height, 2)));
				$s_tot = $third;
				$s_lat = 2 * $height * ($first + $second);
				$s_top = $first * $second;
				$s_btm = $first * $second;
				$volume_ans = $first * $second * $height;
			}elseif ($choose === "vlw") {
				$length = $first;
				$width = $second;
				$height = $third / ($length * $width);
				$diagonal = sqrt((pow($length, 2)) + (pow($width, 2)) + (pow($height, 2)));
				$s_tot = 2 * (($length * $width) + ($length * $height) + ($width * $height));
				$s_lat = 2 * $height * ($length + $width);
				$s_top = $length * $width;
				$s_btm = $length * $width;
				$volume_ans = $third;
			}else{
				$length = $first;
				$width = $second;
				$height = sqrt((pow($third, 2)) - (pow($first, 2)) - (pow($second, 2)));
				$diagonal = $third;
				$s_tot = 2 * (($length * $width) + ($length * $height) + ($width * $height));
				$s_lat = 2 * $height * ($length + $width);
				$s_top = $length * $width;
				$s_btm = $length * $width;
				$volume_ans = $first * $second * $height;
			}

			if ($units === "mm") {
				$single_val = 10;
				$square_val = 100;
				$cube_val = 1000;
			}elseif ($units === "cm") {
				$single_val = 1;
				$square_val = 1;
				$cube_val = 1;
			}elseif ($units === "m") {
				$single_val = 0.01;
				$square_val = 0.0001;
				$cube_val = 0.000001;
			}elseif ($units === "km") {
				$single_val = 0.00001;
				$square_val = 0.0000000001;
				$cube_val = 0.000000000000001;
			}elseif ($units === "in") {
				$single_val = 0.393701;
				$square_val = 0.155;
				$cube_val = 0.0610237;
			}elseif ($units === "ft") {
				$single_val = 0.0328084;
				$square_val = 0.0010763888889;
				$cube_val = 0.000035315;
			}elseif ($units === "yd") {
				$single_val = 0.0109361;
				$square_val = 0.00011959876543333333655;
				$cube_val = 0.00000130795;
			}else{
				$single_val =  0.0000062137;
				$square_val = 0.00000000003861013863421143294;
				$cube_val = 0.000000000000000239913;
			}
		}else{
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		$this->param['length'] = round(($length * $single_val), 2);
		$this->param['width'] = round(($width * $single_val), 2);
		$this->param['height'] = round(($height * $single_val), 2);
		$this->param['diagonal'] = round(($diagonal * $single_val), 2);
		$this->param['s_tot'] = round(($s_tot * $square_val), 2);
		$this->param['s_lat'] = round(($s_lat * $square_val), 2);
		$this->param['s_top'] = round(($s_top * $square_val), 2);
		$this->param['s_btm'] = round(($s_btm * $square_val), 2);
		$this->param['volume_ans'] = round(($volume_ans * $cube_val), 2);
	    $this->param[ 'RESULT' ] = 1;
		return $this->param;
	}

	// Volume of Frustum Cone Calculator
	function conical($request){
		$choose = $request->choose;
		$first = $request->first;
		$first_unit = $request->first_unit;
		$second = $request->second;
		$second_unit = $request->second_unit;
		$third = $request->third;
		$third_unit = $request->third_unit;
		$pi_val = $request->pi_val;
		$units = $request->units;
		function new_convert_into_cm($unit,$value){
			if($unit === "mm"){
				$val1 = $value*0.1;
			}else if($unit === "cm"){
				$val1 = $value * 1;
			}else if($unit === "m"){
				$val1 = $value * 100;
			}else if($unit === "km"){
				$val1 = $value * 1000;
			}else if($unit === "in"){
				$val1 = $value * 2.54;
			}else if($unit === "ft"){
				$val1 = $value * 30.48;
			}else if($unit === "yd"){
				$val1 = $value * 91.44;
			}else if($unit === "mi"){
				$val1 = $value * 160934;
			}
			return $val1;	
		}
	    if (is_numeric($first) && is_numeric($second) && is_numeric($third) && is_numeric($pi_val)) {
			$first = new_convert_into_cm($first_unit,$first);
			$second = new_convert_into_cm($second_unit,$second);
			$third = new_convert_into_cm($third_unit,$third);
			if ($choose === "r_h") {
				$radius_1 = $first;
				$radius_2 = $second;
				$height = $third;
				$slant_height = sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2));
				$lsa = $pi_val * ($radius_1 + $radius_2) * sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2));
				$tsa = $pi_val * pow($radius_1, 2);
				$bsa = $pi_val * pow($radius_2, 2);
				$ttsa = $pi_val * (pow($radius_1, 2) + pow($radius_2, 2) + ($radius_1 + $radius_2) * sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2)));
				$volume = (1/3) * $pi_val * $height * ($radius_1 * $radius_1 + $radius_2 * $radius_2 + ($radius_1 * $radius_2));
			}elseif ($choose === "r_sh") {
				$radius_1 = $first;
				$radius_2 = $second;
				$slant_height = $third;
				$height = sqrt(pow($slant_height, 2) - pow($radius_1 - $radius_2, 2));
				$volume = (1/3) * $pi_val * $height * ($radius_1 * $radius_1 + $radius_2 * $radius_2 + ($radius_1 * $radius_2));
				$lsa = $pi_val * ($radius_1 + $radius_2) * sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2));
				$tsa = $pi_val * pow($radius_1, 2);
				$bsa = $pi_val * pow($radius_2, 2);
				$ttsa = $pi_val * (pow($radius_1, 2) + pow($radius_2, 2) + ($radius_1 + $radius_2) * sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2)));
			}elseif ($choose === "r_v") {
				$radius_1 = $first;
				$radius_2 = $second;
				$volume = $third;
				$height = ($volume * 3) / ($pi_val * ($radius_1 * $radius_1 + $radius_2 * $radius_2 + ($radius_1 * $radius_2)));
				$slant_height = sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2));
				$lsa = $pi_val * ($radius_1 + $radius_2) * sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2));
				$tsa = $pi_val * pow($radius_1, 2);
				$bsa = $pi_val * pow($radius_2, 2);
				$ttsa = $pi_val * (pow($radius_1, 2) + pow($radius_2, 2) + ($radius_1 + $radius_2) * sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2)));
			}elseif ($choose === "r_l") {
				$radius_1 = $first;
				$radius_2 = $second;
				$lsa = $third;
				$height = sqrt(pow($lsa / ($pi_val * ($radius_1 + $radius_2)), 2) - pow($radius_1 - $radius_2, 2));
				$slant_height = sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2));
				$tsa = $pi_val * pow($radius_1, 2);
				$bsa = $pi_val * pow($radius_2, 2);
				$ttsa = $pi_val * ($radius_1 + $radius_2) * sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2));
				$volume = (1/3) * $pi_val * $height * ($radius_1 * $radius_1 + $radius_2 * $radius_2 + ($radius_1 * $radius_2));
			}else{
				$radius_1 = $first;
				$radius_2 = $second;
				$ttsa = $third;
				$height = sqrt(pow($radius_1 + $radius_2, 2) - pow($radius_1 - $radius_2, 2) - pow($ttsa / $pi_val, 2));
				$volume = (1/3) * $pi_val * $height * ($radius_1 * $radius_1 + $radius_2 * $radius_2 + ($radius_1 * $radius_2));
				$lsa = $pi_val * ($radius_1 + $radius_2) * sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2));
				$slant_height = sqrt(pow($radius_1 - $radius_2, 2) + pow($height, 2));
				$tsa = $pi_val * pow($radius_1, 2);
				$bsa = $pi_val * pow($radius_2, 2);
			}

			if ($units === "mm") {
				$single_val = 10;
				$square_val = 100;
				$cube_val = 1000;
			}elseif ($units === "cm") {
				$single_val = 1;
				$square_val = 1;
				$cube_val = 1;
			}elseif ($units === "m") {
				$single_val = 0.01;
				$square_val = 0.0001;
				$cube_val = 0.000001;
			}elseif ($units === "km") {
				$single_val = 0.00001;
				$square_val = 0.0000000001;
				$cube_val = 0.000000000000001;
			}elseif ($units === "in") {
				$single_val = 0.393701;
				$square_val = 0.155;
				$cube_val = 0.0610237;
			}elseif ($units === "ft") {
				$single_val = 0.0328084;
				$square_val = 0.0010763888889;
				$cube_val = 0.000035315;
			}elseif ($units === "yd") {
				$single_val = 0.0109361;
				$square_val = 0.00011959876543333333655;
				$cube_val = 0.00000130795;
			}else{
				$single_val =  0.0000062137;
				$square_val = 0.00000000003861013863421143294;
				$cube_val = 0.000000000000000239913;
			}
		}else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
		$this->param['radius_1'] = round(($radius_1 * $single_val), 2);
		$this->param['radius_2'] = round(($radius_2 * $single_val), 2);
		$this->param['height'] = round(($height * $single_val), 2);
		$this->param['slant_height'] = round(($slant_height * $single_val), 2);
		$this->param['volume'] = round(($volume * $cube_val), 2);
		$this->param['lsa'] = round(($lsa * $square_val), 2);
		$this->param['tsa'] = round(($tsa * $square_val), 2);
		$this->param['bsa'] = round(($bsa * $square_val), 2);
		$this->param['ttsa'] = round(($ttsa * $square_val), 2);
	    $this->param[ 'RESULT' ] = 1;
	    return $this->param;
	}

	// Log Antilog Calculator
	function log($request){
		$method = $request->method;
		$x = $request->x;
		$y = $request->y;
		$check=true;
		if (!is_numeric($x)) {
			$check=false;
		}
		if ($check==true) {
			if ($method=='log' || $method=='ln') {
				if (is_numeric($y)) {
					$base=$y;
				}else{
					$base=2.71828;
				}
				if ($y=='e') {
					$base=2.71828;
				}
				$y=$x;
				$ans=round(log($y,$base),5);
				$this->param['ans'] = @$ans;
				$this->param['RESULT'] = 1;
				return $this->param;
			}
			if ($method=='anti') {
				if (is_numeric($y)) {
					$base=$y;
				}else{
					$base=10;
				}
				if ($y=='e') {
					$base=2.71828;
				}
				$y=$x;
				$ans=(round(pow($base,$y),5));
				$this->param['ans'] = @$ans;
				$this->param['RESULT'] = 1;
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
		
	}

	// Long Addition Calculator
	function long($request){
		$x = $request->x;
		if (!empty($x)) {
			$array=explode(',', $x);
			$number=true;
			$numbers='';
			foreach ($array as $key => $value) {
				if (!is_numeric($value)) {
					$number=false;
				}
				$numbers.=$value.', ';
			}
			if ($number==true) {
				$sum=array_sum($array);
				$total_nbr=count($array);
				$sum=number_format($sum,2);
				$this->param['sum'] = $sum;
				$this->param['numbers'] = $numbers;
				$this->param['total_nbr'] = $total_nbr;
				$this->param['max'] = max($array);
				$this->param['min'] = min($array);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please Enter Only Numbers.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
	}

	// Prime Factorization Calculator
	function prime($request){
		$from = $request->from;
		$num = $request->num;
		// cheack
		if(is_numeric($num)){
			$newnum = $num;
			if ($newnum>1000000) {
				$this->param['error'] = 'Number is too large.';
				return $this->param;
			}
			if ($from==1) {
				$newtext = "";
				$csv= "";
				$chk = 2;
				$prime=0;
				while ($chk*$chk <= $newnum): //10 => 4
					if ($newnum % $chk == 0){ //10 % 2 = 0
						$newtext = $newtext.$chk; // 0 +2 =2;
						$csv = $csv.$chk;
						$newnum = $newnum/$chk;//10/2 = 5
					if ($newnum != 1){   // 
						$newtext = $newtext." × ";
						$csv = $csv." , ";
					}
					}
					else{
						$chk++;
					}
				endwhile;
				if ($newnum != 1){
					$newtext = $newtext.$newnum;
					$csv = $csv.$newnum;
				}
				if ($newtext == "".$num){
					$newtext = $newtext." is a Prime number.";
					$prime=1;
				}
				if ($prime!=1) {
					$number=$num;
					$divid=explode(' × ', $newtext);
					$count=count($divid);
					$tree="<tr><td class='py-2 text-center'>$number</td><td class='py-2'>&nbsp;</td></tr>";
					foreach ($divid as $key => $value) {
						if($value!=$number){
							$number=$number/$value;
							$tree.="<tr><td class='py-2'>| </td><td class='py-2'>\ </td></tr><tr><td class='py-2'>$number</td><td class='py-2'>$value</td></tr>";
						}
					}
					$this->param['tree'] = $tree;
				}
				$this->param['Factors'] = $newtext;
				$this->param['csv'] = $csv;
				$this->param['prime'] = $prime;
				$this->param['RESULT'] = 1;
				
				return $this->param;
			}elseif ($from==2) {
				$table="<td class='py-2'><del class='text-danger'>1</del></td>";
				$tr=0;
				 for($i = 1; $i <= $num; $i++){
			      $mm = 0;
			      for($j = 2; $j <= $i/2; $j++) {
			        //only not prime numbers
	                if ($i % $j == 0 || $i==1) {
	                	$table.="<td class='py-2'><del class='text-danger'>$i</del></td>";
	                  $mm++;
	                  break;
	                }
			      }
			      if ($mm == 0 && $i!=1) {
					$table.="<td class='py-2'>$i</td>";
			      }
			      $tr++;
			      if ($tr==10) {
			      	$table.='</tr>';
			      	$tr=0;
			      }
			    }
			    $this->param['table'] = $table;
				$this->param['RESULT'] = 1;
				
				return $this->param;
			}elseif ($from==3 || $from==4) {
				$list='';
				$total=0;
				 for($i = 2; $i <= $num; $i++){
			      $mm = 0;
			      for($j = 2; $j <= $i/2; $j++) {
			        //only not prime numbers
	                if ($i % $j == 0) {
	                  $mm++;
	                  break;
	                }
			      }
			      if ($mm == 0) {
					$total++;
					$list.="$i,   ";
			      }
			    }
			    $this->param['list'] = $list;
			    $this->param['total'] = $total;
				$this->param['RESULT'] = 1;
				
				return $this->param;
			}elseif ($from==5) {
				function primeCheck($number){ 
				    if ($number == 1) 
				    return 0; 
				    for ($i = 2; $i <= $number/2; $i++){ 
				        if ($number % $i == 0) 
				            return 0; 
				    } 
				    return 1; 
				}
				$prime_check=primeCheck($num);
				$this->param['prime_check'] = $prime_check;
				$this->param['RESULT'] = 1;
				
				return $this->param;
			}elseif ($from==6) {
				$prev='';
				$i=$num;
				$check_n=0;
				while ($i<10000000 && $check_n!=1)
				{
			      $i++;
			      $mm = 0;
			      for($j = 2; $j <= $i/2; $j++) {
	                if ($i % $j == 0) {
	                  $mm++;
	                  break;
	                }
			      }
			      if ($mm == 0) {
					$next=$i;
					$check_n=1;
			      }
			    }
			    $i=$num;
				$check_n=0;
				while ($i>2 && $check_n!=1)
				{
			      $i--;
			      $mm = 0;
			      for($j = 2; $j <= $i/2; $j++) {
	                if ($i % $j == 0) {
	                  $mm++;
	                  break;
	                }
			      }
			      if ($mm == 0) {
					$prev=$i;
					$check_n=1;
			      }
			    }
				$this->param['next'] = $next;
				$this->param['prev'] = $prev;
				$this->param['RESULT'] = 1;
				
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
	}

	// Percent Error Calculator
	function percent($request){
		$ov = $request->ov;
		$av = $request->av;
		if (is_numeric($ov) && is_numeric($av)) {
			$error= round((($ov - $av)/$av)*100,2);
			$this->param['own_error'] = $error;
			$this->param['RESULT'] = 1;
			// dd($this->param ,$error);
			return $this->param;
		} else {
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
	}

	// Time To Decimal Calculator
	function time_decimal($request){
		$hh= $request->hh;
		$mm= $request->mm;
		$ss= $request->ss;
	    if (empty($hh) && empty($mm) && empty($ss)) {
	    	$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
	    }else{
	    	$hour=0;
	    	$min=0;
	    	$sec=0;
	    	if (is_numeric($hh)) {
	    		$hour=$hh;
	    	}
	    	if (is_numeric($mm)) {
	    		$min=$mm;
	    	}
	    	if (is_numeric($ss)) {
	    		$sec=$ss;
	    	}
	    	$hours=$hour + ($min/60) + ($sec/3600);
	    	$mins=($hour * 60) + ($min) + ($sec/60);
	    	$secs=($hour * 3600) + ($min*60) + $sec;
	    	$this->param['hour'] = sprintf("%02d", $hour);
	    	$this->param['min'] = sprintf("%02d", $min);
	    	$this->param['sec'] = sprintf("%02d", $sec);
	    	$this->param['hours'] = $hours;
	    	$this->param['mins'] = $mins;
	    	$this->param['secs'] = $secs;
			$this->param['RESULT'] = 1;
			return $this->param;
	    }
	}

	// Volume of Capsule Calculator
