			$first = newconvert_into_cm($first_unit,$first);
			$second = newconvert_into_cm($second_unit,$second);
			if ($choose === "a_r") {
				$radius = $first;
				$side = $second;
				$volume = $pi_val * pow($radius, 2) * ((4/3) * $radius + $side);
				$surface = 2 * $pi_val * $radius * (2 * $radius + $side);
				$circumference = 2 * $pi_val * $radius;
			}elseif ($choose === "v_r") {
				$radius = $first;
				$volume = $second;
				$side = (($volume / ($pi_val * pow($radius, 2))) - ((4/3) * $radius));
				$surface = 2 * $pi_val * $radius * (2 * $radius + $side);
				$circumference = 2 * $pi_val * $radius;
			}elseif ($choose === "s_r") {
				$radius = $first;
				$surface = $second;
				$side = $surface / (2 * $pi_val * $radius) - 2 * $radius;
				$volume = $pi_val * pow($radius, 2) * ((4/3) * $radius + $side);
				$circumference = 2 * $pi_val * $radius;
			}else{
				$side = $first;
				$circumference = $second;
				$radius = $circumference / (2 * $pi_val);
				$volume = $pi_val * pow($radius, 2) * ((4/3) * $radius + $side);
				$surface = 2 * $pi_val * $radius * (2 * $radius + $side);
			}

			if ($units === "mm") {
				$single_val = 10;
				$square_val = 100;
				$cube_val = 1000;
			}elseif ($units === "cm") {
				$single_val = 1;
				$square_val = 1;
				$cube_val = 1;
			}elseif ($units === "m") {
				$single_val = 0.01;
				$square_val = 0.0001;
				$cube_val = 0.000001;
			}elseif ($units === "km") {
				$single_val = 0.00001;
				$square_val = 0.0000000001;
				$cube_val = 0.000000000000001;
			}elseif ($units === "in") {
				$single_val = 0.393701;
				$square_val = 0.155;
				$cube_val = 0.0610237;
			}elseif ($units === "ft") {
				$single_val = 0.0328084;
				$square_val = 0.0010763888889;
				$cube_val = 0.000035315;
			}elseif ($units === "yd") {
				$single_val = 0.0109361;
				$square_val = 0.00011959876543333333655;
				$cube_val = 0.00000130795;
			}else{
				$single_val =  0.0000062137;
				$square_val = 0.00000000003861013863421143294;
				$cube_val = 0.000000000000000239913;
			}
		}else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
		$this->param['radius'] = round(($radius * $single_val), 2);
		$this->param['side'] = round(($side * $single_val), 2);
		$this->param['volume'] = round(($volume * $cube_val), 2);
		$this->param['surface'] = round(($surface * $square_val), 2);
		$this->param['circumference'] = round(($circumference * $single_val), 2);
	    $this->param[ 'RESULT' ] = 1;

	    return $this->param;
	}

