	// Average Calculator
	function average($request){
		$x = $request->x;
		$check=true;
		if (empty($x)) {
			$check=false;
		}
		if($request->more == 'space'){
			$seprate=' ';
		}elseif($request->more == ','){
			$seprate=',';
		}else{
            $seprate = $request->seprate;
        }
		if (empty($seprate)) {
			$seprate=' ';
		}
		$numbers=array_map('trim',array_filter(explode($seprate,$x)));
		foreach ($numbers as $value) {
			if (!is_numeric($value)) {
				$check=false;
			}
		}
		if ($check==true) {
			sort($numbers);
			$sum=array_sum($numbers);
			$count=count($numbers);
			$average = round($sum/$count,4);
			if (($count%2)!=0) {
				$center=$count/2;
				$median=$numbers[$center--];
			}else{
				$center=round($count/2);
				$next=$center - 1;
				$median=($numbers[$center]+$numbers[$next])/2;
			}
			$d=1;
			foreach ($numbers as $key => $value) {
				$d= $d * $value;
				if (!is_numeric($value)) {
					$number=false;
				}
			}
			$m_array=array_count_values($numbers);
			$m_max=max($m_array);
			$mode = array();
			$table='';
			foreach ($m_array as $key => $value) {
				$table.="<tr><td class='py-2 border-b'>$key </td><td class='py-2 border-b'>$value </td><td class='py-2 border-b'>".($key*$value)." </td></tr>";
				if ($value==$m_max) {
					$mode[]=$key;
				}
			}
			$sum=array_sum($numbers);
			$m= round($sum / count($numbers),3);
			$d=0;
			foreach ($numbers as $key => $value) {
				$d=$d + pow($value - $m,2);
			}
			$s_d_p= (1/(count($numbers))) * $d;
			$s_d_s= (1/(count($numbers) -1)) * $d;
			$s_d_p=round(sqrt($s_d_p),4);
			$s_d_s=round(sqrt($s_d_s),4);
			$this->param['table'] = $table;
			$this->param['mode'] = $mode;
			$this->param['s_d_p'] = $s_d_p;
			$this->param['s_d_s'] = $s_d_s;
			$this->param['median'] = $median;
			$this->param['average'] = $average;
			$this->param['count'] = $count;
			$this->param['d'] = $d;
			$this->param['numbers'] = $numbers;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
	}

	// Midpoint Calculator
	function midpoint($request){
			$x1=$request->x1;
