				return $this->param;
			}
	}

	// Change of Base Formula Calculator
	function change($request){
		$x = $request->x;
		$a = $request->a;
		$b = $request->b;
		if(is_numeric($x) && is_numeric($a) && is_numeric($b)){
			if ($a <= "0" ) {
				$this->param['error'] = 'number of a value cannot be equal to or less then zero.';
				return $this->param;
			}
			$log_one=log($x, $a);
			if ($b <= "0" ) {
				$this->param['error'] = 'number of b value cannot be equal to or less then zero.';
				return $this->param;
			}
			$log_two=log($x, $b);
			$log_three=log($a, $b);
			if ($log_three <= "0" ) {
				$this->param['error'] = 'number of a or b log value cannot be equal to or less then zero.';
				return $this->param;
			}
			$answer=$log_two/$log_three;
		}else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
		$this->param['answer'] = $answer ;
		$this->param['log_one'] = $log_one ;
		$this->param['log_two'] = $log_two ;
		$this->param['log_three'] = $log_three ;
		$this->param[ 'RESULT' ] = 1;
		return $this->param;
	}

