   	// Slope Percentage Calculator
	function slope_percentage($request){
		$rise = $_POST["rise"];
		$run = $_POST["run"];
		$rise_unit = $_POST["rise_unit"];
		$run_unit = $_POST["run_unit"];
		if (isset($rise_unit)) {
			if ($rise_unit == 'm') {
				$rise = $rise;
			} else if ($rise_unit == 'mm') {
				$rise = $rise * 1000;
			} else if ($rise_unit == 'cm') {
				$rise = $rise * 100;
			} else if ($rise_unit == 'km') {
				$rise = $rise * 0.001;
			} else if ($rise_unit == 'in') {
				$rise = $rise * 39.37;
			} else if ($rise_unit == 'ft') {
				$rise = $rise * 3.281;
			}
		}
		if (isset($run_unit)) {
			if ($run_unit == 'm') {
				$run = $run;
			} else if ($run_unit == 'mm') {
				$run = $run * 1000;
			} else if ($run_unit == 'cm') {
				$run = $run * 100;
			} else if ($run_unit == 'km') {
				$run = $run * 0.001;
			} else if ($run_unit == 'in') {
				$run = $run * 39.37;
			} else if ($run_unit == 'ft') {
				$run = $run * 3.281;
			}
		}
		if (is_numeric($rise)) {
			if ($run != 0) {
				$slopePercentage = ($rise / $run) * 100;
			} else {
				$this->param['error'] = 'The run cannot be zero.';
				return $this->param;
			}
			$slopeAngle = atan($rise / $run);
			$slopeAngleDegrees = rad2deg($slopeAngle);
			$this->param['slopeAngle'] =$slopeAngle;
			$this->param['slopeAngleDegrees'] =$slopeAngleDegrees;
			$this->param['slopePercentage'] = $slopePercentage;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please check your input.';
			return $this->param;
		}
	}

	// Percentage Decrease Calculator
	function per_dec($request){
		$start= $request->start;	
