    // Exponential Growth Calculator
    function exponential($request){
		$operations= $request->operations;
		$first= $request->first;
		$second= $request->second;
		$third= $request->third;
		$four= $request->four;
		$t_unit= $request->t_unit;
        function timer($x,$y){
            if($x=="sec"){
                $timr=$y / 31540000;
            }else if ($x=="min") {
                $timr=$y / 525600;
            }else if ($x=="hr") {
                $timr=$y / 8760;
            }else if ($x=="days") {
                $timr=$y / 365;
            }else if ($x=="wks") {
                $timr=$y / 52.143;
            }else if ($x=="mon") {
                $timr=$y / 12;    
            }else{
                $timr=$y * 1; 
            }
            return $timr;
        }
        $third=timer($t_unit,$third);
        if ($operations=="1") {
            if (is_numeric($second) && is_numeric($third) && is_numeric($four)) {
                $divide=$second / 100;
                $plus=1 + $divide;
                $power=pow($plus, $third);
                $final=$four / $power;
                $final=number_format($final, 4);
                $jawab="Initial Value (x₀)";
            }else{
                $this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
            }
        }else if ($operations=="2") {
            if (is_numeric($first) && is_numeric($third) && is_numeric($four)) {
                $divide1=$four / $first;
                $log_div1=log($divide1);
                $divide2=$log_div1 / $third;
                $antilog = pow(2.718281828,$divide2);
                $minus=$antilog - 1;
                $final=$minus * 100;
                $final=number_format($final, 4);
                $jawab="Rate of Change (r)"; 
            }else{
                $this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
            }
        }else if ($operations=="3") {
            if (is_numeric($first) && is_numeric($second) && is_numeric($four)) {
                $divide=$four / $first;
                $divide2=$second / 100;
                $plus=1 + $divide2;
                $log1=log($plus);
                $log2=log($divide);
                $final=$log2 / $log1;
                $final=number_format($final, 4);
                $jawab="Elapsed Time (t)";
            }else{
                $this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
            }
        }else if ($operations=="4") {
             if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
                $divide=$second / 100;
                $plus=1 + $divide;
                $power=pow($plus, $third);
                $final=$first * $power;
                $final=number_format($final, 4);
                $jawab="Final Value x(t)";
            }else{
                $this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
            }
        }
        $this->param['final']=$final;
        $this->param['operations']=$operations;
        $this->param['jawab']=$jawab;
        $this->param['RESULT'] = 1;


        return $this->param;
    }

    // Fraction exponent Calculator
    function frac_exp($request){
		$x= $request->x;
		$n= $request->n;
		$d= $request->d;
        if (is_numeric($x) && is_numeric($n) && is_numeric($d)) {
            if ($d != 0) {
                if (!is_float($n)) {
                    if ($x >= 0) {
                        $a=pow($x, $n);
                        $ans_f=$n / $d;
                        $answer=pow($x, $ans_f);
                        $z=$x;
                        $a=$x;
                        $r_f=pow($a, 2);
                        $r=sqrt($r_f);
                        $theta=0;
                        $power=1 / $d;
                        $r_pow=pow($r, $power);
                        if ($d > 0) {
                            $d=$d;
                        }else if ($d < 0) {
                            $d=-1 * $d;
                        }
                        for ($i=0; $i < $d; $i++) {
                            $f_step=2 * 180 * $i;
                            $uper_fstep=$theta + $f_step;
                            $f_ans2=$uper_fstep / $d;
                            $cos_fans2=cos(deg2rad($f_ans2));
                            $sin_fans2=sin(deg2rad($f_ans2));
                            $cos_fans=$r_pow * $cos_fans2;
                            $sin_fans=$r_pow * $sin_fans2;
                            if ($sin_fans < 0) {
                                $sin_fans=-1 * $sin_fans;
                                $all_roots[]=$cos_fans."-".$sin_fans."i";
                            }else if ($sin_fans >= 0) {
                                $all_roots[]=$cos_fans."+".$sin_fans."i";
                            }
                        }
                    }else if ($x < 0) {
                        $x=-1 * $x;
                        $a=pow($x, $n);
                        $ans_f=$n / $d;
                        $answer=pow($x, $ans_f);
                        $answer=$answer."i";
                        $z=$x;
                        $a2=$x;
                        $r_f=pow($a2, 2);
                        $r=sqrt($r_f);
                        $theta=0;
                        $power=1 / $d;
                        $r_pow=pow($r, $power);
                        for ($i=0; $i < $d; $i++) {
                            $f_step=2 * 180 * $i;
                            $uper_fstep=$theta + $f_step;
                            $f_ans2=$uper_fstep / $d;
                            $cos_fans2=cos(deg2rad($f_ans2));
                            $sin_fans2=sin(deg2rad($f_ans2));
                            $cos_fans=$r_pow * $cos_fans2;
                            $sin_fans=$r_pow * $sin_fans2;
                            if ($sin_fans < 0) {
                                $sin_fans=-1 * $sin_fans;
                                $all_roots[]=$cos_fans."-".$sin_fans."i";
                            }else if ($sin_fans >= 0) {
                                $all_roots[]=$cos_fans."+".$sin_fans."i";
                            }
                        }
                    }
                }else {
					$this->param['error'] = 'Use only integers for the Numerator.';
					return $this->param;
                }
            }else {
				$this->param['error'] = 'Enter a non-zero Denominator.';
				return $this->param;
            }
        }else {
            $this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
        }
        $this->param['all_roots'] = $all_roots;
        $this->param['a'] = $a;
        $this->param['ans_f'] = $ans_f;
        $this->param['answer'] = $answer;
        $this->param['RESULT'] = 1;
        return $this->param;
    }

