        		$red=deg2rad($angle*180);
        	}
        	$sin=2*(round(sin($red),5) * round(cos($red),5));
        	$cos=1-2*(round(sin($red),5) * round(sin($red),5));
        	$uper=(2*round(tan($red),5));
        	$btm=(1-(round(tan($red),5)*round(tan($red),5)));
        	if ($uper==0 || $btm==0) {
        		$tan=0;
        	}else{
        		$tan=$uper/$btm;
        	}
			$tan=sigFig($tan,6);
			$sin=sigFig($sin,6);
			$cos=sigFig($cos,6);
			$this->param['sin'] = $sin;
			$this->param['cos'] = $cos;
			$this->param['tan'] = $tan;
			$this->param['deg'] = $deg;
			$this->param['red'] = $red;
			$this->param['angle'] = $angle;
			$this->param['unit'] = $unit;
			$this->param['RESULT'] = 1;

			return $this->param;
        }else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// GCF Calculator
	function gcf($request){
		$x = $request->x;
		$method = $request->method;
		$check=true;
		if (empty($x)) {
			$check=false;
		}
		$numbers=array_map('trim',array_filter(explode(',',$x)));
		foreach ($numbers as $value) {
			if (!is_numeric($value)) {
				$check=false;
			}else{
				if ($value>1000000) {
					$this->param['error'] = 'Number must be less than or equal to 1000000.';
					return $this->param;
				}
			}
		}
		if ($check==true) {
			if (count($numbers)==1) {
				$this->param['error'] = 'Please! Enter at least two numbers.';
