	// Slope Intercept Form Calculator
	function slope_intercept($request){
		$type = $request->type;
		$x1 = $request->x1;
		$x2 = $request->x2;
		$y1 = $request->y1;
		$y2 = $request->y2;
		if ($type=='2') {
			if (is_numeric($x1) && is_numeric($x2) && is_numeric($y1) && is_numeric($y2)) {
				$x=$x2 - $x1;
				$y=$y2 - $y1;
				$slope=round($y / $x,4);
				$angle=round(atan($slope) * (180 / pi()),4);
				$distance=round(sqrt(pow($x, 2) + pow($y, 2)),4);
				$b=round($y1 - ($slope*$x1),2);
				$this->param['x'] = $x;
				$this->param['y'] = $y;
				$this->param['b'] = $b;
				$this->param['slope'] = $slope;
				$this->param['angle'] = $angle." deg";
				$this->param['distance'] = $distance;
				$this->param['RESULT'] = 1;
				return $this->param;

			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}elseif ($type=='1') {
			$x1=$x1;
			$y1=$y1;
			$slope=$x2;
			if (is_numeric($x1) && is_numeric($y1) && is_numeric($slope)) {
				$angle=round(atan($slope) * (180 / pi()),4);
				$b=round($y1 - ($slope*$x1),4);
				$this->param['b'] = $b;
				$this->param['slope'] = $slope;
				$this->param['angle'] = $angle." deg";
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$b=$x1;
			$slope=$x2;
			if (is_numeric($b) && is_numeric($slope)) {
				$angle=round(atan($slope) * (180 / pi()),4);
				$this->param['b'] = $b;
				$this->param['slope'] = $slope;
				$this->param['angle'] = $angle." deg";
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
	}

	// Percent To Fraction Calculator
	function per_to_frac($request){
		$percent = $request->percent;
		if (!empty($percent)) {
			$nbr=$percent/100;
			$nbr=explode('.', $nbr);
			$div='1';
				$count=strlen($nbr[1]);
				for ($i=1; $i <= $count ; $i++) { 
					$div.='0';
				}
				$upr=$nbr[0].$nbr[1];
				/****
				** Reduce value
				****/
				function gcd($a,$b) 
				{
					$a = abs($a); $b = abs($b);

					if( $a < $b)
					{ 
						list($b,$a) = Array($a,$b);
					}
					if( $b == 0){
						return 1;
					}
					$r = $a % $b;
					while($r > 0): 
						$a = $b;
						$b = $r;
						$r = $a % $b;
					endwhile;
					return $b;
			
				}

				function reduce($num,$den) 
				{
					$g = gcd($num,$den);
					return array($num/$g,$den/$g);
				}
				$g = gcd($upr,$div);
				list ($uper  , $btm) = reduce($upr,$div);
				$this->param['upr'] =$upr;
				$this->param['div'] =$div;
				$this->param['uper'] =$uper;
				$this->param['btm'] =$btm;
				$this->param['g'] =$g;
				$this->param['RESULT'] =1;
				return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

