			$area = $s1 / 2;
			$this->param['area_cal'] = 'area_cal';
			$this->param['area'] = round($area, 3);
			$this->param['a'] = $a;
			$this->param['b'] = $b;
			$this->param['s1'] = $s1;
		} elseif ($cal_from === 'area_side' && $cal === 'side_a' && is_numeric($area) && is_numeric($b)) {
			$s1 = $area * 2;
			$a = ($s1) / $b;
			$this->param['side_a'] = 'side_a';
			$this->param['a'] = round($a, 3);
			$this->param['area'] = $area;
			$this->param['b'] = $b;
			$this->param['s1'] = $s1;
		} elseif ($cal_from === 'area_side' && $cal === 'side_b' && is_numeric($area) && is_numeric($a)) {
			$s1 = $area * 2;
			$b = ($s1) / $a;
			$this->param['side_b'] = 'side_b';
			$this->param['b'] = round($b, 3);
			$this->param['area'] = $area;
			$this->param['a'] = $a;
			$this->param['s1'] = $s1;
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Weighted Average Calculator
	function weighted($request){
		$weight= $request->weight;
		$value= $request->value;
		$i=0;
		$weight_sum=0;
		$weighted_average=0;
		while ($i<count($weight) && $i<count($value)) {
			if(is_numeric($weight[$i]) && is_numeric($value[$i])){
				$weight_sum=$weight_sum+$weight[$i];
				$weighted_average=$weighted_average+($weight[$i]*$value[$i]);
				$i++;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		$final_ans=$weighted_average/$weight_sum;
		$this->param['weight_sum']=$weight_sum;
		$this->param['weighted_average']=$final_ans;
		$this->param['wv']=count($weight);
		$this->param['v']=count($value);
		$this->param['values']=$value;
		$this->param['weights']=$weight;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Point of Intersection Calculator
	function point_of_intersection($request){
		$x1 = $request->x1;
		$y1 = $request->y1;
		$c1 = $request->c1;
		$x2 = $request->x2;
		$y2 = $request->y2;
		$c2 = $request->c2;
		if(is_numeric($x1) && is_numeric($x2) && is_numeric($y1) && is_numeric($y2) && is_numeric($c1) && is_numeric($c2) ){
			if($x1 == $x2 && $y1==$y2){
				$x = "-Infinity";
				$y = "Infinity";
				$this->param['error'] = 'Both Lines are Parallel.';
				return $this->param;
			}else if($x1 == $y1 && $x2 == $y2){
				$x = "-Infinity";
				$y = "Infinity";
				$this->param['error'] = 'Both Lines are Parallel.';
				return $this->param;
			}else{
				$c1 = -$c1;
				$c2 = -$c2;
				$const1 = $c1*-1;
				$const2 = $c2*-1;
				$parallel ="";
				$x = (($y1*$c2) - ($y2*$c1))/(($x1*$y2) - ($x2*$y1));
				$y = (($x2*$c1) - ($x1*$c2))/(($x1*$y2) - ($x2*$y1));
				$x1num  = ($y1*$c2) - ($y2*$c1);
				$x1den = ($x1*$y2) - ($x2*$y1);
				$y1num =  ($x2*$c1) - ($x1*$c2);
				$y1den = ($x1*$y2) - ($x2*$y1);
				if($x>$y){
					if($x>0){
						$th=round($x)+100;
						for($i=-$th;$i<$th;$i++){
							$Line1[$i] = ($const1/$y1) - ($x1*$i/$y1);
							$Line2[$i] = ($const2/$y2) - ($x2*$i/$y2);
						}
					} else{
						$th = $x*-1;
						$th = round($th)+100;
						for($i=-$th;$i<$th;$i++){
							$Line1[$i] = ($const1/$y1) - ($x1*$i/$y1);
							$Line2[$i] = ($const2/$y2) - ($x2*$i/$y2);
						}
					}
					}elseif($y>$x){
					if($y>0){
						$th=round($y)+100;
						for($i=-$th;$i<$th;$i++){
							$Line1[$i] = ($const1/$y1) - ($x1*$i/$y1);
							$Line2[$i] = ($const2/$y2) - ($x2*$i/$y2);
						}
					}else{
						$th = $y*-1;
						$th=round($th)+100;
						for($i=-$th;$i<$th;$i++){
							$Line1[$i] = ($const1/$y1) - ($x1*$i/$y1);
							$Line2[$i] = ($const2/$y2) - ($x2*$i/$y2);
						}
					}
				}
			}
			$this->param['x'] = $x;
			$this->param['y'] = $y;
			$this->param['th'] = $th;
			$this->param['x1num'] = $x1num;
			$this->param['x1den'] = $x1den;
			$this->param['y1num'] = $y1num;
			$this->param['y1den'] = $y1den;
			$this->param['Line1'] = $Line1;
			$this->param['Line2'] = $Line2;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

