					if ($b > 0)  $temp = $x . ' + ' . $b . 'y = ' . $c;
					else if ($b < 0) $temp =  $x . ' - ' . (-$b) . 'y = ' . $c;
				} else     if ($a == -1) {
					if ($b > 0)  $temp = (-$x) . ' + ' . $b . 'y = ' . $c;
					else if ($b < 0) $temp =  (-$x) . ' - ' . (-$b) . 'y = ' . $c;
				}
			} else if ($b == 1) {
				if (abs($a) != 1) {
					if ($x >= 0)  $temp = $a . ' ⋅ ' . $x . ' + y  = ' . $c;
					else if ($x < 0) $temp =  $a . ' ⋅ (' . $x . ') + y = ' . $c;
				} else     if ($a == 1) {
					$temp = $x . ' + y = ' . $c;
				} else     if ($a == -1) {
					$temp =  (-$x) . ' + y = ' . $c;
				}
			} else if ($b == -1) {
				if (abs($a) != 1) {
					if ($x >= 0)  $temp = $a . ' ⋅ ' . $x . ' - y  = ' . $c;
					else if ($x < 0) $temp =  $a . ' ⋅ (' . $x . ') - y = ' . $c;
				} else     if ($a == 1) {
					$temp = $x . ' - y = ' . $c;
				} else     if ($a == -1) {
					$temp =  (-$x) . ' - y = ' . $c;
				}
			}
			return $temp;
		}
		function are3NumbersZero($a, $b, $c)
		{
			return $a * $a + $b * $b + $c * $c == 0;
		}
		function roundNumb($a)
