		function are2NumbersZero($a, $b)
		{
			return $a * $a + $b * $b == 0;
		}
		function gauss3Equations($s1, $t1, $u1, $v1, $s2, $t2, $u2, $v2, $s3, $t3, $u3, $v3)
		{
			$matrix = [[$s1, $t1, $u1, $v1], [$s2, $t2, $u2, $v2], [$s3, $t3, $u3, $v3]];
			if (!are3NumbersZero($matrix[0][0], $matrix[1][0], $matrix[2][0])) {
				if ($matrix[0][0] == 0 && $matrix[1][0] != 0) {
					$safekeeping = $matrix[0];
					$matrix[0] = $matrix[1];
					$matrix[1] = $safekeeping;
				}
				if ($matrix[0][0] == 0 && $matrix[2][0] != 0) {
					$safekeeping = $matrix[0];
					$matrix[0] = $matrix[2];
					$matrix[2] = $safekeeping;
				}
				if ($matrix[1][0] == 0 && $matrix[2][0] != 0) {
					$safekeeping = $matrix[1];
					$matrix[1] = $matrix[2];
					$matrix[2] = $safekeeping;
				}
				if ($matrix[1][0] == 0 && $matrix[1][1] == 0 && $matrix[2][1] != 0) {
					$safekeeping = $matrix[1];
					$matrix[1] = $matrix[2];
					$matrix[2] = $safekeeping;
				}
			} else if (!are3NumbersZero($matrix[0][1], $matrix[1][1], $matrix[2][1])) {
				if ($matrix[0][1] === 0 && $matrix[1][1] !== 0) {
					$safekeeping = $matrix[0];
					$matrix[0] = $matrix[1];
					$matrix[1] = $safekeeping;
				}
				if ($matrix[0][1] === 0 && $matrix[2][1] !== 0) {
					$safekeeping = $matrix[0];
					$matrix[0] = $matrix[2];
