				}
				if ($matrix[1][1] === 0 && $matrix[2][1] !== 0) {
					$safekeeping = $matrix[1];
					$matrix[1] = $matrix[2];
					$matrix[2] = $safekeeping;
				}
				if ($matrix[1][1] === 0 && $matrix[1][2] === 0 && $matrix[2][2] !== 0) {
					$safekeeping = $matrix[1];
					$matrix[1] = $matrix[2];
					$matrix[2] = $safekeeping;
				}
			} else if (!are3NumbersZero($matrix[0][2], $matrix[1][2], $matrix[2][2])) {
				if ($matrix[0][2] === 0 && $matrix[1][2] !== 0) {
					$safekeeping = $matrix[0];
					$matrix[0] = $matrix[1];
					$matrix[1] = $safekeeping;
				}
				if ($matrix[0][2] === 0 && $matrix[2][2] !== 0) {
					$safekeeping = $matrix[0];
					$matrix[0] = $matrix[2];
					$matrix[2] = $safekeeping;
				}
				if ($matrix[1][2] === 0 && $matrix[2][2] !== 0) {
					$safekeeping = $matrix[1];
					$matrix[1] = $matrix[2];
					$matrix[2] = $safekeeping;
				}
			}
			if ($matrix[1][0] != 0) {
				$matrix[1][3] = roundNumb($matrix[1][3] - $matrix[1][0] * ($matrix[0][3] / $matrix[0][0]));
				$matrix[1][2] = roundNumb($matrix[1][2] - $matrix[1][0] * ($matrix[0][2] / $matrix[0][0]));
				$matrix[1][1] = roundNumb($matrix[1][1] - $matrix[1][0] * ($matrix[0][1] / $matrix[0][0]));
				$matrix[1][0] = 0;
				if ($matrix[2][0] != 0) {
					$matrix[2][3] = roundNumb($matrix[2][3] - $matrix[2][0] * ($matrix[0][3] / $matrix[0][0]));
					$matrix[2][2] = roundNumb($matrix[2][2] - $matrix[2][0] * ($matrix[0][2] / $matrix[0][0]));
					$matrix[2][1] = roundNumb($matrix[2][1] - $matrix[2][0] * ($matrix[0][1] / $matrix[0][0]));
					$matrix[2][0] = 0;
				}
			} else if ($matrix[0][0] == 0 && $matrix[1][1] != 0) {
				$matrix[1][3] = roundNumb($matrix[1][3] - $matrix[1][1] * ($matrix[0][3] / $matrix[0][1]));
				$matrix[1][2] = roundNumb($matrix[1][2] - $matrix[1][1] * ($matrix[0][2] / $matrix[0][1]));
				$matrix[1][1] = 0;
				if ($matrix[2][1] !== 0) {
					$matrix[2][3] = roundNumb($matrix[2][3] - $matrix[2][1] * ($matrix[0][3] / $matrix[0][1]));
					$matrix[2][2] = roundNumb($matrix[2][2] - $matrix[2][1] * ($matrix[0][2] / $matrix[0][1]));
					$matrix[2][1] = 0;
				}
			} else if (are2NumbersZero($matrix[0][0], $matrix[0][1]) && $matrix[1][2] !== 0) {
				$matrix[1][3] = roundNumb($matrix[1][3] - $matrix[1][2] * ($matrix[0][3] / $matrix[0][2]));
				$matrix[1][2] = 0;
				if ($matrix[2][2] !== 0) {
					$matrix[2][3] = roundNumb($matrix[2][3] - $matrix[2][2] * ($matrix[0][3] / $matrix[0][2]));
					$matrix[2][2] = 0;
				}
			}
			if ($matrix[2][1] != 0) {
				if ($matrix[1][1] === 0) {
					$safekeeping = $matrix[1];
					$matrix[1] = $matrix[2];
					$matrix[2] = $safekeeping;
				}
			} else if ($matrix[1][1] == 0 && $matrix[2][2] != 0) {
				$safekeeping = $matrix[1];
				$matrix[1] = $matrix[2];
				$matrix[2] = $safekeeping;
			}
			if ($matrix[2][1] != 0) {
				$matrix[2][3] = roundNumb($matrix[2][3] - $matrix[2][1] * ($matrix[1][3] / $matrix[1][1]));
				$matrix[2][2] = roundNumb($matrix[2][2] - $matrix[2][1] * ($matrix[1][2] / $matrix[1][1]));
				$matrix[2][1] = 0;
			} else if ($matrix[1][1] == 0 && $matrix[2][2] != 0) {
				$matrix[2][3] = roundNumb($matrix[2][3] - $matrix[2][2] * ($matrix[1][3] / $matrix[1][2]));
				$matrix[2][2] = 0;
			}
			return $matrix;
		}
		function solveFor3($s1, $t1, $u1, $v1, $s2, $t2, $u2, $v2, $s3, $t3, $u3, $v3)
		{
			$matrix = gauss3Equations($s1, $t1, $u1, $v1, $s2, $t2, $u2, $v2, $s3, $t3, $u3, $v3);
			if (are3NumbersZero($matrix[2][0], $matrix[2][1], $matrix[2][2])) {
				if ($matrix[2][3] != 0) {
					return 0;
				} else {
					if (are3NumbersZero($matrix[1][0], $matrix[1][1], $matrix[1][2])) {
						if ($matrix[1][3] != 0) {
							return 0;
						} else {
							if (are3NumbersZero($matrix[0][0], $matrix[0][1], $matrix[0][2])) {
								if ($matrix[0][3] !== 0) {
									return 0;
								} else {
									return 1;
								}
							} else if ($matrix[0][0] == 0) {
								$x = [1, 0, 0];
								if ($matrix[0][1] == 0) {
									$y = [0, 1, 0];
									$z = [0, 0, roundNumb($matrix[0][3] / $matrix[0][2])];
								} else if ($matrix[0][2] == 0) {
									$z = [0, 1, 0];
									$y = [0, 0, roundNumb($matrix[0][3] / $matrix[0][1])];
								} else {
									$y = [0, 1, 0];
									$z = [0, roundNumb((-1) * $matrix[0][1] / $matrix[0][2]), roundNumb($matrix[0][3] / $matrix[0][2])];
								}
							} else if ($matrix[0][1] == 0) {
								$y = [1, 0, 0];
								if ($matrix[0][2] === 0) {
									$z = [0, 1, 0];
									$x = [0, 0, roundNumb($matrix[0][3] / $matrix[0][0])];
								} else {
									$x = [0, 1, 0];
									$z = [0, roundNumb((-1) * $matrix[0][0] / $matrix[0][2]), roundNumb($matrix[0][3] / $matrix[0][2])];
								}
							} else if ($matrix[0][2] == 0) {
								$x = [1, 0, 0];
								$z = [0, 1, 0];
								$y = [0, roundNumb((-1) * $matrix[0][0] / $matrix[0][1]), roundNumb($matrix[0][3] / $matrix[0][1])];
							} else {
								$x = [1, 0, 0];
								$y = [0, 1, 0];
								$z = [roundNumb((-1) * $matrix[0][0] / $matrix[0][2]), roundNumb((-1) * $matrix[0][1] / $matrix[0][2]), roundNumb($matrix[0][3] / $matrix[0][2])];
							}
						}
					} else if ($matrix[1][1] === 0) {
						$z = [0, 0, roundNumb($matrix[1][3] / $matrix[1][2])];
						$matrix[0][3] = roundNumb($matrix[0][3] - $matrix[0][2] * $z[2]);
						$matrix[0][2] = 0;
						if ($matrix[0][0] == 0) {
							$x = [1, 0, 0];
							$y = [0, 0, roundNumb($matrix[0][3] / $matrix[0][1])];
						} else if ($matrix[0][1] == 0) {
							$y = [1, 0, 0];
							$x = [0, 0, roundNumb($matrix[0][3] / $matrix[0][0])];
						} else {
							$x = [1, 0, 0];
							$y = [roundNumb((-1) * $matrix[0][0] / $matrix[0][1]), 0, roundNumb($matrix[0][3] / $matrix[0][1])];
						}
					} else if ($matrix[1][2] === 0) {
						$y = [0, 0, roundNumb($matrix[1][3] / $matrix[1][1])];
						$matrix[0][3] = roundNumb($matrix[0][3] - $matrix[0][1] * $y[2]);
						$matrix[0][1] = 0;
						if ($matrix[0][2] === 0) {
							$z = [1, 0, 0];
							$x = [0, 0, roundNumb($matrix[0][3] / $matrix[0][0])];
						} else {
							$x = [1, 0, 0];
							$z = [roundNumb((-1) * $matrix[0][0] / $matrix[0][2]), 0, roundNumb($matrix[0][3] / $matrix[0][2])];
						}
					} else {
						$y = [1, 0, 0];
						$z = [roundNumb((-1) * $matrix[1][1] / $matrix[1][2]), 0, roundNumb($matrix[1][3] / $matrix[1][2])];
						$x = [roundNumb((-1) * ($y[0] * $matrix[0][1] / $matrix[0][0] + $z[0] * $matrix[0][2] / $matrix[0][0])), 0, roundNumb($matrix[0][3] - $y[2] * $matrix[0][1] / $matrix[0][0] - $z[2] * $matrix[0][2] / $matrix[0][0])];
					}
				}
			} else {
				$z = [0, 0, roundNumb($matrix[2][3] / $matrix[2][2])];
				$matrix[1][3] = roundNumb($matrix[1][3] - $matrix[1][2] * $z[2]);
				$matrix[0][3] = roundNumb($matrix[0][3] - $matrix[0][2] * $z[2]);
				$matrix[1][2] = 0;
				$matrix[0][2] = 0;
				$y = [0, 0, roundNumb($matrix[1][3] / $matrix[1][1])];
				$matrix[0][3] = roundNumb($matrix[0][3] - $matrix[0][1] * $y[2]);
				$matrix[0][1] = 0;
				$x = [0, 0, roundNumb($matrix[0][3] / $matrix[0][0])];
			}
			return [$x, $y, $z];
		} 
