	// Fundamental Counting Principle Calculator
	function fundamental($request){
		$choices = $request->choices;
		$i=0;
		if (is_numeric($choices[$i]) && isset($choices[$i])) {
			$answer=1;
			foreach ($choices as $value) {
				$answer = $answer*$value;
				$this->param[ 'answer' ] = $answer;
			}
