		$this->param[ 'RESULT' ] = 1;
		return $this->param;
    }

	// Centroid Calculator
	function centroid($request){
		$shap = $request->shap;
		$x1 = $request->x1;
		$y1 = $request->y1;
		$x2 = $request->x2;
		$y2 = $request->y2;
		$x3 = $request->x3;
		$y3 = $request->y3;
		$total = $request->total;
		if (is_numeric($x1) && is_numeric($y1) && is_numeric($x2) && is_numeric($y2) && is_numeric($x3) && is_numeric($y3)) {
			if($shap=='3'){
				$x=round(($x1 + $x2 + $x3) / 3,3);
				$y=round(($y1 + $y2 + $y3) / 3,3);
				$x3 = $x1 + $x2 + $x3;
				$y3=$y1 + $y2 + $y3;
				$ans=$x." , ".$y;
				$this->param['ans'] = @$ans;
				$this->param['x1'] = $x1;
				$this->param['x2'] = $x2;
				$this->param['x3'] = $x3;
				$this->param['y1'] = $y1;
				$this->param['y2'] = $y2;
				$this->param['y3'] = $y3;
				$this->param['n'] = 3;
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				if (is_numeric($total)) {
					$nbr = $total;
					$x=0;
					$y=0;
					$x1='';
					$x2='';
					$y1='';
					$y2='';
					for ($i=1; $i <= $nbr ; $i++) { 
						if ($i!=$nbr) {
							$x1.="x_$i + ";
							$y1.="y_$i + ";
							$x2.=$_POST['x'.$i]." + ";
							$y2.=$_POST['y'.$i]." + ";
						}else{
							$x1.=" x_$i";
							$y1.=" y_$i";
							$x2.=" ".$_POST['x'.$i];
							$y2.=" ".$_POST['y'.$i];
						}
						$x=$x + $_POST['x'.$i];
						$y=$y + $_POST['y'.$i];
					}
					$x3=$x;
					$y3=$y;
					$x=round($x/$nbr,3);
					$y=round($y/$nbr,3);
					$ans=$x." , ".$y;
					$this->param['x1'] = $x1;
					$this->param['x2'] = $x2;
					$this->param['x3'] = $x3;
					$this->param['y1'] = $y1;
					$this->param['y2'] = $y2;
					$this->param['y3'] = $y3;
					$this->param['n'] = $nbr;
					$this->param['ans'] = $ans;
					$this->param['RESULT'] = 1;
					return $this->param;
				} else {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

