	// Inverse Modulo Calculator
	function inv_mod($request){
		$opr= $request->opr;
		$a= $request->a;
		$b= $request->b;
  		function xgcd($a,$b){
		    $quot=''; $a1=1; $b1=0; $a2=0; $b2=1; $aneg=1; $bneg=1; $result=[];
		    $temp = "";
			$flag = false;
		    if($a < 0) {$a = $a*(-1); $aneg=-1;}
		    if($b < 0) {$b = $b*(-1); $bneg=-1;}
		    if($b > $a) {$temp = $a; $a = $b; $b = $temp; $flag = true;}
	    	while (true) {
	      		$quot = floor($a / $b)*(-1);
	        	$a %= $b;
	        	$a1 += $quot*$a2; $b1 += $quot*$b2;
	        	if($a === 0 && $flag == false) 
	        	{$result[0]=$b*$bneg; $result[1]=$a2; $result[2]=$b2; return $result;}
	         	if($a === 0 && $flag == true) 
	            {$result[0]=$b*$bneg; $result[1]=$b2; $result[2]=$a2; return $result;}              
	         	$quot = floor($b / $a)*(-1);
	         	$b %= $a;
	         	$a2 += $quot*$a1; $b2 += $quot*$b1;
	        	if($b === 0 && $flag == false )
	         	{$result[0]=$a*$aneg; $result[1]=$a1; $result[2]=$b1; return $result;}
	        	if($b === 0 && $flag == true )
	         	{$result[0]=$a*$aneg; $result[1]=$b1; $result[2]=$a1; return $result;}
	      	} 
	  	}
  		if (is_numeric($a) && is_numeric($b)) {
  			$m=$b;
  			if ($opr==1) {
  				$res = xgcd($a,$m)[1];
      			$gcd = xgcd($a,$m)[0];
  				if (abs($gcd) == 1) {
  					while ($res < 0){$res = $res+$m;}
  				}else{
  					$res='no';
  				}
  			}elseif($opr==2) {
  				$res1 = $a*(-1);
				$res2 = $a*(-1);
				while (($res1 < 0 || $res1>=$m) && ($res2 < 0 || $res2>=$m)) {
					$res1 += $m;
					$res2 -= $m;
				}
				if ($res1 >= 0 && $res1<$m){
					$res = $res1;
				}else{
					$res = $res2;
				}
  			}
  			$this->param['res'] = $res;
			$this->param['RESULT'] = 1;
			return $this->param;
  		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
  		}

	}

