  				$ans = '<sup class="font-s-14">'.$b.'</sup>√'.$a.'  = '.(round(pow($a,1/$b),5));
  			}elseif($opr==7) {
  				$ansText = 'log<sub class="font-s-14">a</sub>b  = ?';
  				$ans = 'log<sub class="font-s-14">'.$a.'</sub>'.$b.'  = '.(round(log($b,$a),5));
