	}

	// Rational or Irrational Calculator
	function irrational($request){
		//  dd($request->all());


		$expression_unit= $request->expression_unit;
		$num1= $request->num1;
		$num2= $request->num2;
  		function findRepeat($number)
		{
		    $maxLength = 6;
		    $decimal = substr($number, strpos($number,'.') + 1 );
		    if(strlen($decimal) >= $maxLength )
		        $decimal = substr($decimal,0, $maxLength);
		    else
		        $maxLength = strlen($decimal);

		    for($i =0; $i < $maxLength - 3; ++$i)
		    {
		        //check for single repeition
		        if( $decimal[$i] == $decimal[$i + 1] &&  $decimal[$i + 1] == $decimal[$i+2])
		            return array('position'=>$i,'patternSize'=>1);
		        //triple repetition
		        if(substr($decimal,$i,3) == substr($decimal, $i + 3, 3) )
		            return array('position'=>$i,'patternSize'=>3);
		        //double repetition
		        if(substr($decimal,$i,2) == substr($decimal, $i + 2, 2) )
		            return array('position'=>$i,'patternSize'=>2);
		    }
		    return false;
		}
		if (is_numeric($num1) && is_numeric($num2)) {
			if ($expression_unit=="1") {
				if ($num1 > 0 && $num2 > 0) {
					$num1_ans=1 / $num1;
					$final_ans=pow($num2, $num1_ans);
				}else{
					$this->param['error'] = 'Please Enter value greater than zero.';
					return $this->param;
				}
				if ($num2 % $num1==0) {
					if ($num1==$num2) {
						if ($num1==1 && $num2==1) {
							$exp="Given Number is Rational";
						}else{
							$exp="Given Number is Irrational";
						}
					}else if($num1!=$num2){
						$exp="Given Number is Rational";
					}
				}else{
					$exp="Given Number is Irrational";
				}
			}else if ($expression_unit=="2") {
				if (is_numeric($num1) && $num2 > 0) {
					if ($num1==22 && $num2==7) {
						$final_ans=$num1 / $num2;
						$exp="Given Number is Irrational";
					}else{
						$final_ans=$num1 / $num2;
						$exp="Given Number is Rational";
					}
					if(findRepeat( $final_ans ) !== false){
						$result = findRepeat($final_ans);
						$leadingNum = strstr($final_ans, '.', true);
						$nonRepeat = substr($final_ans, strpos($final_ans, '.') + 1 , $result['position']);
						if($nonRepeat == '')
							$nonRepeat = '.';

						$repeat = substr($final_ans,strpos($final_ans,$nonRepeat) + strlen($nonRepeat), $result['patternSize']);
						$nonRepeat = $nonRepeat == '.' ? '.' : '.'.$nonRepeat;
						$final_ans=$leadingNum.$nonRepeat."<span style='text-decoration:overline'>".$repeat."</span>";
					}
					else{
						$final_ans=$final_ans;
					}
				}else{
					$this->param['error'] = 'Please Enter value greater than zero.';
					return $this->param;
				}
			}
			if (!empty($final_ans)) {
				$this->param['final_ans'] = $final_ans;
			}
			if (!empty($exp)) {
				$this->param['exp'] = $exp;
			}
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
  		}
  	}

	// Combining Like Terms Calculator 
	function combine($request){
  		$input= $request->input;
  		if (!empty($input)) {
  			$parem=$input;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('x=', '', $parem);
			$parem=str_replace('y=', '', $parem);
			$parem=str_replace('−', '-', $parem);
			$parem=str_replace('plus', '+', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			try {
				$client = new Client();
				$response = $client->post("http://167.172.134.148/combine", [
					'form_params' => [
						'equ' => $parem,
					],
					'timeout' => 120,
				]);
				$buffer = $response->getBody();
				$buffer = json_decode($buffer, true);
				$enter=$buffer[0];
                $input=$buffer[1];
                $answer=$buffer[2];

                $like=str_replace('\left(','',$input);
	  			$like=str_replace('\right)','',$like);
	  			$like=str_replace(' ','',$like);
	  			$like=str_replace('\\','',$like);
	  			$likes=explode(',', $like);
	  			$combine=[];
	  			foreach ($likes as $key => $value) {
	  				if (preg_match('/x/i', $value)) {$combine['x'][]=$value;}
	  				elseif (preg_match('/a/i', $value)) {$combine['a'][]=$value;}
	  				elseif (preg_match('/b/i', $value)) {$combine['b'][]=$value;}
	  				elseif (preg_match('/c/i', $value)) {$combine['c'][]=$value;}
	  				elseif (preg_match('/d/i', $value)) {$combine['d'][]=$value;}
	  				elseif (preg_match('/e/i', $value)) {$combine['e'][]=$value;}
	  				elseif (preg_match('/f/i', $value)) {$combine['f'][]=$value;}
	  				elseif (preg_match('/g/i', $value)) {$combine['g'][]=$value;}
	  				elseif (preg_match('/h/i', $value)) {$combine['h'][]=$value;}
	  				elseif (preg_match('/i/i', $value)) {$combine['i'][]=$value;}
	  				elseif (preg_match('/j/i', $value)) {$combine['j'][]=$value;}
	  				elseif (preg_match('/k/i', $value)) {$combine['k'][]=$value;}
	  				elseif (preg_match('/l/i', $value)) {$combine['l'][]=$value;}
	  				elseif (preg_match('/m/i', $value)) {$combine['m'][]=$value;}
	  				elseif (preg_match('/n/i', $value)) {$combine['n'][]=$value;}
	  				elseif (preg_match('/o/i', $value)) {$combine['o'][]=$value;}
	  				elseif (preg_match('/p/i', $value)) {$combine['p'][]=$value;}
	  				elseif (preg_match('/q/i', $value)) {$combine['q'][]=$value;}
	  				elseif (preg_match('/r/i', $value)) {$combine['r'][]=$value;}
	  				elseif (preg_match('/s/i', $value)) {$combine['s'][]=$value;}
	  				elseif (preg_match('/t/i', $value)) {$combine['t'][]=$value;}
	  				elseif (preg_match('/u/i', $value)) {$combine['u'][]=$value;}
	  				elseif (preg_match('/v/i', $value)) {$combine['v'][]=$value;}
	  				elseif (preg_match('/w/i', $value)) {$combine['w'][]=$value;}
	  				elseif (preg_match('/y/i', $value)) {$combine['y'][]=$value;}
	  				elseif (preg_match('/z/i', $value)) {$combine['z'][]=$value;}
	  				else{$combine['zcon'][]=$value;}
	  			}
	  			$powera=[];
	  			foreach ($combine as $key => $value) {
	  				if ($key!='zcon') {
	  					foreach ($value as $key1 => $value1) {
	  						$power=explode($key.'^{',$value1);
	  						if (count($power)==2) {
	  							if (empty(trim($power[0]))){
	  								$power[0]=1;
	  							}
	  							$power[1]=str_replace('}','',$power[1]);
	  							$powera[$key.'^{'.trim($power[1]).'}'][]=trim($power[0]);
	  						}else{
	  							$base=str_replace($key,'',$value1);
	  							if (empty(trim($base))) {
	  								$base=1;
	  							}
	  							$powera[$key][]=$base;
	  						}
	  					}
	  				}else{
	  					foreach ($value as $key1 => $value1) {
	  						$powera['zcon'][]=trim($value1);
	  					}
	  				}
	  			}
	  			$steps=[];
	  			$final=[];
	  			$finals=[];
	  			$ans='';
	  			$i=0;
	  			ksort($powera);
	  			$j=0;
	  			foreach ($powera as $key => $value) {
	  				if ($key!='zcon') {
	  					if (array_sum($value)>0) {
	  						$plus=' + ';
	  					}else{
	  						$plus='';
	  					}
	  					$finals[]=$plus.((array_sum($value)!=1)?array_sum($value):'').$key;
	  					if (count($value)>1) {
		  					$step='Combining like terms ';
		  				}
		  				foreach ($value as $key1 => $value1) {
		  					if (count($value)>1) {
		  						if ($step=='Combining like terms ') {
		  							$step.='\( '.(($value1!=1)?$value1:'').$key.'\)';
		  						}else{
		  							$step.=' and \('.(($value1!=1)?$value1:'').$key.'\)';
		  						}
		  					}
		  					$i++;
			  				if (trim($value1)<0) {
			  					if ($value1==1) {
			  						$ans.=' '.$key;
			  						$final[$j]=@$final[$j].' '.$key;
			  					}else{
			  						$ans.=' '.$value1.$key;
			  						$final[$j]=@$final[$j].' '.$value1.$key;
			  					}
			  				}else{
			  					if ($i!=1) {
			  						if ($value1==1) {
			  							$ans.=' + '.$key;
			  							$final[$j]=@$final[$j].' + '.$key;
			  						}else{
			  							$ans.=' + '.$value1.$key;
			  							$final[$j]=@$final[$j].' + '.$value1.$key;
			  						}
			  					}else{
			  						if ($value1==1) {
			  							$ans.=$key;
			  							$final[$j]=@$final[$j].$key;
			  						}else{
			  							$final[$j]=@$final[$j].$value1.$key;
			  							$ans.=$value1.$key;
			  						}
			  					}
			  				}
		  				}
	  				}else{
	  					if (array_sum($value)>0) {
	  						$plus=' + ';
	  					}else{
	  						$plus='';
	  					}
	  					$finals[]=$plus.array_sum($value);
	  					if (count($value)>1) {
		  					$step='Combining like terms ';
		  				}
	  					foreach ($value as $key1 => $value1) {
	  						if (count($value)>1) {
		  						if ($step=='Combining like terms ') {
		  							$step.='\( '.$value1.'\)';
		  						}else{
		  							$step.=' and \( '.$value1.'\)';
		  						}
		  					}
	  						$i++;
			  				if (trim($value1)<0) {
			  					$ans.=' '.$value1;
			  					$final[$j]=@$final[$j].' '.$value1;
			  				}else{
			  					if ($i!=1) {
			  						$ans.=' + '.$value1;
			  						$final[$j]=@$final[$j].' + '.$value1;
			  					}else{
			  						$ans.=$value1;
			  						$final[$j]=@$final[$j].$value1;
			  					}
			  				}
		  				}
	  				}
	  				if (count($value)>1) {
	  					$steps[]=$step;
	  				}else{
	  					$steps[]='';
	  				}
	  				$j++;
	  			}
				$this->param['enter'] = $enter;
				$this->param['powera'] = $powera;
				$this->param['ans'] = $ans;
				$this->param['input'] = $input;
				$this->param['answer'] = $answer;
				$this->param['steps'] = $steps;
				$this->param['final'] = $final;
				$this->param['finals'] = $finals;
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
  		}else{
  			$this->session->set_flashdata('combine','Please Check Your Input');
			  return $this->param;	
  		}
	}

	// Degree And Leading Coefficient
	function degree($request){
		$equ= $request->equ;
		$vari= $request->vari;
		$range=range('a', 'z');
		if (!empty($equ) && in_array(strtolower($vari), $range)) {
			$input=$equ;
			$input=str_replace(' ', '', $input);
			$input=str_replace('+', 'plus', $input);
			$input=str_replace('{', '(', $input);
			$input=str_replace('}', ')', $input);
			$input=str_replace('xe^', 'x*e^', $input);
			$input=str_replace('ye^', 'y*e^', $input);
			$input=str_replace('e^', 'exp', $input);
			$input=str_replace('exp^', 'exp', $input);
			$input=str_replace('^', '**', $input);
			$input=str_replace('e^sqrt(x)', 'exp(2*x)', $input);
			try {
				$client = new Client();
				$response = $client->post("http://167.172.134.148/degree", [
					'form_params' => [
						'equ' => $input,
					],
					'timeout' => 120,
				]);
				$buffer = $response->getBody();
				$buffer = json_decode($buffer, true);
				$input=$buffer[1];
	            $jawab=trim($buffer[0]);
	            $jawab=str_replace('\left(', '', $jawab);
	            $jawab=str_replace('\right)', '', $jawab);
	            $jawab=str_replace('\\', '', $jawab);
	            $jawab=explode(',', $jawab);
	            $final=[];
	            foreach ($jawab as $key => $value) {
					if (preg_match("/$vari/i", $value)) {
						$index=explode($vari, $value);
						if (count($index)==2) {
							$keyx=trim($index[0]);
							$keyx=str_replace(' ', '', $keyx);
							$valuex=trim($index[1]);
							$valuex=str_replace('^{', '', $valuex);
							$valuex=str_replace('}', '', $valuex);
							$valuex=str_replace(' ', '', $valuex);
							if (empty($valuex)) {
								if (is_numeric($keyx)) {
									$final[$keyx]=1;
								}
							}elseif(is_numeric($valuex) && is_numeric($keyx)){
								$final[$keyx]=$valuex;
							}
						}
					}            	
	            }
	            if (empty($final)) {
	            	$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
	            }else{
		            $degree=max($final);
		            $lead=array_search(max($final), $final);
		            $this->param['input'] = $input;
		            $this->param['lead'] = $lead;
		            $this->param['degree'] = $degree;
	    			$this->param['RESULT'] = 1;
		        	return $this->param;
	            }
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

