	// Multiplying Polynomials Calculator
	function multiplying($request){
		$first= $request->first;
		$second= $request->second;
  		if (!empty($first) && !empty($second)) {
  			$parem=$first;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('−', '-', $parem);
			$parem=str_replace('plus', '+', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);

			$parem1=$second;
			$parem1=str_replace(' ', '', $parem1);
			$parem1=str_replace('−', '-', $parem1);
			$parem1=str_replace('plus', '+', $parem1);
			$parem1=str_replace('{', '(', $parem1);
			$parem1=str_replace('}', ')', $parem1);
			$parem1=str_replace('e^', 'exp', $parem1);
			$parem1=str_replace('exp^', 'exp', $parem1);
			$parem1=str_replace('^', '**', $parem1);
			try {
				$client = new Client();
				$response = $client->post("http://167.172.134.148/multiplying", [
					'form_params' => [
						'equ' => $parem,
						'equ1' => $parem1,
					],
					'timeout' => 120,
				]);
				$buffer = $response->getBody();
				$buffer = json_decode($buffer, true);
				$input1=$buffer[0];
				$input2=$buffer[1];
				$ans=$buffer[2];
				$left=$buffer[3];
				$right=$buffer[4];
				$nextstep=$buffer[5];
	
				$nextstep=str_replace('\left[','',$nextstep);
				  $nextstep=str_replace('\right]','',$nextstep);
				  $nextstep=str_replace(' ','',$nextstep);
				  $nextstep=str_replace('\\','',$nextstep);
				  $nextstep=str_replace('frac','\\dfrac',$nextstep);
				  $nextstep=str_replace('sqrt','\\sqrt',$nextstep);
				  $nextstep=explode(',', $nextstep);
	
				$like=str_replace('\left(','',$left);
				  $like=str_replace('\right)','',$like);
				  $like=str_replace(' ','',$like);
				  $like=str_replace('\\','',$like);
				  $like=str_replace('frac','\\dfrac',$like);
				  $like=str_replace('sqrt','\\sqrt',$like);
				  $lefts=explode(',', $like);
	
				  $like=str_replace('\left(','',$right);
				  $like=str_replace('\right)','',$like);
				  $like=str_replace(' ','',$like);
				  $like=str_replace('\\','',$like);
				  $like=str_replace('frac','\\dfrac',$like);
				  $like=str_replace('sqrt','\\sqrt',$like);
				  $rights=explode(',', $like);
				  $step='';
				  $next='';
				  foreach ($lefts as $key => $value) {
					  foreach ($rights as $key1 => $value1) {
						  if (empty($step)) {
							  $step='('.$value.') \\times ('.$value1.')';
						  }else{
							  $step.=' + ('.$value.') \\times ('.$value1.')';
						  }
					  }
				  }
				  foreach ($nextstep as $key => $value) {
					  if (empty($next)) {
						  $next="( $value )";
					  }else{
						  $next.=" + ( $value )";
					  }
				  }
				$this->param['input1'] = $input1;
				$this->param['input2'] = $input2;
				$this->param['step'] = $step;
				$this->param['next'] = $next;
				$this->param['ans'] = $ans;
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
  		}else{
			$this->param['error'] = '2 values should not be same.';
			return $this->param;
  		}
	}

	// Axis of Symmetry Calculator
	function axis($request){
		function new_gcd($a, $b) {
			return ($b === 0) ? $a : new_gcd($b, $a % $b);
		}			
		function divideOrFactorize($numerator, $denominator) {
			$commonDivisor = new_gcd($numerator, $denominator);
		
			if ($commonDivisor > 1) {
				$numerator /= $commonDivisor;
				$denominator /= $commonDivisor;
			}
			return [
				'numerator' => $numerator,
				'denominator' => $denominator,
			];
		}
		$eq= $request->eq;
		$validator = Validator::make($request->all(), [
			'eq' => 'required|regex:/^[^<>&]*$/i',
		]);
	
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$parem=$eq;
		$parem=str_replace(' ', '', $parem);
		$parem=str_replace('%20', '', $parem);
		$parem=str_replace('+', 'plus', $parem);
		$parem=str_replace('{', '(', $parem);
		$parem=str_replace('}', ')', $parem);
		$parem=str_replace('e^', 'exp', $parem);
		$parem=str_replace('exp^', 'exp', $parem);
		$parem=str_replace('^', '**', $parem);
		$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
		try {
			$client = new Client();
			$response = $client->post("http://167.172.134.148/axis", [
				'form_params' => [
					'equ' => $parem,
				],
				'timeout' => 120,
			]);
			$buffer = $response->getBody();
			$buffer = explode("@@@", $buffer);
			if($buffer[5] === "False"){
				$this->param['error'] = 'The expression provided needs to be a valid univariate quadratic expression in x.';
				return $this->param;
			}
			$input_eq = $buffer[0];
			$coeff_a = $buffer[1];
			$coeff_b = $buffer[2];
			$coeff_c = $buffer[3];
			$expand_eq = $buffer[4];
			$ans = $coeff_b / (2 * $coeff_a);
			if (is_int($ans)) {
				$asal_jawab = ($coeff_b / (2 * $coeff_a)) * (-1);
			} else {
				$result = divideOrFactorize($coeff_b, (2 * $coeff_a));
				if ($result['denominator'] === 1 || $result['denominator'] === 0) {
					$asal_jawab = $result['numerator'] * (-1);
				}else{
					if (($result['numerator'] < 0 && $result['denominator'] < 0) || ($result['numerator'] > 0 && $result['denominator'] > 0)) {
						$asal_jawab = '- \frac{'.$result["numerator"].'}{'.$result["denominator"].'}';
					} else {
						$asal_jawab = '\frac{'.$result["numerator"].'}{'.$result["denominator"].'}';
					}
					
				}
			}
			$this->param['input_eq'] = $input_eq;
			$this->param['coeff_a'] = $coeff_a;
			$this->param['coeff_b'] = $coeff_b;
			$this->param['coeff_c'] = $coeff_c;
			$this->param['expand_eq'] = $expand_eq;
			$this->param['asal_jawab'] = $asal_jawab;
			$this->param['RESULT'] = 1;
			return $this->param;
		} catch (\Exception $response) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

