	// Pythagorean Theorem Calculator
	function pythagorean($request){
		$one= $request->one;
		$two= $request->two;
		$for= $request->for;
		$nbr= $request->nbr;
		if (is_numeric($one) && is_numeric($two) && is_numeric($nbr)) {
			if ($for==='a') {
				$b=$one;
				$c=$two;
				$a=round(sqrt(pow($c, 2) - pow($b, 2)),$nbr);
			}elseif ($for==='b') {
				$a=$one;
				$c=$two;
				$b=round(sqrt(pow($c, 2) - pow($a, 2)),$nbr);
			}elseif ($for==='c' || $for==='ar') {
				$a=$one;
				$b=$two;
				$c=round(sqrt(pow($a, 2) + pow($b, 2)),$nbr);
			}
			$area=($a*$b)/2;
			$peri=$a+$b+$c;
			$h=$a*$b/$c;
			$alfa=round(asin($a/$c),$nbr);
			$a_deg=round(rad2deg($alfa),$nbr);
			$beta=round(asin($b/$c),$nbr);
			$b_deg=round(rad2deg($beta),$nbr);
			$this->param['a'] = $a;
			$this->param['b'] = $b;
			$this->param['c'] = $c;
			$this->param['area'] = $area;
			$this->param['peri'] = $peri;
			$this->param['h'] = $h;
			$this->param['alfa'] = $alfa;
			$this->param['a_deg'] = $a_deg;
			$this->param['beta'] = $beta;
			$this->param['b_deg'] = $b_deg;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
	}

	// Summation Calculator
	function summation($request){
	
		$cal_meth = $_POST['cal_meth'];
		$nums = $_POST['nums'];
		$eq = $_POST['eq'];
		$x = $_POST['x'];
		$n = $_POST['n'];
		if (preg_match("/\<|\>|\&|\+|\-|\(|\)|\{|\}|\[|\]|\||php|print_r|print|echo|sin|cos|tan|arcsin|arccos|arctan|script|=|&|%/i", $nums) || preg_match("/\<|\>|\&|\{|\}|\[|\]|\||php|print_r|print|echo|script|=|&|%/i", $eq) && preg_match("/\<|\>|\&|\+|\(|\)|\{|\}|\[|\]|\||[^o]|php|print_r|print|echo|sin|cos|tan|arcsin|arccos|arctan|script|=|&|%/i", $x) && preg_match("/\<|\>|\&|\+|\-|\(|\)|\{|\}|\[|\]|\||[^o]|php|print_r|print|echo|sin|cos|tan|arcsin|arccos|arctan|script|=|&|%/i", $n)) {
			$this->param['error'] = 'Please! Enter Valid Input.';
			return $this->param;
		}
		if ($cal_meth === 'simple_sum') {
			if (!empty($nums)){
				$nums = str_replace(' ', '', $nums);
				$nums = explode(',', $nums);
				$sum = array_sum($nums);
				$tn = count($nums);
				$this->param['sum'] = $sum;
				$this->param['tn'] = $tn;
				$this->param['RESULT'] = 1;

				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}elseif ($cal_meth === 'sigma_sum') {
			if(!empty($eq) && !empty($x) && !empty($n)) {
				$parem = $eq;
				$parem = str_replace(' ', '', $parem);
				$parem = str_replace('%20', '', $parem);
				$parem = str_replace('+', 'plus', $parem);
				$parem = str_replace('{', '(', $parem);
				$parem = str_replace('}', ')', $parem);
				$parem = str_replace('e^', 'exp', $parem);
				$parem = str_replace('exp^', 'exp', $parem);
				$parem = str_replace('^', '**', $parem);
				$parem = str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
				try{
					$response = Http::timeout(120)->get('http://167.172.134.148/summation', [
						'equ' => $parem,
						'x' => $x,
						'n' => $n,
					]);
					$buffer = $response->body();
					$buffer = explode("@@@", $buffer);
					if ($buffer[0] === 'False') {
						$this->param['cnvrgnt'] = $buffer[0];
						$this->param['enter'] = $buffer[1];
					} else {
						$this->param['cnvrgnt'] = $buffer[0];
						$this->param['enter'] = $buffer[1];
						$this->param['sum'] = $buffer[2];
						$solve = explode("###", $buffer[3]);
						array_pop($solve);
						$this->param['solve'] = $solve;
						$tn = count($solve);
						$this->param['tn'] = $tn;
						$i_n = explode("###", $buffer[4]);
						array_pop($i_n);
						$this->param['i_n'] = $i_n;
					}
					$this->param['RESULT'] = 1;
					return $this->param;
				} catch (\Exception $response) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
			
		}
	}

