	// Parabola Calculator
	function parabola($request){
		$from= $request->from;
		if ($from==='1') {
			$a= $request->a;
			$b= $request->b;
			$c= $request->c;
			if (is_numeric($a) && is_numeric($b) && is_numeric($c)) {
				if ($a==0) {
					$this->param['error'] = 'a can never equal zero for a parabola!';
					return $this->param;
				}
				function gcd($a, $b)
				{
					if ($b == 0)
						return $a;
					return gcd($b, fmod($a , $b));
				}
				$h1=(-1)*$b;
				$h2=2*$a;
				$gcd=gcd($h1,$h2);
				$h1=$h1/$gcd;
				$h2=$h2/$gcd;
				$hf='ni';
				if (fmod($h1,$h2)==0) {
					$hf=$h1/$h2;
				}
				$hf_=$h1/$h2;
				$k1=pow($b,2);
				$k2=4*$a;
				$gcd=gcd($k1,$k2);
				$k1=$k1/$gcd;
				$k2=$k2/$gcd;
				$k1=($c*$k2) - $k1;
				$kf='ni';
				if (fmod($k1,$k2)==0) {
					$kf=$k1/$k2;
				}
				$kf_=$k1/$k2;
				$fu1=(pow($b, 2) - 1);
