	// Lcm Calculator
	function lcm($request){
	
		$x= $request->x;
		$method= $request->method;
		$check=true;
		if (empty($x)) {
			$check=false;
		}
		$numbers=array_map('trim',array_filter(explode(',',$x)));
		foreach ($numbers as $value) {
			$list = explode(".", $value);
			if(count($list) == '2'){
				$this->param['error'] = "Please! Enter numeric values.";
				return $this->param;
			}
			if ($value>100000) {
				$this->param['error'] = "A number can't be greater than 100000.";
				return $this->param;
			}
			if ($value<0) {
				$this->param['error'] = "Please! Enter Only Positive Numbers.";
				return $this->param;
			}
		}
		if (count($numbers)>15) {
			$this->param['error'] = "Please! Enter 15 numbers at most.";
			return $this->param;
		}
		if ($check==true) {
			if ($method=='none') {
				$n=count($numbers);
				function gcd($a12, $b12)
				{
				if ($b12 == 0)
				return $a12;
				return gcd($b12, $a12 % $b12);
				}
				function lcmofn($numbers, $n)
				{
				$ans = $numbers[0];
				for ($i = 1; $i < $n; $i++)
				$ans = ((($numbers[$i] * $ans)) / (gcd($numbers[$i], $ans)));
				return $ans;
				}
				$arr = $numbers;
				$n = sizeof($arr);
				$lcm=lcmofn($arr, $n);
				$this->param['lcm']=$lcm;
				$this->param['RESULT'] = 1;
				return $this->param;	
			}
			if ($method=='lm') {
				$n=count($numbers);
