				{
					if ($b11 == 0)
					return $a11;
					return gcd($b11, $a11 % $b11);
				}
				function lcmofn($numbers, $n)
				{
					$ans = $numbers[0];
					for ($i = 1; $i < $n; $i++)
					$ans = ((($numbers[$i] * $ans)) / (gcd($numbers[$i], $ans)));
					return $ans;
				}
				$arr = $numbers;
				$n = sizeof($arr);
				$lcm=lcmofn($arr, $n);
				$sl='';

				function bruteForce($newNumberList,$lcm,$decimalLength){
					$stepSolution='';
					$numberList='';
					$decimalLength=0;
					function condPlural($word, $count) {
						return $count > 1 ? $word . 's' : $word;
					}
					if($decimalLength>0){
						$stepSolution += '<i> • As not all of your numbers are integers, you first need to shift the decimal ' +
						$decimalLength + condPlural(' place', $decimalLength) + ' to the right. This means we\'$ll $search for $the $LCM $of $the $positive $integers:<br></$i>LCM(' + $newNumberList + 
						'),<i><br> and, at the end, we\'$ll $move $the $decimal $point $of $the $result '+ $decimalLength +
						condPlural(' place', $decimalLength) + ' to the left.</i><br>';
					}
					$lcmLong = $lcm * pow(10,$decimalLength);
					for( $i=0; $i<count($newNumberList); $i++){
						$stepSolution .= '• <b>Multiples of  ' . round($newNumberList[$i],$decimalLength) . ': </b>';
						if(($lcmLong/$newNumberList[$i])+4<100){
							for( $j=1; $j<($lcmLong/$newNumberList[$i])+4; $j++){
								if($newNumberList[$i]*$j==$lcmLong){
									$stepSolution .= '<b>'.round($newNumberList[$i]*$j,$decimalLength) . '</b>, ';
								}else if($j == ($lcmLong/$newNumberList[$i])+3){
									$stepSolution .= round($newNumberList[$i]*$j,$decimalLength) . ' ...';
								}else{
									$stepSolution .= round($newNumberList[$i]*$j,$decimalLength) . ', ';
								}
							} 
						}  else{
							$N_numbers = 10; // must be even
							for( $j=1; $j<$N_numbers; $j++){
								if($j == $N_numbers-1){
									$stepSolution .= round($newNumberList[$i]*$j,$decimalLength) . ', ..., ';
								}else{
									$stepSolution .= round($newNumberList[$i]*$j,$decimalLength) . ', ';
								}	
							} 
							for($j= round(($lcmLong/$newNumberList[$i])/2) - ($N_numbers/2);$j<($lcmLong/$newNumberList[$i])/2 + round($N_numbers/2);$j++){
								if($j == round(($lcmLong/$newNumberList[$i])/2) + ($N_numbers/2 -1)){
									// stepSolution .= '!!' + j + '!!';
									$stepSolution .= round($newNumberList[$i]*$j,$decimalLength) . ', ..., ';
								}
								else
								$stepSolution .= round($newNumberList[$i]*$j,$decimalLength) . ', ';
							}  
							for($j= ($lcmLong/$newNumberList[$i]) - round($N_numbers/2);$j<($lcmLong/$newNumberList[$i]) + round($N_numbers/2);$j++){
								if($newNumberList[$i]*$j==$lcmLong){
									$stepSolution .= '<b>' . round($newNumberList[$i]*$j,$decimalLength) . '</b>, ';
								}
								else if($j == ($lcmLong/$newNumberList[$i])+round($N_numbers/2 -1)) {
									$stepSolution .= round($newNumberList[$i]*$j,$decimalLength) . ' ...';
								}
								else
								$stepSolution .= round($newNumberList[$i]*$j,$decimalLength) . ', ';
							}   
						}
						$stepSolution .= '<br><br>';
					}
					if($decimalLength>0){
						$stepSolution .= 'Thus, <br><br><b>LCM(' . $numberList . ') = ' . $lcm . '</b>';
					}
					return $stepSolution;
				}
				$sl = bruteForce($numbers,$lcm,0);
