	// Synthetic Division Calculator
	function synthetic($request){
		$dividend = $request->dividend;
		$divisor = $request->divisor;
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|sin|cos|tan|arcsin|arccos|arctan|&|%/i", $dividend) || preg_match("/\<|\>|\&|php|print_r|print|echo|script|sin|cos|tan|arcsin|arccos|arctan|&|%/i", $divisor)) {
			$this->param['error'] = "Please Enter Valid Input.";
			return $this->param;
		}
		// $pattern = '/^\s*(-?\d+(\.\d+)?|)([a-zA-Z])\s*([\+\-])\s*(-?\d+(\.\d+)?)\s*$/';
		$pattern = '/^\s*(\(?\s*-?\d+(\.\d+)?\s*\)?|)\s*\(?([a-zA-Z])\)?\s*([\+\-])\s*\(?-?\d+(\.\d+)?\)?\s*$/';
		if (preg_match($pattern, $divisor, $matches)) {
			if (strpos($dividend, $matches[3]) === false) {
				$this->param['error'] = 'Variable '.$matches[3].' does not exist in the function';
				return $this->param;
			}
			preg_match_all('/[a-zA-Z]/', $dividend, $matches2);
			$variableCount = count(array_unique($matches2[0]));
			if ($variableCount > 1) {
				$this->param['error'] = 'Dividend contains more than one variable';
				return $this->param;
			}
			if (!empty($dividend) && !empty($divisor)) {
				$parem = $dividend;
				$parem = str_replace(' ', '', $parem);
				$parem = str_replace('%20', '', $parem);
				$parem = str_replace('+', 'plus', $parem);
				$parem = str_replace('{', '(', $parem);
				$parem = str_replace('}', ')', $parem);
				$parem = str_replace('e^', 'exp', $parem);
				$parem = str_replace('exp^', 'exp', $parem);
				$parem = str_replace('^', '**', $parem);
				$parem = str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
				$parem1 = $divisor;
				$parem1 = str_replace(' ', '', $parem1);
