					$this->param['error'] = "Side length (b) must be longer than the difference between the longer diagonal (" . $log . ") and the shorter diagonal (" . $sam . ") divided by 2 plus (p). Side length (b) must be less than" . $c2 . "or a diagonal must be longer. [b > absolute value of (q-p)/2].";
					return $this->param;
				} elseif ($rad > $c1) {
					$this->param['error'] = "Side length (b) must be shorter than the difference between the longer diagonal (" . $log . ") and the shorter diagonal (" . $sam . ") divided by 2 plus (p). Side length (b) must be less than" . $c1 . "or b diagonal must be longer. [b > absolute value of (q-p)/2].";
					return $this->param;
				} else {
					$a = ((($side1 * $side1) + ($side2 * $side2) - 2 * ($rad * $rad)) / (2));
					$sq = sqrt($a);
					$an = rad2deg(acos(((($side2 * $side2) - ($sq * $sq) - ($rad * $rad)) / ((2 * $sq * $rad)))));
					$b_angle = 180 - $an;
					$h = ($sq * sin(deg2rad($an)));
					$P = (2 * $sq) + (2 * $rad);
					$k = ($sq * $rad * sin(deg2rad($an)));
					$this->param['a'] = $a;
					$this->param['sq'] = $sq;
					$this->param['an'] = $an;
					$this->param['b_angle'] = $b_angle;
					$this->param['h'] = $h;
					$this->param['P'] = $P;
					$this->param['k'] = $k;
					$this->param['RESULT'] = 1;
					return $this->param;
				}
			} else {
				$this->param['error'] = "Please Enter Positive Numbers.";
				return $this->param;
			}
		}
	}

	// Improper Fractions to Mixed Numbers Calculator
	function improper_frac($request){
		$uper= $request->uper;
		$btm= $request->btm;
  		if (is_numeric($uper) && is_numeric($btm)) {
  			if ($uper>=$btm) {
  				$rem=$uper%$btm;
  				$q=floor($uper / $btm);
  				$this->param['q'] = $q;
  				$this->param['rem'] = $rem;
  				$this->param['RESULT'] = 1;
				return $this->param;
  			}else{
  				$this->param['RESULT'] = 1;
				return $this->param;
  			}
  		}else{
			$this->param['error'] = "Please Check Your Input.";
			return $this->param;
		}
	}

	// Fraction Simplifier Calculator
	function simplify($request){
	
		if (is_numeric($request->n2) && is_numeric($request->d1)) {
			$totalN=$request->n2;
			$totalD=$request->d1;
			if (is_numeric($request->n1)) {
				$val1=$request->n1;
				if($val1<0 && $totalN>0){
					$totalN = $totalN * (-1);
				}
				$totalN=($totalD * $val1) + $totalN;
			}
			function gcd($a13,$b13) 
			{
				$a13 = abs($a13); $b13 = abs($b13);

				if( $a13 < $b13)
				{ 
					list($b13,$a13) = Array($a13,$b13);
				}
				if( $b13 == 0){
					return 1;
				}
				$r = $a13 % $b13;
				while($r > 0): 
					$a13 = $b13;
					$b13 = $r;
					$r = $a13 % $b13;
				endwhile;
				return $b13;
		
			}

			function reduce($num,$den) 
			{
				$g = gcd($num,$den);
				return array($num/$g,$den/$g);
			}
			$g = gcd($totalN,$totalD);
			list ($upr  , $btm) = reduce($totalN,$totalD);
			$this->param['upr'] =$upr;
			$this->param['totalN'] =$totalN;
			$this->param['totalD'] =$totalD;
			$this->param['g'] =$g;
			$this->param['btm'] =$btm;
			$this->param['RESULT'] = 1;

			return $this->param;
		}else{
			$this->param['error'] = "Please Check Your Input.";
			return $this->param;
		}
	}

	// FOIL Calculator
	function foil($request){
		$exp = $request->exp;
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|sin|cos|tan|arcsin|arccos|arctan|&|%/i", $exp)) {
			$this->param['error'] = "Please Enter Valid Input.";
			return $this->param;
		}
		if (!empty($exp)) {
			$parem = $exp;
			$parem = str_replace(' ', '', $parem);
			$parem = str_replace('%20', '', $parem);
			$parem = str_replace('plus', '+', $parem);
			$parem = str_replace('{', '(', $parem);
			$parem = str_replace('}', ')', $parem);
			$parem = str_replace('e^', 'exp', $parem);
			$parem = str_replace('exp^', 'exp', $parem);
			$parem = str_replace('^', '**', $parem);
			$parem = str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			if (preg_match('/\*\*2|\*\*3/', $parem)) {
				$s1 = explode('**', $parem);
				$s2 = explode('+', $s1[0]);
				$s2_ = explode('-', $s1[0]);
				if (count($s2) === 2) {
					$opr = '+';
					$s3 = explode('(', $s2[0]);
					$s4 = explode(')', $s2[1]);
				} elseif (count($s2_) === 2) {
					$opr = '-';
					$s3 = explode('(', $s2_[0]);
					$s4 = explode(')', $s2_[1]);
				}
				$a = $opr . $s3[1];
				$b = $opr . $s4[0];
				$expnt = $s1[1];
				$eq = $s1[0];
				try{
					$par = str_replace('+',
						'plus',
						$parem
					);
					$response = Http::timeout(120)->get('http://167.172.134.148/foil', [
						'equ' => $par,
						'a' => $a,
						'opr' => $opr,
						'b' => $b,
						'exp' => $expnt,
						'eq' => $eq,
					]);
					$buffer = $response->body();
					$buffer = explode("@@@", $buffer);
					$this->param['eq'] = $buffer[0];
					$this->param['ans'] = $buffer[1];
					$this->param['a'] = $buffer[2];
					$this->param['b'] = $buffer[3];
					$this->param['s1'] = $buffer[4];
					$this->param['s2'] = $buffer[5];
					$this->param['s3'] = $buffer[6];
					$this->param['s4'] = $buffer[7];
					$this->param['equ'] = $buffer[8];
					$this->param['opr'] = $buffer[9];
					$this->param['exp'] = $buffer[10];
					$this->param['RESULT'] = 1;
					return $this->param;
				} catch (\Exception $response) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			} else {
				$s1 = explode(')(', $parem);
				if (count($s1) > 2) {
					$this->param['error'] = "Please Check Your Input.";
					return $this->param;
				}
				$s2 = explode('(', $s1[0]);
				$s3 = explode(')', $s1[1]);
				$s4 = explode('+', $s2[1]);
				$s4_ = explode('-', $s2[1]);
				$s5 = explode('+', $s3[0]);
				$s5_ = explode('-', $s3[0]);
				if (count($s4) === 2) {
					$opr = 'plus';
					$a = $s4[0];
					$b = $opr . $s4[1];
				} elseif (count($s4_) === 2) {
					$opr = '-';
					$a = $s4_[0];
					$b = $opr . $s4_[1];
				} elseif (count($s4_) === 3) {
					$opr = '-';
					$a = $opr . $s4_[1];
					$b = $opr . $s4_[2];
				}
				if (count($s5) === 2) {
					$opr1 = 'plus';
					$c = $s5[0];
					$d = $opr1 . $s5[1];
				} elseif (count($s5_) === 2) {
					$opr1 = '-';
					$c = $s5_[0];
					$d = $opr1 . $s5_[1];
				} elseif (count($s5_) === 3) {
					$opr1 = '-';
					$c = $opr1 . $s5_[1];
					$d = $opr1 . $s5_[2];
				}
				try{
					$par = str_replace('+',
						'plus',
						$parem
					);
					$response = Http::timeout(120)->get('http://167.172.134.148/foil', [
						'equ' => $par,
						'a' => $a,
						'opr' => $opr,
						'b' => $b,
						'c' => $c,
						'opr1' => $opr1,
						'd' => $d,
					]);
					$buffer = $response->body();
					$buffer = explode("@@@", $buffer);
					$this->param['eq'] = $buffer[0];
					$this->param['ans'] = $buffer[1];
					$this->param['a'] = $buffer[2];
					$this->param['b'] = $buffer[3];
					$this->param['c'] = $buffer[4];
					$this->param['d'] = $buffer[5];
					$this->param['s1'] = $buffer[6];
					$this->param['s2'] = $buffer[7];
					$this->param['s3'] = $buffer[8];
					$this->param['s4'] = $buffer[9];
					$this->param['opr'] = $buffer[10];
					$this->param['opr1'] = $buffer[11];
					$this->param['check'] = $buffer[12];
					$this->param['RESULT'] = 1;
					return $this->param;
				} catch (\Exception $response) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			}
		} else {
			$this->param['error'] = "Please Check Your Input.";
			return $this->param;
		}
	}

	// Mixed Numbers to Improper Fractions Calculator
	function mixed_frac($request){
		$whole= $request->whole;
		$uper= $request->uper;
		$btm= $request->btm;
  		if (is_numeric($uper) && !empty($btm) && is_numeric($whole)) {
  			$multi=$btm*$whole;
  			$plus=$multi+$uper;
			$this->param['multi'] = $multi;
			$this->param['plus'] = $plus;
			$this->param['RESULT'] = 1;

			return $this->param;
  		}else{
			$this->param['error'] = "Please Check Your Input.";
			return $this->param;
		}	
	}
// Inverse Function Calculator
	function inverse($request){
		$equ= $request->equ;
		$validator = Validator::make($request->all(), [
			'equ' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $equ)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		$check=explode('sqrt', $equ);
		if (count($check)===1) {
			if (preg_match("/[a-df-wA-DF-W]|y|z|%/i", $equ)) {
				$this->param['error'] = 'Equestion unacceptable variables.';
				return $this->param;
			}
		}
		$main=str_replace('x', 'y', $equ);
		$main=str_replace(' ', '', $main);
		$main=str_replace('+', 'plus', $main);
		$main=str_replace('%20', '', $main);
		$main=str_replace('{', '(', $main);
		$main=str_replace('}', ')', $main);
		$main=str_replace('e^', 'exp', $main);
		$main=str_replace('exp^', 'exp', $main);
		$main=str_replace('^', '**', $main);
		$main=str_replace('e^sqrt(y)', 'exp(2*y)', $main);

		$equ=str_replace(' ', '', $equ);
		$equ=str_replace('+', 'plus', $equ);
		$equ=str_replace('%20', '', $equ);
		$equ=str_replace('{', '(', $equ);
		$equ=str_replace('}', ')', $equ);
		$equ=str_replace('e^', 'exp', $equ);
		$equ=str_replace('exp^', 'exp', $equ);
		$equ=str_replace('^', '**', $equ);
		$equ=str_replace('e^sqrt(y)', 'exp(2*y)', $equ);

		$main2=$main;
		$main=$main.'-x';
		try{
			$client = new Client();
			$response = $client->post("http://167.172.134.148/new-inv_fun", [
				'form_params' => [
					'equ'=>$equ,
					'main2'=>$main2,
					'main'=>$main,
				],
				'timeout' => 120,
			]);
			$buffer = $response->getBody();
			$buffer = json_decode($buffer, true);
			$res=str_replace('\left[', '', $buffer[2]);
			$res=str_replace('\right]', '', $res);
			$this->param['enter'] = $buffer[0];
			$this->param['enter2'] = $buffer[1];
			$this->param['res'] = $res;
			$this->param['RESULT'] = 1;
			return $this->param;
		} catch (\Exception $response) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	
