	// Polar Coordinates Calculator
	function polar($request){

		$x= $request->x1;
		$y= $request->x2;
		$chose= $request->chose;
		if (!empty($x) && !empty($y)){
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/polar', [
					'x' => $x,
					'y' => $y,
				]);
				$buffer = $response->body();
				$buffer = explode("@@@", $buffer);
				$atn=$buffer[0]/$buffer[4];
                $one=atan($atn);
                $two= $one+pi();
                $x1=$buffer[4]*cos($buffer[0]);
                $y1=$buffer[4]*sin($buffer[0]);
				$this->param['mag'] = $buffer[1];
				$this->param['ex'] = $buffer[2];
				$this->param['ey'] = $buffer[3];
				$this->param['one'] = $one;
				$this->param['x1'] = $x1;
				$this->param['y1'] = $y1;
				$this->param['chose'] = $chose;
				$this->param['x'] = $buffer[4];
				$this->param['y'] = $buffer[0];
				$this->param['two'] = $two;
				$this->param['RESULT'] = 1;
				return $this->param;
			}catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = "Please Check Your Input.";
			return $this->param;
		}
	}

	// Average Rate of Change Calculator
	function arocc($request){
		$x = $request->x;
		$x1 = $request->x1;
		$x2 = $request->x2;
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|sin|cos|tan|arcsin|arccos|arctan|&|%/i", $x)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (is_numeric($x1) && is_numeric($x2) && !empty($x)) {
			$parem = $x;
			$parem = str_replace(' ',
				'',
				$parem
			);
			$parem = str_replace('+', 'plus', $parem);
			$parem = str_replace('%20', '', $parem);
			$parem = str_replace('{', '(', $parem);
			$parem = str_replace('}', ')', $parem);
			$parem = str_replace('e^', 'exp', $parem);
			$parem = str_replace('exp^', 'exp', $parem);
			$parem = str_replace('^', '**', $parem);
			$parem = str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			try{
				$client = new Client();
				$response = $client->post("http://167.172.134.148/new-arocc", [
					'form_params' => [
						'equ' => $parem,
						'x1' => $x1,
						'x2' => $x2,
					],
					'timeout' => 120,
				]);
				$buffer = $response->getBody();
				$buffer = json_decode($buffer, true);
				$this->param['eq'] = $buffer[0];
				$this->param['fx1'] = round($buffer[1], 2);
				$this->param['fx2'] = round($buffer[2], 2);
				$this->param['ans'] = round($buffer[3], 3);
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Composite Function Calculator
	function composite($request){
		$one=$request->one;
		$two=$request->two;
		$point=$request->point;
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $one)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $two)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (is_numeric($point) && !empty($one) && !empty($two)) {
			$one_=str_replace('x', '(x)', $one);
			$one_=str_replace('x', $two, $one_);
			$parem=$one_;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('%20', '', $parem);
			$parem=str_replace('{', '(', $parem);
