	// Cosine Calculator
	function cosine($request){
		$angle= $request->angle;
		$angle_unit= $request->angle_unit;
		if(!empty($angle)){
			if($angle_unit==='deg'){
				$cos=cos(deg2rad($angle));
			}elseif($angle_unit==='pirad'){
				$angle=$angle*pi();
				$cos=cos($angle);
			}elseif($angle_unit==='mrad'){
				$angle=$angle/1000;
				$cos=cos($angle);
			}else{
				$cos=cos($angle);
			}
			$this->param['cos']=round($cos,8);
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

