			}else{
				$div='1';
				$count=strlen($nbr[1]);
				for ($i=1; $i <= $count ; $i++) { 
					$div.='0';
				}
				$upr=$nbr[0].$nbr[1];
				/****
				** Reduce value
				****/
				function gcd($a16,$b16) 
				{
					$a16 = abs($a16); $b16 = abs($b16);

					if( $a16 < $b16)
