		// Fraction To Decimal Calculator
	function frac_to_dec($request){
		if (is_numeric($request->n2) && is_numeric($request->d1)) {
			$totalN=$request->n2;
			$totalD=$request->d1;
			if (is_numeric($request->n1)) {
				$val1=$request->n1;
				if($val1<0 && $totalN>0){
					$totalN = $totalN * (-1);
				}
				$totalN=($totalD * $val1) + $totalN;
			}
			/****
			** Reduce value
			****/
			function gcd($a17,$b17) 
			{
				$a17 = abs($a17); $b17 = abs($b17);

				if( $a17 < $b17)
				{ 
					list($b17,$a17) = Array($a17,$b17);
				}
				if( $b17 == 0){
					return 1;
				}
				$r = $a17 % $b17;
				while($r > 0): 
					$a17 = $b17;
					$b17 = $r;
					$r = $a17 % $b17;
				endwhile;
				return $b17;
		
			}

			function reduce($num,$den) 
			{
				$g = gcd($num,$den);
				return array($num/$g,$den/$g);
			}
			$ans=round($totalN/$totalD,$request->round);
			$g = gcd($totalN,$totalD);
			list ($upr  , $btm) = reduce($totalN,$totalD);
			// return Values
			$this->param['ans'] =$ans;
			$this->param['upr'] =$upr;
			$this->param['totalN'] =$totalN;
			$this->param['totalD'] =$totalD;
			$this->param['g'] =$g;
			$this->param['btm'] =$btm;
			$this->param['RESULT'] =1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

