	function proportion($request){
		$a= $request->a;
		$b= $request->b;
		$c= $request->c;
		$d= $request->d;
		if(!empty($a) && !empty($b) && !empty($c) && !empty($d)){
			if(is_numeric($a) && is_numeric($b) && is_numeric($c) && is_numeric($d)){
				$this->param['error'] = 'Please! Enter the 3 numbers & use any letter for 1 unknown variable.';
				return $this->param;
			}elseif(ctype_alpha($a) && is_numeric($b) && is_numeric($c) && is_numeric($d)){
				$a_val=($b*$c)/$d;
				$this->param['a_val']=$a_val;
			}elseif(is_numeric($a) && ctype_alpha($b) && is_numeric($c) && is_numeric($d)){
				$b_val=($a*$d)/$c;
				$this->param['b_val']=$b_val;
			}elseif(is_numeric($a) && is_numeric($b) && ctype_alpha($c) && is_numeric($d)){
				$c_val=($a*$d)/$b;
				$this->param['c_val']=$c_val;
			}elseif(is_numeric($a) && is_numeric($b) && is_numeric($c) && ctype_alpha($d)){
				$d_val=($b*$c)/$a;
				$this->param['d_val']=$d_val;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
