		}
	}

	// Parallel and Perpendicular line calculator
	function parallel($request){
		function new_gcd_($a18,$b18) 
		{
			$a18 = abs($a18); $b18 = abs($b18);

			if( $a18 < $b18)
			{ 
				list($b18,$a18) = Array($a18,$b18);
			}
			if( $b18 == 0){
				return 1;
			}
			$r = $a18 % $b18;
			while($r > 0): 
				$a18 = $b18;
				$b18 = $r;
				$r = $a18 % $b18;
			endwhile;
			return $b18;
	
		}
		function new_reduce($num,$den) 
		{
			$g = new_gcd_($num,$den);
			return array($num/$g,$den/$g);
		}
		$a= $request->a;
		$b= $request->b;
		$c= $request->c;
		$form= $request->form;
		$method= $request->method;
		$p1= $request->p1;
		$p2= $request->p2;
		if (is_numeric($a) && is_numeric($b) && is_numeric($p1) && is_numeric($p2)) {
			if ($form==='1') {
				if(is_numeric($c)) {
					if ($method==='2') {
						$y=$b;
						list ($upr , $btm) = new_reduce($a,$y);
						if ($btm<0) {
							$btm=abs($btm);
							$upr=$upr*(-1);
						}
						$btm_=$upr;
						$upr=$btm;
						$upr_=$btm;
						$btm=$btm_;
						$this->param['upr_'] = $btm_;
						$this->param['btm_'] = $upr_;
					} else {
						$y=$b*(-1);
						list ($upr , $btm) = new_reduce($a,$y);
						if ($btm<0) {
							$btm=abs($btm);
							$upr=$upr*(-1);
						}
					}
					$y=$b*(-1);
					list ($upr1 , $btm1) = new_reduce($c,$y);
					if ($btm1<0) {
						$btm1=abs($btm1);
						$upr1=$upr1*(-1);
					}
					$au=($upr*$p1)*(-1);
					$ab=$btm*$p2;
					$au=$ab + $au;
					list ($upr2 , $btm2) = new_reduce($au,$btm);
					if ($btm2<0) {
						$btm2=abs($btm2);
						$upr2=$upr2*(-1);
					}
					// echo "$upr2 / $btm2";die;
					$this->param['upr'] = $upr;
					$this->param['btm'] = $btm;
					$this->param['upr1'] = $upr1;
					$this->param['btm1'] = $btm1;
					$this->param['upr2'] = $upr2;
					$this->param['btm2'] = $btm2;
					$this->param['form'] = $form;
					$this->param['method'] = $method;
					$this->param['a'] = $a;
					$this->param['b'] = $b;
					$this->param['c'] = $c;
					$this->param['p1'] = $p1;
					$this->param['p2'] = $p2;
					$this->param['RESULT'] = 1;

					return $this->param;
				} else {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			} else {
				if ($method==='1') {
					$au=($a*$p1)*(-1);
					$au=$au+$p2;
					$this->param['au'] = $au;
					$this->param['method'] = $method;
					$this->param['form'] = $form;
					$this->param['a'] = $a;
					$this->param['b'] = $b;
					$this->param['p1'] = $p1;
					$this->param['p2'] = $p2;
					$this->param['RESULT'] = 1;

					return $this->param;
				} else {
					if ($a<0) {
						$au=abs($a);
						$upr=1;
					}else{
						$upr=-1;
						$au=$a;
					}
					$au1=($upr*$p1)*(-1);
					$ab=$au*$p2;
					$au1=$ab + $au1;
					list ($upr2 , $btm2) = new_reduce($au1,$au);
					if ($btm2<0) {
						$btm2=abs($btm2);
						$upr2=$upr2*(-1);
					}
					$this->param['upr'] = $upr;
					$this->param['au'] = $au;
					$this->param['form'] = $form;
					$this->param['method'] = $method;
					$this->param['upr2'] = $upr2;
					$this->param['btm2'] = $btm2;
