					$this->param['b'] = $b;
					$this->param['p1'] = $p1;
					$this->param['p2'] = $p2;
					$this->param['RESULT'] = 1;
					return $this->param;
				}
			}
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		
	}

	// Polynomial Long Division Calculator
	function polynomial($request){
		$dividend = trim($_POST['dividend']);
		$divisor = trim($_POST['divisor']);
		$validator = Validator::make($request->all(), [
			'dividend' => 'required|regex:/^[^<>&]*$/i',
			'divisor' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|sin|cos|tan|arcsin|arccos|arctan|&|%/i", $dividend) || preg_match("/\<|\>|\&|php|print_r|print|echo|script|sin|cos|tan|arcsin|arccos|arctan|&|%/i", $divisor)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (!empty($dividend) && !empty($divisor)) {
			$parem = $dividend;
			$parem = str_replace(' ', '', $parem);
			$parem = str_replace('%20', '', $parem);
			$parem = str_replace('+', 'plus', $parem);
			$parem = str_replace('{', '(', $parem);
			$parem = str_replace('}', ')', $parem);
			$parem = str_replace('e^', 'exp', $parem);
			$parem = str_replace('exp^', 'exp', $parem);
			$parem = str_replace('^', '**', $parem);
			$parem = str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			$parem1 = $divisor;
			$parem1 = str_replace(' ', '', $parem1);
			$parem1 = str_replace('%20', '', $parem1);
			$parem1 = str_replace('+', 'plus', $parem1);
			$parem1 = str_replace('{', '(', $parem1);
			$parem1 = str_replace('}', ')', $parem1);
			$parem1 = str_replace('e^', 'exp', $parem1);
			$parem1 = str_replace('exp^', 'exp', $parem1);
			$parem1 = str_replace('^', '**', $parem1);
			$parem1 = str_replace('e^sqrt(x)', 'exp(2*x)', $parem1);
			if (preg_match("/x/i", $divisor) && preg_match("/y/i", $dividend) || preg_match("/y/i", $divisor) && preg_match("/x/i", $dividend)) {
				$this->param['error'] = 'The divisor and dividend have different variables.';
				return $this->param;
			}
			if (preg_match("/x/i", $divisor) && preg_match("/y/i", $divisor)
			) {
				$check = "xy";
			} elseif (preg_match("/x/i", $divisor) && !preg_match("/y/i", $divisor)) {
				$check = "x";
			} elseif (preg_match("/y/i", $divisor) && !preg_match("/x/i", $divisor)) {
				$check = "y";
			} else {
				$check = "";
			}
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/polynomial', [
					'eq' => $parem,
					'eq1' => $parem1,
					'check' => $check,
				]);
				$buffer = $response->body();
				$buffer = explode("@@@", $buffer);
				$this->param['check'] = $check;
				$this->param['eq'] = $buffer[0];
				$this->param['eq1'] = $buffer[1];
				$this->param['quot'] = $buffer[2];
				$this->param['rmnd'] = $buffer[3];
				if ($check !== "xy") {
					$quotient = $buffer[4];
					$quotient = explode('###', $quotient);
					array_pop($quotient);
					$multiplies = $buffer[5];
					$multiplies = explode('###', $multiplies);
					array_pop($multiplies);
					$steps = $buffer[6];
					$steps = explode('###', $steps);
					array_pop($steps);
					$divCoeff = $buffer[7];
					$divCoeff = explode('###', $divCoeff);
					array_pop($divCoeff);
					$leading_term = $buffer[9];
					$leading_term = explode('###', $leading_term);
					array_pop($leading_term);
					$this->param['quotient'] = $quotient;
					$this->param['multiplies'] = $multiplies;
					$this->param['steps'] = $steps;
					$this->param['divCoeff'] = $divCoeff;
					$this->param['loop_len'] = $buffer[8];
					$this->param['leading_term'] = $leading_term;
					$this->param['divby_lt'] = $buffer[10];
				}
				$this->param['RESULT'] = 1;
				return $this->param;
			}catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

