	//Binary Calculator
	function binary($request){
		$bnr_tpe1= $request->bnr_tpe1;
		$bnr_tpe2= $request->bnr_tpe2;
		$bnr_frs= $request->bnr_frs;
		$bnr_sec= $request->bnr_sec;
		$bnr_slc= $request->bnr_slc;
		$check = true;
		if ($check === true) {
			function bnrType($nn,$bnr_tpe) {
				if ($bnr_tpe === "binary") { //Binary
					$n = base_convert($nn, 2, 10);
				} elseif ($bnr_tpe === "decimal") { //Decimal
					$n = $nn;
				} elseif ($bnr_tpe === "hexadecimal") { //Hexadecimal
					$n = base_convert($nn, 16, 10);
				} elseif ($bnr_tpe === "octal") { //Octal
					$n = base_convert($nn, 8, 10);
				}
				return $n;
			}

			$fN = bnrType($bnr_frs,$bnr_tpe1);
			$sN = bnrType($bnr_sec,$bnr_tpe2);

			function bnrCal($fN,$sN,$bnr_slc) {
				if ($bnr_slc === "add") { //Add
					$rN = $fN + $sN;
					$dc = $rN;
					$bn = base_convert(abs($dc), 10, 2);
					$hx = strtoupper(base_convert(abs($dc), 10, 16));
					$oc = base_convert(abs($dc), 10, 8);
				} elseif ($bnr_slc === "sub") { //Subtract
					$rN = $fN - $sN;
					$dc = $rN;
					if($dc < 0) {
						$bn = "-" . base_convert(abs($dc), 10, 2);
						$hx = "-" . strtoupper(base_convert(abs($dc), 10, 16));
						$oc = "-" . base_convert(abs($dc), 10, 8);
					} else {
						$bn = base_convert(abs($dc), 10, 2);
						$hx = strtoupper(base_convert(abs($dc), 10, 16));
						$oc = base_convert(abs($dc), 10, 8);
					}
				} elseif ($bnr_slc === "mult") { //Multiply
					$rN = $fN * $sN;
					$dc = $rN;
					$bn = base_convert(abs($dc), 10, 2);
					$hx = strtoupper(base_convert(abs($dc), 10, 16));
					$oc = base_convert(abs($dc), 10, 8);
				} elseif ($bnr_slc === "divd") { //Divide
					$rN = $fN / $sN;
					$dc = round($rN);
					$bn = base_convert(abs($dc), 10, 2);
					$hx = strtoupper(base_convert(abs($dc), 10, 16));
					$oc = base_convert(abs($dc), 10, 8);
				}
				return array($bn, $dc, $hx, $oc);
			}

			$this->param["bn"] = bnrCal($fN,$sN,$bnr_slc)[0];
			$this->param["dc"] = bnrCal($fN,$sN,$bnr_slc)[1];
			$this->param["hx"] = bnrCal($fN,$sN,$bnr_slc)[2];
			$this->param["oc"] = bnrCal($fN,$sN,$bnr_slc)[3];
			$this->param["RESULT"] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}

	}

		// X and Y Intercepts Calculator
		function intercepts($request){
			$EnterEq=$request->EnterEq;
			if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|&|%/i",$EnterEq)) {
				$this->param['error'] = 'Please Enter Valid Input.';
				return $this->param;
			}
			if (!empty($EnterEq)) {
				$parem=$EnterEq;
				$parem=str_replace(' ', '', $parem);
				$parem=str_replace('+', 'plus', $parem);
				$parem=str_replace('{', '(', $parem);
				$parem=str_replace('}', ')', $parem);
				$parem=str_replace('e^', 'exp', $parem);
				$parem=str_replace('exp^', 'exp', $parem);
				$parem=str_replace('^', '**', $parem);
				$parem=str_replace('log', 'ln', $parem);
				$parem=str_replace('=', '-', $parem);
				$parem=str_replace('sin', 'sin', $parem);
				$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
				try{
					$client = new Client();
					$response = $client->post("http://167.172.134.148/intercepts", [
						'form_params' => [
							'equ'=>$parem,
						],
						'timeout' => 120,
					]);
					$buffer =  $response->getBody();
					$buffer = json_decode($buffer,true);
					/*echo"<pre>";
					print_r($buffer);
					die;*/
					  $equation=$buffer[0];
					$morgan=explode(",",$buffer[1]);
					$c=count($morgan);
					for ($i=0; $i <$c ; $i++) { 
						if($morgan[$i]=='\left[ \right]'){
							$morgan[$i]="0";	
						}
						$final_ans[]=$morgan[$i].",0";
					}
					$res=str_replace('\left[', '', $final_ans);
					$res=str_replace('\right]', '', $res);
					$buffer2=str_replace('\left[', '', $buffer[2]);
					$buffer2=str_replace('\right]', '', $buffer2);
					$this->param['equation'] =$equation;
					$this->param['buffer_zero'] =$res;
					$this->param['c']=$c;
					if($buffer['3']=="C"){
						if($buffer[2]=='\left[ \right]'){
						$buffer[2]="0,0";
						$buffer2=$buffer[2];
						}else{
							$buffer[2]="0,".$buffer[2];
							$buffer2=$buffer[2];
						}
					}
					$buffer2=str_replace('\left[', '', $buffer[2]);
					$buffer2=str_replace('\right]', '', $buffer2);
					$this->param['buffer_one'] = $buffer2;
					$this->param['method']=$buffer['3'];
					$this->param['RESULT'] = 1;
					return $this->param;
				} catch (\Exception $response) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please Check Your Input.';
				return $this->param;
			}
		}

