	// Average Value Of Function
	function avg_fun($request){
		$fun= $request->fun;
		$lb= $request->lb;
		$ub= $request->ub;
		if (!empty($fun) && is_numeric($lb) && is_numeric($ub)) {
			$vari = 0;
			$fun = str_replace(' ','',$fun);
			$fun = str_replace('%20','',$fun);
			$fun = str_replace('plus','+',$fun);
			$value = $fun;
			if (preg_match('/x/i', $value)) {$vari++;$with='x';}
			if (preg_match('/a/i', $value)) {$vari++;$with='a';}
			if (preg_match('/b/i', $value)) {$vari++;$with='b';}
			if (preg_match('/c/i', $value)) {$vari++;$with='c';}
			if (preg_match('/d/i', $value)) {$vari++;$with='d';}
			if (preg_match('/f/i', $value)) {$vari++;$with='f';}
			if (preg_match('/g/i', $value)) {$vari++;$with='g';}
			if (preg_match('/h/i', $value)) {$vari++;$with='h';}
			if (preg_match('/i/i', $value)) {$vari++;$with='i';}
			if (preg_match('/j/i', $value)) {$vari++;$with='j';}
			if (preg_match('/k/i', $value)) {$vari++;$with='k';}
			if (preg_match('/l/i', $value)) {$vari++;$with='l';}
			if (preg_match('/m/i', $value)) {$vari++;$with='m';}
			if (preg_match('/n/i', $value)) {$vari++;$with='n';}
			if (preg_match('/o/i', $value)) {$vari++;$with='o';}
			if (preg_match('/p/i', $value)) {$vari++;$with='p';}
			if (preg_match('/q/i', $value)) {$vari++;$with='q';}
			if (preg_match('/r/i', $value)) {$vari++;$with='r';}
			if (preg_match('/s/i', $value)) {$vari++;$with='s';}
			if (preg_match('/t/i', $value)) {$vari++;$with='t';}
			if (preg_match('/u/i', $value)) {$vari++;$with='u';}
			if (preg_match('/v/i', $value)) {$vari++;$with='v';}
			if (preg_match('/w/i', $value)) {$vari++;$with='w';}
			if (preg_match('/y/i', $value)) {$vari++;$with='y';}
			if (preg_match('/z/i', $value)) {$vari++;$with='z';}
			if ($vari==1) {
				if ($lb>$ub) {
					$this->param['error'] = 'Upper Limit must be greater than Lower Limit.';
					return $this->param;
				}
				$divide = ($ub - $lb);
				$parem=$fun;
				$parem=str_replace(' ', '', $parem);
				$parem=str_replace('+', 'plus', $parem);
				$parem=str_replace('{', '(', $parem);
				$parem=str_replace('}', ')', $parem);
				$parem=str_replace('e^', 'exp', $parem);
				$parem=str_replace('exp^', 'exp', $parem);
				$parem=str_replace('^', '**', $parem);
				$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
				// echo $parem;die();
				$parem1=trim($with);
				try{
					$client = new Client();
					$r = $client->post("http://167.172.134.148/avg_fun", [
						'form_params' => [
							'equ'=>$parem,
							'wrt'=>$parem1,
							'ub'=>$ub,
							'lb'=>$lb,
							'divide'=>$divide,
						],
						'timeout' => 120,
					]);
					$buffer =  $r->getBody();
	                $buffer = json_decode($buffer,true);
					$this->param['input'] = $buffer[0];
					$this->param['sim'] = $buffer[1];
					$this->param['ans'] = $buffer[2];
					$this->param['with'] = $with;
					$this->param['divide'] = $divide;
					$this->param['RESULT'] = 1;
					return $this->param;
				} catch (\Exception $r) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'The function contains more than one variable.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please Check Your Input!';
			return $this->param;
		}
	}

    // Product Sum Calculator
    function pro_sum($request){
		$product = $request->product;
		$sum = $request->sum;
        if (is_numeric($product) && is_numeric($sum)) {
            $A = 1;
            $B = -1 * $sum;
            $C = $product;
            $dis = pow($B, 2) - (4*$A*$C);
            if ($dis>0) {   
                $x1= round((($B * (-1)) + sqrt($dis)) / (2*$A),4);
                $x2= round((($B * (-1)) - sqrt($dis)) / (2*$A),4);
                $this->param['fact'] = $A."(x ".(($x1<0)?"+ ".($x1*(-1)):"- ".$x1)." )"."(x ".(($x2<0)?"+ ".($x2*(-1)):"- ".$x2)." )";
                $this->param['roots'] = 'x₁ = '.$x1.' , x₂ = '.$x2;
            }
            if ($dis<0) {
                $x1= round(($B * (-1))/(2*$A),4).' + '.round(sqrt(($dis * (-1))) / (2*$A),4);
                $x2= round(($B * (-1))/(2*$A),4).' - '.round(sqrt(($dis * (-1))) / (2*$A),4);
                $this->param['fact'] = $A."(x - (".$x1."\,i) )"."(x - (".($x2)."\,i) )";
                $this->param['roots'] = 'x₁ = '.$x1.' <i>i</i><br> x₂ = '.$x2.' <i>i</i>';
            }
            if ($dis==0) {
                $x1= round(($B * (-1)) /(2*$A),4);
                $this->param['fact'] = $A."(x ".(($x1<0)?"+ ".($x1*(-1)):"- ".($x1 * (-1)))." )^2";
                $this->param['roots'] = 'x = '.$x1;
            }
			$this->param['dis'] = $dis;
			$this->param['a'] = $A;
			$this->param['B'] = $B;
			$this->param['C'] = $C;
			$this->param['RESULT'] = 1;
			return $this->param;
        }else{
            $this->param['error'] = 'Please Check Your Input!';
			return $this->param;
        }
    }

	// Zeros Calculator
	function zeros($request){
		$eq = $request->eq;
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|sin|cos|tan|arcsin|arccos|arctan|&|%/i", $eq)) {
            $this->param['error'] = 'Please Check Your Input!';
			return $this->param;
		}
		if (!empty($eq)) {
			$parem = $eq;
			$parem = str_replace(' ', '', $parem);
			$parem = str_replace('%20', '', $parem);
			$parem = str_replace('+', 'plus', $parem);
			$parem = str_replace('{', '(', $parem);
			$parem = str_replace('}', ')', $parem);
			$parem = str_replace('e^', 'exp', $parem);
			$parem = str_replace('exp^', 'exp', $parem);
			$parem = str_replace('^', '**', $parem);
			$parem = str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			$parem = explode('=', $parem);
			if (count($parem) === 2) {
				$eq = '(' . $parem[0] . ')-(' . $parem[1] . ')';
			} else {
				$eq = $parem[0];
			}
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/zeros', [
					'equ' => $eq,
				]);
				$buffer =  $response->getBody();
				$buffer = explode("@@@", $buffer);
				$this->param['eq'] = $buffer[0];
