	// Descartes Rule Of Signs Calculator
	function descartes($request){
		$equ=$_POST['equ'];
		$vari=$_POST['vari'];
		$range=range('a', 'z');
		if (!empty($equ) && in_array(strtolower($vari), $range)) {
			$input=$equ;
			$input=str_replace(' ', '', $input);
			$input=str_replace('+', 'plus', $input);
			$input=str_replace('{', '(', $input);
			$input=str_replace('}', ')', $input);
			$input=str_replace('xe^', 'x*e^', $input);
			$input=str_replace('ye^', 'y*e^', $input);
			$input=str_replace('e^', 'exp', $input);
			$input=str_replace('exp^', 'exp', $input);
			$input=str_replace('^', '**', $input);
			$input=str_replace('e^sqrt(x)', 'exp(2*x)', $input);
			$input1=str_replace($vari,'(-'.$vari.')',$input);
			try{
				$client = new Client();
				$r = $client->post("http://167.172.134.148/descartes", [
					'form_params' => [
						'equ'=>$input,
						'equ1'=>$input1,
						'wrt'=>$vari,
					],
					'timeout' => 120,
				]);
				$buffer =  $r->getBody();
	            $buffer = json_decode($buffer,true);
	            $cof1=array_filter(explode(',', $buffer[2]));
	            $cof2=array_filter(explode(',', $buffer[3]));
	            $sign1=[];
	            foreach ($cof1 as $key => $value) {
	            	if (is_numeric(trim($value))) {
	            		if (trim($value)<0) {
	            			$sign1[]='-';
	            		}else{
	            			$sign1[]='+';
	            		}
	            	}else{
	            		$this->session->set_flashdata('descartes','Please! Enter Univariate Polynomial');
						return false;
						break;
	            	}
	            }
	            $sign2=[];
	            foreach ($cof2 as $key => $value) {
	            	if (is_numeric(trim($value))) {
	            		if (trim($value)<0) {
	            			$sign2[]='-';
	            		}else{
	            			$sign2[]='+';
	            		}
	            	}else{
	            		$this->session->set_flashdata('descartes','Please! Enter Univariate Polynomial');
						return false;
						break;
	            	}
	            }
	            $positive=0;
	            foreach ($sign1 as $key => $value) {
	            	if (isset($sign1[$key+1]) && $value!=$sign1[$key+1]) {
	            		$positive++;
	            	}
	            }

	            $negative=0;
	            foreach ($sign2 as $key => $value) {
	            	if (isset($sign2[$key+1]) && $value!=$sign2[$key+1]) {
	            		$negative++;
	            	}
	            }
	            $this->param['input1'] = $buffer[0];
	            $this->param['input2'] = $buffer[1];
	            $this->param['positive'] = $positive;
	            $this->param['negative'] = $negative;
	            $this->param['cof1'] = $cof1;
	            $this->param['cof2'] = $cof2;
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $r) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
            $this->param['error'] = 'Please Check Your Input!';
			return $this->param;
		}
	}

	// Exponential Function Calculator
	function exponet_function($request){
		$t1 = $request->t1;
		$y1 = $request->y1;
		$t2 = $request->t2;
		$y2 = $request->y2;
		$point_optional = $request->point_optional;
	    if(is_numeric($t1) && is_numeric($y1) && is_numeric($t2) && is_numeric($y2)){
			if(($y1!=$y2 && $t1!=$t2) && ($y1>0 && $y2>0)){
				$y = $y1/$y2;
				$natural_log = log($y);
				$time_minus = $t1 - $t2;
				$time = 1/$time_minus;
				$k = round($time*$natural_log,4); 
				$exp_power = $k * $t2 * -1;
				$e = exp($exp_power);
				$A = round($y2 * $e,4);
				if(!empty($point_optional)){
					$exp_fun = exp($k*$point_optional);
				}else{
					$exp_fun = exp($k*2);
				}
				$f = round($A*$exp_fun,4);
				$this->param['k'] = $k;
				$this->param['A'] = $A;
				$this->param['f'] = $f;
				$this->param['RESULT'] = 1;
				return $this->param;

			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

