			if(empty($len_a) && empty($len_c) && empty($angle_alpha) && empty($area)){
				$method=8;
				$len_b=$len_b;
				if($angle_beta_unit=="0.017453"){
					$angleb=($angle_beta*3.141592653589793238)/180;
					$anglea=3.141592653589793238/2-$angleb;
				}else if($angle_beta_unit=="57.3"){
					$anglea=3.141592653589793238/2-$angle_beta;
				}
				$len_a=$len_b*tan($anglea);
				$c=sqrt($len_a*$len_a+$len_b*$len_b);
				$anglea=atan($len_a/$len_b);
				$angleb=atan($len_b/$len_a);
				$area=($len_a*$len_b)/2;
				$this->param['area']=$area;
			}else{
				$this->param['error'] = 'Please! Enter only two values in one of the following fields.';
				return $this->param;
			}
		}else if(is_numeric($angle_beta) && is_numeric($len_c)){
			if(empty($len_a) && empty($len_b) && empty($angle_alpha) && empty($area)){
				$method=9;
				$c=$len_c;
				if($angle_beta_unit=="0.017453"){
					$angleb=($angle_beta*3.141592653589793238)/180;
					$anglea=3.141592653589793238/2-$angleb;
				}else if($angle_beta_unit=="57.3"){
					$anglea=3.141592653589793238/2-$angle_beta;
				}
				$len_a=$c*sin($anglea);
				$len_b=$c*cos($anglea);
				$anglea=atan($len_a/$len_b);
				$angleb=atan($len_b/$len_a);
				$area=($len_a*$len_b)/2;
				$this->param['area']=$area;
			}else{
				$this->param['error'] = 'Please! Enter only two values in one of the following fields.';
				return $this->param;
			}
		}else if(is_numeric($area) && is_numeric($len_a)){
			if(empty($len_b) && empty($len_c) && empty($angle_alpha) && empty($angle_beta)){
				$method=10;
				$len_a=$len_a;
				$area_value=new_centi($area_unit,$area);
				$len_b=2*$area_value/$len_a;
				$c=sqrt(($len_a*$len_a)+($len_b*$len_b));
				$anglea=atan($len_a/$len_b);
				$angleb=atan($len_b/$len_a);
				$this->param['area']=$area_value;
			}else{
				$this->param['error'] = 'Please! Enter only two values in one of the following fields.';
				return $this->param;
			}
		}else if(is_numeric($area) && is_numeric($len_b)){
			if(empty($len_a) && empty($len_c) && empty($angle_alpha) && empty($angle_beta)){
				$method=11;
				$len_b=$len_b;
				$area_value=new_centi($area_unit,$area);
				$len_a=2*$area_value/$len_b;
				$c=sqrt(($len_a*$len_a)+($len_b*$len_b));
				$anglea=atan($len_a/$len_b);
				$angleb=atan($len_b/$len_a);
				$this->param['area']=$area_value;
			}else{
				$this->param['error'] = 'Please! Enter only two values in one of the following fields.';
				return $this->param;
			}
		}else if(is_numeric($area) && is_numeric($len_c)){
			if(empty($len_a) && empty($len_b) && empty($angle_alpha) && empty($angle_beta)){
				$method=12;
				$c=$len_c;
				$area_value=new_centi($area_unit,$area);
				$len_a=sqrt(($c*$c+sqrt(pow($c,4)-16*$area_value*$area_value))/2);
				$len_b=sqrt(($c*$c-sqrt(pow($c,4)-16*$area_value*$area_value))/2);
				$anglea=asin($len_a/$c);
				$angleb=atan($len_b/$len_a);
				$this->param['area']=$area_value;
			}else{
				$this->param['error'] = 'Please! Enter only two values in one of the following fields.';
				return $this->param;
			}
		}else if(is_numeric($area) && is_numeric($angle_alpha)){
			if(empty($len_a) && empty($len_b) && empty($len_c) && empty($angle_beta)){
				$method=13;
				$area_value=new_centi($area_unit,$area);
				$anglea=$angle_alpha*$angle_alpha_unit;
				$len_a=sqrt(2*$area_value*tan($anglea));
				$len_b=sqrt(2*$area_value/tan($anglea));
				$c=sqrt($len_a*$len_a+$len_b*$len_b);
				$anglea=atan($len_a/$len_b);
				$angleb=atan($len_b/$len_a);
				$this->param['area']=$area_value;
			}else{
				$this->param['error'] = 'Please! Enter only two values in one of the following fields.';
				return $this->param;
			}
		}else if(is_numeric($area) && is_numeric($angle_beta)){
			if(empty($len_a) && empty($len_b) && empty($len_c) && empty($angle_alpha)){
				$method=14;
				$area_value=new_centi($area_unit,$area);
				$angleb=$angle_beta*$angle_beta_unit;
				$len_a=sqrt(2*$area_value*tan($angleb));
				$len_b=sqrt(2*$area_value/tan($angleb));
				$c=sqrt($len_a*$len_a+$len_b*$len_b);
				$anglea=atan($len_a/$len_b);
				$angleb=atan($len_b/$len_a);
				$this->param['area']=$area_value;
			}else{
				$this->param['error'] = 'Please! Enter only two values in one of the following fields.';
				return $this->param;
			}
		}else if(is_numeric($angle_alpha) && is_numeric($angle_beta)){
			if(empty($len_a) && empty($len_b) && empty($len_c) && empty($area)){
				$this->param['error'] = 'Can not calculate based on 2 angles only.';
            	return $this->param;
			}else{
				$this->param['error'] = 'Please! Enter only two values in one of the following fields.';
				return $this->param;
			}
		}
		$this->param['method']=$method;
		$this->param['a']=$len_a;
		$this->param['b']=$len_b;
		$this->param['c']=$c;
		$this->param['anglea']=$anglea;
		$this->param['angleb']=$angleb;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Mixed Number Calculator
	function mixed($request){
		if (is_numeric($request->n1) && is_numeric($request->d1) && is_numeric($request->n2) && is_numeric($request->d2)) {
			$N1 = $request->n1;
			$D1 = $request->d1;
			$N2 =$request->n2;
			$D2 = $request->d2;
			if (is_numeric($request->s1)) {
				$val1=$request->s1;
				if($val1<0 && $N1>0){
					$N1 = $N1 * (-1);
				}
				$N1=($D1 * $val1) + $N1;
			}
			if (is_numeric($request->s2)) {
				$val2=$request->s2;
				if($val2<0 && $N2>0){
					$N2 = $N2 * (-1);
				}
				$N2=($D2 * $val2) + $N2;
			}
			$action = $request->action;
			if($action == '+')
			{
				$totalN = ($N1 * $D2)+($N2 * $D1);
				$totalD = ($D1 * $D2);
				$done = 1;
			}
			if($action == '-')
			{
				$totalN = ($N1 * $D2)-($N2 * $D1);
				$totalD = ($D1 * $D2);
				$done = 1;
			}
			if($action == '÷')
			{
				$totalN = ($N1 * $D2);
				$totalD = ($N2 * $D1);
				$done = 1;
			}
			if($action == '×')
			{
				$totalN = ($N1 *$N2);
				$totalD = ($D1 * $D2);
				$done = 1;
				
			}
			/****
			** Reduce value
			****/
			function gcd($a22,$b22) 
			{
				$a22 = abs($a22); $b22 = abs($b22);

				if( $a22 < $b22)
				{ 
					list($b22,$a22) = Array($a22,$b22);
				}
				if( $b22 == 0){
					return 1;
				}
				$r = $a22 % $b22;
				while($r > 0): 
					$a22 = $b22;
					$b22 = $r;
					$r = $a22 % $b22;
				endwhile;
				return $b22;
		
			}

			function reduce($num1,$den1) 
			{
				$g = gcd($num1,$den1);
				return array($num1/$g,$den1/$g);
			}
			$g = gcd($totalN,$totalD);
			list ($upr  , $btm) = reduce($totalN,$totalD);
			// return Values
			$this->param['upr'] =$upr;
			$this->param['N1'] =$N1;
			$this->param['N2'] =$N2;
			$this->param['D1'] =$D1;
			$this->param['D2'] =$D2;
			$this->param['totalN'] =$totalN;
			$this->param['totalD'] =$totalD;
			$this->param['g'] =$g;
			$this->param['btm'] =$btm;
			return $this->param;
		}else{
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}

	// Quadratic Formula Calculator
	function quadratic($request){
		if (is_numeric($request->a) && is_numeric($request->b) && is_numeric($request->c)) {
			$A=$request->a;
			if($request->formula=='1'){
				$B=$request->b;
				$C=$request->c;
			}
			if ($request->formula=='2') {
				$C=(pow($request->b, 2) * $request->a) + $request->c;
				$B=(($request->b * (-1))*2) * $request->a;
			}
			if ($request->formula==3) {
				$B=$request->b.' '.(($request->c<0)?$request->c:' + '.$request->c);
				$B=(eval('return '.$B.';')) * $A;
				$C= ($request->b*$request->c)*$request->a;
			}
			$firstx= round(($B*(-1)) / (2*$A),3);
			$first_part=pow($firstx,2)*$A;
	      	$second_part=$B*$firstx;
	      	if ($second_part<0 && $C<0) {
				$eq=$first_part.' '.$second_part.' '.$C;
			}
			if ($second_part<0 && $C>=0) {
				$eq=$first_part.' '.$second_part.' + '.$C;
			}
			if ($second_part>=0 && $C<0) {
				$eq=$first_part.' + '.$second_part.' '.$C;
			}
			if ($second_part>=0 && $C>=0) {
				$eq=$first_part.' + '.$second_part.' + '.$C;
			}
			$yaxis=eval('return '.$eq.';');
			$yaxis=round($yaxis,3);
			$this->param['vertex']=$A."(x ".(($firstx<0)?"+ ".($firstx*(-1))." )^2":"- ".$firstx." )^2 ").(($yaxis<0)?"- ".($yaxis*(-1)):"+ ".$yaxis);
			if($request->method==2){
				$dis= pow($B, 2) - (4*$A*$C);
				if ($dis>0) {
					$x1= round((($B * (-1)) + sqrt($dis)) / (2*$A),4);
					$x2= round((($B * (-1)) - sqrt($dis)) / (2*$A),4);
					$this->param['fact']=$A."(x ".(($x1<0)?"+ ".($x1*(-1)):"- ".$x1)." )"."(x ".(($x2<0)?"+ ".($x2*(-1)):"- ".$x2)." )";
					$this->param['roots'] = 'x₁ = '.$x1.' , x₂ = '.$x2;
				}
				if ($dis<0) {
					$x1= round(($B * (-1))/(2*$A),4).' + '.round(sqrt(($dis * (-1))) / (2*$A),4);
					$x2= round(($B * (-1))/(2*$A),4).' - '.round(sqrt(($dis * (-1))) / (2*$A),4);
					$this->param['fact']=$A."(x - (".$x1."\,i) )"."(x - (".($x2)."\,i) )";
					$this->param['roots'] = 'x₁ = '.$x1.' <i>i</i><br> x₂ = '.$x2.' <i>i</i>';
				}
				if ($dis==0) {
					$x1= round(($B * (-1)) /(2*$A),4);
					$this->param['fact']=$A."(x ".(($x1<0)?"+ ".($x1*(-1)):"- ".($x1 * (-1)))." )^2";
					$this->param['roots'] = 'x = '.$x1;
				}
				$this->param['dis']=$dis;
				$this->param['B']=$B;
				$this->param['C']=$C;
				$this->param['RESULT'] = 1;
				return $this->param;
			}elseif ($request->method==1) {
				$left_side=$B/$A;
				$C_= $C*(-1) / $A;
				$right_side= $C_ + (pow($B, 2) / pow(($A*2), 2));
				if ($right_side>0) {
					$x1=round((($left_side/2)*(-1)) + sqrt($right_side),4);
					$x2=round((($left_side/2)*(-1)) - sqrt($right_side),4);
					$this->param['fact']=$A."(x ".(($x1<0)?"+ ".($x1*(-1)):"- ".$x1)." )"."(x ".(($x2<0)?"+ ".($x2*(-1)):"- ".$x2)." )";
					$this->param['roots'] = 'x₁ = '.$x1.' , x₂ = '.$x2;
				}
				if ($right_side<0) {
					$right_side=$right_side * (-1);
					$x1=round((($left_side/2)*(-1)),4)." + ".round(sqrt($right_side),4);
					$x2=round((($left_side/2)*(-1)),4)." - ".round(sqrt($right_side),4);
					$this->param['fact']=$A."(x - (".$x1."\,i) )"."(x - (".($x2)."\,i) )";
					$this->param['roots'] = 'x₁ = '.$x1.' <i>i</i><br> x₂ = '.$x2.' <i>i</i>';
				}
				if ($right_side==0) {
					$x1=round((($left_side/2)*(-1)),4);
					$this->param['fact']=$A."(x ".(($x1<0)?"+ ".($x1*(-1)):"- ".($x1 * (-1)))." )^2";
					$this->param['roots'] = 'x = '.$x1;
				}
				$this->param['B']=$B;
				$this->param['C']=$C;
				$this->param['x1']=$x1;
				$this->param['x2']=@$x2;
				$this->param['RESULT'] = 1;
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}

	// Multiplicative Inverse Calculator
	function multiplicative($request){
		$dec= $request->dec;
		$is_frac= $request->is_frac;
		$s1= $request->s1;
		$n1= $request->n1;
		$d1= $request->d1;
		$check=true;
		if ($is_frac==1) {
			if (is_numeric($dec)) {
				$upr=$dec;
				$btm=1;
			}else{
				$check=false;
			}
		}elseif($is_frac==2){
			if (is_numeric($n1) && is_numeric($d1)) {
				$upr=$n1;
				$btm=$d1;
			}else{
				$check=false;
			}
		}else{
			if (is_numeric($n1) && is_numeric($d1) && is_numeric($s1)) {
				if ($n1<0) {
					$this->param['error'] = 'Numerator and denominator must be positive.';
					return $this->param;
				}
				if ($s1<1) {
					$upr=($d1*$s1)-$n1;
				}else{
					$upr=($d1*$s1)+$n1;
				}
				$btm=$d1;
			}else{
				$check=false;
			}
		}
		if ($check==true) {
			$this->param['ans'] = round($btm/$upr,8);
			$this->param['upr'] = $upr;
			$this->param['btm'] = $btm;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
	}

	// 30 60 90 Triangle Calculator
	function thirty($request){
		$sides = $request->sides;
		$input = $request->input;
		$linear_unit = $request->linear_unit;
		$square_unit = $request->square_unit;
		function again_unit_convert($unit,$value){
			if($unit === "mm"){
				$val1 = $value*0.1;
			}else if($unit === "cm"){
				$val1 = $value * 1;
			}else if($unit === "m"){
				$val1 = $value * 100;
			}else if($unit === "km"){
				$val1 = $value * 1000;
			}else if($unit === "in"){
				$val1 = $value * 2.54;
			}else if($unit === "ft"){
				$val1 = $value * 30.48;
			}else if($unit === "yd"){
				$val1 = $value * 91.44;
			}else if($unit === "mi"){
				$val1 = $value * 160934;
			}
			return $val1;	
		}
		function again_centi($unit3,$value3){
			if($unit3 === "mm²"){
				$val3 = $value3 * 0.01;
			}else if($unit3 === "cm²"){
				$val3 = $value3 * 1;
			}else if($unit3 === "m²"){
				$val3 = $value3 * 10000;
			}else if($unit3 === "km²"){
				$val3 = $value3 * 10000000000;
			}else if($unit3 === "in²"){
				$val3 = $value3 * 6.452;
			}else if($unit3 === "ft²"){
				$val3 = $value3 * 929;
			}else if($unit3 === "yd²"){
				$val3 = $value3 * 8361;
			}else if($unit3 === "mi²"){
				$val3 = $value3 * 25899881103;
			}
			return $val3;
		}
		if(is_numeric($input)){
			if ($sides === "a") {
				$method = 1;
				$lena_val = again_unit_convert($linear_unit,$input);
				$b=sqrt(3)*$lena_val;
				$c=2*$lena_val;
				$area=($lena_val*$b/2);
				$peri=$lena_val+$b+$c;
				$height=$b/2;
				$in_radius=($lena_val*$b)/$peri;
				$radius=$c/2;
			}else if ($sides === "b"){
				$method = 2;
				$b = again_unit_convert($linear_unit,$input);
				$lena_val = ($b*sqrt(3))/3;
				$c = 2*(($b*sqrt(3))/3);
				$area = ($lena_val*$b/2);
				$peri = $lena_val+$b+$c;
				$height = $b/2;
				$in_radius = ($lena_val*$b)/$peri;
				$radius = $c/2;
			}else if ($sides === "c"){
				$method = 3;
				$c = again_unit_convert($linear_unit,$input);
				$b=($c*sqrt(3))/2;
				$lena_val=$c/2;
				$area=($lena_val*$b/2);
				$peri=$lena_val+$b+$c;
				$height=$b/2;
				$in_radius=($lena_val*$b)/$peri;
				$radius=$c/2;
			}else if ($sides === "h"){
				$method = 4;
				$height = again_unit_convert($linear_unit,$input);
				$b=$height*2;
				$lena_val=$b/sqrt(3);
				$c=2*$lena_val;
				$area=($lena_val*$lena_val)*(sqrt(3)/2);
				$peri=$lena_val+$b+$c;
				$in_radius=($lena_val*$b)/$peri;
				$radius=$c/2;
			}else if ($sides === "A"){
				$method = 5;
				$area = again_centi($square_unit,$input);
				$lena_val=sqrt(2*$area/sqrt(3));
				$b=$lena_val*sqrt(3);
				$c=2*$lena_val;
				$height=$lena_val*$b/$c;
				$peri=$lena_val+$b+$c;
				$in_radius=($lena_val*$b)/$peri;
				$radius=$c/2;
			}else if ($sides === "p"){
				$method = 6;
				$peri = again_unit_convert($linear_unit,$input);
				$lena_val=$peri/(3+sqrt(3));
				$b=$lena_val*sqrt(3);
				$c=2*$lena_val;
				$height=($lena_val*$b)/$c;
				$area=($lena_val*$lena_val)*(sqrt(3)/2);
				$in_radius=($lena_val*$b)/$peri;
				$radius=$c/2;
			}
	   	}else{
		   $this->param['error'] = 'Please Check Your Input.';
			return $this->param;
	   	}
		$this->param['method'] = $method;
		$this->param['a'] = round($lena_val,3);
		$this->param['a_unit'] = $linear_unit;
		$this->param['b'] = round($b,3);
		$this->param['b_unit'] = $linear_unit;
		$this->param['c'] = round($c,3);
		$this->param['c_unit'] = $linear_unit;
		$this->param['area_unit'] = $square_unit;
		$this->param['perimeter_unit'] = $linear_unit;
		$this->param['aa'] = round($area,3);
		$this->param['peri'] = round($peri,3);
		$this->param['height'] = round($height,3);
		$this->param['height_unit'] = $linear_unit;
		$this->param['in_radius'] = round($in_radius,3);
		$this->param['radius'] = round($radius,3);
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Geometric Sequence Calculator
	function geometric($request){
		$find= $request->find;
		$cw= $request->cw;
		$a1= $request->a1;
		$r= $request->r;
		$n= $request->n;
		$an= $request->an;
		$sn= $request->sn;
		$n1= $request->n1;
		$a_n= $request->a_n;
		if($find==='gs' && is_numeric($a1) && is_numeric($r) && is_numeric($n)){
			$an_val=$a1*pow($r,$n-1);
			$sn_val=$a1*(1-pow($r,$n))/(1-$r);
			$seq='';
			for($i=1; $i < 11; $i++){
				$sum=pow($a1,$i);
				if($i<11){
				$seq.="$sum, ";
				}
				if($i>9){
				$seq.=" ....";
				}
			}
			$this->param['an_val'] = $an_val;
			$this->param['sn_val'] = $sn_val;
			$this->param['seq'] = $seq;
		}elseif($find==='a1' && is_numeric($r) && is_numeric($n1) && is_numeric($a_n)){
			$a1_val=$a_n/pow($r,$n1-1);
			$this->param['a1_val'] = $a1_val;
		}elseif($find==='r' && is_numeric($a1) && is_numeric($n1) && is_numeric($a_n)){
			$r_val=pow(($a_n/$a1),(1/($n1-1)));
			$this->param['r_val'] = $r_val;
		}elseif($find==='n' && is_numeric($a1) && is_numeric($r)){
			if($cw==='nth' && is_numeric($an)){
				$n_val=(log($an/$a1)/log($r))+1;
				$this->param['n_val'] = $n_val;
			}elseif($cw==='s_n' && is_numeric($sn)){
				$n_val=log(((($sn/$a1)*(1-$r))-1)*(-1))/log($r);
				$this->param['n_val'] = $n_val;
			}
		}else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}

    // Long Multiplication Calculator
	function l_multiplication($request){
		$first = $request->first;
		$second = $request->second;
        if (is_numeric($first) && is_numeric($second)) {
            // $answer = $first * $second;
            $answer1 = $first * $second;
            $aa = explode('.', $answer1);
            if (count($aa) == 1) {
                $answer = $answer1;
            }else if (count($aa) == 2) {
                $answer = $aa[0].$aa[1];
            }
            // $jawab = number_format($answer,0,'','');
            $xx = explode('.', $first);
            $yy = explode('.', $second);
            if ((count($xx) == 2) || (count($yy) == 2)) {
                if (count($xx) == 2) {
                    $l1 = strlen($xx[1]);
                }
                if  (count($yy) == 2) {
                    $l2 = strlen($yy[1]);
                }
                if (!empty($l1) && !empty($l2)) {
                    $total = $l1 + $l2;
                }else{
                    if (!empty($l1)) {
                        $total = $l1;
                    }else if (!empty($l2)) {
                        $total = $l2;
                    }
                }
                $line1 = "The following decimals contain overall <b>".$total."</b> decimal places";
                $line2 = "You just need to carry out long multiplication as you do with normal integers by ignoring the decimals.";
                $line3 = "In the final final, start from right to left and move up to <b>".$total."</b> decimal places to insert the decimal. This is the final answer.";
                $this->param['line1'] = $line1;
                $this->param['line2'] = $line2;
                $this->param['line3'] = $line3;
            }
            $first = str_replace(".","",$first); 
            $second = str_replace(".","",$second);
            if ($first < 0) {
                $first = $first * (-1);
            }
            if ($second < 0) {
                $second = $second * (-1);
            }
            $answer2 = $first * $second;
            $f_len = strlen($first);
            $s_len = strlen($second);
            // $col = strlen($jawab);
            $col = strlen($answer);
            $f_array = str_split($first);
            $s_array = str_split($second);
            $arr_rev = array();
            if ($f_len >= $s_len) {
                $rev_array = $s_array;
                for($i = sizeof($rev_array) - 1; $i >= 0; $i--) {
                    array_push($arr_rev,$rev_array[$i]);
                }
                foreach ($arr_rev as $value) {
                    $m_j[] = $value * $first;
                }
                $upper = $f_array;
                $lower = $s_array;
            }else if ($f_len < $s_len) {
                $rev_array = $f_array;
                for($i = sizeof($rev_array) - 1; $i >= 0; $i--) {
                    array_push($arr_rev,$rev_array[$i]);
                }
                foreach ($arr_rev as $value) {
                    $m_j[] = $value * $second;
                }
                $upper = $s_array;
                $lower = $f_array;
            }
            $final = str_split($answer);
        }else{
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
        }
        $this->param['upper'] =$upper;
        $this->param['lower'] =$lower;
        $this->param['col'] =$col;
        $this->param['m_j'] =$m_j;
        // $this->param['jawab'] =$jawab;
        $this->param['final'] =$final; 
        $this->param['answer'] =$answer;    
        $this->param['answer1'] =$answer1;   
        $this->param['RESULT'] = 1;
        return $this->param;
    }

	// Quotient and Remainder Calculator
	function remainder($request){
		if (is_numeric($request->x) && is_numeric($request->y)) {
			$mod=$request->x % $request->y;
			$q=floor($request->x / $request->y);
			$this->param['r'] = $mod;
			$this->param['q'] = $q;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
	}

	// SGPA To Percentage Calculator
	function sgpa($request){
		
		$type = $request->type;
		$sgp = $request->sgp;
		$sgpa = $request->sgpa;
		$selection = $request->selection;
		$number_of_semesters = $request->number_of_semesters;
		$sum = $request->sum;
		if ($type == "first") {
			if ($selection == "1") {
				if (is_numeric($sgp)) {
					$single_value = ($sgp - 0.75) * 10;
					$this->param['final_gpa'] = $single_value;
					$this->param['RESULT'] = 1;
					return $this->param;
				} else {
					$this->param['error'] = 'Please Check Your Input.';
					return $this->param;
				}
			} else if ($selection == "2") {
				if (is_numeric($number_of_semesters) && is_numeric($sum)) {
					if ($number_of_semesters > 0 && $sum > 0) {
						if ($number_of_semesters < 25) {
							$semester = $number_of_semesters * 10;
							if ($sum > $semester) {
								$this->param['error'] = 'Sgpa should be within ' . $semester;
								return $this->param;
							} else {
								$final_result = $sum / $number_of_semesters;
								$this->param['final_result'] = $final_result;
								$this->param['RESULT'] = 1;
								return $this->param;
							}
						} else {
							$this->param['error'] = 'Enter number of semester below 25.';
							return $this->param;
						}
					} else {
						$this->param['error'] = 'Please! Enter Positive Number.';
						return $this->param;
					}
				} else {
					$this->param['error'] = 'Please Check Your Input.';
					return $this->param;
				}
			}
		} else if ($type == "second") {
			$count = count($sgpa);
			$sum = 0;
			$i = 0;
			while ($i < $count) {
				if (is_numeric($sgpa[$i])) {
					$sum = $sum + $sgpa[$i];
					$percentage = $sum / $count;
				} else {
					$this->param['error'] = 'Please Check Your Input.';
					return $this->param;
				}
				$i++;
			}
			$final_gpa = ($percentage - 0.75) * 10;
			$this->param['final_gpa'] = $final_gpa;
			$this->param['percentage'] = $percentage;
			$this->param['sgpa'] = $sgpa;
			$this->param['RESULT'] = 1;
			return $this->param;
		}
	}

