	// Jacobian Number Calculator
	function jacobian($request){
		$xu = $request->xu;
		$xu_var = $request->xu_var;
		$yv = $request->yv;
		$yv_var = $request->yv_var;
		$zw = $request->zw;
		$zw_var = $request->zw_var;
		$submit = $request->type;
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $xu) || preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $yv) || preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $zw)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (!empty($xu) && !empty($yv)) {
			$parem = $xu;
			$parem = str_replace(' ', '', $parem);
			$parem = str_replace('%20', '', $parem);
			$parem = str_replace('+', 'plus',
				$parem
			);
			$parem = str_replace('{', '(', $parem);
			$parem = str_replace('}', ')', $parem);
			$parem = str_replace('e^', 'exp',
				$parem
			);
			$parem = str_replace('exp^', 'exp', $parem);
			$parem = str_replace('^', '**', $parem);
			$parem = str_replace('e^sqrt(x)',
				'exp(2*x)',
				$parem
			);
			$parem1 = $yv;
			$parem1 = str_replace(' ', '', $parem1);
			$parem1 = str_replace('%20', '', $parem1);
			$parem1 = str_replace('+', 'plus',
				$parem1
			);
			$parem1 = str_replace('{', '(', $parem1);
			$parem1 = str_replace('}', ')', $parem1);
			$parem1 = str_replace('e^', 'exp',
				$parem1
			);
			$parem1 = str_replace('exp^', 'exp', $parem1);
			$parem1 = str_replace('^', '**', $parem1);
			$parem1 = str_replace('e^sqrt(x)',
				'exp(2*x)',
				$parem1
			);
			if ($submit === 'three' && !empty($xu) && !empty($yv) && !empty($zw)) {
				$parem2 = $zw;
				$parem2 = str_replace(' ', '', $parem2);
				$parem2 = str_replace('%20', '', $parem2);
				$parem2 = str_replace('+', 'plus',
					$parem2
				);
				$parem2 = str_replace('{', '(', $parem2);
				$parem2 = str_replace('}', ')', $parem2);
				$parem2 = str_replace('e^', 'exp',
					$parem2
				);
				$parem2 = str_replace('exp^', 'exp', $parem2);
				$parem2 = str_replace('^', '**', $parem2);
				$parem2 = str_replace('e^sqrt(x)',
					'exp(2*x)',
					$parem2
				);
				try{
					$response = Http::timeout(120)->get('http://167.172.134.148/jacobian', [
						'equ' => $parem,
						'equ1' => $parem1,
						'equ2' => $parem2,
						'var' => $xu_var,
						'var1' => $yv_var,
						'var2' => $zw_var,
						'check' => $submit,
					]);
					$buffer = $response->body();
					$buffer = explode("@@@", $buffer);
					$this->param['enter'] = $buffer[0];
					$this->param['enter1'] = $buffer[1];
					$this->param['enter2'] = $buffer[2];
					$this->param['jacob'] = $buffer[3];
					$this->param['dtrmnt'] = $buffer[4];
					$this->param['var'] = $buffer[5];
					$this->param['var1'] = $buffer[6];
					$this->param['var2'] = $buffer[7];
					$this->param['check'] = $submit;
					$this->param['RESULT'] = 1;

					return $this->param;
