			$s3 = (pow($side_a, 2) + pow($side_b, 2) - pow($side_c, 2)) / (2 * $side_a * $side_b);
			$angle_c = acos($s3);
			$P = $side_a + $side_b + $side_c;
			$s = 0.5 * $P;
			$K = sqrt($s * ($s - $side_a) * ($s - $side_b) * ($s - $side_c));
			$r = sqrt((($s - $side_a) * ($s - $side_b) * ($s - $side_c)) / $s);
			$R = ($side_a * $side_b * $side_c) / (4 * $K);
			$this->param['angle_a'] = rad2deg($angle_a);
			$this->param['angle_b'] = rad2deg($angle_b);
			$this->param['angle_c'] = rad2deg($angle_c);
		} elseif ($cal === 'ac' && is_numeric($side_a) && is_numeric($side_b) && is_numeric($side_c)) {
			$s1 = (pow($side_b, 2) + pow($side_c, 2) - pow($side_a, 2)) / (2 * $side_b * $side_c);
			$angle_a = acos($s1);
			$s2 = (pow($side_a, 2) + pow($side_c, 2) - pow($side_b, 2)) / (2 * $side_a * $side_c);
			$angle_b = acos($s2);
			$s3 = (pow($side_a, 2) + pow($side_b, 2) - pow($side_c, 2)) / (2 * $side_a * $side_b);
			$angle_c = acos($s3);
			$P = $side_a + $side_b + $side_c;
			$s = 0.5 * $P;
			$K = sqrt($s * ($s - $side_a) * ($s - $side_b) * ($s - $side_c));
			$r = sqrt((($s - $side_a) * ($s - $side_b) * ($s - $side_c)) / $s);
			$R = ($side_a * $side_b * $side_c) / (4 * $K);
			$this->param['angle_a'] = rad2deg($angle_a);
