			$side_a = sqrt(pow($side_b, 2) + pow($side_c, 2) - 2 * $side_b * $side_c * cos(deg2rad($angle_a)));
			$s1 = (pow($side_a, 2) + pow($side_c, 2) - pow($side_b, 2)) / (2 * $side_a * $side_c);
			$angle_b = acos($s1);
