		} elseif ($cal === 'sc' && is_numeric($side_a) && is_numeric($side_b) && is_numeric($angle_c)) {
			$side_c = sqrt(pow($side_a, 2) + pow($side_b, 2) - 2 * $side_a * $side_b * cos(deg2rad($angle_c)));
			$s1 = (pow($side_b, 2) + pow($side_c, 2) - pow($side_a, 2)) / (2 * $side_b * $side_c);
			$angle_a = acos($s1);
			$s2 = (pow($side_a, 2) + pow($side_c, 2) - pow($side_b, 2)) / (2 * $side_a * $side_c);
			$angle_b = acos($s2);
			$P = $side_a + $side_b + $side_c;
