		return $this->param;
	}

	// Hyperbola Calculator
	function hyperbola($request){
		$x= $request->x;
		$y= $request->y;
		$a= $request->a;
		$b= $request->b;
		if (is_numeric($x) && is_numeric($y) && is_numeric($a) && is_numeric($b)) {
			function isPerfectSquare($n)
			{
			    for ($i = 1; $i * $i <= $n; $i++) { 
			        // If (i * i = n)
			        if (($n % $i == 0) && ($n / $i == $i)) {
			            return sqrt($n);
			        }
			    }
			    return "\\sqrt{$n}";
			}
			$c1=$x;
			$c2=$y;
			$as=sqrt($a);
			$bs=sqrt($b);
			$v1=($c1) - ($as)." , ".$c2;
			$v2=($c1) + ($as)." , ".$c2;
			$v21=($c2) - ($bs);
			$v22=($c2) + ($bs);
			$c=sqrt($a+$b);
			$f1=($c1) - ($c)." , ".$c2;
			$f2=($c1) + ($c)." , ".$c2;
			$ecc=$c/$as;
			$fp=$b/$c;
			$dir1=$c1-(($a*$c)/($a+$b));
			$dir2=$c1+(($a*$c)/($a+$b));
			$fl1=$c1-$c;
			$fl2=$c1+$c;
			$ashow=isPerfectSquare($a);
			$bshow=isPerfectSquare($b);
			$cshow=isPerfectSquare($b+$a);
			$this->param['as'] = $as;
			$this->param['bs'] = $bs;
			$this->param['v1'] = $v1;
			$this->param['v2'] = $v2;
			$this->param['v21'] = $v21;
			$this->param['v22'] = $v22;
			$this->param['f1'] = $f1;
			$this->param['f2'] = $f2;
			$this->param['ecc'] = $ecc;
			$this->param['fp'] = $fp;
			$this->param['dir1'] = $dir1;
			$this->param['dir2'] = $dir2;
			$this->param['fl1'] = $fl1;
			$this->param['fl2'] = $fl2;
			$this->param['c'] = $c;
			$this->param['ashow'] = $ashow;
			$this->param['bshow'] = $bshow;
			$this->param['cshow'] = $cshow;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}

	}

