	// Difference Quotient Calculator
	function difference($request){
		$EnterEq= $request->EnterEq;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (!empty($EnterEq)) {
			$parem=strtolower($EnterEq);
			$parem = str_replace(['f^-1(x)', 'f(x)=', 'y=', 'h(x)=', 'f-1(2)=', 'y=f(x)=', '=y', '∣', 'f^-1(x)=', '%20', '|', 'f ( x ) =', '=', 'f(x)','fx=','fx'], '', $parem);
			// $parem = str_replace(' ', '', $parem);
			preg_match_all('/[a-zA-Z]+/', $parem, $matches);
			$filtered_vars = array_filter($matches[0], function($var) {
				$functions = ['log', 'sin', 'cos', 'tan', 'exp', 'sqrt','e','arctan'];
				return !in_array($var, $functions);
			});
			$unique_vars = array_unique($filtered_vars);
			if (count($unique_vars) > 1) {
				$this->param['error'] = 'More than one variable found in the equation';
				return $this->param;
			} elseif (count($unique_vars) === 1) {
				if(isset($unique_vars[0])){
					$with = "$unique_vars[0]";
				}elseif(isset($unique_vars[1])){
					$with = "$unique_vars[1]";
				}else{
					$with = "x";
				}
			} else {
				$this->param['error'] = 'No variable found in the equation.';
				return $this->param;
			}
			$parem = preg_replace('/sqrt\(/i', 'sqrt(', $parem);
			$parem = preg_replace('/arctan\(/i', 'atan(', $parem);
			$parem = preg_replace('/e\^([a-z0-9\(\)\*\+]+)/i', 'zain($1)', $parem);
			$parem = str_replace('^', '**', $parem);
			$parem = str_replace('−', '-', $parem);
			$parem = str_replace('{', '(', $parem);
			$parem = str_replace('}', ')', $parem);
			$parem = str_replace('[', '(', $parem);
			$parem = str_replace(']', ')', $parem);
			$parem = preg_replace('/(\d)([a-z\(])/', '$1*$2', $parem);
			$parem1 = str_replace($with, "($with + h)", $parem);
			$parem1 = preg_replace('/arctan\(/i', 'atan(', $parem1);
			$parem1 = preg_replace('/sqrt\(/i', 'sqrt(', $parem1);
			$final = '(('.$parem1.') - ('.$parem.'))/h';
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/difference', [
					'equ' => $parem,
					'wrt' => $with,
					'equ1' => $parem1,
					'final' => $final,
				]);
				if ($response->failed()) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
				$buffer = $response->body();
				$buffer=explode("@@@", $buffer);
		    	$this->param['with'] = $with;
		    	$this->param['enter'] = $buffer[0];
		    	$this->param['equ1'] = $buffer[1];
		    	$this->param['final'] = $buffer[2];
		    	$this->param['res'] = $buffer[3];
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

