				}
				$parem=$eq;
				$parem=str_replace(' ', '', $parem);
				$parem=str_replace('+', 'plus', $parem);
				$parem=str_replace('%20', '', $parem);
				$parem=str_replace('{', '(', $parem);
				$parem=str_replace('}', ')', $parem);
				$parem=str_replace('e^', 'exp', $parem);
				$parem=str_replace('exp^', 'exp', $parem);
				$parem=str_replace('^', '**', $parem);
				$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
				try {
					$client = new Client();
					$r = $client->post("http://167.172.134.148/new_factoring", [
						'form_params' => [
							'equ'=>$parem,
						],
						'timeout' => 120,
					]);
					$buffer =  $r->getBody();
					$buffer = json_decode($buffer,true);
					$factors = $buffer[0];
					$eq_enter = $buffer[1];
					$all_coeffs = $buffer[2];
					$eq_degree = $buffer[3];
					if ($eq_degree === "2") {
						preg_match_all('/(\+|-){0,1}\d+\.{0,1}\d*/', $all_coeffs, $matches);
						$eq_coeff_ans = $matches[0];
						$a = $matches[0][0];
						$b = $matches[0][1];
						$c = $matches[0][2];
						if ($a === "0") {
							$this->param['error'] = 'Please! Check Your Input.';
							return $this->param;
						}
						if ($c !== "0") {
							$step1 = abs($a*$c);
							$divisors_ans = printDivisors($step1);
							$new_array = $divisors_ans;
							$median = 0;
							if (count($divisors_ans) % 2 !== 0){
								$length = count($divisors_ans);
								$half_length = $length / 2;
								$median_index = (int) $half_length;
								$median = $divisors_ans[$median_index];
								$new_array = $divisors_ans;
								unset($new_array[$median_index]);
							}
							$toote = count($new_array) / 2;
							$toote_array = array_chunk($new_array,$toote);
							$step2_array_first = $toote_array[0];
							$step2_array_second = array_reverse($toote_array[1]);
							if ($median > 0) {
								array_push($step2_array_first,$median);
								array_push($step2_array_second,$median);
							}
							foreach ($step2_array_first as $key => $value) {
								$step2_ans_array[] = ((int) $value) * ((int) $step2_array_second[$key]);
							}
							foreach ($step2_array_first as $key => $value) {
								$step3_array_first[] = $value;
								$step3_array_first[] = "-".$value;
								$step3_array_second[] = $step2_array_second[$key];
								$step3_array_second[] = "-".$step2_array_second[$key];
							}
							foreach ($step3_array_first as $key => $value) {
								$val1 = (int) $value;
								$val2 = (int) $step3_array_second[$key];
								if ($c < 0) {
									$step3_ans_array[] = $val1 - $val2;
									if (($val1 - $val2) == $b) {
										$pair1 = $val1;
										$pair2 = $val2;
									}
								} else {
									$step3_ans_array[] = $val1 + $val2;
									if (($val1 + $val2) == $b) {
										$pair1 = $val1;
										$pair2 = $val2;
									}
								}
							}
							$square = (pow($b, 2)) - (4 * $a * $c);
							$this->param['divisors_ans'] = $divisors_ans;
							$this->param['step2_array_first'] = $step2_array_first;
							$this->param['step2_array_second'] = $step2_array_second;
							$this->param['step2_ans_array'] = $step2_ans_array;
							$this->param['step3_array_first'] = $step3_array_first;
							$this->param['step3_array_second'] = $step3_array_second;
							$this->param['step3_ans_array'] = $step3_ans_array;
							$this->param['median'] = $median;
							$this->param['square'] = $square;
							if (isset($pair1)) {
								$this->param['pair1'] = $pair1;
							}
							if (isset($pair2)) {
								$this->param['pair2'] = $pair2;
							}
						}
						$variable_ans = implode("",$variables_list);
						$this->param['a'] = (int) $a;
						$this->param['b'] = (int) $b;
						$this->param['c'] = (int) $c;
						$this->param['variable_ans'] = $variable_ans;
					}else{
