					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Enter Valid Equation.';
				return $this->param;
			}	
			$this->param['factors'] = $factors;
			$this->param['eq_enter'] = $eq_enter;
			$this->param['all_coeffs'] = $all_coeffs;
			$this->param['eq_degree'] = $eq_degree;
		}
		$this->param['submit'] = $submit;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Triangle Calculator
	function triangle($request){
		function DDtoDMS($dec){
			$vars = explode(".", $dec);
			$deg = $vars[0];
			$tempma = "0." . @$vars[1];

			$tempma = $tempma * 3600;
			$min = floor($tempma / 60);
			$sec = round($tempma - ($min * 60), 0);

			return array("deg" => $deg, "min" => $min, "sec" => $sec);
		}
		$a = $request->a;
		$b = $request->b;
		$c = $request->c;
		$A = $request->A;
		$B = $request->B;
		$C = $request->C;
		$unit = $request->unit;
		$check = false;
		if (is_numeric($a) && is_numeric($b) && is_numeric($c) && empty($A) && empty($B) && empty($C)) {
			$A = (pow($b, 2) + pow($c, 2) - pow($a, 2)) / (2 * $b * $c);
			$Ar = acos($A);
			$Ad = rad2deg($Ar);
			$At = DDtoDMS($Ad);
			$B = (pow($a, 2) + pow($c, 2) - pow($b, 2)) / (2 * $a * $c);
			$Br = acos($B);
			$Bd = rad2deg($Br);
			$Bt = DDtoDMS($Bd);
			$C = (pow($a, 2) + pow($b, 2) - pow($c, 2)) / (2 * $a * $b);
			$Cr = acos($C);
			$Cd = rad2deg($Cr);
			$Ct = DDtoDMS($Cd);
			$check = true;
			$comb = 1;
		}elseif(is_numeric($a) && is_numeric($b) && empty($c) && !empty($A) && empty($B) && empty($C)) {
			if ($unit == '1') {
				$Ad = $A;
				$At = DDtoDMS($Ad);
				$Ar = deg2rad($A);
			} else {
				$Ac = explode('/', $A);
				if (count($Ac) == 2) {
					if ($Ac[0] == 'pi' || $Ac[0] == 'pi()') {
						if (is_numeric($Ac[1])) {
							$Ar = $A;
							$Ad = 180 / $Ac[1];
							$Ar = deg2rad($Ad);
							$At = DDtoDMS($Ad);
						} else {
							$this->param['error'] = 'Please! Check Your Input.';
							return $this->param;
						}
					}
				} elseif (is_numeric($A)) {
					$Ar = $A;
					$Ad = rad2deg($A);
					$At = DDtoDMS($Ad);
				}
			}
			if ($Ad >= 180) {
				$this->param['error'] = 'Angle ∠A is too big.';
				return $this->param;
			}
			$Br = asin($b * sin($Ar) / $a);
			if (is_nan($Br) || is_infinite($Br) || empty($Br)) {
				$this->param['error'] = "These three values can't be used to develop a valid triangle.";
				return $this->param;
			} else {
				$Bd = rad2deg($Br);
				$Bt = DDtoDMS($Bd);
				$Cd = 180 - $Ad - $Bd;
				$Cr = deg2rad($Cd);
				$Ct = DDtoDMS($Cd);
				$c = round(($a * sin($Cr)) / sin($Ar), 5);
				$B1 = asin(($b * sin($Ar)) / $a);
				$Bd1 = 180 - rad2deg($B1);
				$Bt1 = DDtoDMS($Bd1);
				$Br1 = deg2rad($Bd1);
				$Cd1 = 180 - $Bd1 - $Ad;
				if ($Cd1 > 0) {
					$Ct1 = DDtoDMS($Cd1);
					$Cr1 = deg2rad($Cd1);
					$c1 = ($a * sin($Cr1)) / sin($Ar);
					$area1 = round(($a * $b * sin($Cr)) / 2, 5);
					$peri1 = $a + $b + $c1;
					$semi1 = round(($a + $b + $c1) / 2, 5);
					$ha1 = round((2 * $area1) / $a, 5);
					$hb1 = round((2 * $area1) / $b, 5);
					$hc1 = round((2 * $area1) / $c1, 5);
					$ma1 = round(sqrt(pow($a / 2, 2) + pow($c1, 2) - ($a * $c1 * cos($Br1))), 5);
					$mb1 = round(sqrt(pow($b / 2, 2) + pow($a, 2) - ($a * $b * cos($Cr1))), 5);
					$mc1 = round(sqrt(pow($c1 / 2, 2) + pow($b, 2) - ($b * $c1 * cos($Ar))), 5);
					$inr1 = round($area1 / $semi1, 5);
					$circ1 = round($a / (2 * sin($Ar)), 5);
					$this->param['comb2'] = 2;
					$this->param['c1'] = $c1;
					$this->param['Br1'] = $Br1;
					$this->param['Bd1'] = $Bd1;
					$this->param['Bt1'] = $Bt1;
					$this->param['Cr1'] = $Cr1;
					$this->param['Cd1'] = $Cd1;
					$this->param['Ct1'] = $Ct1;
					$this->param['area1'] = $area1;
					$this->param['peri1'] = $peri1;
					$this->param['semi1'] = $semi1;
					$this->param['ha1'] = $ha1;
					$this->param['hb1'] = $hb1;
					$this->param['hc1'] = $hc1;
					$this->param['ma1'] = $ma1;
					$this->param['mb1'] = $mb1;
					$this->param['mc1'] = $mc1;
					$this->param['inr1'] = $inr1;
					$this->param['circ1'] = $circ1;
				}
				$check = true;
				$comb = 2;
			}
		} elseif (is_numeric($a) && is_numeric($b) && empty($c) && empty($A) && !empty($B) && empty($C)) {
			if ($unit == '1') {
				$Bd = $B;
				$Bt = DDtoDMS($Bd);
				$Br = deg2rad($B);
			} else {
				$Bc = explode('/', $B);
				if (count($Bc) == 2) {
					if ($Bc[0] == 'pi' || $Bc[0] == 'pi()') {
						if (is_numeric($Bc[1])) {
							$Br = $B;
							$Bd = 180 / $Bc[1];
							$Br = deg2rad($Bd);
							$Bt = DDtoDMS($Bd);
						} else {
							$this->param['error'] = 'Please! Check Your Input.';
							return $this->param;
						}
					}
				} elseif (is_numeric($B)) {
					$Br = $B;
					$Bd = rad2deg($B);
					$Bt = DDtoDMS($Bd);
				}
			}
			if ($Bd >= 180) {
				$this->param['error'] = 'Angle ∠B is too big.';
				return $this->param;
			}
			$A = asin(($a * sin($Br)) / $b);
			$Ar = $A;
			$Ad = rad2deg($Ar);
			$At = DDtoDMS($Ad);
			$Cd = 180 - $Ad - $Bd;
			$Ct = DDtoDMS($Cd);
			$Cr = deg2rad($Cd);
			$c = round(($b * sin($Cr)) / sin($Br), 5);
			$comb = 3;
			$check = true;
		} elseif (is_numeric($a) && is_numeric($b) && empty($c) && empty($A) && empty($B) && !empty($C)) {
			if ($unit == '1') {
				$Cd = $C;
				$Ct = DDtoDMS($Cd);
				$Cr = deg2rad($C);
			} else {
				$Cc = explode('/', $C);
