				} elseif (is_numeric($B)) {
					$Br = $B;
					$Bd = rad2deg($B);
					$Bt = DDtoDMS($Bd);
				}
			}
			if ($Bd >= 180) {
				$this->param['error'] = 'Angle ∠B is too big.';
				return $this->param;
			}
			if (($Bd + $Cd) >= 180) {
				$this->param['error'] = "These three values can't be used to develop a valid triangle.";
				return $this->param;
			}
			$Ad = 180 - $Bd - $Cd;
			$Ar = deg2rad($Ad);
			$At = DDtoDMS($Ad);
			$a = round(($c * sin($Ar)) / sin($Cr), 5);
			$b = round(($c * sin($Br)) / sin($Cr), 5);
			$comb = 13;
			$check = true;
		}
		if ($check == true) {
			$area = round(($a * $b * sin($Cr)) / 2, 5);
			$peri = $a + $b + $c;
			$semi = round(($a + $b + $c) / 2, 5);
			$ha = round((2 * $area) / $a, 5);
			$hb = round((2 * $area) / $b, 5);
			$hc = round((2 * $area) / $c, 5);
			$ma = round(sqrt(pow($a / 2, 2) + pow($c, 2) - ($a * $c * cos($Br))), 5);
			$mb = round(sqrt(pow($b / 2, 2) + pow($a, 2) - ($a * $b * cos($Cr))), 5);
			$mc = round(sqrt(pow($c / 2, 2) + pow($b, 2) - ($b * $c * cos($Ar))), 5);
			$inr = round($area / $semi, 5);
			$circ = round($a / (2 * sin($Ar)), 5);
			$this->param['a'] = $a;
			$this->param['b'] = $b;
			$this->param['c'] = $c;
			$this->param['Ar'] = $Ar;
			$this->param['Ad'] = $Ad;
			$this->param['At'] = $At;
			$this->param['Br'] = $Br;
			$this->param['Bd'] = $Bd;
			$this->param['Bt'] = $Bt;
			$this->param['Cr'] = $Cr;
			$this->param['Cd'] = $Cd;
			$this->param['Ct'] = $Ct;
			$this->param['area'] = $area;
			$this->param['peri'] = $peri;
			$this->param['semi'] = $semi;
			$this->param['ha'] = $ha;
			$this->param['hb'] = $hb;
			$this->param['hc'] = $hc;
			$this->param['ma'] = $ma;
			$this->param['mb'] = $mb;
			$this->param['mc'] = $mc;
			$this->param['inr'] = $inr;
			$this->param['circ'] = $circ;
			$this->param['comb'] = $comb;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = "Please! Check Your Input.";
			return $this->param;
		}
	}

	// Shell Method Calculator
	function shell($request){
		$EnterEq= $request->EnterEq;
		$ub= $request->ub;
		$lb= $request->lb;
		$with= $request->with;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (!empty($EnterEq) && is_numeric($lb) && is_numeric($ub)) {
			$parem=$EnterEq;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('%20', '', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^x', 'exp(x)', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			$with=trim($with);
			$equ="2*pi*".$with."(".$parem.")";
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/shell', [
					'equ' => $equ,
					'ub' => $ub,
					'lb' => $lb,
					'with' => $with,
				]);
				$buffer = $response->body();
				$buffer=explode("@@@", $buffer);
			    $this->param['step'] = $buffer[0];
				$this->param['res'] = $buffer[1];
				$this->param['enter'] = $buffer[2];
				$this->param['ress'] = $buffer[3];
				$this->param['ress1'] = $buffer[4];
				$this->param['RESULT'] = 1;
				return $this->param;
			}catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Area Between Two Curves Calculator
	function area($request){
		$EnterEq1= $request->EnterEq1;
		$EnterEq2= $request->EnterEq2;
		$with= $request->with;
		$ub= $request->upper;
		$lb= $request->lower;
		$validator = Validator::make($request->all(), [
			'EnterEq1' => 'required|regex:/^[^<>&]*$/i',
			'EnterEq2' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq1) || preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq2)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (!empty($EnterEq1) && !empty($EnterEq2) && !empty($lb) && !empty($ub)) {
			$parem='('.$EnterEq1.')-('.$EnterEq2.')';
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('%20', '', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			$ub=str_replace('inf', 'oo', $ub);
			$ub=str_replace('∞', 'oo', $ub);
			if ($ub=='e') {
				$ub=2.71828;
			}
			$lb=str_replace('inf', 'oo', $lb);
			$lb=str_replace('∞', 'oo', $lb);
			if ($lb=='e') {
				$lb=2.71828;
			}
			try {
				$client = new Client();
				$r = $client->post("http://167.172.134.148/new-area", [
					'form_params' => [
						'equ'=>$parem,
                	 	'wrt'=>$with,
                	 	'ub'=>$ub,
                	 	'lb'=>$lb,
					],
					'timeout' => 120,
				]);
				$buffer =  $r->getBody();
				$buffer = json_decode($buffer,true);
				$parem=str_replace('"', '', $parem);
		    	$parem=str_replace('plus', '+', $parem);
				$this->param['enter'] = str_replace('**', '^', $parem);
				$this->param['with'] = $with;
				$this->param['ub'] = $ub;
				$this->param['lb'] = $lb;
				$this->param['ans'] = $buffer[0];
				$this->param['ans1'] = $buffer[1];
				$this->param['steps'] = $buffer[2];
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $r) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		
	}

