		    	$btm=str_replace($parem1,'('.$parem2.')',$check2[1]);
		    }
			try {
				$client = new Client();
				if (count($check2)===2) {
					$r = $client->post("http://167.172.134.148/new-limit", [
						'form_params' => [
							'equ'=>$parem,
							'wrt'=>$parem1,
							'lim'=>$parem2,
							'op'=>$parem3,
							'upr'=>$upr,
							'btm'=>$btm,
						],
						'timeout' => 120,
					]);
				}else{
					$r = $client->post("http://167.172.134.148/new-limit", [
						'form_params' => [
							'equ'=>$parem,
							'wrt'=>$parem1,
							'lim'=>$parem2,
							'op'=>$parem3,
						],
						'timeout' => 120,
					]);

				}
				$buffer =  $r->getBody();
                $buffer = json_decode($buffer,true);
                $enter=str_replace($with, '('.$how.')', $buffer[1]);
                if (count($check2)===2) {
                	$upr=$buffer[2];
                	$btm=$buffer[3];
                	if (is_numeric($upr) && is_numeric($btm) && $btm!=1) {
                		$this->param['upr'] = $upr;
						$this->param['btm'] = $btm;		
						$this->param['ser'] = $buffer[4];
                	}
                }else{
					$this->param['ser'] = $buffer[2];
            	}
				$this->param['ans'] = $buffer[0];
				$this->param['inf'] = $how;
				$this->param['with'] = $with;
				$this->param['how'] = $how;
				$this->param['dir'] = $dir;
				$this->param['enter'] = $buffer[1];
				$this->param['put'] = $enter;
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $r) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
