					'equ'=>$parem,
				],
				'timeout' => 120,
			]);
			$buffer =  $r->getBody();
			$buffer = json_decode($buffer,true);
			if(count($buffer)<=1){
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}elseif(count($buffer)<=8){
				$this->param['no'] = 'no';
			}elseif(count($buffer)==11){
				$this->param['ip_1'] = 'ip_1';
				$this->param['ip1'] = round($buffer[7],3);
				$this->param['ip11'] = round($buffer[8],3);
				$this->param['root'] = $buffer[9];
				$this->param['iptype'] = $buffer[10];
			}else{
				$this->param['ip1'] = round($buffer[7],3);
				$this->param['ip11'] = round($buffer[8],3);
				$this->param['ip2'] = round($buffer[9],3);
				$this->param['ip22'] = round($buffer[10],3);
				$this->param['root'] = $buffer[11];
				$this->param['iptype'] = $buffer[12];
			}
			$this->param['enter'] = $buffer[0];
			$this->param['diff'] = $buffer[1];
			$this->param['step'] = $buffer[2];
			$this->param['diff1'] = $buffer[3];
			$this->param['step1'] = $buffer[4];
			$this->param['diff2'] = $buffer[5];
			$this->param['step2'] = $buffer[6];
