			return $this->param;
		}
	}

	// Riemann Sum Calculator
	function riemann($request){
		$EnterEq= $request->EnterEq;
		$lb= $request->lb;
		$ub= $request->ub;
		$type= $request->type;
		$n= $request->n;
		$with= $request->with;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (is_numeric($lb) && is_numeric($ub) && is_numeric($n)) {
			$parem=$EnterEq;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			if ($lb>=$ub) {
				$this->param['error'] = 'The lower limit should be less than the upper limit.';
				return $this->param;
			}
			$diff=($ub-$lb)/$n;
			$final=$lb;
			if ($type!=2) {
				$limit_a[]=$lb;
			}
			$limit="$final";
			while ($final<$ub) {
				$final=$final+$diff;
				$limit_a[]=$final;
				$limit.=", $final";
			}
			$lb_=$lb;
			if ($type==='2') {
				$lb_=$lb_+$diff;
			}
			try {
				$client = new Client();
				$r = $client->post("http://167.172.134.148/new-riemann", [
					'form_params' => [
						'equ'=>$parem,
						'with'=>$with,
						'ub'=>$ub,
						'lb'=>$lb_,
						'n'=>$n,
						'type'=>$type,
						'diff'=>$diff,
					],
					'timeout' => 120,
				]);
				$buffer =  $r->getBody();
				$buffer = json_decode($buffer,true);
				$steps=explode('HA', $buffer[0]);
		    	$this->param['steps'] = $steps;
		    	$this->param['res'] = $buffer[1];
		    	$this->param['enter'] = $buffer[2];
		    	$this->param['ub'] = $ub;
		    	$this->param['lb'] = $lb;
		    	$this->param['n'] = $n;
		    	$this->param['type'] = $type;
		    	$this->param['diff'] = $diff;
		    	$this->param['limit'] = $limit;
		    	$this->param['limit_a'] = $limit_a;
		    	$this->param['with'] = $with;
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $r) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Euler's Method Calculator
	function eulers($request){
		$EnterEq= $request->EnterEq;
		$step= $request->steps;
		$size= $request->size;
		$ini= $request->ini;
		$con= $request->con;
		$find= $request->find;
		// if($size > $find){
		// 	$this->param['error'] = 'Step Size cannot be greater than t1.';
		// 	return $this->param;
		// }
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		// if(preg_match('/=/', $EnterEq)) {
		// 	$this->param['error'] = 'Place Your Expression Without The = Sign.';
		// 	return $this->param;
		// }
		// if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
		// 	$this->param['error'] = 'Please! Check Your Input.';
		// 	return $this->param;
		// }
		$check_eq=str_replace(' ', '', $EnterEq);
		$check_eq=str_replace('sqrt', '', $EnterEq);
		$check_eq=str_replace('exp', '', $check_eq);
		$check_eq=str_replace('y=', '', $check_eq);
		$check_eq=str_replace('f(x)=', '', $check_eq);
		$check_eq=str_replace('y′=', '', $check_eq);
		$check_eq=str_replace("y'=", '', $check_eq);
		$check='';
		if (preg_match("/x/i", $check_eq) && preg_match("/y/i", $check_eq)) {
			$one='x';
			$two='y';
			$check='xy';
		}
		$check2='';
		if (preg_match("/t/i", $check_eq) && preg_match("/y/i", $check_eq)) {
			$check2='ty';
			$one='t';
			$two='y';
		}
		if ($check=='xy' && $check2=='ty') {
			$this->param['error'] = 'Equestion contain more variables.';
			return $this->param;
		}
		if (empty($check2) && empty($check)) {
			$this->param['error'] = 'Please check equation.';
			return $this->param;
		}
		if (is_numeric($size) && is_numeric($ini) && is_numeric($con) && is_numeric($find)) {
			$parem=$EnterEq;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('y=', '', $parem);
			$parem=str_replace('f(x)=', '', $parem);
			$parem=str_replace('y′=', '', $parem);
			$parem=str_replace("y'=", '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^x', 'exp(x)', $parem);
			$parem=str_replace('e^y', 'exp(y)', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$end=$ini;
			// if ($ini>=$find) {
			// 	$this->param['error'] = 'End value should be greater than the initial value.';
			// 	return $this->param;
			// }
			if ($step=='h') {
				if($size > $find){
					$this->param['error'] = 'Step Size cannot be greater than t1.';
					return $this->param;
				}
				$h=$size;
			}else{
				if ($ini>=$find) {
					$this->param['error'] = 't1 value should be greater than the initial value.';
					return $this->param;
				}
				$h=($find-$ini)/$size;
			}
			$length=0;
			while ($end < $find) {
				$end=$end+$h;
				$length++;
			}
			if ($length>100) {
				if ($step=='h') {
					$this->param['error'] = 'Step Size too small.';
				}else{
					$this->param['error'] = 'Number of steps too large.';
				}
				return $this->param;
			}
			// if ((string)$size > (string)$find) {
			// 	if ($step=='h') {
			// 		$this->param['error'] = 'Invalid step size.';
			// 	}else{
			// 		$this->param['error'] = 'Invalid Number of steps.';
			// 	}
			// 	return $this->param;
			// }
			try {
				$client = new Client();
				$r = $client->post("http://167.172.134.148/new-eulers", [
					'form_params' => [
						'equ'=>$parem,
                	 	'one'=>$one,
                	 	'two'=>$two,
                	 	'ini'=>$ini,
                	 	'h'=>$h,
                	 	'con'=>$con,
                	 	'find'=>$find,
					],
					'timeout' => 120,
				]);
				$buffer =  $r->getBody();
				$buffer = json_decode($buffer,true);
				$steps=explode('HA', $buffer[0]);
		    	$steps1=explode('HA', $buffer[1]);
		    	$this->param['steps'] = $steps;
		    	$this->param['steps1'] = $steps1;
		    	$this->param['ans'] = $buffer[2];
		    	$this->param['enter'] = $buffer[3];
		    	$this->param['one'] = $one;
		    	$this->param['two'] = $two;
		    	$this->param['ini'] = $ini;
		    	$this->param['h'] = $h;
		    	$this->param['con'] = $con;
		    	$this->param['step'] = $step;
		    	$this->param['find'] = $find;
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $r) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

