	// Taylor Series Calculator
	function taylor($request){
		$EnterEq= $request->EnterEq;
		$point= $request->point;
		$find= $request->find;
		$n= $request->n;
		$with= $request->with;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if($find == null) {
			$find = "";	
		}
		if (strpos($EnterEq, $with) === false) {
			$this->param['error'] = 'Variable '.$with.' does not exist in the function';
			return $this->param;
		}
		if (is_numeric($point) && is_numeric($n)) {
			$parem=$EnterEq;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('e^x', 'exp(x)', $parem);
			$parem=str_replace('e^y', 'exp(y)', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/taylor', [
					'equ' => $parem,
					'wrt' => $with,
					'how' => $n,
					'find' => $find,
					'point' => $point,
