	// Maclaurin Series Calculator
	function maclaurin($request){
		$EnterEq= $request->EnterEq;
		$point=0;
		$find= $request->find;
		$n= $request->n;
		$with= $request->with;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if($find == null) {
			$find = "";	
		}
		if (is_numeric($n)) {
			$parem=$EnterEq;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('e^x', 'exp(x)', $parem);
			$parem=str_replace('e^y', 'exp(y)', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/taylor', [
					'equ' => $parem,
					'wrt' => $with,
					'how' => $n,
					'find' => $find,
					'point' => $point,
				]);
				$buffer = $response->body();
				$buffer=explode("@HA_", $buffer);
		    	$this->param['eexe'] = $buffer[0];
		    	$this->param['enter'] = $buffer[1];
		    	$this->param['res'] = $buffer[2];
		    	$this->param['series'] = $buffer[3];
		    	if (is_numeric($find)) {
		    		$this->param['efun'] = $buffer[4];
		    		$this->param['eser'] = $buffer[5];
		    		$this->param['efv'] = $buffer[6];
		    		$this->param['fsv'] = $buffer[7];
		    		$this->param['err'] = $buffer[8];
		    	}
				$this->param['RESULT'] = 1;

				return $this->param;
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Implicit Differentiation Calculator
	function implicit($request){
		$EnterEq= $request->EnterEq;
		$EnterEq1= $request->EnterEq1;
		$x= $request->x;
		$y= $request->y;
		$with= $request->with;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
			'EnterEq1' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq) || preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq1)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if($x == null) {
			$x = "";	
		}
		if($y == null) {
			$y = "";	
		}
		if (!empty($with)) {
			$parem=$EnterEq;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('%20', '', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			$parem1=$EnterEq1;
			$parem1=str_replace(' ', '', $parem1);
			$parem1=str_replace('+', 'plus', $parem1);
			$parem1=str_replace('%20', '', $parem1);
			$parem1=str_replace('{', '(', $parem1);
			$parem1=str_replace('}', ')', $parem1);
			$parem1=str_replace('e^x', 'exp(x)', $parem1);
			$parem1=str_replace('e^', 'exp', $parem1);
			$parem1=str_replace('exp^', 'exp', $parem1);
			$parem1=str_replace('^', '**', $parem1);
			$parem1=str_replace('e^sqrt(x)', 'exp(2*x)', $parem1);
			$equ="(".$parem.")-(".$parem1.")";
			try{
				if (is_numeric($x) && is_numeric($y)) {
					$response = Http::timeout(120)->get('http://167.172.134.148/implicit', [
						'equ' => $parem,
						'equ1' => $parem1,
						'with' => $with,
						'x' => $x,
						'y' => $y,
						'main' => $equ,
					]);
            	}else{
					$response = Http::timeout(120)->get('http://167.172.134.148/implicit', [
						'equ' => $parem,
						'equ1' => $parem1,
						'with' => $with,
						'main' => $equ,
					]);
            	}
				$buffer = $response->body();
				$buffer=explode("@@@", $buffer);
				$this->param['res'] = $buffer[0];
				$this->param['enter'] = $buffer[1];
				$this->param['enter1'] = $buffer[2];
				if (is_numeric($x) && is_numeric($y)) {
					$this->param['resf'] = $buffer[3];
				}
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Washer Method Calculator
	function washer($request){
		$EnterEq= $request->EnterEq;
		$EnterEq1= $request->EnterEq1;
		$ub= $request->ub;
		$lb= $request->lb;
		$validator = Validator::make($request->all(), [
