	// Partial Derivative Calculator
	function partial($request){
		$EnterEq= $request->EnterEq;
		$with= $request->with;
		$how= $request->how;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$parem=$EnterEq;
		$parem=str_replace(' ', '', $parem);
		$parem=str_replace('+', 'plus', $parem);
		$parem=str_replace('{', '(', $parem);
		$parem=str_replace('}', ')', $parem);
		$parem=str_replace('e^x', 'exp(x)', $parem);
		$parem=str_replace('e^y', 'exp(y)', $parem);
		$parem=str_replace('e^', 'exp', $parem);
		$parem=str_replace('exp^', 'exp', $parem);
		$parem=str_replace('^', '**', $parem);
		$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
		$parem2=$how;
		$parem1=trim($with);
		try{
			$response = Http::timeout(120)->get('http://167.172.134.148/derivative', [
				'equ' => $parem,
				'wrt' => $parem1,
				'how' => $parem2,
			]);
			$buffer = $response->body();
			$buffer=explode("@@@", $buffer);
			if ($how>1) {
				$this->param['enter'] = $buffer[0];
				$this->param['final_res'] = $buffer;
			}else{
				$this->param['buffer'] = $buffer[0];
				$this->param['ans'] = $buffer[1];
				$this->param['enter'] = $buffer[2];
				$this->param['simple'] = $buffer[3];
			}
			$this->param['RESULT'] = 1;
			return $this->param;
		} catch (\Exception $response) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

