		$cub_side = $request->input("cub_side");
		$cub_side_units = $request->input("cub_side_units");
		$cyl_height = $request->input("cyl_height");
		$cyl_height_units = $request->input("cyl_height_units");
		$cyl_diameter = $request->input("cyl_diameter");
		$cyl_diameter_units = $request->input("cyl_diameter_units");
		$con_height = $request->input("con_height");
		$con_height_units = $request->input("con_height_units");
		$con_diameter = $request->input("con_diameter");
		$con_diameter_units = $request->input("con_diameter_units");
		$sph_diameter = $request->input("sph_diameter");
		$sph_diameter_units = $request->input("sph_diameter_units");
		$tri_base = $request->input("tri_base");
		$tri_h = $request->input("tri_h");
		$tri_h_units = $request->input("tri_h_units");
		$tri_base_units = $request->input("tri_base_units");
		$tri_length = $request->input("tri_length");
		$tri_length_units = $request->input("tri_length_units");
		$tri_height = $request->input("tri_height");
		$tri_height_units = $request->input("tri_height_units");
		$volume_select = $request->input("volume_select");
		$pyr_height = $request->input("pyr_height");
		$pyr_height_units = $request->input("pyr_height_units");
		$pyr_side = $request->input("pyr_side");
		$pyr_side_units = $request->input("pyr_side_units");
		$cap_radius = $request->input("cap_radius");
		$cap_radius_units = $request->input("cap_radius_units");
		$cap_height = $request->input("cap_height");
		$cap_height_units = $request->input("cap_height_units");
		$hem_radius = $request->input("hem_radius");
		$hem_radius_units = $request->input("hem_radius_units");
		$hol_height = $request->input("hol_height");
		$hol_height_units = $request->input("hol_height_units");
		$hol_outer_dia = $request->input("hol_outer_dia");
		$hol_outer_dia_units = $request->input("hol_outer_dia_units");
		$hol_inner_dia = $request->input("hol_inner_dia");
		$hol_inner_dia_units = $request->input("hol_inner_dia_units");
		$coni_height = $request->input("coni_height");
		$coni_height_units = $request->input("coni_height_units");
		$coni_bottom_r = $request->input("coni_bottom_r");
		$coni_bottom_r_units = $request->input("coni_bottom_r_units");
		$coni_top_r = $request->input("coni_top_r");
		$coni_top_r_units = $request->input("coni_top_r_units");
		$tru_height = $request->input("tru_height");
		$tru_height_units = $request->input("tru_height_units");
		$tru_top_side = $request->input("tru_top_side");
		$tru_top_side_units = $request->input("tru_top_side_units");
		$tru_base_side = $request->input("tru_base_side");
		$tru_base_side_units = $request->input("tru_base_side_units");
		$ell_sem_a = $request->input("ell_sem_a");
		$ell_sem_a_units = $request->input("ell_sem_a_units");
		$ell_sem_b = $request->input("ell_sem_b");
		$ell_sem_b_units = $request->input("ell_sem_b_units");
		$ell_sem_c = $request->input("ell_sem_c");
		$ell_sem_c_units = $request->input("ell_sem_c_units");
		$square = $request->input("square");
		$square_units = $request->input("square_units");
		$col_height = $request->input("col_height");
		$col_height_units = $request->input("col_height_units");
		$col_radi = $request->input("col_radi");
		$col_radi_units = $request->input("col_radi_units");
		
		function convert_unit($unit, $value) {
			if (isset($unit)) {
				if ($unit == 'cm') {
					$value = $value * 1;
				}elseif ($unit == 'm') {
					$value /= 100; 
				} elseif ($unit == 'in') {
					$value /= 2.54; 
				} elseif ($unit == 'ft') {
					$value /= 30.48; 
				} elseif ($unit == 'yd') {
					$value /= 91.44; 
				}
				return $value;
			}			
		}

		if(isset($volume_select) && $volume_select === 'Rectangular'){
			if(is_numeric($rec_height) && is_numeric($rec_width) && is_numeric($rec_length)){
				$rec_height = convert_unit($rec_height_units,$rec_height);
				$rec_width = convert_unit($rec_width_units,$rec_width);
				$rec_length = convert_unit($rec_length_units,$rec_length);
				$rectangular = $rec_height * $rec_width * $rec_length;
				$this->param[ 'rectangular' ] = $rectangular;
		}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Cube'){
			if(is_numeric($cub_side)){
				$cub_side = convert_unit($cub_side_units,$cub_side);
				$cube = $cub_side * $cub_side * $cub_side;
				$this->param[ 'cube' ] = $cube;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Cylinder'){
			if(is_numeric($cyl_height) && is_numeric($cyl_diameter)){
					$cyl_height = convert_unit($cyl_height_units,$cyl_height);
					$cyl_diameter = convert_unit($cyl_diameter_units,$cyl_diameter);
					$radius = $cyl_diameter / 2;
					$cylinder =pi() * pow($radius, 2) * $cyl_height;
					$this->param[ 'cylinder' ] = $cylinder;
					$this->param[ 'radius' ] = $radius;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Cone'){
			if(is_numeric($con_height) && is_numeric($con_diameter)){
				$con_height = convert_unit($con_height_units,$con_height);
				$con_diameter = convert_unit($con_diameter_units,$con_diameter);
				$radius = $con_diameter / 2;
				$cone = (1/3) * M_PI * pow($radius, 2) * $con_height;
				$this->param[ 'cone' ] = $cone;
				$this->param[ 'radius' ] = $radius;
				
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Sphere'){
			if(is_numeric($sph_diameter)){
				$sph_diameter = convert_unit($sph_diameter_units,$sph_diameter);
				$radius = $sph_diameter / 2;
				$sphere = (4/3) * pi() * pow($radius, 3);
				$this->param[ 'sphere' ] = $sphere;
				$this->param[ 'radius' ] = $radius;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}

		}elseif(isset($volume_select) && $volume_select === 'Triangular'){
			if(is_numeric($tri_height) && is_numeric($tri_base) && is_numeric($tri_length)){
				$tri_a = convert_unit($tri_base_units,$tri_base);
				$tri_b = convert_unit($tri_length_units,$tri_length);
				$tri_c = convert_unit($tri_height_units,$tri_height);
				$tri_d = convert_unit($tri_h_units,$tri_h);

				$triangular = 1/4 * $tri_d * (sqrt(($tri_a + $tri_b + $tri_c)*($tri_b + $tri_c - $tri_a)*
				($tri_c + $tri_a - $tri_b)*($tri_a + $tri_b - $tri_c)));
				
				$baseArea = ($tri_a + $tri_b + $tri_c)*($tri_b + $tri_c - $tri_a)*
				($tri_c + $tri_a - $tri_b)*($tri_a + $tri_b - $tri_c);
				$this->param[ 'triangular' ] = $triangular;
				$this->param[ 'baseArea' ] = $baseArea;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
				return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Capsule'){
			if(is_numeric($cap_radius) && is_numeric($cap_height)){
				$cap_radius = convert_unit($cap_radius_units,$cap_radius);
				$cap_height = convert_unit($cap_height_units,$cap_height);
				
				$capsule = pi() * pow($cap_radius, 2) * ($cap_radius * 4/3 + $cap_height);

				$this->param[ 'capsule' ] = $capsule;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Hemisphere'){
			if(is_numeric($hem_radius)){
				$hem_radius = convert_unit($hem_radius_units,$hem_radius);
				$hemisphere = (2/3) * pi() * pow($hem_radius, 3);
				
				$this->param[ 'hemisphere' ] = $hemisphere;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Hollow'){
			if(is_numeric($hol_height) && is_numeric($hol_outer_dia) && is_numeric($hol_inner_dia)){
				$hol_height = convert_unit($hol_height_units,$hol_height);
				$hol_outer_dia = convert_unit($hol_outer_dia_units,$hol_outer_dia);
				$hol_inner_dia = convert_unit($hol_inner_dia_units,$hol_inner_dia);
				if($hol_outer_dia <= $hol_inner_dia){
					$this->param['error'] = 'Outer diameter should be greater than inner diameter.' ;
					return $this->param;
				}else{
					$rad = pow($hol_outer_dia,2) - pow($hol_inner_dia,2);
					$hollow = pi() * $hol_height * $rad/4;
					$this->param[ 'hollow' ] = $hollow;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Conical'){
			if(is_numeric($coni_height) && is_numeric($coni_bottom_r) && is_numeric($coni_top_r)){
				$coni_height = convert_unit($coni_height_units,$coni_height);
				$coni_bottom_r = convert_unit($coni_bottom_r_units,$coni_bottom_r);
				$coni_top_r = convert_unit($coni_top_r_units,$coni_top_r);
				$At = pi() * pow($coni_top_r, 2); 
				$Ab = pi() * pow($coni_bottom_r, 2);
				$conical = ($coni_height / 3) * ($At + $Ab + sqrt($At * $Ab));
				$this->param[ 'conical' ] = $conical;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Truncated'){
			if(is_numeric($tru_height) && is_numeric($tru_top_side) && is_numeric($tru_base_side)){
				$tru_height = convert_unit($tru_height_units,$tru_height);
				$tru_top_side = convert_unit($tru_top_side_units,$tru_top_side);
				$tru_base_side = convert_unit($tru_base_side_units,$tru_base_side);
					$A1 = ($tru_top_side * $tru_top_side);
					$A2 = ($tru_base_side * $tru_base_side);
					$truncated = (1/3) * $tru_height * ($A1 + $A2 + sqrt($A1 * $A2));
				$this->param[ 'truncated' ] = $truncated;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Ellipsoid'){
			if(is_numeric($ell_sem_a) && is_numeric($ell_sem_b) && is_numeric($ell_sem_c)){
				$ell_sem_a = convert_unit($ell_sem_a_units,$ell_sem_a);
				$ell_sem_b = convert_unit($ell_sem_b_units,$ell_sem_b);
				$ell_sem_c = convert_unit($ell_sem_c_units,$ell_sem_c);
				$ellipsoid = (4/3) * pi() * $ell_sem_a * $ell_sem_b* $ell_sem_c;
				$this->param[ 'ellipsoid' ] = $ellipsoid;
			}else{	
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Pyramid'){
			if(is_numeric($pyr_height) && is_numeric($pyr_side)){
				$pyr_height = convert_unit($pyr_height_units,$pyr_height);
				$pyr_side = convert_unit($pyr_side_units,$pyr_side);
				$baseArea = $pyr_side * $pyr_side;
				$pyramid = (1/3) * $baseArea * $pyr_height;
				$this->param[ 'pyramid' ] = $pyramid;
				$this->param[ 'baseArea' ] = $baseArea;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Square'){
			if(is_numeric($square)){
				$square = convert_unit($square_units,$square);
				
				$square = $square * $square * $square;
				$this->param[ 'square' ] = $square;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Square'){
			if(is_numeric($square)){
				$square = convert_unit($square_units,$square);
				
				$square = $square * $square * $square;
				$this->param[ 'square' ] = $square;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}elseif(isset($volume_select) && $volume_select === 'Column'){
			if(is_numeric($col_height) && is_numeric($col_radi) ){
				$col_radi = convert_unit($col_radi_units,$col_radi);
				$col_height = convert_unit($col_height_units,$col_height);
				
				$column = pi() * pow($col_radi, 2) * $col_height;
				$this->param[ 'column' ] = $column;
			}else{
				$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
			}
		}
		$this->param[ 'RESULT' ] = 1;
		return $this->param;
	}

	// POLYGON CALCULATOR
	public function polygon($request){
		$num1=$request->input('operations');
		$num2=$request->input('npolygon');
		$num3=$request->input('calculation');
		$Label=$request->input('labl');
		$pie=$request->input('pie');
		$unit=$request->input('units');

			if (is_numeric($Label) && is_numeric($pie)) {
				$nvalue=$num1;
			if ($nvalue==15) {
				$nvalue=$num2;
				if (!is_numeric($nvalue) && $nvalue<=0) {
					$this->param['error'] = 'Enter number of polygon:';
					return $this->param;
				}
			}
			if($num3=='01'){
				$num01= $pie / $nvalue;
				$co=1 / tan($num01);
				$res=0.5*$Label;
				$inradius=$res*$co;
				$se=1/cos($num01);
				$circumradius=$inradius*$se;
				$rr=$inradius*$inradius;
				$nr=$nvalue*$rr;
				$ta=tan($num01);
				$area=$nr*$ta;
				$perimeter=$nvalue*$Label;
				$sub=$nvalue-2;
				$di=$sub/$nvalue;
				$interior=$di*180;
				$extrior= 360 / $nvalue;
				$side_a=$Label;
			}
			if($num3=='02'){
				$a2=tan($pie/$nvalue);
				$a0=2*$Label;
				$side_a=$a2*$a0;
				$r1=0.5 * $side_a;
				$r2=1/$a2;
				$inradius=$r1*$r2;
				$R1=1/cos($pie/$nvalue);
				$circumradius=$inradius*$R1;
				$A1=$inradius*$inradius;
				$A2=$nvalue*$A1;
				$area=$A2*$a2;
				$perimeter=$nvalue*$side_a;
				$sub=$nvalue-2;
				$di=$sub/$nvalue;
				$interior=$di*180;
				$extrior= 360 / $nvalue;
			}
			if ($num3=='03') {
				$Ra=2 * $Label;
				$Ra1=sin($pie/$nvalue);
				$side_a=$Ra*$Ra1;
				$inradius=$Label*cos($pie/$nvalue);
				$RR1=1/cos($pie/$nvalue);
				$circumradius=$inradius*$RR1;
				$area=$nvalue*pow($inradius, 2) * tan($pie/$nvalue);
				$perimeter=$nvalue*$side_a;
				$sub=$nvalue-2;
				$di=$sub/$nvalue;
				$interior=$di*180;
				$extrior= 360 / $nvalue;
			}
			if ($num3=='04') {
				$nvalue=$num1;
				$Aa1=tan($pie/$nvalue);
				$Aa2=4*$Aa1*$Label;
				$Aa3=$Aa2/$nvalue;
				$side_a=sqrt($Aa3);
				$Ar1=1/tan($pie/$nvalue);
				$inradius=0.5*$side_a*$Ar1;
				$AR1=1/cos($pie/$nvalue);
				$circumradius=$inradius*$AR1;
				$perimeter=$nvalue*$side_a;
				$sub=$nvalue-2;
				$di=$sub/$nvalue;
				$interior=$di*180;
				$extrior= 360 / $nvalue;
				$area=$Label;
			}
			if ($num3=='05') {
				$side_a=$Label/$nvalue;
				$pr1=1/tan($pie/$nvalue);
				$inradius=0.5*$side_a*$pr1;
				$pR1=1/cos($pie/$nvalue);
				$circumradius=$inradius*$pR1;
				$pA1=$inradius*$inradius;
				$pA2=$nvalue*$pA1;
				$pA3=tan($pie/$nvalue);
				$area=$pA2*$pA3;
				$sub=$nvalue-2;
				$di=$sub/$nvalue;
				$interior=$di*180;
				$extrior= 360 / $nvalue;
				$perimeter=$Label;
			}
			$this->param['nvalue'] = $nvalue;
			$this->param['side_a'] = $side_a;
			$this->param['inradius'] = $inradius;
			$this->param['circumradius'] = $circumradius;
			$this->param['area'] = $area;
			$this->param['perimeter'] = $perimeter;
			$this->param['interior'] = $interior;
			$this->param['extrior'] = $extrior;
			$this->param['unit'] = $unit;
				$this->param['RESULT'] = 1;
			return $this->param;
			}else{
			$this->param['error'] = 'Please Check Your Input';
			return $this->param;
			}
	}

	// Vector Addition Calculator
	public function vector_addition($request){
		//  dd($request->all());
		$calculation=$request->input('calculation');
		$operation=$request->input('operation');
		$alpha=$request->input('alpha');
		$beta=$request->input('beta');
		$vectora_representation=$request->input('vectora_representation');
		$ax=$request->input('ax');
		$ay=$request->input('ay');
		$az=$request->input('az');
		$vectorb_representation=$request->input('vectorb_representation');
		$bx=$request->input('bx');
		$by=$request->input('by');
		$bz=$request->input('bz');
		$magnitude_x=$request->input('magnitude_x');
		$direction_x=$request->input('direction_x');
		$direction_x_unit=$request->input('direction_x_unit');
		$magnitude_y=$request->input('magnitude_y');
		$direction_y=$request->input('direction_y');
		$direction_y_unit=$request->input('direction_y_unit');
		function convert_angle($unit,$value){
			// dd($unit,$value);
			if($unit=="deg"){
				$val1=$value*0.017453;
			}else if($unit=="rad"){
				$val1=$value*1;
			}else if($unit=="gon"){
				$val1=$value*0.015708;
			}else if($unit=="tr"){
				$val1=$value*6.283;
			}else if($unit=="arcmin"){
				$val1=$value*0.0002909;
			}else if($unit=="arcsec"){
				$val1=$value*0.000004848;
			}else if($unit=="mrad"){
				$val1=$value*0.001;
			}else if($unit=="μrad"){
				$val1=$value*0.000001;
			}else if($unit=="* π rad"){
				$val1=$value*3.1416;
			}
			return $val1;
		}
		if($calculation=="3D"){//Three Dimensional
			if($operation=="1"){//Addition without multiples
				if(is_numeric($ax) && is_numeric($ay) && is_numeric($bx) && is_numeric($by) && is_numeric($az) && is_numeric($bz)){
					$calculate_x=($ax+$bx);
					$calculate_y=($ay+$by);
					$calculate_z=($az+$bz);
					$calculate_m=sqrt(($ax+$bx)*($ax+$bx)+($ay+$by)*($ay+$by));
					$q=$bx+$ax;
					$theta=acos($q/$calculate_m);	
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}else if($operation=="2"){//Addition with multiplies
				if(is_numeric($ax) && is_numeric($ay) && is_numeric($bx) && is_numeric($by) && is_numeric($az) && is_numeric($bz) && is_numeric($alpha) && is_numeric($bx) && is_numeric($beta)){
					$calculate_x=($ax*$alpha)+($bx*$beta);
					$calculate_y=($ay*$alpha)+($by*$beta);
					$calculate_z=($az*$alpha)+($bz*$beta);
					
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}else if($operation=="3"){//Subtraction without multiplies
				if(is_numeric($ax) && is_numeric($ay) && is_numeric($bx) && is_numeric($by) && is_numeric($az) && is_numeric($bz) && is_numeric($alpha) && is_numeric($bx) && is_numeric($beta)){
					$calculate_x=($ax-$bx);
					$calculate_y=($ay-$by);
					$calculate_z=($az-$bz);
					
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}else if($operation=="4"){//Subtraction with multiplies
				if(is_numeric($ax) && is_numeric($ay) && is_numeric($bx) && is_numeric($by) && is_numeric($az) && is_numeric($bz) && is_numeric($alpha) && is_numeric($bx) && is_numeric($beta)){
					$calculate_x=($ax*$alpha)-($bx*$beta);
					$calculate_y=($ay*$alpha)-($by*$beta);
					$calculate_z=($az*$alpha)-($bz*$beta);
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}
			$this->param['x']=$calculate_x;
			$this->param['y']=$calculate_y;
			$this->param['z']=$calculate_z;
			$this->param['operation']=$operation;
		}else if($calculation=="2D"){
			
			if($operation=="1" || $operation=="2" || $operation=="3" || $operation=="4"){//Addition without multiples
				if($vectora_representation=="1" && $vectorb_representation=="1"){//When both are cartesian coordinates
					if(is_numeric($ax) && is_numeric($ay) && is_numeric($bx) && is_numeric($by)){
						if($operation=="1"){
							$calculate_x=$ax+$bx;
							$calculate_y=$ay+$by;
							$calculate_m=sqrt(($ax+$bx)*($ax+$bx)+($ay+$by)*($ay+$by));
							$q=$bx+$ax;
							$theta=acos($q/$calculate_m);
							$method=1;
						}else if($operation=="2"){
							if(is_numeric($alpha) && is_numeric($beta)){
								$calculate_x=($ax*$alpha)+($bx*$beta);
								$calculate_y=($ay*$alpha)+($by*$beta);
								$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
								$q=$calculate_x;
								$theta=acos($q/$calculate_m);	
							}else{
								$this->param['error'] = 'Please! Check your input';
								return $this->param;
							}
							$method=1;
						}else if($operation=="3"){
							$calculate_x=$ax-$bx;
							$calculate_y=$ay-$by;
							$calculate_m=sqrt(($ax-$bx)*($ax-$bx)+($ay-$by)*($ay-$by));
							$q=$ax-$bx;
								if ($calculate_m == 0.0) {
									if ($q == 0.0) {
										$theta = 0; // You are **forcing** answer to 0
									} else {
										$theta = INF; // or some defined large value
									}
								} else {
									$theta=acos($q/$calculate_m);
								}
							$method=2;
						}else if($operation=="4"){
							if(is_numeric($alpha) && is_numeric($beta)){
								$calculate_x=($ax*$alpha)-($bx*$beta);
								$calculate_y=($ay*$alpha)-($by*$beta);
								$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
								// $theta=acos($calculate_x/$calculate_m);
								if ($calculate_m != 0) {
									$theta = acos($calculate_x / $calculate_m);
								} else {
									$theta = null; // or some fallback value
								
								}
								
								$method=2;
							}else{
								$this->param['error'] = 'Please! Check your input';
								return $this->param;	
							}
							
						}
					}else{
						$this->param['error'] = 'Please! Check your input';
						return $this->param;
					}
				}else if($vectora_representation=="1" && $vectorb_representation=="2"){//When x is coordinate and y is magnitude
					if(is_numeric($ax) && is_numeric($ay) && is_numeric($magnitude_y) && is_numeric($direction_y)){
						$direction_y_value=convert_angle($direction_y_unit,$direction_y);
						if($operation=="1"){
							$calculate_x=round($ax+$magnitude_y*cos($direction_y_value),4);
							$calculate_y=round($ay+$magnitude_y*sin($direction_y_value),4);
							$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
							$q=$calculate_x;
							$theta=acos($q/$calculate_m);
							$method=1;	
						}else if($operation=="2"){
							if(is_numeric($alpha) && is_numeric($beta)){
								$calculate_x=(($ax*$alpha)+($magnitude_y*$beta)*cos($direction_y_value));
								$calculate_y=(($ay*$alpha)+$magnitude_y*(sin($direction_y_value)*$beta));
								$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
								$q=$calculate_x;
								$theta=acos($q/$calculate_m);
							}else{
								$this->param['error'] = 'Please! Check your input';
								return $this->param;			
							}
							$method=1;
						}else if($operation=="3"){
							$calculate_x=$ax-$magnitude_y*cos($direction_y_value);
							$calculate_y=$ay-$magnitude_y*sin($direction_y_value);
							$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
							$q=$calculate_x;
							$theta=acos($q/$calculate_m);
							$method=2;	
						}else if($operation=="4"){
							if(is_numeric($alpha) && is_numeric($beta)){
								$calculate_x=($ax*$alpha)-($magnitude_y*$beta)*cos($direction_y_value);
								$calculate_y=($ay*$alpha)-$magnitude_y*(sin($direction_y_value)*$beta);
								$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
								$q=$calculate_x;
								$theta=acos($q/$calculate_m);
							}else{
								$this->param['error'] = 'Please! Check your input';
								return $this->param;	
							}
							$method=2;
						}
					}else{
						$this->param['error'] = 'Please! Check your input';
						return $this->param;
					}
				}else if($vectorb_representation=="1" && $vectora_representation=="2"){//When x is magnitude and y is coordinate
					if(is_numeric($bx) && is_numeric($by) && is_numeric($magnitude_x) && is_numeric($direction_x)){
						$direction_x_value=convert_angle($direction_x_unit,$direction_x);
						if($operation=="1"){
							$calculate_x=$magnitude_x*cos($direction_x_value)+$bx;
							$calculate_y=$magnitude_x*sin($direction_x_value)+$by;
							$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
							$theta=acos($calculate_x/$calculate_m);
							$method=1;	
						}else if($operation=="2"){
							if(is_numeric($alpha) && is_numeric($beta)){
								$calculate_x=($magnitude_x*cos($direction_x_value)*$alpha)+($bx*$beta);
								$calculate_y=($magnitude_x*sin($direction_x_value)*$alpha)+($by*$beta);
								$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
								$theta=acos($calculate_x/$calculate_m);
							}else{
								$this->param['error'] = 'Please! Check your input';
								return $this->param;			
							}
							$method=1;
						}else if($operation=="3"){
							$calculate_x=round($bx-$magnitude_x*cos($direction_x_value),4);
							$calculate_y=round($by-$magnitude_x*sin($direction_x_value),4);
							$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
							$q=$calculate_x;
							$theta=acos($q/$calculate_m);
							$method=2;
						}else if($operation=="4"){
							if(is_numeric($alpha) && is_numeric($beta)){
								$calculate_x=($magnitude_x*cos($direction_x_value)*$alpha)-($bx*$beta);
								$calculate_y=($magnitude_x*sin($direction_x_value)*$alpha)-($by*$beta);
								$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
								$theta=acos($calculate_x/$calculate_m);
							}else{
								$this->param['error'] = 'Please! Check your input';
								return $this->param;
							}
							$method=2;
						}
					}else{
						$this->param['error'] = 'Please! Check your input';
						return $this->param;
					}
				}else if($vectorb_representation=="2" && $vectora_representation=="2"){//When x is magnitude and y is magnitude
					if(is_numeric($magnitude_y) && is_numeric($direction_y) && is_numeric($magnitude_x) && is_numeric($direction_x)){
						if($operation=="1"){
							$direction_x_value=convert_angle($direction_x_unit,$direction_x);
							$direction_y_value=convert_angle($direction_y_unit,$direction_y);
							$x1=$magnitude_x*cos($direction_x_value);
							$x2=$magnitude_x*sin($direction_x_value);
							$y1=$magnitude_y*cos($direction_y_value);
							$y2=$magnitude_y*sin($direction_y_value);	
							$calculate_x=$x1+$y1;
							$calculate_y=$x2+$y2;	
							$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
							$q=$x1+$x2;
							$theta=acos($calculate_x/$calculate_m);
							$method=1;	
						}else if($operation=="2"){
							if(is_numeric($alpha) && is_numeric($beta)){
								$direction_x_value=convert_angle($direction_x_unit,$direction_x);
								$direction_y_value=convert_angle($direction_y_unit,$direction_y);
								$x1=$magnitude_x*cos($direction_x_value)*$alpha;
								$x2=$magnitude_x*sin($direction_x_value)*$alpha;
								$y1=$magnitude_y*cos($direction_y_value)*$beta;
								$y2=$magnitude_y*sin($direction_y_value)*$beta;	
								$calculate_x=$x1+$y1;
								$calculate_y=$x2+$y2;	
								$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
								$q=$x1+$x2;
								$theta=acos($calculate_x/$calculate_m);
								$method=1;
							}else{
								$this->param['error'] = 'Please! Check your input';
								return $this->param;			
							}
						}else if($operation=="3"){
							$direction_x_value=convert_angle($direction_x_unit,$direction_x);
							$direction_y_value=convert_angle($direction_y_unit,$direction_y);
							$x1=$magnitude_x*cos($direction_x_value);
							$x2=$magnitude_x*sin($direction_x_value);
							$y1=$magnitude_y*cos($direction_y_value);
							$y2=$magnitude_y*sin($direction_y_value);	
							$calculate_x=$x1-$y1;
							$calculate_y=$x2-$y2;	
							$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
							$q=$x1+$x2;
							$theta=acos($calculate_x/$calculate_m);
							$method=2;
						}
						else if($operation=="4"){
							if(is_numeric($alpha) && is_numeric($beta)){
								$direction_x_value=convert_angle($direction_x_unit,$direction_x);
								$direction_y_value=convert_angle($direction_y_unit,$direction_y);
								$x1=$magnitude_x*cos($direction_x_value)*$alpha;
								$x2=$magnitude_x*sin($direction_x_value)*$alpha;
								$y1=$magnitude_y*cos($direction_y_value)*$beta;
								$y2=$magnitude_y*sin($direction_y_value)*$beta;	
								$calculate_x=$x1-$y1;
								$calculate_y=$x2-$y2;	
								$calculate_m=sqrt(($calculate_x)*($calculate_x)+($calculate_y)*($calculate_y));
								$q=$x1+$x2;
									if ($calculate_m == 0.0) {
									if ($calculate_x == 0.0) {
										$theta = 0; // You are **forcing** answer to 0
									} else {
										$theta = INF; // or some defined large value
									}
								} else {
									$theta=acos($calculate_x/$calculate_m);
								}

							}else{
								$this->param['error'] = 'Please! Check your input';
								return $this->param;			
							}
							$method=2;
						}
					}else{
						$this->param['error'] = 'Please! Check your input';
						return $this->param;
					}
				}
			}
			$this->param['x']=$calculate_x;
			$this->param['y']=$calculate_y;
			$this->param['m']=$calculate_m;
			$this->param['theta']=$theta;	
			$this->param['method']=$method;
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	/**********************
	Venn DiaGram Calculator
	**********************/
	public function venn($request){
		$submit = trim( $request->input( 'selection' ));
		$venn_name = trim( $request->input( 'venn_name' ));
		$ta = trim( $request->input( 'ta' ));
		$tb = trim( $request->input( 'tb' ));
		$a = trim( $request->input( 'a' ));
		$b = trim( $request->input( 'b' ));
		$u = trim( $request->input( 'u' ));
		$c = trim( $request->input( 'c' ));
		$venn_name3 = trim( $request->input( 'venn_name3' ));
		$ta3 = trim( $request->input( 'ta3' ));
		$tb3 = trim( $request->input( 'tb3' ));
		$tc3 = trim( $request->input( 'tc3' ));
		$a3 = trim( $request->input( 'a3' ));
		$b3 = trim( $request->input( 'b3' ));
		$c3 = trim( $request->input( 'c3' ));
		$u3 = trim( $request->input( 'u3' ));
		$anb3 = trim( $request->input( 'anb3' ));
		$bnc3 = trim( $request->input( 'bnc3' ));
		$cna3 = trim( $request->input( 'cna3' ));
		$anbnc = trim( $request->input( 'anbnc' ));
		

		// echo $z_score;
		if($submit == 'twoset'){
			if ( !empty( $venn_name ) && !empty( $ta ) && !empty( $tb ) && is_numeric($a) && is_numeric($b) && is_numeric($u) && is_numeric($c)) {
				
				$a_only = $a - $c;
				$b_only = $b - $c;
				$res = $a_only + $b_only + $c;
				$res2set = $u - ($a_only + $b_only + $c);	
				// echo ($res2set);die;
				
			}
			else {
				$this->param ['error'] = 'Please! Check Your Input' ;
				return $this->param;
			}
		}else if($submit == 'threeset'){
			 if(!empty( $venn_name3 ) && !empty( $ta3 ) && !empty( $tb3 ) && !empty( $tc3 ) && is_numeric($a3) && is_numeric($b3) 
			 && is_numeric($c3) && is_numeric($u3) && is_numeric($anb3) && is_numeric($bnc3) && is_numeric($cna3) && is_numeric($anbnc)){

					$ab = $anb3 - $anbnc;
					$bc = $bnc3 - $anbnc;
					$ca = $cna3 - $anbnc;

					$a_only = $a3 - ($ab + $anbnc + $ca);
					$b_only = $b3 - ($bc + $anbnc + $ab);
					$c_only = $c3 - ($bc + $anbnc + $ca);
					$res = $a_only + $b_only + $c_only + $ab + $bc + $ca + $anbnc;
					$d = $u3 - ($a_only + $b_only + $c_only + $ab + $bc + $ca + $anbnc);	

			}else {
				$this->param['error'] = 'Please! Check Your Input' ;
				return $this->param;
			}
		}else {
			$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
		}

		if($submit == 'twoset'){
				$this->param[ 'res2set' ] = $res2set;
				$this->param[ 'a' ] = $a;
				$this->param[ 'c' ] = $c;
				$this->param[ 'b' ] = $b;
				$this->param[ 'u' ] = $u;
				$this->param[ 'venn_name' ] = $venn_name;
				$this->param[ 'ta' ] = $ta;
				$this->param[ 'tb' ] = $tb;
				$this->param[ 'res' ] = $res;
			
		}
		else if($submit == 'threeset'){
			$this->param[ 'venn_name3' ] = $venn_name3;
			$this->param[ 'u3' ] = $u3;
			$this->param[ 'a3' ] = $a3;
			$this->param[ 'b3' ] = $b3;
			$this->param[ 'c3' ] = $c3;
			$this->param[ 'anb3' ] = $anb3;
			$this->param[ 'bnc3' ] = $bnc3;
			$this->param[ 'cna3' ] = $cna3;
			$this->param[ 'anbnc' ] = $anbnc;
			$this->param[ 'a_only' ] = $a_only;
			$this->param[ 'b_only' ] = $b_only;
			$this->param[ 'c_only' ] = $c_only;
			$this->param[ 'ab' ] = $ab;
			$this->param[ 'bc' ] = $bc;
			$this->param[ 'ca' ] = $ca;
			$this->param[ 'd' ] = $d;
			$this->param[ 'ta3' ] = $ta3;
			$this->param[ 'tb3' ] = $tb3;
			$this->param[ 'tc3' ] = $tc3;
			$this->param[ 'res' ] = $res;

			
		}
		else {
			$this->param['error'] = 'Please! Check Your Input' ;
			return $this->param;
		}
		
		$this->param[ 'RESULT' ] = 1;
		return $this->param;
	}

	/************************
        Surface Area calculator
    ************************/   
    public function surface_area($request){
		$operations=$request->input('operations');
		$shape=$request->input('shape');
		$first=$request->input('first');
		$second=$request->input('second');
		$third=$request->input('third');
		$four=$request->input('four');
		$pi=$request->input('pi');
		$unit1=$request->input('unit1');
		$unit2=$request->input('unit2');
		$unit3=$request->input('unit3');
		$unit4=$request->input('unit4');
		
		function calculation($a,$b){
			// dd($b);
			if($b == 'cm'){
				$val = $a;
			}elseif($b == 'mm'){
				$val = $a / 10;
			}elseif($b == 'm'){
				$val = $a * 100;

			}elseif($b == 'in'){
				$val = $a * 2.54;

			}elseif($b == 'ft'){
				$val = $a * 30.48;

			}elseif($b == 'yd'){
				$val = $a * 91.44;
			}
			return $val;
		}

        $first = calculation($first , $unit1);
        $second = calculation($second , $unit2);
        $third = calculation($third , $unit3);
        $four = calculation($four , $unit4);
        if ($operations == "1") {
            if (is_numeric($first) && is_numeric($second) && is_numeric($pi)) {
                $ttsa = 2 * $pi * $first * ((2 * $first) + $second);
                $this->param['ttsa'] = $ttsa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="2") {
            if (is_numeric($first) && is_numeric($second) && is_numeric($pi)) {
                $s = pow($first, 2) + pow($second, 2);
                $s_sqrt = sqrt($s);
                $lsa = $pi * $first * $s_sqrt;
                $bsa = $pi * pow($first, 2);
                $ttsa = $pi * $first * ($first + $s_sqrt);
                $this->param['lsa'] = $lsa;
                $this->param['bsa'] = $bsa;
                $this->param['ttsa'] = $ttsa;
            }else{
                $this->param['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="3") {
            if (is_numeric($first) && is_numeric($second) && is_numeric($third) && is_numeric($pi)) {
                $top = $pi * pow($first, 2);
                $bsa = $pi * pow($second, 2);
                $s = pow($first - $second, 2) + pow($third, 2);
                $s_sqrt = sqrt($s);
                $ttsa = $pi * ((pow($first, 2)) + (pow($second, 2)) + ($first * $second) * $s_sqrt);
                $lsa = $pi * ($first + $second) * $s_sqrt;
                $this->param['top'] = $top;
                $this->param['bsa'] = $bsa;
                $this->param['ttsa'] = $ttsa;
                $this->param['lsa'] = $lsa;
            }else{
                $this->param['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="4") {
            if (is_numeric($first)) {
                $bsa = pow($first, 2);
                $top = pow($first, 2);
                $lsa = 4 * (pow($first, 2));
                $ttsa = 6 * $bsa;
                $this->param['top'] = $top;
                $this->param['bsa'] = $bsa;
                $this->param['ttsa'] = $ttsa;
                $this->param['lsa'] = $lsa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="5") {
            if (is_numeric($first) && is_numeric($second) && is_numeric($pi)) {
                $top = $pi * pow($first, 2);
                $bsa = $pi * pow($first, 2);
                $ttsa = 2 * $pi * $first * ($second + $first);
                $lsa = $ttsa - ($top + $bsa);
                $this->param['top'] = $top;
                $this->param['bsa'] = $bsa;
                $this->param['ttsa'] = $ttsa;
                $this->param['lsa'] = $lsa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="6") {
            if (is_numeric($first) && is_numeric($pi)) {
                $csa = 2 * $pi * pow($first, 2);
                $bsa = $pi * pow($first, 2);
                $ttsa = 3 * $pi * pow($first, 2);
                $this->param['bsa'] = $bsa;
                $this->param['ttsa'] = $ttsa;
                $this->param['csa'] = $csa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="7") {
            if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
                $bsa = $first * $second;
                $top = $third * $first;
                $top2 = $third * $second;
                $ttsa = 2 * ($bsa + $top + $top2);
                $lsa = $ttsa - ($bsa + $top);
                $this->param['top'] = $top;
                $this->param['bsa'] = $bsa;
                $this->param['ttsa'] = $ttsa;
                $this->param['lsa'] = $lsa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="8") {
            if (is_numeric($first) && is_numeric($pi)) {
                $ttsa = 4 * $pi * pow($first, 2);
                $this->param['ttsa'] = $ttsa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="9") {
            if (is_numeric($first) && is_numeric($second) && is_numeric($pi)) {
                $csa = 2 * $pi * $first * $second;
                $this->param['csa'] = $csa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="10"){
            if (is_numeric($first) && is_numeric($second) && is_numeric($third) && is_numeric($four)) {
                $add = $second + $third;
                if ($first >= $add) {
                    $this->param ['error'] = 'The sum of sides b and c must be greater than side a to form a triangle';
                    return $this->param;
                }
                $top_sq = ($first + $second + $third) * ($second + $third - $first) * ($third + $first - $second) * ($first + $second - $third);
                $top = (1/4) * sqrt($top_sq);
                $bsa = $top;
                $lsa = $four * ($first + $second + $third);
                $ttsa = $top + $bsa + $lsa;
                $this->param['top'] = $top;
                $this->param['bsa'] = $bsa;
                $this->param['ttsa'] = $ttsa;
                $this->param['lsa'] = $lsa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="11") {
            if($shape == 1){
                if (is_numeric($first) && is_numeric($second)) {
                    $height = 0.8660 * $first;
                    $bsa = (pow($first, 2) * sqrt(3)) / 4;
                    $lsa = 1.5 * $first * $second;
                    $ttsa = $bsa + $lsa;
                    $this->param['height'] = $height;
                    $this->param['bsa'] = $bsa;
                    $this->param['lsa'] = $lsa;
                    $this->param['ttsa'] = $ttsa;
                }else{
                    $this->param ['error'] = 'Please check your input';
                    return $this->param;
                }
            }elseif($shape == 2){
                if (is_numeric($first) && is_numeric($second)) {
                    $f_sql = 4 * pow($second, 2);
                    $minus_div = ($f_sql - pow($first, 2)) / 4;

                    $height = sqrt($minus_div);
                    $bsa = pow($first, 2);
                    $lsa = $first * (sqrt(pow($first, 2) + 4 * pow($height, 2)));
                    $ttsa = $bsa + $lsa;
                    $this->param['height'] = $height;
                    $this->param['bsa'] = $bsa;
                    $this->param['lsa'] = $lsa;
                    $this->param['ttsa'] = $ttsa;
                }else{
                    $this->param ['error'] = 'Please check your input';
                    return $this->param;
                }
            }elseif($shape == 3){
                if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
                    $la = sqrt(pow($third, 2) + ((pow($second, 2)) / 4));
                    $lb = sqrt(pow($third, 2) + ((pow($first, 2)) / 4));
                    $bsa = $first * $second;
                    $lsa = $first * $la + $second * $lb;
                    $ttsa = $bsa + $lsa;
                    $this->param['bsa'] = $bsa;
                    $this->param['lsa'] = $lsa;
                    $this->param['ttsa'] = $ttsa;
                }else{
                    $this->param ['error'] = 'Please check your input';
                    return $this->param;
                }
            }elseif($shape == 4){
                if (is_numeric($first) && is_numeric($second)) {
                    $height = sqrt(pow($second, 2) - ((6.25 * pow($first, 2)) / 13.1769));
                    $bsa = 1.7222 * pow($first, 2);
                    $lsa = 2.5 * $first * sqrt((0.474 * pow($first, 2)) + pow($height, 2));
                    $ttsa = $bsa + $lsa;
                    $this->param['height'] = $height;
                    $this->param['bsa'] = $bsa;
                    $this->param['lsa'] = $lsa;
                    $this->param['ttsa'] = $ttsa;
                }else{
                    $this->param ['error'] = 'Please check your input';
                    return $this->param;
                }
            }elseif($shape == 5){
                if (is_numeric($first) && is_numeric($second)) {
                    $height = sqrt(pow($second, 2) - ((3 * pow($first, 2)) / 4));
                    $bsa = 2.5981 * pow($first, 2);
                    $lsa = 3 * $first * sqrt(pow($height, 2) + ((3 * pow($first, 2)) / 4));
                    $ttsa = $bsa + $lsa;
                    $this->param['height'] = $height;
                    $this->param['bsa'] = $bsa;
                    $this->param['lsa'] = $lsa;
                    $this->param['ttsa'] = $ttsa;
                }else{
                    $this->param ['error'] = 'Please check your input';
                    return $this->param;
                }
            }
        }else if ($operations=="12") {
            if (is_numeric($first)) {
                $ttsa = 4 * 3.141593 * pow($first, 2);
                $this->param['ttsa'] = $ttsa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }else if ($operations=="13") {
            if (is_numeric($first) && is_numeric($second) && is_numeric($four)) {
                $f_mul = pow(($first * $second), 1.6);
                $s_mul = pow(($first * $four), 1.6);
                $t_mul = pow(($second * $four), 1.6);
                $divide = ($f_mul + $s_mul + $t_mul) / 3;
                $ttsa = 4 * 3.141593 * pow($divide, 0.625);
                $this->param['ttsa'] = $ttsa;
            }else{
                $this->param ['error'] = 'Please check your input';
                return $this->param;
            }
        }
        $this->param['RESULT'] = 1;
        return $this->param;
    }

	// Angle Between Two Vectors Calculator
	public function angle($request)
	{
	
		$dimen = $request->input('dimen');
		$a_rep = $request->input('a_rep');
