	// volume of triangular_pyramid
	public function triangular_pyramid($request){
		
		$selection=$request->input('selection');
		$triangle_type=$request->input('triangle_type');
		$base=$request->input('base');
		$base_unit=$request->input('base_unit');
		$base_height=$request->input('base_height');
		$base_height_unit=$request->input('base_height_unit');
		$pyramid_height=$request->input('pyramid_height');
		$pyramid_height_unit=$request->input('pyramid_height_unit');
		$pyramid_base_area=$request->input('pyramid_base_area');
		$pyramid_base_area_unit=$request->input('pyramid_base_area_unit');
		$sidea=$request->input('sidea');
		$sidea_length_unit=$request->input('sidea_length_unit');
		$sideb=$request->input('sideb');
		$sideb_length_unit=$request->input('sideb_length_unit');
		$sidec=$request->input('sidec');
		$sidec_length_unit=$request->input('sidec_length_unit');
		$angle_gamma=$request->input('angle_gamma');
		$angle_gamma_unit=$request->input('angle_gamma_unit');
		$angle_beta=$request->input('angle_beta');
		$angle_beta_unit=$request->input('angle_beta_unit');
		
		function unit_convert($unit,$value){
			if($unit=="mm"){
				$val1=$value*0.1;
			}else if($unit=="cm"){
				$val1=$value*1;
			}else if($unit=="m"){
				$val1=$value*100;
			}else if($unit=="km"){
				$val1=$value*1000;
			}else if($unit=="in"){
				$val1=$value*2.54;
			}else if($unit=="ft"){
				$val1=$value*30.48;
			}else if($unit=="yd"){
				$val1=$value*91.44;
			}else if($unit=="mi"){
				$val1=$value*160934;
			}
			return $val1;	
		}
		function angle_convert($unit2,$value2){
			if($unit2=="deg"){
				$val2=$value2 * 0.017453;
			}else if($unit2=="rad"){
				$val2=$value2 * 1;
			}
			return $val2;
		}
		function centi($unit3,$value3){
			if($unit3=="mm²"){
				$val3=$value3*0.01;
			}else if($unit3=="cm²"){
				$val3=$value3*1;
			}else if($unit3=="m²"){
				$val3=$value3*10000;
			}else if($unit3=="km²"){
				$val3=$value3*10000000000;
			}else if($unit3=="in²"){
				$val3=$value3*6.452;
			}else if($unit3=="ft²"){
				$val3=$value3*929;
			}else if($unit3=="yd²"){
				$val3=$value3*8361;
			}else if($unit3=="mi²"){
				$val3=$value3*25899881103;
			}
			return $val3;
		}
		if($selection=="1"){
			if($triangle_type=="1"){
				if(is_numeric($base) && is_numeric($base_height) && is_numeric($pyramid_height)){
					$b_value=unit_convert($base_unit,$base);
					$bh_value=unit_convert($base_height_unit,$base_height);
					$ph_value=unit_convert($pyramid_height_unit,$pyramid_height);
					$pba=($b_value*$bh_value)/2;
					$volume=($pba*$ph_value)/3;	
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}	
			}else if($triangle_type=="2"){
				if(is_numeric($sidea) && is_numeric($sideb) && is_numeric($sidec) && is_numeric($pyramid_height)){
					if($sidea>$sideb+$sidec){
						$this->param['error'] = 'Side a must be less than the sum of the other two sides (b+c)';
						return $this->param;
					}else if($sideb>$sidea+$sidec){
						$this->param['error'] = 'Side b must be less than the sum  of the other two sides (a+c)';
						return $this->param;
					}else if($sidec>$sidea+$sideb){
						$this->param['error'] = 'Side c must be less than the sum of the other two sides (a+b)';
						return $this->param;
					}else{
						$sa_value=unit_convert($sidea_length_unit,$sidea);
						$sb_value=unit_convert($sideb_length_unit,$sideb);
						$sc_value=unit_convert($sidec_length_unit,$sidec);
						$ph_value=unit_convert($pyramid_height_unit,$pyramid_height);
						$sect_one=($sa_value+$sb_value+$sc_value);
						$sect_two=(-$sa_value+$sb_value+$sc_value);
						$sect_three=($sa_value-$sb_value+$sc_value);
						$sect_four=($sa_value+$sb_value-$sc_value);
						$pba=0.25*sqrt($sect_one*$sect_two*$sect_three*$sect_four);
						$volume=($pba*$ph_value)/3;
					}
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}else if($triangle_type=="3"){
				if(is_numeric($sidea) && is_numeric($sideb) && is_numeric($angle_gamma) && is_numeric($pyramid_height)){
					$sa_value=unit_convert($sidea_length_unit,$sidea);
					$sb_value=unit_convert($sideb_length_unit,$sideb);
					$alpha_value=angle_convert($angle_gamma_unit,$angle_gamma);
					if($angle_gamma_unit=="deg"){
						if($alpha_value<180){
						$ph_value=unit_convert($pyramid_height_unit,$pyramid_height);
						$pba=($sa_value*$sb_value*sin($alpha_value))*0.5;
						$volume=($pba*$ph_value)/3;
						}else{
							$this->param['error'] = 'Angles should be between 0 and 180 deg';
							return $this->param;
						}
					}else if($angle_gamma_unit=="rad"){
						if($alpha_value<3){
							$ph_value=unit_convert($pyramid_height_unit,$pyramid_height);
							$pba=($sa_value*$sb_value*sin($alpha_value))*0.5;
							$volume=($pba*$ph_value)/3;
						}else{
							$this->param['error'] = 'Angles should be between 0 and 180 deg';
							return $this->param;
						}
					}
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}else if($triangle_type=="4"){
				if(is_numeric($sidea) && is_numeric($angle_beta) && is_numeric($angle_gamma) && is_numeric($pyramid_height)){
					$sa_value=unit_convert($sidea_length_unit,$sidea);
					if($angle_gamma_unit=="rad"){
						$angle_gamma_unit = "57.3";
						$ang=$angle_gamma_unit/$angle_gamma_unit;
						$alpha_value=$angle_gamma*$ang;
					}else if($angle_gamma_unit=="deg"){
						$angle_gamma_unit= "0.017453";
						$alpha_value=$angle_gamma*$angle_gamma_unit;
					}
					if($angle_beta_unit=="rad"){
						$angle_beta_unit = "57.3";
						$ang2=$angle_beta_unit/$angle_beta_unit;
						$beta_value=$angle_beta*$ang2;
					}else if($angle_beta_unit=="deg"){
						$angle_beta_unit= "0.017453";
						$beta_value=$angle_beta*$angle_beta_unit;
					}
					// $alpha_value=$angle_gamma*$ang;
					// $beta_value=$angle_beta*$ang2;
					// dd($alpha_value);
					if($alpha_value<180 && $beta_value<180){
						if($alpha_value+$beta_value<180){
						$ph_value=unit_convert($pyramid_height_unit,$pyramid_height);
						$sect1=$sa_value*$sa_value*sin($beta_value)*sin($alpha_value);
						$sect2=2*sin($alpha_value+$beta_value);
						$pba=$sect1/$sect2;
						$volume=($pba*$ph_value)/3;	
						}else{
							$this->param['error'] = 'The sum of the two angles cannot exceed 180 deg.';
							return $this->param;
						}
					}else{
						$this->param['error'] = 'Angles should be between 0 and 180 deg range';
						return $this->param;	
					}
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}
			$this->param['pba']=$pba;
			$this->param['volume']=$volume;
		}else if($selection=="2"){
			if(is_numeric($pyramid_base_area) && is_numeric($pyramid_height)){
				$pb_value=centi($pyramid_base_area_unit,$pyramid_base_area);
				$ph_value=unit_convert($pyramid_height_unit,$pyramid_height);
				$volume=($pb_value*$ph_value)/3;
				$this->param['volume']=$volume;
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}
		$this->param['RESULT'] = 1;


		return $this->param;
	}

	// area calculator
	public function areaa($request){
		$shapes=$request->input('shapes');
		$radius=$request->input('radius');
		$radius_unit=$request->input('radius_unit');
		$area=$request->input('area');
		$area_unit=$request->input('area_unit');
		$box=$request->input('box');
		$box_unit=$request->input('box_unit');
		$angle_alpha=$request->input('angle_alpha');
		$angle_alpha_unit=$request->input('angle_alpha_unit');
		$height=$request->input('height');
		$height_unit=$request->input('height_unit');
		$bara_radius=$request->input('bara_radius');
		$bara_radius_unit=$request->input('bara_radius_unit');
		$e=$request->input('e');
		$e_unit=$request->input('e_unit');
		$f=$request->input('f');
		$f_unit=$request->input('f_unit');
		$number_of_sides=$request->input('number_of_sides');
		$find_triangle=$request->input('find_triangle');
		$find_triangle_two=$request->input('find_triangle_two');
		$find_triangle_three=$request->input('find_triangle_three');
		$find_triangle_four=$request->input('find_triangle_four');
		$c=$request->input('c');
		$c_unit=$request->input('c_unit');
		$angle_gamma=$request->input('angle_gamma');
		$angle_gamma_unit=$request->input('angle_gamma_unit');
		$angle_beta=$request->input('angle_beta');
		$angle_beta_unit=$request->input('angle_beta_unit');
		$angle_theta=$request->input('angle_theta');
		$angle_theta_unit=$request->input('angle_theta_unit');

		function unit_convert($unit,$value){
			if($unit=="mm"){
				$val1=$value*0.1;
			}else if($unit=="cm"){
				$val1=$value*1;
			}else if($unit=="m"){
				$val1=$value*100;
			}else if($unit=="km"){
				$val1=$value*1000;
			}else if($unit=="in"){
				$val1=$value*2.54;
			}else if($unit=="ft"){
				$val1=$value*30.48;
			}else if($unit=="yd"){
				$val1=$value*91.44;
			}else if($unit=="mi"){
				$val1=$value*160934;
			}
			return $val1;	
		}
		function angle_convert($unit2,$value2){
			if($unit2=="deg"){
				$val2=$value2*0.017453;
			}else if($unit2=="rad"){
				$val2=$value2*1;
			}
			return $val2;
		}
		function centi($unit3,$value3){
			if($unit3=="mm²"){
				$val3=$value3*0.01;
			}else if($unit3=="cm²"){
				$val3=$value3*1;
			}else if($unit3=="m²"){
				$val3=$value3*10000;
			}else if($unit3=="km²"){
				$val3=$value3*10000000000;
			}else if($unit3=="in²"){
				$val3=$value3*6.452;
			}else if($unit3=="ft²"){
				$val3=$value3*929;
			}else if($unit3=="yd²"){
				$val3=$value3*8361;
			}else if($unit3=="mi²"){
				$val3=$value3*25899881103;
			}
			return $val3;
		}
		if($shapes=="square"){
			$method=1;
			if(is_numeric($area)){
				$area_value= unit_convert($area_unit,$area);
				$answer=$area_value*$area_value;
				$this->param['area']=$area;
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if($shapes=="rectangle"){
			$method=2;
			if(is_numeric($area) && is_numeric($box)){
				$area_value= unit_convert($area_unit,$area);
				$box_value=unit_convert($box_unit,$box);
				$this->param['area']=$area_value;
				$this->param['box']=$box_value;
				$answer=$area_value*$box_value;
				
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if($shapes=="triangle"){
			if($find_triangle=="1"){
				$method=31;
				if(is_numeric($box) && is_numeric($height)){
					$box_value=unit_convert($box_unit,$box);
					$height_value=unit_convert($height_unit,$height);
					$this->param['height']=$height_value;
					$this->param['box']=$box_value;
					$answer=$box_value*$height_value/2;	
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}else if($find_triangle=="2"){
				$method=32;
				if(is_numeric($box) && is_numeric($area) && is_numeric($c)){
					$box_value=unit_convert($box_unit,$box);
					$area_value=unit_convert($area_unit,$area);
					$c_value=unit_convert($c_unit,$c);
					$sect_one=($area_value+$box_value+$c_value);
					$sect_two=(-$area_value+$box_value+$c_value);
					$sect_three=($area_value-$box_value+$c_value);
					$sect_four=($area_value+$box_value-$c_value);
					$answer=0.25*sqrt($sect_one*$sect_two*$sect_three*$sect_four);
					$this->param['area']=$area_value;
					$this->param['box']=$box_value;
					$this->param['c']=$c_value;	
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}else if($find_triangle=="3"){
				$method=33;
				if(is_numeric($area) && is_numeric($box) && is_numeric($angle_gamma)){
					$box_value=unit_convert($box_unit,$box);
					$area_value=unit_convert($area_unit,$area);
					$gamma_value=angle_convert($angle_gamma_unit,$angle_gamma);
					$answer=$area_value*$box_value*sin($gamma_value)*0.5;
					$this->param['area']=$area_value;
					$this->param['box']=$box_value;
					$this->param['gamma']=$gamma_value;
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;	
				}
			}else if($find_triangle=="4"){
				$method=34;
				if(is_numeric($area) && is_numeric($angle_beta) && is_numeric($angle_gamma)){
					$area_value=unit_convert($area_unit,$area);
					$gamma_value=angle_convert($angle_gamma_unit,$angle_gamma);
					$beta_value=angle_convert($angle_beta_unit,$angle_beta);
					if($gamma_value<180 && $beta_value<180){
						if($gamma_value+$beta_value<180){
						$sect1=$area_value*$area_value*sin($beta_value)*sin($gamma_value);
						$sect2=2*sin($gamma_value+$beta_value);
						$answer=$sect1/$sect2;	
						}else{
							$this->session->set_flashdata('triangular','The sum of the two angles cannot exceed 180 deg.');
							return false;
						}
					}else{
						$this->session->set_flashdata('triangular','Angles should be between 0 and 180 deg range');
						return false;	
					}
					$this->param['area']=$area_value;
					$this->param['beta']=$beta_value;
					$this->param['gamma']=$gamma_value;
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;	
				}
			}
		}else if($shapes=="parallelogram"){
			$method=15;
			if($find_triangle_two=="1"){
				if(is_numeric($box) && is_numeric($height)){
					$box_value=unit_convert($box_unit,$box);
					$height_value=unit_convert($height_unit,$height);
					$this->param['height']=$height_value;
					$this->param['box']=$box_value;
					$answer=$box_value*$height_value;
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;	
				}
			}if($find_triangle_two=="2"){
				$method=16;
				if(is_numeric($area) && is_numeric($box) && is_numeric($angle_alpha)){
					$area_value=unit_convert($area_unit,$area);
					$box_value=unit_convert($box_unit,$box);
					$alpha_value=angle_convert($angle_alpha_unit,$angle_alpha);
					$this->param['area']=$area_value;
					$this->param['box']=$box_value;
					$this->param['alpha']=$alpha_value;
					$answer=$box_value*$area_value*sin($alpha_value);
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;	
				}
			}else if($find_triangle_two=="3"){
				$method=17;
				if(is_numeric($e) && is_numeric($f) && is_numeric($angle_theta)){
					$e_value=unit_convert($e_unit,$e);
					$f_value=unit_convert($f_unit,$f);
					$theta_value=angle_convert($angle_theta_unit,$angle_theta);
					$this->param['e']=$e_value;
					$this->param['f']=$f_value;
					$this->param['theta_value']=$theta_value;
					$answer=$e_value*$f_value*sin($theta_value);
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;
				}
			}
		}else if($shapes=="rhombus"){
			if($find_triangle_three=="1"){
				$method=21;
				if(is_numeric($area) && is_numeric($height)){
					$area_value=unit_convert($area_unit,$area);
					$height_value=unit_convert($height_unit,$height);
					$this->param['height']=$height_value;
					$this->param['area']=$area_value;
					$answer=$area_value*$height_value;
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;	
				}
			}else if($find_triangle_three=="2"){
				$method=22;
				if(is_numeric($e) && is_numeric($f)){
					$e_value=unit_convert($e_unit,$e);
					$f_value=unit_convert($f_unit,$f);
					$this->param['e']=$e_value;
					$this->param['f']=$f_value;
					$answer=$e_value*$f_value/2;
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;	
				}
			}else if($find_triangle_three=="3"){
				$method=23;
				if(is_numeric($area) && is_numeric($angle_alpha)){
					$area_value=unit_convert($area_unit,$area);
					$alpha_value=angle_convert($angle_alpha_unit,$angle_alpha);
					$this->param['area']=$area_value;
					$this->param['alpha_value']=$alpha_value;
					$answer=$area_value*$area_value*sin($alpha_value);
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;	
				}
			}
		}else if($shapes=="kite"){
			if($find_triangle_four=="2"){
				$method=24;
				if(is_numeric($area) && is_numeric($box) && is_numeric($angle_alpha)){
					$area_value=unit_convert($area_unit,$area);
					$box_value=unit_convert($box_unit,$box);
					$alpha_value=angle_convert($angle_alpha_unit,$angle_alpha);
					$this->param['area']=$area_value;
					$this->param['box']=$box_value;
					$this->param['alpha']=$alpha_value;
					$answer=$box_value*$area_value*sin($alpha_value);
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;	
				}
			}else if($find_triangle_four=="1"){
				$method=25;
				if(is_numeric($e) && is_numeric($f)){
					$e_value=unit_convert($e_unit,$e);
					$f_value=unit_convert($f_unit,$f);
					$this->param['e']=$e_value;
					$this->param['f']=$f_value;
					$answer=$e_value*$f_value/2;
				}else{
					$this->param['error'] = 'Please! Check your input';
					return $this->param;	
				}
			}
		}else if($shapes=="circle"){
			$method=4;
			if(is_numeric($radius)){
				$radius_value= unit_convert($radius_unit,$radius);
				$answer=$radius_value*$radius_value*3.14159265358;
				$this->param['radius']=$radius_value;
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if($shapes=="semicircle"){
			$method=5;
			if(is_numeric($radius)){
				$radius_value= unit_convert($radius_unit,$radius);
				$answer=($radius_value*$radius_value*3.14159265358)*0.5;
				$this->param['radius']=$radius;
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if($shapes=="sector"){
			$method=6;
			if(is_numeric($angle_alpha) && is_numeric($radius)){
				$radius_value= unit_convert($radius_unit,$radius);
				$angle_value=angle_convert($angle_alpha_unit,$angle_alpha);
				$answer=($radius_value*$radius_value*$angle_value)/2;
				$this->param['angle_value']=$angle_value;
				$this->param['radius']=$radius;
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;	
			}
		}else if($shapes=="ellipse"){
			$method=7;
			if(is_numeric($area) && is_numeric($box)){
				$area_value= unit_convert($area_unit,$area);
				$box_value=unit_convert($box_unit,$box);
				$answer=$area_value*$box_value*3.14;
				$this->param['area']=$area_value;
				$this->param['box']=$box_value;
				
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if($shapes=="trapezoid"){
			$method=8;
			if(is_numeric($area) && is_numeric($box) && is_numeric($height)){
				$area_value= unit_convert($area_unit,$area);
				$box_value=unit_convert($box_unit,$box);
				$height_value=unit_convert($height_unit,$height);
				$answer=($area_value+$box_value)*$height_value/2;
				$this->param['area']=$area_value;
				$this->param['box']=$box_value;
				$this->param['height']=$height_value;
				
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if($shapes=="regular pentagon"){
			$method=9;
			if(is_numeric($area)){
				$area_value= unit_convert($area_unit,$area);
				$answer=$area_value*$area_value*sqrt(25+10*sqrt(5))/4;
				$this->param['area']=$area_value;
				
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if($shapes=="regular hexagon"){
			$method=10;
			if(is_numeric($area)){
				$area_value= unit_convert($area_unit,$area);
				$answer=3/2*sqrt(3)*$area_value*$area_value;
				$this->param['area']=$area_value;
				
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if($shapes=="regular octagon"){
			$method=11;
			if(is_numeric($area)){
				$area_value= unit_convert($area_unit,$area);
				$answer=2*(1+sqrt(2))*$area_value*$area_value;
				$this->param['area']=$area_value;
				
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if($shapes=="annulus (ring)"){
			$method=12;
			if(is_numeric($radius) && is_numeric($bara_radius)){
				if($bara_radius>$radius){
					$radius_value= unit_convert($radius_unit,$radius);
					$bara_radius_value= unit_convert($bara_radius_unit,$bara_radius);
					$answer=3.14159265358*($bara_radius_value*$bara_radius_value-$radius_value*$radius_value);
					$this->param['radius']=$radius_value;
					$this->param['bara_radius']=$bara_radius_value;	
				}else{
					$this->param['error'] = 'Radius R should be greater than r.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if ($shapes=="irregular quadrilateral") {
			$method=13;
			if(is_numeric($e) && is_numeric($f) && is_numeric($angle_alpha)){
				$e_value=unit_convert($e_unit,$e);
				$f_value=unit_convert($f_unit,$f);
				$angle_value=angle_convert($angle_alpha_unit,$angle_alpha);
				$answer=$e_value*$f_value*sin($angle_value);
				$this->param['e']=$e_value;
				$this->param['f']=$f_value;
				$this->param['angle_value']=$angle_value;
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}else if ($shapes=="regular polygon") {
			$method=14;
			if(is_numeric($area) && is_numeric($number_of_sides)){
				$area_value= unit_convert($area_unit,$area);
				$answer=$number_of_sides*$area_value*$area_value*1/tan(3.14159265358/$number_of_sides)/4;
				$this->param['number_of_sides']=$number_of_sides;
				$this->param['area']=$area_value;
			}else{
				$this->param['error'] = 'Please! Check your input';
				return $this->param;
			}
		}
		$this->param['answer']=$answer;
		$this->param['method']=$method;
		$this->param['RESULT'] = 1;

		return $this->param;
	}

	// permeter calculator
	function perimeter($request){
		// $this->load->library('form_validation');
			$shape=$request->input('shape');
			$given=$request->input('given');
			$givena=$request->input('givena');
			$givena=$request->input('givena');
			$r=$request->input('r');
			$r_unit=$request->input('r_unit');
			$b=$request->input('b');
			$b_unit=$request->input('b_unit');
			$c=$request->input('c');
			$c_unit=$request->input('c_unit');
			$d=$request->input('d');
			$d_unit=$request->input('d_unit');
			$angle=$request->input('angle');
			$angle_unit=$request->input('angle_unit');
			$angleb=$request->input('angleb');
			$nbr=$request->input('nbr');
			$angleb_unit=$request->input('angleb_unit');
		if ($shape==='1') {
			if (is_numeric($r)) {
				$peri=round(($r*4),3).' '.$r_unit;
				$this->param['peri'] = $peri;
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		}elseif ($shape==='2') {
			if (is_numeric($r)) {
				if ($r_unit==$b_unit) {
					$peri=round(2*($r+$b),3).' '.$r_unit;
				}else{
					if ($r_unit=='mm') {
						$r=$r*0.1;
					}elseif($r_unit=='m'){
						$r=$r*100;
					}elseif($r_unit=='in'){
						$r=$r*2.54;
					}elseif ($r_unit=='ft') {
						$r=$r*30.48;
					}elseif($r_unit=='yd'){
						$r=$r*91.44;
					}
					if ($b_unit=='mm') {
						$b=$b*0.1;
					}elseif($b_unit=='m'){
						$b=$b*100;
					}elseif($b_unit=='in'){
						$b=$b*2.54;
					}elseif ($b_unit=='ft') {
						$b=$b*30.48;
					}elseif($b_unit=='yd'){
						$b=$b*91.44;
					}
					$peri=round(2*($r+$b),3).' cm';
				}
				$this->param['peri'] = $peri;
