	// Second Derivative Calculator
	function second($request){
		$EnterEq=$request->EnterEq;
		$with=$request->with;
		$how=2;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$parem=$EnterEq;
		$parem=str_replace(' ', '', $parem);
		$parem=str_replace('+', 'plus', $parem);
		$parem=str_replace('{', '(', $parem);
		$parem=str_replace('}', ')', $parem);
		$parem=str_replace('e^x', 'exp(x)', $parem);
		$parem=str_replace('e^y', 'exp(y)', $parem);
		$parem=str_replace('e^', 'exp', $parem);
		$parem=str_replace('exp^', 'exp', $parem);
		$parem=str_replace('^', '**', $parem);
		$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
		$parem2=$how;
		$parem1=trim($with);
		try{
			$response = Http::timeout(120)->get('http://167.172.134.148/derivative', [
				'equ' => $parem,
				'wrt' => $parem1,
				'how' => $parem2,
			]);
			$buffer = $response->body();
			$buffer=explode("@@@", $buffer);
			$this->param['enter'] = $buffer[0];
			$this->param['final_res'] = $buffer;
			$this->param['RESULT'] = 1;
			return $this->param;
		} catch (\Exception $response) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Even or Odd Function Calculator
	function even($request){
		$EnterEq= $request->EnterEq;
		$with= $request->with;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$parem=$EnterEq;
		$abs=substr_count($parem, "|");
		if ($abs>1) {
			$parem=str_replace('|', '', $parem);
			$this->param['mode'] = $with;
		}
		$parem=str_replace(' ', '', $parem);
		$parem=str_replace('+', 'plus', $parem);
		$parem=str_replace('{', '(', $parem);
		$parem=str_replace('}', ')', $parem);
		$parem=str_replace('e^x', 'exp(x)', $parem);
		$parem=str_replace('e^y', 'exp(y)', $parem);
		$parem=str_replace('e^', ' exp', $parem);
		$parem=str_replace('exp^', 'exp', $parem);
		$parem=str_replace('^', '**', $parem);
		$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
		$new=str_replace('exp','e',$parem);
		$parem1=str_replace($with,'(-'.$with.')',$new);
		$parem1=str_replace('e', ' exp', $parem1);
		try{
			$response = Http::timeout(120)->get('http://167.172.134.148/even', [
				'equ' => $parem,
				'equ1' => $parem1,
				'wrt' => $with,
			]);
			$buffer = $response->body();
			$buffer=explode("@@@", $buffer);
			$this->param['ans'] = $buffer[0];
			$this->param['enter'] = $buffer[1];
			$this->param['with'] = $with;
			$this->param['RESULT'] = 1;
			return $this->param;
		} catch (\Exception $response) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

