	// Simpson's Rule Calculator
	function simpsons($request){
		$EnterEq= $request->EnterEq;
		$lb= $request->lb;
		$ub= $request->ub;
		$n= $request->n;
		$with= $request->with;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/[<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		if(!empty($lb) && !empty($ub) && is_numeric($n)) {
			if ($n%2!=0) {
				$this->param['error'] = 'Number of rectangles should be even number.';
				return $this->param;
			}
			$parem=$EnterEq;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			if ($lb>=$ub) {
				$this->param['error'] = 'The lower limit should be less than the upper limit.';
				return $this->param;
			}
			$diff=($ub-$lb)/$n;
			$final=$lb;
			$limit_a[]=$lb;
			$limit="$final";
			while ($final<$ub) {
				$final=$final+$diff;
				$limit_a[]=$final;
				$limit.=", $final";
			}
			$lb_=$lb;
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/simpsons', [
					'equ' => $parem,
					'with' => $with,
					'lb' => $lb,
					'ub' => $ub,
					'n' => $n,
					'diff' => $diff,
				]);
				$buffer = $response->body();
				$buffer=explode("@@@", $buffer);
			    $error=abs(($buffer[4]-$buffer[1])/$buffer[4]);
			    $steps=explode('HA', $buffer[0]);
		    	$this->param['steps'] = $steps;
		    	$this->param['res'] = $buffer[1];
		    	$this->param['enter'] = $buffer[2];
		    	$this->param['int'] = $buffer[3];
		    	$this->param['intv'] = $buffer[4];
		    	$this->param['errorans'] = $error;
		    	$this->param['ub'] = $ub;
		    	$this->param['lb'] = $lb;
		    	$this->param['n'] = $n;
		    	$this->param['diff'] = $diff;
		    	$this->param['limit'] = $limit;
		    	$this->param['limit_a'] = $limit_a;
		    	$this->param['with'] = $with;
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
  	}

