	// Ellipse Calculator
	function ellipse($request){
		$d1= $request->d1;
		$n2= $request->n2;
		$second_value= $request->second_value;
		$c1= $request->c1;
		$c2= $request->c2;
		$selection= $request->selection;
		if($selection=="1"){
			if(is_numeric($d1) && is_numeric($n2) && is_numeric($second_value) && $d1>0 && $n2>0 && $second_value>0 ){
				if (is_numeric($n2) && is_numeric($d1)) {
					$totalN=$n2;
					$totalD=$d1;
					function gcd($a23,$b23) 
					{
						$a23 = abs($a23); $b23 = abs($b23);

						if( $a23 < $b23)
						{ 
							list($b23,$a23) = Array($a23,$b23);
						}
						if( $b23 == 0){
							return 1;
						}
						$r = $a23 % $b23;
						while($r > 0): 
							$a = $b23;
							$b23 = $r;
							$r = $a % $b23;
						endwhile;
						return $b23;
				
					}
					function reduce($num23,$den23) 
					{
						$g = gcd($num23,$den23);
						return array($num23/$g,$den23/$g);
					}
					$g = gcd($totalN,$totalD);
					list ($upr  , $btm) = reduce($totalN,$totalD);
					// return Values
					$this->param['upr'] =$upr;
					$this->param['totalN'] =$totalN;
					$this->param['totalD'] =$totalD;
					$this->param['g'] =$g;
					$this->param['btm'] =$btm;
					$this->param['method']=$selection;
				}
				if (is_numeric($n2) && is_numeric($second_value)) {
					$totalN1=$n2;
					$totalD1=$second_value;
					$g1= gcd($totalN1,$totalD1);
					list ($upr1  , $btm1) = reduce($totalN1,$totalD1);
					// return Values
					$this->param['upr1'] =$upr1;
					$this->param['totalN1'] =$totalN1;
					$this->param['totalD1'] =$totalD1;
					$this->param['g1'] =$g1;
					$this->param['btm1'] =$btm1;
					$this->param['method']=$selection;
					$this->param['RESULT'] = 1;
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;

			}
		}else if($selection=="2"){
			if(is_numeric($c1) && is_numeric($c2) && is_numeric($d1) && is_numeric($second_value) && $d1>0 && $second_value>0){
				if($d1>$second_value){
					$calculate_eccentricity=sqrt(((($d1*$d1)-($second_value*$second_value))))/$d1;
				}else if($second_value>$d1){
					$calculate_eccentricity=sqrt(((($second_value*$second_value)-($d1*$d1))))/$second_value;
				}
				$area=3.14*$d1*$second_value;
				$this->param['d1']=$d1;
				$this->param['c2']=$second_value;
				$this->param['center1']=$c1;
				$this->param['center2']=$c2;
				$this->param['calculate_eccentricity']=$calculate_eccentricity;
				$this->param['area']=$area;
				$this->param['method']=$selection;
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
	}

