	// Average Percentage Calculator
	function avg_percentage($request){
		$same_sample = $request->same_sample;
		$percentage = $request->percentage;
		$sample = $request->sample;
		$check = true;
		if($same_sample === 'yes'){
			$percentage = array_filter($percentage, function($value){
				return !empty($value);
			});
			if(count($percentage) < 2){
				$check = false;
			}
		}else{
			$percentage = array_filter($percentage, function($value){
				return !empty($value);
			});
			$sample = array_filter($sample, function($value){
				return !empty($value);
			});

			if(count($percentage) < 2 || count($sample) < 2){
				$check = false;
			}
		}

		if($check === true){
			if($same_sample === 'yes'){
				$percents_sum = array_sum($percentage);
				$samples_sum = count($percentage);
			}else{
				$percents = [];
				$percents_show = '';
				$percents_show1 = '';

				foreach($percentage as $key => $value){
					$percents[] = (float)$value * (float)$sample[$key];
					if($key + 1 !== count($percentage)){
						$plus = ' + ';
					}else{
						$plus = '';
					}
					$percents_show .= $value.'\% * '.$sample[$key].$plus;
					$percents_show1 .= $percents[$key].'\%'.$plus;
				}

				$percents_sum = array_sum($percents);
				$samples_sum = array_sum($sample);

				$this->param['percents_show'] = $percents_show;
				$this->param['percents_show1'] = $percents_show1;
			}
			$result = $percents_sum / $samples_sum;
			$this->param['percentage'] = $percentage;
			$this->param['percents_sum'] = $percents_sum;
			$this->param['sample'] = $sample;
			$this->param['samples_sum'] = $samples_sum;
			$this->param['same_sample'] = $same_sample;
			$this->param['result'] = $result;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Rotation Calculator
	function rotation($request){

		$point_rotate_one= $request->point_rotate_one;
		$point_rotate_two= $request->point_rotate_two;
		$angle= $request->angle;
		$unit= $request->unit;
		$point_around_one= $request->point_around_one;
		$point_around_two= $request->point_around_two;
		$direction= $request->direction;
		if($unit=="radians"){
			if(is_numeric($point_rotate_one) && is_numeric($point_rotate_two) && is_numeric($angle) && is_numeric($point_around_one) && is_numeric($point_around_two)){
				if($direction=="anticlockwise" || $direction=="clockwise"){
					if($direction=="clockwise"){
						$angle=$angle*(-1);
					}else if($direction=="anticlockwise"){
						$angle=$angle*(1);
					}
					$first_point=$point_rotate_one-$point_around_one;
					$second_point=$point_rotate_two-$point_around_two;
					$first_part=$first_point*cos($angle);
					$second_part=$second_point*sin($angle);
					$formula=($first_part-$second_part)+$point_around_one;
					$third_part=$first_point*sin($angle);
					$fourth_part=$second_point*cos($angle);
					$formula2=($third_part+$fourth_part)+$point_around_two;
					$this->param['point_rotate_one']=$point_rotate_one;
					$this->param['point_rotate_two']=$point_rotate_two;	
					$this->param['point_around_one']=$point_around_one;
					$this->param['point_around_two']=$point_around_two;
					$this->param['formula_one']=$formula;
					$this->param['formula_two']=$formula2;	
					$this->param['angle']=$angle;
					$this->param['angle2']=$angle;
					$this->param['unit']=$unit;
					$this->param['direction']=$direction;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($unit=="degrees"){
				if(is_numeric($point_rotate_one) && is_numeric($point_rotate_two) && is_numeric($angle) && is_numeric($point_around_one) && is_numeric($point_around_two)){
					if($direction=="anticlockwise" || $direction=="clockwise"){
						if($direction=="clockwise"){
							$angle=$angle*(-1);
						}else if($direction=="anticlockwise"){
							$angle=$angle*(1);
						}
						$first_point=$point_rotate_one-$point_around_one;
						$second_point=$point_rotate_two-$point_around_two;
						$sp=$angle* 3.141592653589793238/180;
						$first_part=$first_point*cos($sp);
						$second_part=$second_point*sin($sp);
						$formula=($first_part-$second_part)+$point_around_one;
						$third_part=$first_point*sin($sp);
						$fourth_part=$second_point*cos($sp);
						$formula2=($third_part+$fourth_part)+$point_around_two;
						$this->param['point_rotate_one']=$point_rotate_one;
						$this->param['point_rotate_two']=$point_rotate_two;	
						$this->param['point_around_one']=$point_around_one;
						$this->param['point_around_two']=$point_around_two;
						$this->param['formula_one']=$formula;
						$this->param['formula_two']=$formula2;	
						$this->param['angle']=$sp;
						$this->param['angle2']=$angle;
						$this->param['direction']=$direction;
						$this->param['unit']=$unit;
					}
				}else{
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}	
		}
		$this->param['RESULT'] = 1;

		return $this->param;
	}

    // Hex Calculator
    function hex($request){
		$type= $request->type;
		$bnr_frs= $request->bnr_frs;
		$bnr_sec= $request->bnr_sec;
		$bnr_slc= $request->bnr_slc;
		$options= $request->options;
		$nmbr= $request->nmbr;
        function bnrCal($fN,$sN,$bnr_slc) {
            if ($bnr_slc === "add") { //Add
                $rN = $fN + $sN;
                $decimal = $rN;
                $binary = base_convert(abs($decimal), 10, 2);
                $hexa = strtoupper(base_convert(abs($decimal), 10, 16));
                $octal = base_convert(abs($decimal), 10, 8);
                $operate="+";
            } elseif ($bnr_slc === "sub") { //Subtract
                $rN = $fN - $sN;
                $decimal = $rN;
                $operate="-";
                if($decimal < 0) {
                    $binary = "-" . base_convert(abs($decimal), 10, 2);
                    $hexa = "-" . strtoupper(base_convert(abs($decimal), 10, 16));
                    $octal = "-" . base_convert(abs($decimal), 10, 8);
                } else {
                    $binary = base_convert(abs($decimal), 10, 2);
                    $hexa = strtoupper(base_convert(abs($decimal), 10, 16));
                    $octal = base_convert(abs($decimal), 10, 8);
                }
            } elseif ($bnr_slc === "mul") { //Multiply
                $rN = $fN * $sN;
                $decimal = $rN;
                $operate = "×";
                $binary = base_convert(abs($decimal), 10, 2);
                $hexa = strtoupper(base_convert(abs($decimal), 10, 16));
                $octal = base_convert(abs($decimal), 10, 8);
            } elseif ($bnr_slc === "divide") { //Divide
                $rN = $fN / $sN;
                $operate = "÷";
                $decimal = round($rN);
                $binary = base_convert(abs($decimal), 10, 2);
                $hexa = strtoupper(base_convert(abs($decimal), 10, 16));
                $octal = base_convert(abs($decimal), 10, 8);
            }
            return array($binary,$decimal,$hexa,$octal,$operate);
        }
        if ($type=="first") {
            if (!empty($bnr_frs) && !empty($bnr_sec)) {
                $fN = base_convert($bnr_frs, 16, 10);
                $sN = base_convert($bnr_sec, 16, 10);
                $first_ans1 = $bnr_frs;
                $second_ans1 = $bnr_sec;
                $first_ans = base_convert($bnr_frs, 16, 10);
                $second_ans = base_convert($bnr_sec, 16, 10);
                $chuti_kr=bnrCal($fN,$sN,$bnr_slc);
                $bn=$chuti_kr[0];
                $dc=$chuti_kr[1];
                $hx=$chuti_kr[2];
                $oc=$chuti_kr[3];
                $op=$chuti_kr[4];
            }else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
            }
            $this->param["first_ans1"] = $first_ans1;
            $this->param["second_ans1"] = $second_ans1;
            $this->param["first_ans"] = $first_ans;
            $this->param["second_ans"] = $second_ans;
            $this->param["bn"] = $bn;
            $this->param["dc"] = $dc;
            $this->param["hx"] = $hx;
            $this->param["oc"] = $oc;
            $this->param["op"] = $op;
        }else if ($type=="second") {
            if ($options=="1") {
                if (!empty($nmbr)) {
                    $answer = base_convert($nmbr, 16, 10);
                    $text="Decimal numeral";
                }else{
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
                }
            }else if ($options=="2") {
                if (!empty($nmbr)) {
                    $answer = base_convert($nmbr, 10, 16);
                    $text="Hex numeral";
                }else{
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
                }
            }else if ($options=="3") {
                if (!empty($nmbr)) {
                    $answer = base_convert($nmbr, 16, 2);
                    $text="Binary numeral";
                }else{
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
                }
            }else if ($options=="4") {
                $answer = base_convert($nmbr, 2, 16);
                $text="Hex numeral";
            }
            $this->param["answer"] = $answer;
            $this->param["text"] = $text;
        }
        $this->param["type"] = $type;
        $this->param["RESULT"] = 1;
        return $this->param;
    }

	// Elementary Matrix Calculator
	function elementary_matrix_function($request){
		$matrix_size = $request->matrix_size;
		$pth_matrix = $request->pth_matrix;
		$a = $request->a;
		$b = $request->b;
		$type = $request->type;
		$result_q = $request->result_q;
		if(is_numeric($matrix_size) && is_numeric($pth_matrix) && is_numeric($a) && is_numeric($b) && is_numeric($result_q)){
			if($type=="row"){
				if(($result_q<=$matrix_size && $pth_matrix<=$matrix_size) && ($result_q>0 && $pth_matrix>0)){
					if($pth_matrix !=$result_q){
						for ($row = 0; $row < $matrix_size; $row++)
						{
							for ($col = 0; $col < $matrix_size; $col++)
							{
								// Checking if row is
								// equal to column
								if ($row == $col)
								$array[$row][$col] = 1;
								else
								$array[$row][$col] = 0;
							}
						}
						// ------------------------
						$identity_matrix = $array;
						$multiply_matrix = $array;
						// ------------------------
						for($i=0;$i<$matrix_size;$i++){
							$multiply_matrix[$pth_matrix-1][$i] =  $a * $array[$pth_matrix-1][$i];
							$multiply_matrix[$result_q-1][$i] =  $b * $array[$result_q-1][$i];
						}

						// ------------------------------------
						$addition_matrix = $multiply_matrix;
						// ------------------------------------

						for($i=0;$i<$matrix_size;$i++){
							$addition_matrix[$result_q-1][$i] = $addition_matrix[$result_q-1][$i] + $addition_matrix[$pth_matrix-1][$i];
						}

						for($i=0;$i<$matrix_size;$i++){
							$array1[0][$i] = $a * $array[$pth_matrix-1][$i];
							$array2[0][$i] = $b * $array[$result_q-1][$i];
						}
						
						
						for($i=0;$i<$matrix_size;$i++){
							$array[$result_q-1][$i] = $array1[0][$i] + $array2[0][$i];
						}
						
						$this->param['array'] = $array;
						$this->param['identity_matrix'] = $identity_matrix;
						$this->param['multiply_matrix'] = $multiply_matrix;
						$this->param['addition_matrix'] = $addition_matrix;
						$this->param['RESULT'] = 1;
						return $this->param;
					}else{
						$this->param['error'] = 'The row p and q cannot be equal.';
						return $this->param;
					}
				}else{
					$this->param['error'] = 'The row p and q cannot be greater then n or less then 1.';
					return $this->param;
				}
			}elseif($type=="col"){
				if(($result_q<=$matrix_size && $pth_matrix<=$matrix_size) && ($result_q>0 && $pth_matrix>0)){
					if($pth_matrix !=$result_q){
						for ($row = 0; $row < $matrix_size; $row++)
						{
							for ($col = 0; $col < $matrix_size; $col++)
							{
								// Checking if row is
								// equal to column
								if ($row == $col)
								$array[$row][$col] = 1;
								else
								$array[$row][$col] = 0;
							}
						}
						// ------------------------
						$identity_matrix = $array;
						$multiply_matrix = $array;
						// ------------------------

						for($i=0;$i<$matrix_size;$i++){
							$multiply_matrix[$i][$pth_matrix-1] =  $a * $array[$i][$pth_matrix-1];
							$multiply_matrix[$i][$result_q-1] =  $b * $array[$i][$result_q-1];
						}

						// ------------------------------------
						$addition_matrix = $multiply_matrix;
						// ------------------------------------

						for($i=0;$i<$matrix_size;$i++){
							$addition_matrix[$i][$result_q-1] = $addition_matrix[$i][$result_q-1] + $addition_matrix[$i][$pth_matrix-1];
						}

						for($i=0;$i<$matrix_size;$i++){
							$array1[$i][0] = $a * $array[$i][$pth_matrix-1];
							$array2[$i][0] = $b * $array[$i][$result_q-1];
						}
						
						for($i=0;$i<$matrix_size;$i++){
							$array[$i][$result_q-1] = $array1[$i][0] + $array2[$i][0];
						}
						
						$this->param['array'] = $array;
						$this->param['identity_matrix'] = $identity_matrix;
						$this->param['multiply_matrix'] = $multiply_matrix;
						$this->param['addition_matrix'] = $addition_matrix;
						$this->param['RESULT'] = 1;
						return $this->param;
					}else{
						$this->param['error'] = 'The coloume p and q cannot be equal.';
						return $this->param;
					}
				}else{
					$this->param['error'] = 'The coloume p and q cannot be greater then n or less then 1.';
					return $this->param;
				}
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Pascal's Triangle Calculator
	function pascals($request){
		$method= $request->method;
		$row= $request->row;
		$to_row= $request->to_row;
		$column= $request->column;
		if($method=="1"){
			if(is_numeric($row)){
				if($row>=0){
					if($row<100){
						$this->param['row']=$row;
					}else{
						$this->param['error'] = 'The row must be less than 100.';
						return $this->param;
					}
				}else{
					$this->param['error'] = 'The row must be non-negative.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($method=="2"){
			if(is_numeric($row)){
				if($row>=0){
					if($row<100){
					}else{
						$this->param['error'] = 'The row must be less than 100.';
						return $this->param;
					}
				}else{
					$this->param['error'] = 'The row must be non-negative.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($method=="3"){
			if(is_numeric($row) && is_numeric($to_row)){
				if($row>=0 && $to_row>=0){
					if($to_row>=$row){
						$this->param['col']=$to_row;
					}else{
						$this->param['error'] = 'The end-row must be at least equal to the one we started with.';
						return $this->param;
					}
				}else{
					$this->param['error'] = 'The row must be non-negative.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($method=="4"){
			if(is_numeric($column) && is_numeric($row)){
				if($row>=$column && $row>0 && $column>0){
					$this->param['column']=$column;
				}else{
					$this->param['error'] = 'Enter Row n ≥ Col k ≥ 0.';
					return $this->param;
				}
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		$this->param['row']=$row;
		$this->param['method']=$method;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

