	// Gauss Seidel Method Calculator
	function gauss($request){
		$number= $request->number;
		$value= $request->value;
		for($i=0;$i<=$number;$i++){
			for($j=0;$j<=$number;$j++){
				if(is_numeric($_POST['matrix'.$i.'_'.$j])){
					$r[]=$_POST['matrix'.$i.'_'.$j];
				}else{
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			}
		}
		$upper=array();
		for($k = 0; $k <=$number; $k++)
		{
			for($f = 0; $f <=$number; $f++)
			{
				if($k > $f){
					$upper[$k][$f]=0;
				}
				else{
					$upper[$k][$f]=$_POST['matrix'.$k.'_'.$f];
				}
			}
		}
		function solve_matrix($m)
		{
		$_size = count($m);
		switch ($_size)
		{
		case 1:
		return $m[0][0];
		case 2:
		return (($m[0][0] * $m[1][1]) - ($m[0][1] * $m[1][0]));
		case 3:
		return ($m[0][0]*($m[1][1]*$m[2][2]-$m[1][2]*$m[2][1])) - ($m[0][1]*($m[1][0]*$m[2][2]-$m[2][0]*$m[1][2])) + ($m[0][2]*($m[1][0]*$m[2][1]-$m[2][0]*$m[1][1]));
		default:
		return 0;
		}
		}
		$lower=array();
		for ($i=0; $i<=$number; $i++)
		for ($j=0; $j<=$number; $j++)
			if($j > $i){
				$lower[$i][$j]=0;
			}
			else{
				$lower[$i][$j]=$_POST['matrix'.$i.'_'.$j];
			}
		$I_matrix_I = solve_matrix($lower);
		$adjoint = array();
		$inverse = array();
		for ($i=0; $i<=$number; $i++)
		for ($j=0; $j<=$number; $j++)
		{
		$cofactor = array();
		for ($k=0; $k<=$number; $k++)
		{
		if ($i!=$k)
		{
		$temp = array();
		for ($l=0; $l<=$number; $l++)
		{
		if ($j!=$l)
		array_push($temp, $lower[$k][$l]);
		}
		array_push($cofactor, $temp);
		}
		}
		$adjoint[$j][$i] = solve_matrix($cofactor)*pow((-1),($i+$j));
		}
		for ($i=0; $i<=$number; $i++)
		for ($j=0; $j<=$number; $j++)
		$inverse[$i][$j] = $adjoint[$i][$j]/$I_matrix_I;

		$result=array();
		for ($i = 0; $i < count($upper); $i++)
			{
			for ($j = 0; $j < count($upper); $j++)
			{
			if ($i == $j){
				$upper[$i][$j] = 0;
			}
		}
		}
	
		for ($i=0;$i<count($inverse);$i++) { //Count Rows of inverse matrix
			for($j=0;$j<count($upper);$j++){
				$result[$i][$j]=0;
				for($k=0;$k<count($upper);$k++){
					$result[$i][$j]+=(-$inverse[$i][$k]*$upper[$k][$j]);
				}
			}
		}
		for ($i=0;$i<count($inverse);$i++) { //Count Rows of inverse matrix
			for($j=0;$j<1;$j++){
				$result2[$i][$j]=0;
				for($k=0;$k<=$number;$k++){
					$result2[$i][$j]+=($inverse[$i][$k]*$value[$k]);
				}
			}
		}
		for($h=0;$h<19;$h++){
			for ($j=0; $j<count($result);$j++) {
				for ($k=0;$k <1;$k++) { 
					$result3[$j][$k]=0;	
					for($m=0;$m<count($result2);$m++){
						if($h==0){
							$result3[$j][$k]+=($result[$j][$m]*$result2[$m][$k]);
						}else{
							$result3[$j][$k]+=($result[$j][$m]*$resultt[$m][$k]);
						}
					}
				}
			}
			for ($n=0; $n <count($result3) ; $n++) { 
				for ($z=0; $z <1 ; $z++) {
					$resultt[$n][$z]=0;
					$resultt[$n][$z]=$result3[$n][$z]+$result2[$n][$z];
				}
			}	
		}
		$this->param['upper']=$upper;
		$this->param['lower']=$lower;
		$this->param['number']=$number;
		$this->param['invrse']=$inverse;
		$this->param['value']=$value;
		$this->param['result']=$result;
		$this->param['result2']=$result2;
		$this->param['main_result']=$resultt;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Rational Zeros Calculator
	function rational_zero($request){
		$v1= $request->v1;
		$v2= $request->v2;
		$v3= $request->v3;
		$v4= $request->v4;
		$v5= $request->v5;
		$v6= $request->v6;
		$v7= $request->v7;
		$v8= $request->v8;
		$v9= $request->v9;
		$v10= $request->v10;
		$no_of= $request->no_of;
		if(is_numeric($v1) && is_numeric($v2) && is_numeric($v3) && is_numeric($v4) && is_numeric($v5) && is_numeric($v6) && is_numeric($v7) && is_numeric($v9) && is_numeric($v10) && is_numeric($no_of)){
			$q = $v1;
			if($no_of == 2){
				$p = $v3;
			}elseif($no_of == 3){
				$p = $v4;
			}elseif($no_of == 4){
				$p = $v5;
			}elseif($no_of == 5){
				$p = $v6;
			}elseif($no_of == 6){
				$p = $v7;
			}elseif($no_of == 7){
				$p = $v8;
			}elseif($no_of == 8){
				$p = $v9;
			}elseif($no_of == 9){
				$p = $v10;
			}
			function printDivisors($n) {
				for($i = 1; $i <= $n; $i++) {
					if($n%$i == 0){
						$divi[]=$i;
					}
				}
				return($divi);
			}
			if ($p < 0) {
				$p = $p * (-1);
			}
			$array_p = printDivisors($p);
			foreach ($array_p as $value) {
				$new_times[] = (-1)*$value;
			}
			$array_q = printDivisors($q);
			$final_p = array_merge($array_p,$new_times);
			foreach ($array_q as $value) {
				$new_times2[] = $value*(-1);
			}
			$final_q = array_merge($array_q,$new_times2);
			for($i = 0; $i < count($final_q); $i++){
				if($final_q[$i] != 1 ){
					foreach($final_p as $value ){
						if ($value%$final_q[$i] == "0") {
							$ans[] =$value/$final_q[$i];
						}else{
							// $ans[] =$value." / ".$final_q[$i];
							$ans[] = '\frac{'.$value."}{".$final_q[$i]."}"; 
						}
						$main_ans[] ='\frac{'.$value."}{".$final_q[$i]."}";
						$main_ans2[] =$value/$final_q[$i];
						$main_ans3[] =$value." / ".$final_q[$i];
					}
				}
			}
			$uq =array_unique($ans);
			$uq =array_values(array_filter(array_unique($ans)));
			$s1 = ($v1 != 1) ?$v1 : '';
			$s2 = ($v2 >= 0) ? " +" .$v2 : $v2;
			$s3 = ($v3 >= 0) ? " +" .$v3 : $v3;
			$s4 = ($v4 >= 0) ? " +" .$v4 : $v4;
			$s5 = ($v5 >= 0) ? " +" .$v5 : $v5;
			$s6 = ($v6 >= 0) ? " +" .$v6 : $v6;
			$s7 = ($v7 >= 0) ? " +" .$v7 : $v7;
			$s8 = ($v8 >= 0) ? " +" .$v8 : $v8;
			$s9 = ($v9 >= 0) ? " +" .$v9 : $v9;
			$s10 = ($v10 >= 0) ? " +" .$v10 : $v10;
			for($i=0; $i < count($uq); $i++){
				if($no_of == 2){
					$eq[] =  '\( \text{P}{\left(x\right)}='.$s1.'x^{2}'.$s2.'x'.$s3.'\)';
					$result[] =  '\( \text{P}{\left('.$uq[$i].'\right)}=\left('.$v1.'\right)\left('.$uq[$i].'\right)^{2}+\left('.$v2.'\right)\left('.$uq[$i].'\right)+'. $v3 . '\)';
					$final_result[] =   ($v1)*(pow($main_ans2[$i],2)) + ($v2)*($main_ans2[$i]) + ($v3);
				} elseif($no_of == 3){
					$eq[] = '\( \text{P}{\left(x\right)}='.$s1.'x^{3}'.$s2.'x^{2}'.$s3.'x'.$s4.'\)';
					$result[] = '\( \text{P}{\left('.$uq[$i].'\right)}=\left('.$v1.'\right)\left('.$uq[$i].'\right)^{3}+\left('.$v2.'\right)\left('.$uq[$i].'\right)^{2}+\left('.$v3.'\right)\left('.$uq[$i].'\right)+'.$v4. '\)';
					$final_result[] =   ($v1)*(pow($main_ans2[$i],3)) + ($v2)*(pow($main_ans2[$i],2)) + ($v3)*($main_ans2[$i]) + $v4;                         
				}elseif($no_of == 4){
					$eq[] = '\( \text{P}{\left(x\right)}='.$s1.'x^{4}'.$s2.'x^{3}'.$s3.'x^{2}'.$s4.'x'.$s5.'\)';
					$result[] = '\( \text{P}{\left('.$uq[$i].'\right)}=\left('.$v1.'\right)\left('.$uq[$i].'\right)^{4}+\left('.$v2.'\right)\left('.$uq[$i].'\right)^{3}+\left('.$v3.'\right)\left('.$uq[$i].'\right)^{2}+\left('.$v4.'\right)\left('.$uq[$i].'\right)+' .$v5. '\)';
					$final_result[] =   ($v1)*(pow($main_ans2[$i],4)) + ($v2)*(pow($main_ans2[$i],3)) + ($v3)*(pow($main_ans2[$i],2)) + ($v4)*($main_ans2[$i]) + $v5;                       
				}elseif($no_of == 5){
					$eq[] =  '\( \text{P}{\left(x\right)}='.$s1.'x^{5}'.$s2.'x^{4}'.$s3.'x^{3}'.$s4.'x^{2}'.$s5.'x'.$s6.'\)';
					$result[] = '\( \text{P}{\left('.$uq[$i].'\right)}=\left('.$v1.'\right)\left('.$uq[$i].'\right)^{5}+\left('.$v2.'\right)\left('.$uq[$i].'\right)^{4}+\left('.$v3.'\right)\left('.$uq[$i].'\right)^{3}+\left('.$v4.'\right)\left('.$uq[$i].'\right)^{2}+\left(' .$v5.'\right)\left('.$uq[$i].'\right)+'.$v6. '\)';
					$final_result[] =   ($v1)*(pow($main_ans2[$i],5)) + ($v2)*(pow($main_ans2[$i],4)) + ($v3)*(pow($main_ans2[$i],3)) + ($v4)*(pow($main_ans2[$i],2)) + ($v5)*($main_ans2[$i])+ $v6;                         
				}elseif($no_of == 6){
					$eq[] = '\( \text{P}{\left(x\right)}='.$s1.'x^{6}'.$s2.'x^{5}'.$s3.'x^{4}'.$s4.'x^{3}'.$s5.'x^{2}'.$s6.'x'.$s7.'\)';
					$result[] = '\( \text{P}{\left('.$uq[$i].'\right)}=\left('.$v1.'\right)\left('.$uq[$i].'\right)^{6}+\left('.$v2.'\right)\left('.$uq[$i].'\right)^{5}+\left('.$v3.'\right)\left('.$uq[$i].'\right)^{4}+\left('.$v4.'\right)\left('.$uq[$i].'\right)^{3}+\left(' .$v5.'\right)\left('.$uq[$i].'\right)^{2}+\left('.$v6.'\right)\left('.$uq[$i].'\right)+' .$v7.'\)';
					$final_result[] =   ($v1)*(pow($main_ans2[$i],6)) + ($v2)*(pow($main_ans2[$i],5)) + ($v3)*(pow($main_ans2[$i],4)) + ($v4)*(pow($main_ans2[$i],3)) + ($v5)*(pow($main_ans2[$i],2)) + ($v6)*($main_ans2[$i]) + $v7;                    
				}elseif($no_of == 7){
					$eq[] = '\( \text{P}{\left(x\right)}='.$s1.'x^{7}'.$s2.'x^{6}'.$s3.'x^{5}'.$s4.'x^{4}'.$s5.'x^{3}'.$s6.'x^{2}'.$s7.'x'.$s8.'\)';
					$result[] = '\( \text{P}{\left('.$uq[$i].'\right)}=\left('.$v1.'\right)\left('.$uq[$i].'\right)^{7}+\left('.$v2.'\right)\left('.$uq[$i].'\right)^{6}+\left('.$v3.'\right)\left('.$uq[$i].'\right)^{5}+\left('.$v4.'\right)\left('.$uq[$i].'\right)^{4}+\left(' .$v5.'\right)\left('.$uq[$i].'\right)^{3}+\left('.$v6.'\right)\left('.$uq[$i].'\right)^{2}+\left('.$v7.'\right)\left('.$uq[$i].'\right)+' .$v8.'\)';
					$final_result[] =   ($v1)*(pow($main_ans2[$i],7)) + ($v2)*(pow($main_ans2[$i],6)) + ($v3)*(pow($main_ans2[$i],5)) + ($v4)*(pow($main_ans2[$i],4)) + ($v5)*(pow($main_ans2[$i],3)) + ($v6)*(pow($main_ans2[$i],2)) + ($v7)*($main_ans2[$i]) + $v8;                    
				}elseif($no_of == 8){
					$eq[] = '\( \text{P}{\left(x\right)}='.$s1.'x^{8}'.$s2.'x^{7}'.$s3.'x^{6}'.$s4.'x^{5}'.$s5.'x^{4}'.$s6.'x^{2}'.$s7.'x^{2}'.$s8.'x'.$s9.'\)';
					$result[] = '\( \text{P}{\left('.$uq[$i].'\right)}=\left('.$v1.'\right)\left('.$uq[$i].'\right)^{}+\left('.$v2.'\right)\left('.$uq[$i].'\right)^{7}+\left('.$v3.'\right)\left('.$uq[$i].'\right)^{6}+\left('.$v4.'\right)\left('.$uq[$i].'\right)^{5}+\left(' .$v5.'\right)\left('.$uq[$i].'\right)^{4}+\left('.$v6.'\right)\left('.$uq[$i].'\right)^{3}+\left('.$v7.'\right)\left('.$uq[$i].'\right)^{2}+\left('.$v8.'\right)\left('.$uq[$i].'\right)+' .$v9.'\)';
					$final_result[] =   ($v1)*(pow($main_ans2[$i],8)) + ($v2)*(pow($main_ans2[$i],7)) + ($v3)*(pow($main_ans2[$i],6)) + ($v4)*(pow($main_ans2[$i],5)) + ($v5)*(pow($main_ans2[$i],4)) + ($v6)*(pow($main_ans2[$i],3)) + ($v7)*(pow($main_ans2[$i],2)) + $v8*($main_ans2[$i]) + $v9;                       
				}elseif($no_of == 9){
					$eq[] = '\( \text{P}{\left(x\right)}='.$s1.'x^{9}'.$s2.'x^{8}'.$s3.'x^{7}'.$s4.'x^{6}'.$s5.'x^{5}'.$s6.'x^{4}'.$s7.'x^{3}'.$s8.'x^{2}'.$s9.'x'.$s10.'\)';
					$result[] = '\( \text{P}{\left('.$uq[$i].'\right)}=\left('.$v1.'\right)\left('.$uq[$i].'\right)^{9}+\left('.$v2.'\right)\left('.$uq[$i].'\right)^{8}+\left('.$v3.'\right)\left('.$uq[$i].'\right)^{7}+\left('.$v4.'\right)\left('.$uq[$i].'\right)^{6}+\left(' .$v5.'\right)\left('.$uq[$i].'\right)^{5}+\left('.$v6.'\right)\left('.$uq[$i].'\right)^{4}+\left('.$v7.'\right)\left('.$uq[$i].'\right)^{3}+\left('.$v8.'\right)\left('.$uq[$i].'\right)^{2}+\left('.$v9.'\right)\left('.$uq[$i].'\right)+' .$v10.'\)';
					$final_result[] =   ($v1)*(pow($main_ans2[$i],9)) + ($v2)*(pow($main_ans2[$i],8)) + ($v3)*(pow($main_ans2[$i],7)) + ($v4)*(pow($main_ans2[$i],6)) + ($v5)*(pow($main_ans2[$i],5)) + ($v6)*(pow($main_ans2[$i],4)) + ($v7)*(pow($main_ans2[$i],3)) + $v8*(pow($main_ans2[$i],2)) + $v9*($main_ans2[$i]) + $v10;
				} 
			}
			$this->param['v1']     		= $v1;
			$this->param['v2']     		= $v2;
			$this->param['v3']     		= $v3;
			$this->param['v4']     		= $v4;
			$this->param['v5']     		= $v5;
			$this->param['v6']     		= $v6;
			$this->param['v7']     		= $v7;
			$this->param['v8']     		= $v8;
			$this->param['v9']     	 	= $v9;
			$this->param['v10']     	 	= $v10;
			$this->param['no_of']   	= $no_of;
			$this->param['p']      		= $p;
			$this->param['q']      		= $q;
			$this->param['main_ans']    = $main_ans;
			$this->param['main_ans2']   = $main_ans2;
			$this->param['main_ans3']   = $main_ans3;
			$this->param['ans']      	= $ans;
			$this->param['uq']      	= $uq;
			$this->param['final_p']     	= $final_p;
			$this->param['final_q']     	= $final_q;
			$this->param['eq']     			= $eq;
			$this->param['result']     		= $result;
			$this->param['final_result']    = $final_result;
			$this->param['RESULT']      	= 1;
			return $this->param;
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Area of a Semicircle Calculator
	function semicircle($request){
		$radius= $request->radius;
		$selection= $request->selection;	
		$pi= $request->pi;
		$units= $request->units;
		function conversion($unit,$rad){
			if($unit=="cm"){
				$answer=$rad*1;
			}else if($unit=="m"){
				$answer=$rad*100;
			}else if($unit=="in"){
				$answer=$rad*2.54;
			}else if($unit=="ft"){
				$answer=$rad*30.48;
			}else if($unit=="yd"){
				$answer=$rad*91.44;
			}
			return $answer;
		}
		if($selection=="1"){//Given Radius
			if(is_numeric($radius) && is_numeric($pi) && $radius>0){
				$ans=conversion($units,$radius);
				$diameter=$ans*2;
				$area=($pi*($ans*$ans))/2;
				$perimeter=($pi*$ans)+(2*$ans);
				$arc_length=3.14*$ans;
				$rad=$ans;
				$per=$perimeter;
				$da=$diameter;
				$ac=$arc_length;
				$a=$area;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($selection=="2"){//Given Perimeter
			if(is_numeric($radius) && is_numeric($pi) && $radius>0){
				$ans=conversion($units,$radius);
				$diameter=$ans/2;
				$arc_length=$diameter*3.14;
				$perimeter=($pi*$diameter)+(2*$diameter);
				$area=($pi*($diameter*$diameter))/2;
				$da=$ans;
				$rad=$diameter;
				$ac=$arc_length;
				$a=$area;
				$per=$perimeter;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($selection=="3"){//Given Circumference (a)
			if(is_numeric($radius) && is_numeric($pi) && $radius>0){
				$ans=conversion($units,$radius);	
				$radius=$ans/$pi;
				$diameter=$radius*2;
				$perimeter=($pi*$radius)+(2*$radius);
				$area=($pi*($radius*$radius))/2;
				$ac=$ans;
				$da=$diameter;
				$a=$area;
				$per=$perimeter;
				$rad=$radius;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($selection=="4"){//Given Perimeter
			if(is_numeric($radius) && is_numeric($pi) && $radius>0){
				$ans=conversion($units,$radius);	
				$radius=($ans/($pi-(-2)));
				$diameter=$radius*2;
				$arc_length=$radius*$pi;
				$area=($pi*($radius*$radius))/2;
				$per=$ans;
				$da=$diameter;
				$a=$area;
				$ac=$arc_length;
				$rad=$radius;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else if($selection=="6"){//Given Area
			if(is_numeric($radius) && is_numeric($pi) && $radius>0){
				$ans=conversion($units,$radius);	
				$radius=sqrt((2*($ans/$pi)));
				$diameter=$radius*2;
				$arc_length=$radius*3.14;
				$perimeter=$radius*$pi-(-2*$radius);
				$a=$ans;
				$da=$diameter;
				$per=$perimeter;
				$ac=$arc_length;
				$rad=$radius;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		$this->param['radius']=round($rad,3);
		$this->param['perimeter']=round($per,3);
		$this->param['diameter']=round($da,3);
		$this->param['arc_length']=round($ac,3);
		$this->param['area']=round($a,3);
		$this->param['unit']=$units;
		$this->param['pi']=$pi;
		$this->param['selection']=$selection;
		$this->param['RESULT'] = 1;

		return $this->param;
	}

	// System of Equations Calculator
	function system($request){
	
		$operations= $request->operations;
		$method= $request->method;
		$a1_f= $request->a1_f;
		$b1_f= $request->b1_f;
		$k1_f= $request->k1_f;
		$a2_f= $request->a2_f;
		$b2_f= $request->b2_f;
		$k2_f= $request->k2_f;
		$a1_s= $request->a1_s;
		$b1_s= $request->b1_s;
		$c1_s= $request->c1_s;
		$k1_s= $request->k1_s;
		$a2_s= $request->a2_s;
		$b2_s= $request->b2_s;
		$c2_s= $request->c2_s;
		$k2_s= $request->k2_s;
		$a3_s= $request->a3_s;
		$b3_s= $request->b3_s;
		$c3_s= $request->c3_s;
		$k3_s= $request->k3_s;
        function invert($A, $debug = FALSE){
			/// @todo check rows = columns

			$n = count($A);

			// get and append identity matrix
			$I = identity_matrix($n);
			for ($i = 0; $i < $n; ++ $i) {
				$A[$i] = array_merge($A[$i], $I[$i]);
			}

			if ($debug) {
				echo "\nStarting matrix: ";
				print_matrix($A);
			}

			// forward run
			for ($j = 0; $j < $n-1; ++ $j) {
				// for all remaining rows (diagonally)
				for ($i = $j+1; $i < $n; ++ $i) {
					// if the value is not already 0
					if ($A[$i][$j] !== 0) {
						// adjust scale to pivot row
						// subtract pivot row from current
						$scalar = $A[$j][$j] / $A[$i][$j];
						for ($jj = $j; $jj < $n*2; ++ $jj) {
							$A[$i][$jj] *= $scalar;
							$A[$i][$jj] -= $A[$j][$jj];
						}
					}
				}
				if ($debug) {
					echo "\nForward iteration $j: ";
					print_matrix($A);
				}
			}

			// reverse run
			for ($j = $n-1; $j > 0; -- $j) {
				for ($i = $j-1; $i >= 0; -- $i) {
					if ($A[$i][$j] !== 0) {
						$scalar = $A[$j][$j] / $A[$i][$j];
						for ($jj = $i; $jj < $n*2; ++ $jj) {
							$A[$i][$jj] *= $scalar;
							$A[$i][$jj] -= $A[$j][$jj];
						}
					}
				}
				if ($debug) {
					echo "\nReverse iteration $j: ";
					print_matrix($A);
				}
			}

			// last run to make all diagonal 1s
			/// @note this can be done in last iteration (i.e. reverse run) too!
			for ($j = 0; $j < $n; ++ $j) {
				if ($A[$j][$j] !== 1) {
					$scalar = 1 / $A[$j][$j];
					for ($jj = $j; $jj < $n*2; ++ $jj) {
						$A[$j][$jj] *= $scalar;
					}
				}
				if ($debug) {
					echo "\n1-out iteration $j: ";
					print_matrix($A);
				}
			}

			// take out the matrix inverse to return
			$Inv = array();
			for ($i = 0; $i < $n; ++ $i) {
				$Inv[$i] = array_slice($A[$i], $n);
			}

			return $Inv;
		}
		function print_matrix($A, $decimals = 6){
			foreach ($A as $row) {
				echo "\n\t[";
				foreach ($row as $i) {
					echo "\t" . sprintf("%01.{$decimals}f", round($i, $decimals));
				}
				echo "\t]";
			}
		}
		function identity_matrix($n){
			$I = array();
			for ($i = 0; $i < $n; ++ $i) {
				for ($j = 0; $j < $n; ++ $j) {
					$I[$i][$j] = ($i == $j) ? 1 : 0;
				}
			}
			return $I;
		}
		function multiply(&$mat1, &$mat2){
			$res=[];
		    $N = count($mat1);
		    for ($i = 0; $i < $N; $i++)
		    {
		        for ($j = 0; $j < count($mat2[0]); $j++)
		        {
		            $res[$i][$j] = 0;
		            for ($k = 0; $k < $N; $k++)
		                $res[$i][$j] += $mat1[$i][$k] * 
		                                $mat2[$k][$j];
		        }
		    }
		    return $res;
		}
        function rref2($matrix)
        {
            $lead = 0;
            $rowCount = count($matrix);
            if ($rowCount == 0)
                return $matrix;
            $columnCount = 0;
            if (isset($matrix[0])) {
                $columnCount = count($matrix[0]);
            }
            for ($r = 0; $r < $rowCount; $r++) {
                if ($lead >= $columnCount)
                    break;        
                {
                    $i = $r;
                    while ($matrix[$i][$lead] == 0) {
                        $i++;
                        if ($i == $rowCount) {
                            $i = $r;
                            $lead++;
                            if ($lead == $columnCount)
                                return $matrix;
                        }
                    }
                    $temp = $matrix[$r];
                    $matrix[$r] = $matrix[$i];
                    $matrix[$i] = $temp;
                }
                {
                    $lv = $matrix[$r][$lead];
                    for ($j = 0; $j < $columnCount; $j++) {
                        $matrix[$r][$j] = $matrix[$r][$j] / $lv;
                    }
                }
                for ($i = 0; $i < $rowCount; $i++) {
                    if ($i != $r) {
                        $lv = $matrix[$i][$lead];
                        for ($j = 0; $j < $columnCount; $j++) {
                            $matrix[$i][$j] -= $lv * $matrix[$r][$j];
                        }
                    }
                }
                $lead++;
            }
            return $matrix;
        }
        function deter($arr){
        	$determinant = $arr[0][0] * ($arr[1][1]*$arr[2][2] - $arr[1][2]*$arr[2][1]) -
               $arr[0][1] * ($arr[1][0]*$arr[2][2] - $arr[1][2]*$arr[2][0]) +
               $arr[0][2] * ($arr[1][0]*$arr[2][1] - $arr[1][1]*$arr[2][0]);
            return $determinant;
        }
        if ($operations==1) {
        	if (is_numeric($k1_f) && is_numeric($k2_f)) {
        		if (empty($a1_f) && empty($a2_f)) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
        		}
        		if (empty($b1_f) && empty($b2_f)) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
        		}
        		if ($method==1) {
        			if($a1_f==1){
        				$multiBy=$a2_f;
		        		$n1=$a2_f-($a1_f*$a2_f);
		        		$n2=$b2_f-($b1_f*$a2_f);
		        		$n3=$k2_f-($k1_f*$a2_f);
        			}elseif($a1_f>1){
        				$multiBy='\\dfrac{'.$a2_f.'}{'.$a1_f.'}';
        				$n1=$a2_f-($a1_f*($a2_f/$a1_f));
		        		$n2=$b2_f-($b1_f*($a2_f/$a1_f));
		        		$n3=$k2_f-($k1_f*($a2_f/$a1_f));
        			}elseif ($a1_f==0) {
        				$multiBy='swap';
        				$n1=$a1_f;
        				$n2=$b1_f;
        				$n3=$k1_f;
        				$a1_f=$a2_f;
        				$b1_f=$b2_f;
        				$k1_f=$k2_f;
        			}elseif($a1_f==-1){
        				$multiBy=$a2_f;
        				$n1=$a2_f+($a1_f*$a2_f);
		        		$n2=$b2_f+($b1_f*$a2_f);
		        		$n3=$k2_f+($k1_f*$a2_f);
        			}elseif($a1_f<-1){
        				$multiBy='\\dfrac{'.$a2_f.'}{'.$a1_f.'}';
        				$n1=$a2_f+($a1_f*($a2_f/abs($a1_f)));
		        		$n2=$b2_f+($b1_f*($a2_f/abs($a1_f)));
		        		$n3=$k2_f+($k1_f*($a2_f/abs($a1_f)));
        			}
        			$y=$n3/$n2;
        			$x=($k1_f-($b1_f*$y))/$a1_f;
        			$this->param['x'] = $x;
        			$this->param['y'] = $y;
        			$this->param['n1'] = $n1;
        			$this->param['n2'] = $n2;
        			$this->param['n3'] = $n3;
        			$this->param['a1_f'] = $a1_f;
        			$this->param['b1_f'] = $b1_f;
        			$this->param['k1_f'] = $k1_f;
        			$this->param['RESULT'] = 1;
		        	return $this->param;
        		}elseif ($method==2) {
        			$invers=[[$a1_f,$b1_f],[$a2_f,$b2_f]];
        			$inv=invert($invers);
        			// echo "<pre>";
        			// print_r($inv);
        			// die;
        			$side=[[$k1_f],[$k2_f]];
        			$multi=multiply($inv,$side);
        			$this->param['x'] = $multi[0][0];
        			$this->param['y'] = $multi[1][0];
        			$this->param['inv'] = $inv;
        			$this->param['multi'] = $multi;
        			$this->param['RESULT'] = 1;
		        	return $this->param;
        		}elseif ($method==3) {
        			$det1=($a1_f * $b2_f)-($a2_f*$b1_f);
        			$det2=($k1_f * $b2_f)-($k2_f*$b1_f);
        			$det3=($a1_f * $k2_f)-($a2_f*$k1_f);
        			$x=$det2/$det1;
        			$y=$det3/$det1;
        			$this->param['x'] = $x;
        			$this->param['y'] = $y;
        			$this->param['det1'] = $det1;
        			$this->param['det2'] = $det2;
        			$this->param['det3'] = $det3;
        			$this->param['RESULT'] = 1;
		        	return $this->param;
        		}
        	}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
        	}
        }elseif($operations==2){
        	if ($method==1) {
        		$A=[[$a1_s,$b1_s,$c1_s,$k1_s],[$a2_s,$b2_s,$c2_s,$k2_s],[$a3_s,$b3_s,$c3_s,$k3_s]];
        		$rref=rref2($A);
        		$x=$rref[0][3];
        		$y=$rref[1][3];
        		$z=$rref[2][3];
        		$this->param['rref'] = $rref;
    			$this->param['x'] = $x;
    			$this->param['y'] = $y;
    			$this->param['z'] = $z;
    			$this->param['RESULT'] = 1;
	        	return $this->param;
        	}elseif($method==2){
        		$A=[[$a1_s,$b1_s,$c1_s],[$a2_s,$b2_s,$c2_s],[$a3_s,$b3_s,$c3_s]];
        		$inv=invert($A);
    			$side=[[$k1_s],[$k2_s],[$k3_s]];
    			$multi=multiply($inv,$side);
    			$this->param['x'] = $multi[0][0];
    			$this->param['y'] = $multi[1][0];
    			$this->param['z'] = $multi[2][0];
    			$this->param['inv'] = $inv;
    			$this->param['multi'] = $multi;
    			$this->param['RESULT'] = 1;
	        	return $this->param;
        	}elseif($method==3){
        		$A=[[$a1_s,$b1_s,$c1_s],[$a2_s,$b2_s,$c2_s],[$a3_s,$b3_s,$c3_s]];
        		$B=[[$k1_s,$b1_s,$c1_s],[$k2_s,$b2_s,$c2_s],[$k3_s,$b3_s,$c3_s]];
        		$C=[[$a1_s,$k1_s,$c1_s],[$a2_s,$k2_s,$c2_s],[$a3_s,$k3_s,$c3_s]];
        		$D=[[$a1_s,$b1_s,$k1_s],[$a2_s,$b2_s,$k2_s],[$a3_s,$b3_s,$k3_s]];
        		$det1=deter($A);
        		$det2=deter($B);
        		$det3=deter($C);
        		$det4=deter($D);
        		$x=$det2/$det1;
    			$y=$det3/$det1;
    			$z=$det4/$det1;
    			$this->param['x'] = $x;
    			$this->param['y'] = $y;
    			$this->param['z'] = $z;
    			$this->param['det1'] = $det1;
    			$this->param['det2'] = $det2;
    			$this->param['det3'] = $det3;
    			$this->param['det4'] = $det3;
    			$this->param['RESULT'] = 1;
	        	return $this->param;
        	}
        }
	}

