	// sig fig calculator
	function sig($request){
		$x = trim($request->x);
		$x = str_replace(' ', '', $x);
		$y = $request->y;
		if(empty($x)){
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if(is_numeric(trim($x)) || is_float(trim($x))){
			// if (empty($y)) {
			// 	$y = 1;
			// }
			$number = $request->number;
			function new_sigFig($value, $digits)
			{
				if ($value == 0) {
					$decimalPlaces = $digits - 1;
				} elseif ($value < 0) {
					$decimalPlaces = $digits - floor(log10($value * -1)) - 1;
				} else {
					$decimalPlaces = $digits - floor(log10($value)) - 1;
				}
				$answer = round($value, $decimalPlaces);
				return $answer;
			}
			if (!empty($x)) {
				if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $x)) {
					$this->param['error'] = 'Please Enter Valid Input.';
					return $this->param;
				}
				if ($number==='Invalid') {
					$this->param['error'] = 'Please Enter Valid Input.';
					return $this->param;
				}
				$nbr=$x;
				$nbr=trim($nbr);
				$nbr=htmlspecialchars($nbr);
				$nbr=stripcslashes($nbr);
	
				$nbr=str_replace('log','log10', $nbr);
				$nbr=str_replace('ln','log', $nbr);
				$nbr=str_replace('**','*', $nbr);
				$nbr=str_replace('10^(','pow(10, ', $nbr);
				if (empty($number)) {
					$this->param['error'] = 'Please Enter Valid Input.';
					return $this->param;
				}
				$chacking=true;
				$check=explode('+', $x);
				if (count($check)>1) {
					$chacking=false;
				}
				$check=explode('-', $x);
				if (count($check)>1) {
					$chacking=false;
				}
				$check=explode('/', $x);
				if (count($check)>1) {
					$chacking=false;
				}
				$check=explode('*', $x);
				if (count($check)>1) {
					$chacking=false;
				}
				$check=explode('log', $x);
				if (count($check)>1) {
					$chacking=false;
				}
				$check=explode('ln', $x);
				if (count($check)>1) {
					$chacking=false;
				}
				$check=explode('10^', $x);
				if (count($check)>1) {
					$chacking=false;
				}
				if (is_numeric($x)) {
					$nbr=$x;
				}else{
					$nbr=eval('return '.$nbr.';');
				}
				$nbr1=eval('return '.$nbr.';');
				$original=strlen($nbr);
				if (preg_match('/([0-9])\.([0-9])/', $nbr)) {
					$original--;
					$decimal=explode('.', $nbr);
					$decimal=strlen($decimal[1]);
				} else {
					$decimal=0;
				}
				if (!empty($y)) {
					$after=new_sigFig($nbr,$y) * 1;
					$original_after=strlen($after);
					$float_check=explode('.', $after);
					if (count($float_check)>1) {
						$original_after--;
						$decimal_after=explode('.', $after);
						$decimal_after=strlen(@$decimal_after[1]);
					} else {
						$decimal_after=0;
					}
				}else{
					$after=$nbr;
					$original_after=strlen($nbr);
					if (preg_match('/([0-9])\.([0-9])/', $nbr)) {
						$original_after--;
						$decimal_after=explode('.', $nbr);
						$decimal_after=strlen($decimal_after[1]);
					} else {
					}
				}
				$o_count = str_split($nbr);
				$r_count = str_split($after);
				$e_before=sprintf('%.3E', $nbr);
				$s_before=explode('E', $e_before);
				$s_before= $s_before[0]." ×10<sup>".$s_before[1]."<sup>";
				$e_after=sprintf('%.3E', $after);
				$s_after=explode('E', $e_after);
				$s_after= $s_after[0]." ×10<sup>".$s_after[1]."<sup>";
				$this->param['s_before'] = $s_before;
				$this->param['s_after'] = $s_after;
				$this->param['original'] = $original;
				$this->param['decimal'] = $decimal;
				$this->param['after'] = $after;
				$this->param['nbr'] = $nbr;
				$this->param['y'] = $y;
				$this->param['e_before'] = $e_before;
				$this->param['o_count'] = $o_count;
				$this->param['r_count'] = $r_count;
				$this->param['e_after'] = $e_after;
				$this->param['original_after'] = $original_after;
				$this->param['decimal_after'] = @$decimal_after;
				$this->param['disable'] = "zain";
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}		
		}else{
			$format = '{
