	// Diamond Problem Calculator
	function diamond($request){
		$factor_a= $request->factor_a;
		$factor_b= $request->factor_b;
		$product= $request->product;
		$sum= $request->sum;
		if(is_numeric($factor_a) && is_numeric($factor_b)){
			if(empty($product) && empty($sum)){
				$facta=$factor_a;
				$factb=$factor_b;
				$pro=$factor_a*$factor_b;
				$su=$factor_a+$factor_b;
				$met=1;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		else if(is_numeric($factor_a) && is_numeric($product)){
			if(empty($factor_b) && empty($sum)){
				$facta=$factor_a;
				$factb=round($product/$factor_a,3);
				$pro=$product;
				$su=$factor_a+$factb;
				$met=2;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		else if(is_numeric($factor_a) && is_numeric($sum)){
			if(empty($factor_b) && empty($product)){
				$facta=$factor_a;
				$factb=$sum-$factor_a;
				$su=$sum;
				$pro=($facta*$factb);
				$met=3;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		else if(is_numeric($factor_b) && is_numeric($product)){
			if(empty($factor_a) && empty($sum)){
				$factb=$factor_b;
				$facta=round($product/$factor_b,2);
				$pro=$product;
				$su=($facta+$factb);
				$met=4;	
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		else if(is_numeric($factor_b) && is_numeric($sum)){
			if(empty($factor_a) && empty($product)){
				$factb=$factor_b;
				$facta=$sum-$factor_b;
				$su=$sum;
				$pro=$facta*$factor_b;
				$met=5;	
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		else if(is_numeric($product) && is_numeric($sum)){
			if(empty($factor_a) && empty($factor_b)){
				for ($i = 1; $i*$i <= $product; $i++){
					if ($product % $i == 0){
					   if($i+$product/$i==$sum){
					   		$fahad1=$i+$product/$i;
					   		$fahad2=$i;
					   		$fahad3=$product/$i;
					   }
					}
				}
				if($fahad2+$fahad3==$sum){
					$pro=$product;
					$su=$sum;
					$facta=$fahad2;
					$factb=$fahad3;
				}else{
					$this->param['error'] = 'Cannot find two factors of '.$product." that sum equal to ".$sum;
					return $this->param;
				}
				$met=6;
			}else{
				$this->param['error'] = 'Please! Enter any two values.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Enter any two values.';
			return $this->param;
		}
		$this->param['facta'] = $facta;
		$this->param['factb'] = $factb;
		$this->param['pro'] = $pro;
		$this->param['su'] = $su;
		$this->param['met'] = $met;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// Order Of Operations Calculator
	function order($request){
