				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Input.';
			return $this->param;
		}
	}

	// LCD Calculator
	function lcd($request){
  		$x= $request->x;
		if (!empty($x)) {
			$x=trim($x);
			$check=true;
			$input=explode(',', $x);
			$upper=[];
			$btm=[];
			foreach ($input as $key => $value) {
				$fraction_check=explode('/', trim($value));
				if (count($fraction_check)==2) {
					$mixed_check=explode(' ',trim($fraction_check[0]));
					if (count($mixed_check)==2) {
						if (is_numeric(trim($mixed_check[0])) && is_numeric(trim($mixed_check[1])) && is_numeric(trim($fraction_check[1]))) {
							$up=(trim($mixed_check[0])*trim($fraction_check[1]))+trim($mixed_check[1]);
							$upper[]=$up;
							$btm[]=trim($fraction_check[1]);
						}else{
							$check=false;
							break;
						}
					}elseif(count($mixed_check)>2){
						$check=false;
						break;	
					}else{
						if (is_numeric(trim($fraction_check[0])) && is_numeric(trim($fraction_check[1]))) {
							$upper[]=trim($fraction_check[0]);
							$btm[]=trim($fraction_check[1]);
						}else{
							$check=false;
							break;
						}
					}
				}elseif (count($fraction_check)>2) {
					$check=false;
					break;
				}else{
					if (is_numeric(trim($value))) {
						$upper[]=trim($value);
						$btm[]=1;
					}else{
						$check=false;
						break;	
					}
				}
			}
			if ($check==true) {
				function gcd($a24, $b25)
				{
					if ($b25 == 0)
					return $a24;
					return gcd($b25, $a24 % $b25);
				}
				function lcmofn($numbers, $n)
				{
					$ans = $numbers[0];
					for ($i = 1; $i < $n; $i++)
					$ans = ((($numbers[$i] * $ans)) / (gcd($numbers[$i], $ans)));
					return $ans;
				}
				$n = sizeof($btm);
				$lcm=lcmofn($btm, $n);
				$multiple=[];
				foreach ($btm as $key => $value) {
					$multiple[]=$lcm/$value;
				}
				$this->param['input'] = $input;
				$this->param['upper'] = $upper;
				$this->param['btm'] = $btm;
				$this->param['multiple'] = $multiple;
				$this->param['lcm'] = $lcm;
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

