	// Compound Inequality Calculator
	function inequality($request){
		$select = $request->select;
		$equ1 = $request->equ1;
		$con = $request->con;
		$equ2 = $request->equ2;
		// $vari = $request->vari;
		$vari = "x";
		if (!empty($equ1)) {
			$equ1 = str_replace(' ', '', $equ1);
			$greater_than_equal_count = substr_count($equ1, '>=');
			$less_than_equal_count = substr_count($equ1, '<=');
			$less_than_count = substr_count($equ1, '<') - $less_than_equal_count;
			$greater_than_count = substr_count($equ1, '>') - $greater_than_equal_count;
			$equal_count = substr_count($equ1, '=') - $greater_than_equal_count - $less_than_equal_count;
			$all_count = $greater_than_equal_count + $less_than_equal_count + $less_than_count + $greater_than_count + $equal_count;
			if ($all_count > 1) {
				$this->param['error'] = "Equation has more than one symbol.";
				return $this->param;
			}
			if(strpos($equ1, '>=') !== false){
				$equ1 = str_replace('>=', 'gtae', $equ1);
			}elseif(strpos($equ1, '<=') !== false){
				$equ1 = str_replace('<=', 'ltae', $equ1);
			}elseif(strpos($equ1, '<') !== false){
				$equ1 = str_replace('<', 'less', $equ1);
			}elseif(strpos($equ1, '>') !== false){
				$equ1 = str_replace('>', 'greater', $equ1);
			}elseif(strpos($equ1, '=') !== false){
				$equ1 = str_replace('=', 'equal', $equ1);
			}
