					$less_than_equal_count = substr_count($equ2, '<=');
					$less_than_count = substr_count($equ2, '<') - $less_than_equal_count;
					$greater_than_count = substr_count($equ2, '>') - $greater_than_equal_count;
					$equal_count = substr_count($equ2, '=') - $greater_than_equal_count - $less_than_equal_count;
					$all_count = $greater_than_equal_count + $less_than_equal_count + $less_than_count + $greater_than_count + $equal_count;
					if ($all_count > 1) {
						$this->param['error'] = "Second Equation has more than one symbol.";
						return $this->param;
					}
					if(strpos($equ2, '>=') !== false){
						$equ2 = str_replace('>=', 'gtae', $equ2);
					}elseif(strpos($equ2, '<=') !== false){
						$equ2 = str_replace('<=', 'ltae', $equ2);
