    // Matrix Transpose Calculator
    function transpose($request){
		$matrix2=$request->matrix2;
		$matrix22=$request->matrix22;
		for($i=1;$i<=$request->matrix2;$i++){
			for($j=1;$j<=$request->matrix22;$j++){
				if (isset($request['matrix3' . $i . '_' . $j]) && is_numeric($request['matrix3' . $i . '_' . $j])) {
					$second_matrix[] = $request['matrix3' . $i . '_' . $j];
					$chuti[] = "&matrix3" . $i . '_' . $j . "=";
				}
			}
		} 
        function tp($A){
            // reset all the variables before they are used 
            $i = $j = $k = $l = $m = null;
            // set number of rows
            $i = count($A);
            // return if there are no rows
            if($i === 0){ return $A; }
            // set number of columns
            $j = count($A[0]);  
            
            // handle matrices with fewer rows than columns or the same number of rows and columns  
            if($i <= $j){
              // add extra rows to the end of the matrix if necessary
              for($k = 0; $k < $j - $i; $k++){
                $A[$i + $k] = array();
              }
              // switch indices of rows and columns in the matrix
              for($l = 0; $l < $i; $l++){  
                for($m = $j; $m > $l; $m--){  
                  if(!isset($A[$m - 1][$l])){
                    $A[$m - 1][$l] = $A[$l][$m - 1]; 
                    unset($A[$l][$m - 1]);
                  }else{
                    $temp = $A[$m - 1][$l];
                    $A[$m - 1][$l] = $A[$l][$m - 1]; 
                    $A[$l][$m - 1] = $temp;
                  }   
                }
              }   
            // handle matrices with more rows than columns  
            } else {
              // switch indices of rows and columns in the matrix
              for($l = 0; $l < $i; $l++){
                for($m = 0; $m < $j && $m < $l; $m++){
                  if(!isset($A[$m][$l])){
                    $A[$m][$l] = $A[$l][$m];
                    unset($A[$l][$m]);
                    if(empty($A[$l])){ unset($A[$l]);}
                  } else {
                    $temp = $A[$m][$l];
                    $A[$m][$l] = $A[$l][$m];
                    $A[$l][$m] = $temp;
                  }
                }
              }
            }
            // we are done, return transposed matrix
            return $A;
        }
        $mul = $matrix22*$matrix2;
        if ($mul==count($second_matrix)) {
             $zain=(array_chunk($second_matrix,$matrix22));
            $jawab = tp($zain);
        }else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
        }
        $this->param['zain']=$zain;
        $this->param['jawab']=$jawab;
        $this->param['chuti']=$chuti;
        $this->param['second_matrix']=$second_matrix;
        $this->param['RESULT'] = 1;

        return $this->param;
    }

    // Gram-Schmidt Calculator
    function gram($request){
		$matrix2=$request->matrix2;
		$matrix22=$request->matrix22;
		for($i=1;$i<=$request->matrix2;$i++){
			for($j=1;$j<=$request->matrix22;$j++){
				if (isset($request['matrix3' . $i . '_' . $j]) && is_numeric($request['matrix3' . $i . '_' . $j])) {
					$second_matrix[] = $request['matrix3' . $i . '_' . $j];
					$chuti[] = "&matrix3" . $i . '_' . $j . "=";
				}
			}
		}
        function new_roundNumb($a) {
            return round($a, 2);
        }
        function normalizeVector($coordinates, $vector) {
            $divisor = 0;
            for ($i = 0; $i < $coordinates; $i++) {
                $divisor = $divisor + pow($vector[$i], 2);
            }
            $divisor = sqrt($divisor);
            if ($divisor != 0) {
                for ($i = 0; $i < $coordinates; $i++) {
                    $vector[$i] = new_roundNumb($vector[$i] / $divisor);
                }
            }
            return $vector;
        }
        function subtractPrevious($coordinates, $vector1, $vector2) {
            $divisor1 = 0;
            $divisor2 = 0;
            $dotProduct = 0;
            for ($i = 0; $i < $coordinates; $i++) {
                $divisor1 += $vector1[$i]*$vector1[$i];
                $divisor2 += $vector2[$i]*$vector2[$i];
                $dotProduct += $vector1[$i] * $vector2[$i];
            }
            if ($divisor1 != 0 && $divisor2 != 0) {
                for ($i = 0; $i < $coordinates; $i++) {
                    $vector1[$i] = new_roundNumb($vector1[$i] - $dotProduct * $vector2[$i] / $divisor2);
                }
            }
            return $vector1;
        }
        $mul = $matrix22*$matrix2;
        if ($mul==count($second_matrix)) {
            $zain=(array_chunk($second_matrix,$matrix22));
            for ($i=0; $i < $matrix22; $i++) { 
                $all_vec[] = array_column($zain, $i);
            }
            $ans_vec = normalizeVector($matrix2,$all_vec[0]);
            $first_unit = normalizeVector($matrix2,$all_vec[0]);
            $fahad = max($matrix22,$matrix2);
            $f_vec = $all_vec[0];
            $total = [];
            $con = $fahad - 1;
            for ($i=1; $i <= $fahad; $i++) { 
                $k = $i;
				if(isset($all_vec[$k])){
					$s_vec = $all_vec[$k];
					foreach ($f_vec as $key=>$price) {
						$total[$i][] = $price * $s_vec[$key];   
					}
					$vector_unit[] = array_sum($total[$i]);
				}
            }
            foreach ($f_vec as $value) {
                $itself_mul[] = pow($value, 2);
            }
            $vector_u = array_sum($itself_mul);
            foreach ($vector_unit as $index => $value7) {
                $combined_vector[] = $value7 / $vector_u;
            }
