                $pros_ans[] = array_column($ans_pro, $m);
            }
            $zaini = $all_vec;
            array_shift($zaini);
            foreach ($pros_ans as $main => $value) {
                $subtract[] = subtractPrevious($matrix2,$zaini[$main],$value);
            }
            foreach ($subtract as $value) {
                $all_vecunit[] = normalizeVector($matrix2,$value);
            }
            array_pop($all_vecunit);
            array_pop($subtract);
            array_pop($pros_ans);
        }else{
            $this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
        }
        $this->param['all_vec'] = $all_vec;
