						$m[] = $second_matrix;
					} else {
						$this->param['error'] = 'Please! Check Your Input.';
						return $this->param;
					}
				}
			}
			$result = array();
			for ($i = 1; $i <= $count_rows; $i++) {
				for ($j = 1; $j <= $matrix22; $j++) {
					$result[$i][$j] = 0;
					for ($k = 1; $k <= $matrix2; $k++) {
						$result[$i][$j] += $request['matrix' . $i . '_' . $k] * $request['matrix3' . $k . '_' . $j];
						$result[$i][$j];
					}
				}
			}
			for ($i = 1; $i <= $count_rows; $i++) {
				for ($j = 1; $j <= $matrix22; $j++) {
					$result[$i][$j];
					$l[] = $result[$i][$j];
				}
			}
		} else {
			$this->param['error'] = 'The number of columns in the first matrix should be equal to the number of rows in the second.';
			return $this->param;
		}
		$this->param['r'] = $r;
		$this->param['l'] = $l;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

