			return $this->param;
		}
	}

    // Inverse Matrix Calculator
    function inv_mat($request){
		//  dd($request->all());
        function invert($A, $debug = false){
            $swap=[];
            $swap_line=[];
            /// @todo check rows = columns

            $n = count($A);
            $pz = $A;

            // get and append identity matrix
            $I = identity_matrix($n);
            for ($i = 0; $i < $n; ++ $i) {
                $A[$i] = array_merge($A[$i], $I[$i]);
                $pz[$i] = array_merge($pz[$i], $I[$i]);
            }

            if ($debug) {
                echo "\nStarting matrix: ";
                echo "<pre>";
                print_matrix($A);
            }

            // forward run
            for ($j = 0; $j < $n-1; ++ $j) {
                // for all remaining rows (diagonally)
                for ($i = $j+1; $i < $n; ++ $i) {
                    // if the value is not already 0
                    if ($A[$i][$j] !== 0) {
                        // adjust scale to pivot row
                        // subtract pivot row from current
                        $scalar = $A[$j][$j] / $A[$i][$j];
                        for ($jj = $j; $jj < $n*2; ++ $jj) {
                            $A[$i][$jj] *= $scalar;
                            $A[$i][$jj] -= $A[$j][$jj];
                        }
                    }
                }
                if ($debug) {
                    echo "\nForward iteration $j: ";
                    print_matrix($A);
                }
            }

            // reverse run
            for ($j = $n-1; $j > 0; -- $j) {
                for ($i = $j-1; $i >= 0; -- $i) {
                    if ($A[$i][$j] !== 0) {
                        $scalar = $A[$j][$j] / $A[$i][$j];
                        for ($jj = $i; $jj < $n*2; ++ $jj) {
                            $A[$i][$jj] *= $scalar;
                            $A[$i][$jj] -= $A[$j][$jj];
                        }
                    }
                }
                if ($debug) {
                    echo "\nReverse iteration $j: ";
                    print_matrix($A);
                }
            }

            // last run to make all diagonal 1s
            /// @note this can be done in last iteration (i.e. reverse run) too!
            for ($j = 0; $j < $n; ++ $j) {
                if ($A[$j][$j] !== 1) {
                    $scalar = 1 / $A[$j][$j];
                    for ($jj = $j; $jj < $n*2; ++ $jj) {
                        $A[$j][$jj] *= $scalar;
                    }
                }
                if ($debug) {
                    echo "\n1-out iteration $j: ";
                    print_matrix($A);
                }
            }

            // take out the matrix inverse to return
            $Inv = array();
            for ($i = 0; $i < $n; ++ $i) {
                $Inv[$i] = array_slice($A[$i], $n);
            }

            return $Inv;
        }
        function rref2($matrix){
            $lead = 0;
            $pz=$matrix;
            $swap=[];
            $swap_line=[];
            $rowCount = count($matrix);
            if ($rowCount == 0)
                return $matrix;
            $columnCount = 0;
            if (isset($matrix[0])) {
                $columnCount = count($matrix[0]);
            }
            for ($r = 0; $r < $rowCount; $r++) {
                if ($lead >= $columnCount)
                    break;        
                {
                    $i = $r;
                    while ($matrix[$i][$lead] == 0) {
                        $i++;
                        if ($i == $rowCount) {
                            $i = $r;
                            $lead++;
                            if ($lead == $columnCount)
                                return $matrix;
                        }
                    }
                    $temp = $matrix[$r];
                    $matrix[$r] = $matrix[$i];
                    $matrix[$i] = $temp;
                    if ($matrix[$i][$lead] == 0) {
                        $swap_line[]="Swap the row ".($r+1)." with row ".($i+1);
                        $temp = $pz[$r];
                        $pz[$r] = $pz[$i];
                        $pz[$i] = $temp;
                        $swap[]=$pz;
                    }
                }
                {
                    $lv = $matrix[$r][$lead];
                    for ($j = 0; $j < $columnCount; $j++) {
                        $matrix[$r][$j] = $matrix[$r][$j] / $lv;
                        $pz[$r][$j] = $pz[$r][$j]/$lv;
                    }
                    $test1=convert2($lv);
                    if ($test1[1]==1) {
                        $lv=$lv;
                        $swap_line[]='Divide row '.($r+1).' by '.$lv.": R<sub>".($r+1)."</sub> = R<sub>".($r+1)."</sub>/".$lv;
                    }else if ($test1[1]!=1) {                          
                        $lv=$test1[0]."/".$test1[1];
                        $lv3=$test1[1]."/".$test1[0];
                        $swap_line[]='Multiply row '.($r+1).' by '.$lv3.": R<sub>".($r+1)." = ".$lv3."</sub> R<sub>".($r+1)."</sub>";
                    }
                    $swap[]=$pz;
                }
                for ($i = 0; $i < $rowCount; $i++) {
                    if ($i != $r) {
                        $lv = $matrix[$i][$lead];
                        $lv2 = $pz[$i][$lead];
                        for ($j = 0; $j < $columnCount; $j++) {
                            $matrix[$i][$j] -= $lv * $matrix[$r][$j];
                            $pz[$i][$j] -= $lv2 * $pz[$r][$j];
                        }
                    $swap[]=$pz;
                    $test=convert2($lv);
                    if ($test[1]==1) {
                      $lv=$lv;
                    }else if ($test[1]!=1) {                          
                      $lv=$test[0]."/".$test[1];
                    }
                    $swap_line[]='Subtract row '.($i).' multiplied by '.$lv." from row R".($i+1).": R<sub>".($i+1)."</sub> = R<sub>".($i+1)."</sub> - ".$lv."R<sub>".($i)."</sub>";
                    }
                }
                $lead++;
            }
            return array($matrix,$swap,$swap_line,$pz);
        }
        function print_matrix($A, $decimals = 6){
            foreach ($A as $row) {
                echo "\n\t[";
                foreach ($row as $i) {
                    echo "\t" . sprintf("%01.{$decimals}f", round($i, $decimals));
                }
                echo "\t]";
            }
        }
        function identity_matrix($n){
            $I = array();
            for ($i = 0; $i < $n; ++ $i) {
                for ($j = 0; $j < $n; ++ $j) {
                    $I[$i][$j] = ($i == $j) ? 1 : 0;
                }
            }
            return $I;
        }
        function deter($arr,$N){
            if ($N == 2) {
                $determinant = $arr[0][0] * $arr[1][1] - $arr[0][1] * $arr[1][0];
            }else{
                $determinant = $arr[0][0] * ($arr[1][1]*$arr[2][2] - $arr[1][2]*$arr[2][1]) -
                   $arr[0][1] * ($arr[1][0]*$arr[2][2] - $arr[1][2]*$arr[2][0]) +
                   $arr[0][2] * ($arr[1][0]*$arr[2][1] - $arr[1][1]*$arr[2][0]);
            }
            return $determinant;
        }
        function getCofactor($A,$temp,$p,$q,$n){
            $i = 0; 
            $j = 0;
            // Looping for each element of the matrix
            for ($row = 0; $row < $n; $row++){
                for ($col = 0; $col < $n; $col++){
                    // Copying into temporary matrix only those element
                    // which are not in given row and column
                    if ($row != $p && $col != $q){
                        $temp[$i][$j++] = $A[$row][$col];
                        // Row is filled, so increase row index and
                        // reset col index
                        if ($j == $n - 1){
                            $j = 0;
                            $i++;
                        }
                    }
                }
            }
            return $temp;
        }
        /* Recursive function for finding determinant of matrix.
        n is current dimension of A[][]. */
        function determinant($A,$n,$N){
            $D = 0; // Initialize result
            // Base case : if matrix contains single element
            if ($n == 1)
                return $A[0][0];

            $temp = array_fill( 0, $N, null);// To store cofactors
            for($i=0;$i<$N;$i++){
                $temp[$i]= array_fill( 0, $N, null);
            }

            $sign = 1; // To store sign multiplier

            // Iterate for each element of first row
            for ($f = 0; $f < $n; $f++)
            {
                // Getting Cofactor of A[0][f]
                $temp = getCofactor($A, $temp, 0, $f, $n);
                $D += $sign * $A[0][$f] * determinant($temp, $n - 1,$N);

                // terms are to be added with alternate sign
                $sign = -$sign;
            }
            return $D;
        }

        // Function to get adjoint of A[N][N] in adj[N][N].
        function adjoint($A,$adj,$N){
            if ($N == 1){
                $adj[0][0] = 1; 
                return;
            }
            // temp is used to store cofactors of A[][]
            $sign = 1;
            $temp = array_fill( 0, $N, null);
            for($i=0;$i<$N;$i++){
                $temp[$i]= array_fill( 0, $N, null);
            }
            for ($i = 0; $i < $N; $i++){
                for ($j = 0; $j < $N; $j++){
                    // Get cofactor of A[i][j]
                    $temp = getCofactor($A, $temp, $i, $j, $N);
                    // sign of adj[j][i] positive if sum of row
                    // and column indexes is even.
                    $sign = (($i + $j) % 2 == 0)? 1: -1;
                    $sign22[] = $sign;
                    $sign_pow[] = ($i+1)." + ".($j+1);
                    $c_sign[] = ($i+1).($j+1);
                    // Interchanging rows and columns to get the
                    // transpose of the cofactor matrix
                    $adj[$j][$i] = $sign * (determinant($temp, $N-1,$N));
                }
            }
            return array($adj,$sign22,$sign_pow,$temp,$c_sign);
        }
        function transpose($A,$N){
            // $N = 2;
            for ($i = 0; $i < $N; $i++){
                for ($j = 0; $j < $N; $j++){
                    $B[$i][$j] = $A[$j][$i];
                }
            }
            return $B;
        }
        function convert2($xelem){
            $sign = '';
            $sign2 = '+';
            $f=false;
            $x = $xelem;
            $x2 = roundresult2($x);
            $absx=abs($x2);
            $y=floor($absx);
            $frac=($absx-$y);
            if( $x2<0 ) 
                $sign = $sign2 = '-';
            $d = digits_after_period2($absx);
            $den = round(pow(10,$d));
            $num = round($frac * $den);
            $a12=strval($num);
            $len=strlen($a12);
            if( $len>8 ) $f=true;
            $g = gcd22($num,$den,$f);
            $num2 = round($num / $g);
            $den2 = round($den / $g);
            $txt=$x2." ";
            $txt.=$num."/".$den;
            $top_jawab=$sign.($num2+$den2*$y);
            $down_jawab=$den2;
            return array($top_jawab,$down_jawab);
        }
        function gcd22($a, $b, $f) {
          if( $f ){
                if ( $b<=1 )
                   return $a;
            }else{
                if ( !$b )
                   return $a;
            }
            return gcd22($b, $a % $b, $f);
        }
        function roundresult2($x){
            $y=floatval($x);
            $y=roundnum2($y,10);
            return $y;
        }
        function toPrecision2($number, $precision) {
            if ($number == 0) return 0;
            $exponent = floor(log10(abs($number)) + 1);
            $significand =
                round(
                    ($number / pow(10, $exponent))
                    * pow(10, $precision)
                )
                / pow(10, $precision);
            return $significand * pow(10, $exponent);
        }
        function roundnum2($x,$p){
            $n=floatval($x);
            $m=toPrecision2($n,($p+1));
            $y=strval($m);
            $i=strpos($y,'e');
            if($i==-1)
                $i=strlen($y);
            $j=strpos($y,'.');
            return $y;
        }
        function digits_after_period2($x){
           $f = strval($x);
           $i = strpos($f,'.');
           $len = strlen($f)-$i-1;
           return $len;
        }
        for($i=0;$i< $request->dtrmn_slct_method;$i++){
            for($j=0;$j< $request->dtrmn_slct_method;$j++){
                if(is_numeric($request['dtrmn_'.$i.'_'.$j])){
                    $all[]=$request['dtrmn_'.$i.'_'.$j];
                }else{
                    $this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
                }
            }
        }
        $zain=(array_chunk($all,$request->dtrmn_slct_method));
        if ($request->dtrmn_opts_method=="exp_col") {
            $N = $request->dtrmn_slct_method;
            $det = deter($zain,$N);
            if ($det != 0 ) {
                $f_ans = invert($zain);
                $n = count($zain);
                $I = identity_matrix($n);
                for ($i = 0; $i < $n; ++ $i) {
                    $invt[$i] = array_merge($zain[$i], $I[$i]);
                }
                $ans=rref2($invt);
                foreach ($f_ans as $value) {
                    foreach ($value as $value2) {
                        $yy = explode('.', $value2);
                        if (count($yy)==2) {
                            $inverse[] = number_format($value2, 3);
                        }else if (count($yy)==1) {
                            $inverse[] = $value2;
                        }
                    }
                }
                $inverse = (array_chunk($inverse,$request->dtrmn_slct_method));
                $this->param['matrix']=$ans[0];
                $this->param['swap']=$ans[1];
                $this->param['swap_line']=$ans[2];
            }else if ($det == 0) {
                $inverse = "The matrix is not invertible.";
            }
        }else if ($request->dtrmn_opts_method=="exp_row") {
            $N = $request->dtrmn_slct_method;
            $det = deter($zain,$N);
            if ($det==0) {
                $inverse = "The matrix is not invertible.";
            }else if ($det != 0) {
                // $det1 = deter($zain);
                $temp = array_fill( 0, $N-1, null);
                for($i=0;$i<$N-1;$i++){
                    $temp[$i]= array_fill( 0, $N-1, null);
                }
                for ($i = 0; $i < $N; $i++){
                    for ($j = 0; $j < $N; $j++){
                        // Get cofactor of A[i][j]
                        $cofa[] = getCofactor($zain, $temp, $i, $j, $N);
                    }
                }
                foreach ($cofa as $value) {
                    $all_cofadet[] = determinant($value, $N-1,$N);
                }
                $adj = array_fill( 0, $N, null);
                for($i=0;$i<$N;$i++){
                    $adj[$i] = array_fill( 0, $N, null);
                }
                $res = adjoint($zain,$adj,$N);
                for ($i=0; $i < count($all_cofadet); $i++) { 
                    $allans_det[] = $all_cofadet[$i] * $res[1][$i];
                }
                $adj_ans = $res[0];
                $c_down = $res[4];
                $minus_pow = $res[2];
                $all_cofy = $cofa;
                $final_cofa=(array_chunk($allans_det,$request->dtrmn_slct_method));
                $ans_tran = transpose($final_cofa,$N);
                for ($i = 0; $i < $N; $i++){
                    for ($j = 0; $j < $N; $j++){
                        $in = $adj_ans[$i][$j]/$det;
                        $yy = explode('.', $in);
                        if (count($yy)==2) {
                            $inverse[$i][$j] = number_format($in, 3);
                        }else if (count($yy)==1) {
                            $inverse[$i][$j] = $in;
                        }
                    }
                }
                $allcofy_det = $allans_det;
                $this->param["c_down"] = $c_down;
                $this->param["minus_pow"] = $minus_pow;
                $this->param["all_cofy"] = $all_cofy;
                $this->param["allcofy_det"] = $allcofy_det;
                $this->param["ans_tran"] = $ans_tran;
                $this->param["final_cofa"] = $final_cofa;
            }
        }
        $this->param["zain"] = $zain;   
        $this->param["det"] = $det;
        $this->param["inverse"] = $inverse;
        $this->param["RESULT"] = 1;
        return $this->param;	
    }

