    // Characteristic Polynomial Calculator
    function characteristic($request){

		$matrix22=$request->matrix22;
		for($i=1;$i<=$matrix22;$i++){
			for($j=1;$j<=$matrix22;$j++){
				if (isset($request['matrix3' . $i . '_' . $j]) && is_numeric(($request['matrix3' . $i . '_' . $j]))) {
					$second_matrix[]=$request['matrix3' . $i . '_' . $j];
				}
			}
		}
        $mul = $matrix22*$matrix22;
        if ($mul==count($second_matrix)) {
            $zain=(array_chunk($second_matrix,$matrix22));
            $down = ($matrix22+1);
            for ($i=0; $i < count($second_matrix); $i++) { 
                if ($i/$down==1) {
                    $advance[] = $second_matrix[$i]."-λ";
                    $down = $down + $down;
                }else{
                    if ($i == 0) {
                        $advance[] = $second_matrix[$i]."-λ";
                    }else{
                        $advance[] = $second_matrix[$i];
                    }
                }
            }
            $val_array = array_chunk($advance,$matrix22);
            $len = count($val_array);
            foreach ($val_array as $value) {
                $aja = count($value);
                foreach ($value as $value3) {
                    $input[] = $value3;
                    if (--$aja <= 0) {
                        break;
                    }
                    $input[] = ",";
                }
                if (--$len <= 0) {
                    break;
                }
                $input[] = "@@";
            }
            $in = implode("",$input);
			try{
				$client = new Client();
				$response = $client->post("http://167.172.134.148/characteristic", [
					'form_params' => [
						'mat'=>$in,
					],
					'timeout' => 120,
				]);
				$buffer = $response->getBody();
				$buffer=explode("@@@", $buffer);
                $this->param['answer'] = $buffer[0];
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
        }else{
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
        }
        $this->param['matrix'] = $val_array;
        $this->param['input_ma'] = $zain;
        $this->param['RESULT'] = 1;

        return $this->param;
    }

	// Critical Point Calculator
	function critical($request){
		$EnterEq= $request->EnterEq;
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		$parem=$EnterEq;
		$parem=str_replace(' ', '', $parem);
		$parem=str_replace('+', 'plus', $parem);
		$parem=str_replace('{', '(', $parem);
		$parem=str_replace('}', ')', $parem);
		$parem=str_replace('e^x', 'exp(x)', $parem);
		$parem=str_replace('exp^', 'exp', $parem);
		$parem=str_replace('^', '**', $parem);
		$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
		try{
			if (preg_match("/y/i", $parem) && preg_match("/x/i", $parem)) {
				$response = Http::timeout(120)->get('http://167.172.134.148/critical', [
					'equ' => $parem,
					'wrt' => "xy",
				]);
			}else{
				$response = Http::timeout(120)->get('http://167.172.134.148/critical', [
					'equ' => $parem,
					'wrt' => "x",
				]);
			}
			$buffer =  $response->getBody();
			$buffer=explode("@@@", $buffer);
			$this->param['buffer'] = $buffer[0];
			$this->param['ans'] = $buffer[1];
			$this->param['enter'] = $buffer[2];
			$this->param['simple'] = $buffer[3];
			$this->param['root'] = $buffer[4];
			if ($buffer['4']=='\left[ \right]') {
				$this->session->set_flashdata('critical','no solution exist');
				return false;
			}
			if (preg_match("/y/i", $parem) && preg_match("/x/i", $parem)) {
				$this->param['step'] = $buffer[5];
				$this->param['ans1'] = $buffer[6];
				$this->param['wrt'] = 'xy';
			}else{
				$this->param['mini'] = $buffer[5];
				$this->param['maxi'] = $buffer[6];
			}
			$this->param['RESULT'] = 1;
			$this->param['RESULT'] = 1;
			return $this->param;
		}catch (\Exception $response) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

	// Radius Of Convergence Calculator

	function radius($request){
		$EnterEq= $request->EnterEq;
		$with= $request->with;			
		$validator = Validator::make($request->all(), [
			'EnterEq' => 'required|regex:/^[^<>&]*$/i',
		]);
		if ($validator->fails()) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $EnterEq)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (!empty($with)) {
			$parem=$EnterEq;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('%20', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			$enter=$parem;
			$upr=str_replace('n', '(nplus1)', $parem);
			$parem='('.$upr.')/('.$parem.')';
		    $parem1=trim($with);
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/radius', [
					'equ' => $parem,
					'wrt' => $parem1,
					'enter' => $enter,
				]);
				if ($response->failed()) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
				$buffer =  $response->getBody();
				$buffer=explode("@@@", $buffer);
    			$this->param['enter'] = $buffer[0];
    			$this->param['ans'] = $buffer[1];
    			$this->param['equs'] = $buffer[2];
				// $queryParams = $request->all();
				// $baseUrl = url()->current();
				// $queryString = http_build_query($queryParams);
				// $shareURL = $baseUrl . '/?' . $queryString;
    			$this->param['shareURL'] = $shareURL;
				$this->param['RESULT'] = 1;
				return $this->param;
			}catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}else{
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
  	}
