	// Absolute Value Calculator

	// Absolute Value Calculator
	function absolute($request){
		$eq = $request->eq;
		$n = $request->n;
		$n1 = $request->n1;
		$var = $request->var;
		$submit = $request->type;
		if ($submit === 'm1' && is_numeric($n)) {
			$res = abs($n);
			$this->param['res'] = $res;
			$this->param['RESULT'] = 1;
			return $this->param;
		} elseif ($submit === 'm2' && !empty($eq) && !empty($n1)) {
			$validator = Validator::make($request->all(), [
				'eq' => 'required|regex:/^[^<>&]*$/i',
			]);
			if ($validator->fails()) {
				$this->param['error'] = 'Please Enter Valid Input.';
				return $this->param;
			}
			if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $eq)) {
				$this->param['error'] = 'Please Enter Valid Input.';
				return $this->param;
			}
			$parem = $eq;
			$parem = str_replace(' ', '', $parem);
			$parem = str_replace('%20', '', $parem);
			$parem = str_replace('+', 'plus',
				$parem
			);
			$parem = str_replace('{', '(', $parem);
			$parem = str_replace('}', ')', $parem);
			$parem = str_replace('e^', 'exp',
				$parem
			);
			$parem = str_replace('exp^', 'exp', $parem);
			$parem = str_replace('^', '**', $parem);
			$parem = str_replace('e^sqrt(x)',
				'exp(2*x)',
				$parem
			);
			$parem1 = $n1;
			$parem1 = str_replace(' ', '', $parem1);
			$parem1 = str_replace('%20', '', $parem1);
			$parem1 = str_replace('+', 'plus',
				$parem1
			);
			$parem1 = str_replace('{', '(', $parem1);
			$parem1 = str_replace('}', ')', $parem1);
			$parem1 = str_replace('e^', 'exp',
				$parem1
			);
			$parem1 = str_replace('exp^', 'exp', $parem1);
			$parem1 = str_replace('^', '**', $parem1);
			$parem1 = str_replace('e^sqrt(x)',
				'exp(2*x)',
				$parem1
			);
			$equ = "(" . $parem . ")-(" . $parem1 . ")";
			$equ1 = "(" . $parem . ")plus(" . $parem1 . ")";
			try{
				$response = Http::timeout(120)->get('http://167.172.134.148/absolute', [
					'eq' => $equ,
					'eq1' => $equ1,
					'var' => $var,
					'e1' => $parem,
					'e2' => $parem1,
				]);
				$buffer =  $response->getBody();
				$buffer = explode("@@@", $buffer);
				$this->param['res'] = $buffer[0];
				$this->param['res1'] = $buffer[1];
				$check1 = $buffer[2];
				$check11 = $buffer[3];
				$check2 = $buffer[4];
				$check22 = $buffer[5];
				if (preg_match('/\|/', $eq)) {
					$check1 = abs($check1);
					$check2 = abs($check2);
				} elseif (preg_match('/\|/', $n1)) {
					$check11 = abs($check11);
					$check22 = abs($check22);
				}
				$this->param['check1'] = $check1;
				$this->param['check11'] = $check11;
				$this->param['check2'] = $check2;
				$this->param['check22'] = $check22;
				$this->param['eq'] = $eq;
				$this->param['n1'] = $n1;
				$this->param['RESULT'] = 1;
				return $this->param;
			}catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
	}
