	// Solve for x Calculator
	function solve($request){
		$input= $request->input;
		$is_equal= $request->is_equal;
  		if (!empty($input) && is_numeric($is_equal)) {
  			if (preg_match('/x/i', $input)==0) {
				$this->param['error'] = 'x is not in the Equestion.';
				return $this->param;
  			}
  			$parem=$input;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('−', '-', $parem);
			$parem=str_replace('plus', '+', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			$parem=$parem.'-('.$is_equal.')';
			try {
				$client = new Client();
				$response = $client->post("http://167.172.134.148/solve-x", [
					'form_params' => [
						'equ' => $parem,
					],
					'timeout' => 120,
				]);
				$buffer = $response->getBody();
				$buffer = json_decode($buffer,true);
                $ans=$buffer[0];
                $this->param['ans'] = $ans;
				$this->param['RESULT'] = 1;
				return $this->param;
			} catch (\Exception $response) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
  		}else{
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
  		}
	}

	// Null Space Calculator
	function null($request){
		$row = $request->row;
		$colum = $request->colum;
		$input = '';
		for ($i = 0; $i < $row; $i++) {
			for ($j = 0; $j < $colum; $j++) {
				if (!is_numeric($request['matrix_' . $i . '_' . $j])) {
					$this->param['error'] = 'Please enter only numeric values.';
					return $this->param;
				}
				if ($j == ($colum - 1)) {
					$input .= $request['matrix_' . $i . '_' . $j];
				} else {
					$input .= $request['matrix_' . $i . '_' . $j] . ',';
				}
			}
			if ($i != ($row - 1)) {
				$input .= '@@';
			}
		}
		try{
			$response = Http::timeout(120)->get('http://167.172.134.148/null', [
				'mat' => $input,
			]);
			$buffer = $response->body();
			$buffer = explode("@@@", $buffer);
			$reff = str_replace('\left( \left[', '\left[', $buffer[0]);
			$reff = explode('\left(', $reff);
			$reff = explode(',', $reff[0]);
			$this->param['rref'] = $reff[0];
			$this->param['null'] = $buffer[1];
			$this->param['enter'] = $buffer[2];
			$this->param['total'] = $buffer[3];
			$this->param['input'] = $input;
			$this->param['row'] = $row;
			$this->param['colum'] = $colum;
			$this->param['RESULT'] = 1;
			return $this->param;
		} catch (\Exception $response) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}

    // Gaussian Elimination Calculator
    function gaussian($request){
		$matrix2= $request->matrix2;
		$matrix22= $request->matrix22;
        function gcd22($a, $b, $f) {
          if( $f ){
                if ( $b<=1 )
                   return $a;
            }else{
                if ( !$b )
                   return $a;
            }
            return gcd22($b, $a % $b, $f);
        }
        function roundresult2($x){
            $y=floatval($x);
            $y=roundnum2($y,10);
            return $y;
        }
        function toPrecision2($number, $precision) {
            if ($number == 0) return 0;
            $exponent = floor(log10(abs($number)) + 1);
            $significand =
                round(
                    ($number / pow(10, $exponent))
                    * pow(10, $precision)
                )
                / pow(10, $precision);
            return $significand * pow(10, $exponent);
        }
        function roundnum2($x,$p){
            $n=floatval($x);
            $m=toPrecision2($n,($p+1));
            $y=strval($m);
            $i=strpos($y,'e');
            if($i==-1)
                $i=strlen($y);
            $j=strpos($y,'.');
            return $y;
        }
        function digits_after_period2($x)
        {
           $f = strval($x);
           $i = strpos($f,'.');
           $len = strlen($f)-$i-1;
           return $len;
        }
        function convert2($xelem)
        {
            $sign = '';
            $sign2 = '+';
            $f=false;
            $x = $xelem;
            $x2 = roundresult2($x);
            $absx=abs($x2);
            $y=floor($absx);
            $frac=($absx-$y);
            if( $x2<0 ) 
                $sign = $sign2 = '-';
            $d = digits_after_period2($absx);
            $den = round(pow(10,$d));
            $num = round($frac * $den);
            $a12=strval($num);
            $len=strlen($a12);
            if( $len>8 ) $f=true;
            $g = gcd22($num,$den,$f);
            $num2 = round($num / $g);
            $den2 = round($den / $g);
            $txt=$x2." ";
            $txt.=$num."/".$den;
            $top_jawab=$sign.($num2+$den2*$y);
            $down_jawab=$den2;
            return array($top_jawab,$down_jawab);
        }
        function rref2($matrix)
        {
            $lead = 0;
            $pz=$matrix;
            $swap=[];
            $swap_line=[];
            $rowCount = count($matrix);
            if ($rowCount == 0)
                return $matrix;
            $columnCount = 0;
            if (isset($matrix[0])) {
                $columnCount = count($matrix[0]);
            }
            if ($rowCount > $columnCount) {
                $bus=$rowCount-2;
            }else if ($rowCount < $columnCount) {
                $bus=$rowCount;
            }else if ($rowCount == $columnCount) {
                $bus=$rowCount-1;
            } 
            // $bus=$rowCount;
            for ($r = 0; $r < $bus; $r++) {
                if ($lead >= $columnCount)
                    break;        
                {
                    $i = $r;
                    while ($matrix[$i][$lead] == 0) {
                        $i++;
                        if ($i == $rowCount) {
                            $i = $r;
                            $lead++;
                            if ($lead == $columnCount)
                                return $matrix;
                        }
                    }
                    $temp = $matrix[$r];
                    $matrix[$r] = $matrix[$i];
                    $matrix[$i] = $temp;
                    if ($matrix[$i][$lead] == 0) {
                        $swap_line[]="Swap the row ".($r+1)." with row ".($i+1);
                        $temp = $pz[$r];
                        $pz[$r] = $pz[$i];
                        $pz[$i] = $temp;
                        $swap[]=$pz;
                    }
                }
                {
                    $lv = $matrix[$r][$lead];
                    for ($j = 0; $j < $columnCount; $j++) {
                        $matrix[$r][$j] = $matrix[$r][$j] / $lv;
                        $pz[$r][$j] = $pz[$r][$j]/$lv;
                    }
                    $test1=convert2($lv);
                    if ($test1[1]==1) {
                        $lv=$lv;
                        $swap_line[]='Divide row '.($r).' by '.$lv.": R<sub>".($r)."</sub> = R<sub>".($r)."</sub>/".$lv;
                    }else if ($test1[1]!=1) {                          
                        $lv=$test1[0]."/".$test1[1];
                        $lv3=$test1[1]."/".$test1[0];
                        $swap_line[]='Multiply row '.($r).' by '.$lv3.": R<sub>".($r)." = ".$lv3."</sub> R<sub>".($r)."</sub>";
                    }
                    $swap[]=$pz;
                }
                for ($i = 0; $i < $rowCount; $i++) {
                    if ($i != $r) {
                        $lv = $matrix[$i][$lead];
                        $lv2 = $pz[$i][$lead];
                        for ($j = 0; $j < $columnCount; $j++) {
                            $matrix[$i][$j] -= $lv * $matrix[$r][$j];
                            $pz[$i][$j] -= $lv2 * $pz[$r][$j];
                        }
                        $swap[]=$pz;
                        $test=convert2($lv);
                        if ($test[1]==1) {
                          $lv=$lv;
                        }else if ($test[1]!=1) {                          
                          $lv=$test[0]."/".$test[1];
                        }
                        if ($lv < 0) {
                            // $lv=-1 * $lv;
                            $swap_line[]='Add row '.($i).' multiplied by '.$lv." from row R".($r).": R<sub>".($i)."</sub> = R<sub>".($i)."</sub> + ".$lv."R<sub>".($r)."</sub>";
                        }else if ($lv >= 0) {
                            $swap_line[]='Subtract row '.($i).' multiplied by '.$lv." from row R".($r).": R<sub>".($i)."</sub> = R<sub>".($i)."</sub> - ".$lv."R<sub>".($r)."</sub>";
                        }
                    }
                }
                $lead++;
            }
            return array($matrix,$swap,$swap_line,$pz);
        }
		for($i=1;$i<=$matrix2;$i++){
			for($j=1;$j<=$matrix22;$j++){
				if (isset($request['matrix3' . $i . '_' . $j]) && is_numeric(($request['matrix3' . $i . '_' . $j]))) {
					$second_matrix[]=$request['matrix3' . $i . '_' . $j];
				}else{
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
			}
		}
        $zain=(array_chunk($second_matrix,$matrix22));
        $fahad2=rref2($zain);
        $this->param['matrix']=$fahad2[0];
        $this->param['swap']=$fahad2[1];
        $this->param['swap_line']=$fahad2[2];
        $this->param['pz']=$fahad2[3];
        $this->param['RESULT'] = 1;
        return $this->param;
    }

