	// Divisible Calculator
	function divisible($request){
		$no        = $request->no;
		$divisible = $request->divisible;
		if(is_numeric($no) && is_numeric($divisible) && $no > 0 && $divisible > 0 && $no >= $divisible){
			$division        = intval($no / $divisible);
			$modulus         = $no % $divisible;
			$division_array  = str_split($division);
			$divisible_array = str_split($divisible);
			$number_array    = str_split($no);
			$counter         = 1;

			for($i = 0; $i < count($number_array); $i++){
				if ($i == 0) {
					$com = $number_array[$i];
				}
				if($com < $divisible){
					$com     = $com.$number_array[$i+1];
					$counter = $counter + 1;
				}
			}

			$stokes    = $com;
			$com_array = str_split($com);

			for ($z = count($com_array); $z < count($number_array) ; $z++) { 
				$separate_values[] = $number_array[$z];
			}

			for($j = 0; $j < count($division_array); $j++){
				$multiplication[] = $divisible * $division_array[$j];  
				$p                = $com - $multiplication[$j];
				$p_length[]       = $p;
				$tree[]           = $p; 
				
				if($p < $divisible){
					if(isset($separate_values[$j])){
						$com = $p.$separate_values[$j];
						$extra[] = $com;
					}
				}
				$read[] = $com;
			}
			
			$this->param['stokes']          = $stokes;
			$this->param['divisible_array'] = $divisible_array;
			$this->param['number_array']    = $number_array;
			$this->param['number']          = $no;
			$this->param['divisible']       = $divisible;
			$this->param['division']        = $division;
			$this->param['modulus']         = $modulus;
			$this->param['multiply']        = $multiplication;
			$this->param['read']            = $read;
			$this->param['com']             = $com;
			$this->param['p_length']        = $p_length;
			$this->param['tree_array']      = $tree;
			$this->param['RESULT']          = 1;
			return $this->param;
		}
		else{
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
	}

