	// Equation of a line Calculator
    function line($request){
		
		$type= $request->type;
		$x1= $request->x1;
		$x2= $request->x2;
		$y1= $request->y1;
		$y2= $request->y2;
		$x3= $request->x3;
		$y3= $request->y3;
        if ($type=='2') {
            if (is_numeric($x1) && is_numeric($x2) && is_numeric($y1) && is_numeric($y2)) {
                $x=$x2 - $x1;
                $y=$y2 - $y1;
                $slope=round($y / $x,4);
                $angle=round(atan($slope) * (180 / pi()),4);
                $distance=round(sqrt(pow($x, 2) + pow($y, 2)),4);
                $b=round($y1 - ($slope*$x1),2);
                $type=$type;
                $this->param['type'] = $type;
                $this->param['x'] = $x;
                $this->param['y'] = $y;
                $this->param['b'] = $b;
                $this->param['slope'] = $slope;
                $this->param['angle'] = $angle." deg";
                $this->param['distance'] = $distance;
            } else {
				$this->param['error'] = 'Please Check Your Input.';
				return $this->param;
            }
        }else if ($type=='1') {
            $slope=$x2;
            if (is_numeric($x1) && is_numeric($y1) && is_numeric($slope)) {
                $angle=round(atan($slope) * (180 / pi()),4);
                $b=round($y1 - ($slope*$x1),4);
                $type=$type;
                 $this->param['type'] = $type;
                $this->param['b'] = $b;
                $this->param['slope'] = $slope;
                $this->param['angle'] = $angle." deg";
            }else{
				$this->param['error'] = 'Please Check Your Input.';
				return $this->param;
            }
        }else if ($type=='3') {
            $b=$x1;
            $slope=$x2;
            if (is_numeric($b) && is_numeric($slope)) {
                $angle=round(atan($slope) * (180 / pi()),4);
                $type=$type;
                $this->param['type'] = $type;
                $this->param['b'] = $b;
                $this->param['slope'] = $slope;
                $this->param['angle'] = $angle." deg";
            }else{
				$this->param['error'] = 'Please Check Your Input.';
				return $this->param;
            }
        }else if ($type=='4') {
            if (is_numeric($x1) && is_numeric($x2) && is_numeric($y1) && is_numeric($y2) && is_numeric($x3) && is_numeric($y3)) {
                $f_down=$y1 - $x1;
                $s_down=$y2 - $x2;
                $t_down=$y3 - $x3;
                $type=$type;
                $this->param['type'] = $type;
                $this->param['f_down'] = $f_down;
                $this->param['s_down'] = $s_down;
                $this->param['t_down'] = $t_down;
            } else {
				$this->param['error'] = 'Please Check Your Input.';
				return $this->param;
            }
        }
        $this->param['RESULT'] = 1;
        return $this->param;
    }

	// Standard Form Calculator
	function standard($request){
		$x = $request->x;
		$x = str_replace('−','-',$x);
		$x = str_replace('×','*',$x);
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|≥|𝑥|•|−|,|g|y|m|=|&|%/i", $x)) {
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
		if (is_numeric($x)) {
			$number=$x;
            $real_num = 1;
		}else{
			$nbr=array_map('trim',array_filter(explode('x 10^',$x)));
			if (count($nbr)==1) {
				$nbr=array_map('trim',array_filter(explode('x10^',$x)));
			}
			if (count($nbr)==1) {
				$nbr=array_map('trim',array_filter(explode('x10 ^',$x)));
			}
			if (count($nbr)==1) {
				$nbr=array_map('trim',array_filter(explode('* 10^',$x)));
			}
			if (count($nbr)==1) {
				$nbr=array_map('trim',array_filter(explode('*10 ^',$x)));
			}
			if (count($nbr)==1) {
				$nbr=array_map('trim',array_filter(explode('*10 ^',$x)));
			}
			if (count($nbr)==1) {
				$nbr=array_map('trim',array_filter(explode('*10^',$x)));
			}
			if (count($nbr)>1) {
				$number=$nbr[0].'e'.$nbr[1];
				$number=str_replace(array('(', ')'), '', $number);
                $real_num = 0;
			}else{
				$number=eval('return '.$x.';');
                $real_num = 1;
			}
		}
		if (is_numeric($number)) {
			$x=(float)$number;
			$number=$x;
			function getOrderOfMagnitude($value) {
			    if($value == 0)
			        return null; 
			    $absValue = abs($value);
			    $orderOfMagnitude = 0;

			    while($absValue >= 10) {
			        $absValue /= 10;
			        $orderOfMagnitude++;
			    }
			    while($absValue < 0.1) {
			        $absValue *= 10;
			        $orderOfMagnitude--;
			    }

			    return $orderOfMagnitude;
			}
			$order_of_magnitude=getOrderOfMagnitude($x);
			$left= $x / pow(10,$order_of_magnitude);
			$e_ans=sprintf('%.3e', $x);
			$ans=sprintf('%.3E', $x);
			$ans=explode('E', $ans);
			$ee_ans=$ans[0][0].$ans[0][2].$ans[0][3].$ans[0][1].$ans[0][4];
			$takat=$ans[1]-2;
			$ee_ans=$ee_ans;
			$ee_p=$takat;
			$this->param['ans'] = $ans[0]." ×10<sup>".$ans[1]."<sup>";
			$this->param['left'] = $ans[0];
			$this->param['number'] = $number;
			$this->param['right'] = $ans[1];
			$this->param['e_ans'] = $e_ans;
			$this->param['ee_ans'] = $ee_ans;
			$this->param['ee_p'] = $ee_p;
			$this->param['real_num'] = $real_num;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;
		}
	}

