				$ans1=round(sqrt(pow(($x2 - $x1),2) + pow(($y2 - $y1),2)),4);
				$ans2=round(sqrt(pow(($x3 - $x2),2) + pow(($y3 - $y2),2)),4);
				$ans3=round(sqrt(pow(($x3 - $x1),2) + pow(($y3 - $y1),2)),4);
