				return $this->param;
			}
		}
		if ($type=='3P' && $dimen =='3D') {
			if (is_numeric($x31) && is_numeric($y31) && is_numeric($z31) && is_numeric($x32) && is_numeric($y32) && is_numeric($z32) && is_numeric($x33) && is_numeric($y33) && is_numeric($z33)) {
				$ans1=round(sqrt(pow(($x32 - $x31),2) + pow(($y32 - $y31),2) + pow(($z32 - $z31),2)),4);
				$ans2=round(sqrt(pow(($x33 - $x32),2) + pow(($y33 - $y32),2) + pow(($z33 - $z32),2)),4);
				$ans3=round(sqrt(pow(($x33 - $x31),2) + pow(($y33 - $y31),2) + pow(($z33 - $z31),2)),4);
				$this->param['ans1'] = $ans1;
				$this->param['ans2'] = $ans2;
				$this->param['ans3'] = $ans3;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields';
				return $this->param;
			}
		}
		if ($type=='3P' && $dimen =='4D') {
			if (is_numeric($x41) && is_numeric($y41) && is_numeric($z41) && is_numeric($k41) && is_numeric($x42) && is_numeric($y42) && is_numeric($z42) && is_numeric($k42) && is_numeric($x43) && is_numeric($y43) && is_numeric($z43) && is_numeric($k43)) {
				$ans1=round(sqrt(pow(($x42 - $x41),2) + pow(($y42 - $y41),2) + pow(($z42 - $z41),2) + pow(($k42 - $k41),2)),4);
				$ans2=round(sqrt(pow(($x43 - $x42),2) + pow(($y43 - $y42),2) + pow(($z43 - $z42),2) + pow(($k43 - $k42),2)),4);
				$ans3=round(sqrt(pow(($x43 - $x41),2) + pow(($y43 - $y41),2) + pow(($z43 - $z41),2) + pow(($k43 - $k41),2)),4);
				$this->param['ans1'] = $ans1;
