				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields';
				return $this->param;
			}
		}
		if ($type=='PS') {
			if (is_numeric($x1) && is_numeric($y1) && is_numeric($m) && is_numeric($b)) {
				$ans=round(abs($m*$x1-$y1 + $b) / sqrt((pow($m, 2) + 1)),4);
				$this->param['ans'] = $ans;
