	// Reciprocal Calculator
	function reciprocal($request){
		$operations = $request->input('operations');
		$first = $request->input('first');
		$second = $request->input('second');
		$third = $request->input('third');
	
		function gcd($a,$b){
			$a = abs($a); $b = abs($b);
			if( $a < $b){ 
				list($b,$a) = Array($a,$b);
			}
			if( $b == 0){
				return 1;
			}
			$r = $a % $b;
			while($r > 0): 
				$a = $b;
				$b = $r;
				$r = $a % $b;
			endwhile;
			return $b;
		}
		function reduce($num,$den) {
			$g = gcd($num,$den);
			return array($num/$g,$den/$g);
		}
		if ($operations==1) {
			if (is_numeric($second) && is_numeric($third)) {
				if ($second != 0) {
					if ($third != 0) {
						$answer = $third / $second;
						$totalN = $second;
						$totalD = $third;
						$g = gcd($totalN,$totalD);
						list ($upr ,$btm) = reduce($totalN,$totalD);
						$this->param['upr'] =$upr;
						$this->param['totalN'] =$totalN;
						$this->param['totalD'] =$totalD;
						$this->param['g'] =$g;
						$this->param['btm'] =$btm;
						$this->param['answer'] =$answer;
					}else{
							$this->param['error'] =  'Denominator cannot be zero.';
						return  $this->param;
					}
				}else{
						$this->param['error'] =  'Numerator cannot be zero.';
					return  $this->param;
				}
			}else{
					$this->param['error'] =  'Please Check Your Input';
				return  $this->param;
			}
		}else if ($operations==2) {
			if (is_numeric($first)) {
				if ($first != 0) {
					$zz = explode('.', $first);
					if (count($zz)==1) {
						$answer = 1 / $first;
					}else if (count($zz)==2) {
						$answer = 1 / $first;
						$len = strlen($zz[1]);
						for ($i=0; $i < $len; $i++) { 
							$zain[] = "0";
						}
						$aja = implode('', $zain);
						$upper = "1".$aja;
						$lower = $first * $upper;
						$totalN = $upper;
						$totalD = $lower;
						$g = gcd($totalN,$totalD);
						list ($upr ,$btm) = reduce($totalN,$totalD);
						$this->param['upr'] =$upr;
						$this->param['totalN'] =$totalN;
						$this->param['totalD'] =$totalD;
						$this->param['g'] =$g;
						$this->param['btm'] =$btm;
						$this->param['answer'] =$answer;
						$this->param['upper'] =$upper;
						$this->param['lower'] =$lower;
					}
					$this->param['answer'] =$answer;
				}else{
						$this->param['error'] =  'The multiplicative inverse of 0 is undefined.';
					return  $this->param;
				}
			}else{
					$this->param['error'] =  'Please Check Your Input';
				return  $this->param;
			}
		}else if ($operations==3) {
			if (is_numeric($second) && is_numeric($first) && is_numeric($third)) {
				if ($third != 0) {
					$totalD = $third;
					$val1 = $first;
					$totalN = ($totalD * $val1) + $second;
					$g = gcd($totalN,$totalD);
					list ($upr,$btm) = reduce($totalN,$totalD);
					$this->param['upr'] =$upr;
					$this->param['totalN'] =$totalN;
					$this->param['totalD'] =$totalD;
					$this->param['g'] =$g;
					$this->param['btm'] =$btm;
				}else{
						$this->param['error'] =  'Denominator cannot be zero.';
					return  $this-> $this->param;
				}
			}else{
					$this->param['error'] =  'Please Check Your Input';
				return  $this-> $this->param;
			}
		}
		$this->param['operations'] =$operations;
		$this->param['RESULT'] = 1;

		return  $this->param;
	}

	// base calculation 
	function base($request){
		$bnr_frs=$request->input('bnr_frs');
		$bnr_sec=$request->input('bnr_sec');
		$select_base=$request->input('select_base');
		$tool=$request->input('tool');
		$bnr_slc=$request->input('bnr_slc');
		$to_number=$request->input('to_number');
		$bnr_third=$request->input('bnr_third');
		if($tool=="calculator"){
			if($bnr_frs!="" && $bnr_sec!=""){	
				function bnrType($nn,$bnr_tpe) {
					$n = base_convert($nn,$bnr_tpe, 10);
					return $n;
				}
				$fN = bnrType($bnr_frs,$select_base);
				$sN = bnrType($bnr_sec,$select_base);
				function bnrCal($fN,$sN,$bnr_slc,$select_base) {
					if ($bnr_slc === "add") {
						$rN = $fN + $sN;
						$dc = $rN;
						$bn = base_convert(abs($dc), 10,$select_base);
						$hx = strtoupper(base_convert(abs($dc), 10, 16));
						$oc = base_convert(abs($dc), 10, 8);
						return array($bn, $dc);
					} elseif ($bnr_slc === "sub") { //Subtract
						$rN = $fN - $sN;
						$dc = $rN;
						if($dc < 0) {
							$bn = "-" . base_convert(abs($dc), 10,$select_base);
						} else {
							$bn = base_convert(abs($dc), 10,$select_base);
						}
						return array($bn, $dc);
					} elseif ($bnr_slc === "mult") { //Multiply
						$rN = $fN * $sN;
						$dc = $rN;
						$bn = base_convert(abs($dc), 10,$select_base);
						return array($bn, $dc);
					} elseif ($bnr_slc === "divd") { //Divide
						// dd($fN);
						if($fN == '0' || $sN == '0'){
							return ['error' => 'Please! Check your input'];
						}
						$rN = $fN / $sN;
						$dc = round($rN);
						$bn = base_convert(abs($dc), 10,$select_base);
						return array($bn, $dc);
					}
					return array('invalid', null);
				}
				if($bnr_slc=="add"){
					$this->param['pres']="additon";
				}
				else if($bnr_slc=="sub"){
					$this->param['pres']="subtraction";
				}
				else if($bnr_slc=="mult"){
					$this->param['pres']="multiplication";
				}else if($bnr_slc=="divi"){
					$this->param['pres']="division";
				}
				// dd($this->param['pres']);
				// $this->param['bn'] = bnrCal($fN,$sN,$bnr_slc,$select_base)[0];
				$result = bnrCal($fN, $sN, $bnr_slc, $select_base);
				if (is_array($result) && isset($result[0])) {
					$this->param['bn'] = $result[0];
				} else {
					// Handle the error case
					$this->param['bn'] = 'error';
				}
				$this->param['bnr_frs']=$bnr_frs;
				$this->param['bnr_sec']=$bnr_sec;
				$this->param['bnr_slc']=$bnr_slc;
				$this->param['bnr_tpe']=$select_base;
				// $this->param['pres']=$pres;
				$this->param['RESULT'] = 1;


				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check your input';
  			    return $this->param;
			}
			if($bnr_frs!="" && $bnr_sec!=""){
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check your input';
  			    return $this->param;
			}
		}else if($tool=="converter"){
			$binary=base_convert($bnr_third,$select_base,$to_number);
			$this->param['bi'] =$binary;
			$this->param['from_base']=$select_base;
			$this->param['to_base']=$to_number;
			$this->param['resulting_number']=$bnr_third;
			$this->param['RESULT'] = 1;
			return $this->param;
		}
	}

	//Determinant Calculator
	function determinant($request){
		$det = "";
		//Rounding and getting POST data + adding data values in an array and multiplying them
		$check=true;
		function gtVl($arr) {
			$ars = array();
			foreach ($arr as $value) {
				$nms = $_POST['dtrmn_'.$value];
				array_push($ars,$nms);
			}
			return array_product($ars);
		}
		for($i=0;$i<$request->dtrmn_slct_method;$i++){
			for($j=0;$j<$request->dtrmn_slct_method;$j++){
				if(!is_numeric($request['dtrmn_'.$i.'_'.$j])){
					$check=false;
				}
			}
		}
		if ($check==true) {
			if ($request->dtrmn_slct_method=='2') { //Determinant calculation by 2 x 2
				$det = ( gtVl(["0_0","1_1"]) ) - ( gtVl(["1_0","0_1"]) );
			} elseif ($request->dtrmn_slct_method=='3') { //Determinant calculation by 3 x 3
				$det = (
					+ (gtVl(["0_0","1_1","2_2"])) - (gtVl(["0_0","1_2","2_1"])) - (gtVl(["0_1","1_0","2_2"]))
					+ (gtVl(["0_1","1_2","2_0"])) + (gtVl(["0_2","1_0","2_1"])) - (gtVl(["0_2","1_1","2_0"]))
				);
			} elseif ($request->dtrmn_slct_method=='4') {
				$det =  (
					+ (gtVl(["0_0","1_1","2_2","3_3"])) - (gtVl(["0_0","1_1","2_3","3_2"])) - (gtVl(["0_0","1_2","2_1","3_3"]))
					+ (gtVl(["0_0","1_2","2_3","3_1"])) + (gtVl(["0_0","1_3","2_1","3_2"])) - (gtVl(["0_0","1_3","2_2","3_1"]))
					- (gtVl(["0_1","1_0","2_2","3_3"])) + (gtVl(["0_1","1_0","2_3","3_2"])) + (gtVl(["0_1","1_2","2_0","3_3"]))
					- (gtVl(["0_1","1_2","2_3","3_0"])) - (gtVl(["0_1","1_3","2_0","3_2"])) + (gtVl(["0_1","1_3","2_2","3_0"]))
					+ (gtVl(["0_2","1_0","2_1","3_3"])) - (gtVl(["0_2","1_0","2_3","3_1"])) - (gtVl(["0_2","1_1","2_0","3_3"]))
					+ (gtVl(["0_2","1_1","2_3","3_0"])) + (gtVl(["0_2","1_3","2_0","3_1"])) - (gtVl(["0_2","1_3","2_1","3_0"]))
					- (gtVl(["0_3","1_0","2_1","3_2"])) + (gtVl(["0_3","1_0","2_2","3_1"])) + (gtVl(["0_3","1_1","2_0","3_2"]))
					- (gtVl(["0_3","1_1","2_2","3_0"])) - (gtVl(["0_3","1_2","2_0","3_1"])) + (gtVl(["0_3","1_2","2_1","3_0"]))
				);
			} elseif ($request->dtrmn_slct_method=='5') {
				$det =  (
					+ (gtVl(["0_0","1_1","2_2","3_3","4_4"])) + (gtVl(["0_0","1_1","2_3","3_4","4_2"])) + (gtVl(["0_0","1_1","2_4","3_2","4_3"]))
					- (gtVl(["0_0","1_1","2_4","3_3","4_2"])) - (gtVl(["0_0","1_1","2_3","3_2","4_4"])) - (gtVl(["0_0","1_1","2_2","3_4","4_3"]))
					- (gtVl(["0_0","2_1","1_2","3_3","4_4"])) - (gtVl(["0_0","2_1","1_3","3_4","4_2"])) - (gtVl(["0_0","2_1","1_4","3_2","4_3"]))
					+ (gtVl(["0_0","2_1","1_4","3_3","4_2"])) + (gtVl(["0_0","2_1","1_3","3_2","4_4"])) + (gtVl(["0_0","2_1","1_2","3_4","4_3"]))
					+ (gtVl(["0_0","3_1","1_2","2_3","4_4"])) + (gtVl(["0_0","3_1","1_3","2_4","4_2"])) + (gtVl(["0_0","3_1","1_4","2_2","4_3"]))
					- (gtVl(["0_0","3_1","1_4","2_3","4_2"])) - (gtVl(["0_0","3_1","1_3","2_2","4_4"])) - (gtVl(["0_0","3_1","1_2","2_4","4_3"]))
					- (gtVl(["0_0","4_1","1_2","2_3","3_4"])) - (gtVl(["0_0","4_1","1_3","2_4","3_2"])) - (gtVl(["0_0","4_1","1_4","2_2","3_3"]))
					+ (gtVl(["0_0","4_1","1_4","2_3","3_2"])) + (gtVl(["0_0","4_1","1_3","2_2","3_4"])) + (gtVl(["0_0","4_1","1_2","2_4","3_3"]))
					- (gtVl(["1_0","0_1","2_2","3_3","4_4"])) - (gtVl(["1_0","0_1","2_3","3_4","4_2"])) - (gtVl(["1_0","0_1","2_4","3_2","4_3"]))
					+ (gtVl(["1_0","0_1","2_4","3_3","4_2"])) + (gtVl(["1_0","0_1","2_3","3_2","4_4"])) + (gtVl(["1_0","0_1","2_2","3_4","4_3"]))
					+ (gtVl(["1_0","2_1","0_2","3_3","4_4"])) + (gtVl(["1_0","2_1","0_3","3_4","4_2"])) + (gtVl(["1_0","2_1","0_4","3_2","4_3"]))
					- (gtVl(["1_0","2_1","0_4","3_3","4_2"])) - (gtVl(["1_0","2_1","0_3","3_2","4_4"])) - (gtVl(["1_0","2_1","0_2","3_4","4_3"]))
					- (gtVl(["1_0","3_1","0_2","2_3","4_4"])) - (gtVl(["1_0","3_1","0_3","2_4","4_2"])) - (gtVl(["1_0","3_1","0_4","2_2","4_3"]))
					+ (gtVl(["1_0","3_1","0_4","2_3","4_2"])) + (gtVl(["1_0","3_1","0_3","2_2","4_4"])) + (gtVl(["1_0","3_1","0_2","2_4","4_3"]))
					+ (gtVl(["1_0","4_1","0_2","2_3","3_4"])) + (gtVl(["1_0","4_1","0_3","2_4","3_2"])) + (gtVl(["1_0","4_1","0_4","2_2","3_3"]))
					- (gtVl(["1_0","4_1","0_4","2_3","3_2"])) - (gtVl(["1_0","4_1","0_3","2_2","3_4"])) - (gtVl(["1_0","4_1","0_2","2_4","3_3"]))
					+ (gtVl(["2_0","0_1","1_2","3_3","4_4"])) + (gtVl(["2_0","0_1","1_3","3_4","4_2"])) + (gtVl(["2_0","0_1","1_4","3_2","4_3"]))
					- (gtVl(["2_0","0_1","1_4","3_3","4_2"])) - (gtVl(["2_0","0_1","1_3","3_2","4_4"])) - (gtVl(["2_0","0_1","1_2","3_4","4_3"]))
					- (gtVl(["2_0","1_1","0_2","3_3","4_4"])) - (gtVl(["2_0","1_1","0_3","3_4","4_2"])) - (gtVl(["2_0","1_1","0_4","3_2","4_3"]))
					+ (gtVl(["2_0","1_1","0_4","3_3","4_2"])) + (gtVl(["2_0","1_1","0_3","3_2","4_4"])) + (gtVl(["2_0","1_1","0_2","3_4","4_3"]))
					+ (gtVl(["2_0","3_1","0_2","1_3","4_4"])) + (gtVl(["2_0","3_1","0_3","1_4","4_2"])) + (gtVl(["2_0","3_1","0_4","1_2","4_3"]))
					- (gtVl(["2_0","3_1","0_4","1_3","4_2"])) - (gtVl(["2_0","3_1","0_3","1_2","4_4"])) - (gtVl(["2_0","3_1","0_2","1_4","4_3"]))
					- (gtVl(["2_0","4_1","0_2","1_3","3_4"])) - (gtVl(["2_0","4_1","0_3","1_4","3_2"])) - (gtVl(["2_0","4_1","0_4","1_2","3_3"]))
					+ (gtVl(["2_0","4_1","0_4","1_3","3_2"])) + (gtVl(["2_0","4_1","0_3","1_2","3_4"])) + (gtVl(["2_0","4_1","0_2","1_4","3_3"]))
					- (gtVl(["3_0","0_1","1_2","2_3","4_4"])) - (gtVl(["3_0","0_1","1_3","2_4","4_2"])) - (gtVl(["3_0","0_1","1_4","2_2","4_3"]))
					+ (gtVl(["3_0","0_1","1_4","2_3","4_2"])) + (gtVl(["3_0","0_1","1_3","2_2","4_4"])) + (gtVl(["3_0","0_1","1_2","2_4","4_3"]))
					+ (gtVl(["3_0","1_1","0_2","2_3","4_4"])) + (gtVl(["3_0","1_1","0_3","2_4","4_2"])) + (gtVl(["3_0","1_1","0_4","2_2","4_3"]))
					- (gtVl(["3_0","1_1","0_4","2_3","4_2"])) - (gtVl(["3_0","1_1","0_3","2_2","4_4"])) - (gtVl(["3_0","1_1","0_2","2_4","4_3"]))
					- (gtVl(["3_0","2_1","0_2","1_3","4_4"])) - (gtVl(["3_0","2_1","0_3","1_4","4_2"])) - (gtVl(["3_0","2_1","0_4","1_2","4_3"]))
					+ (gtVl(["3_0","2_1","0_4","1_3","4_2"])) + (gtVl(["3_0","2_1","0_3","1_2","4_4"])) + (gtVl(["3_0","2_1","0_2","1_4","4_3"]))
					+ (gtVl(["3_0","4_1","0_2","1_3","2_4"])) + (gtVl(["3_0","4_1","0_3","1_4","2_2"])) + (gtVl(["3_0","4_1","0_4","1_2","2_3"]))
					- (gtVl(["3_0","4_1","0_4","1_3","2_2"])) - (gtVl(["3_0","4_1","0_3","1_2","2_4"])) - (gtVl(["3_0","4_1","0_2","1_4","2_3"]))
					+ (gtVl(["4_0","0_1","1_2","2_3","3_4"])) + (gtVl(["4_0","0_1","1_3","2_4","3_2"])) + (gtVl(["4_0","0_1","1_4","2_2","3_3"]))
					- (gtVl(["4_0","0_1","1_4","2_3","3_2"])) - (gtVl(["4_0","0_1","1_3","2_2","3_4"])) - (gtVl(["4_0","0_1","1_2","2_4","3_3"]))
					- (gtVl(["4_0","1_1","0_2","2_3","3_4"])) - (gtVl(["4_0","1_1","0_3","2_4","3_2"])) - (gtVl(["4_0","1_1","0_4","2_2","3_3"]))
					+ (gtVl(["4_0","1_1","0_4","2_3","3_2"])) + (gtVl(["4_0","1_1","0_3","2_2","3_4"])) + (gtVl(["4_0","1_1","0_2","2_4","3_3"]))
					+ (gtVl(["4_0","2_1","0_2","1_3","3_4"])) + (gtVl(["4_0","2_1","0_3","1_4","3_2"])) + (gtVl(["4_0","2_1","0_4","1_2","3_3"]))
					- (gtVl(["4_0","2_1","0_4","1_3","3_2"])) - (gtVl(["4_0","2_1","0_3","1_2","3_4"])) - (gtVl(["4_0","2_1","0_2","1_4","3_3"]))
					- (gtVl(["4_0","3_1","0_2","1_3","2_4"])) - (gtVl(["4_0","3_1","0_3","1_4","2_2"])) - (gtVl(["4_0","3_1","0_4","1_2","2_3"]))
					+ (gtVl(["4_0","3_1","0_4","1_3","2_2"])) + (gtVl(["4_0","3_1","0_3","1_2","2_4"])) + (gtVl(["4_0","3_1","0_2","1_4","2_3"]))

				);
			}
			$this->param['ans']=$det;
			$this->param['RESULT'] = 1;
			return $this->param;	
		} else {
			$this->param['error'] = 'Please Check Your Input.';
			return $this->param;	
		}
	}

	// Similar Triangles Calculator
	function similar($request){
		$type = $request->type;
		$similarity = $request->similarity;
		$ABC_f = $request->ABC_f;
		$ABC_f_unit = $request->ABC_f_unit;
		$ABC_f_deg_rad = $request->ABC_f_deg_rad;
		$ABC_s = $request->ABC_s;
		$ABC_s_unit = $request->ABC_s_unit;
		$ABC_s_deg_rad = $request->ABC_s_deg_rad;
		$ABC_t = $request->ABC_t;
		$ABC_t_unit = $request->ABC_t_unit;
		$ABC_t_deg_rad = $request->ABC_t_deg_rad;
		$ABC_corresponding = $request->ABC_corresponding;
		$ABC_corresponding_unit = $request->ABC_corresponding_unit;
		$scale_factor = $request->scale_factor;
		$DEF_f = $request->DEF_f;
		$DEF_f_unit = $request->DEF_f_unit;
		$DEF_f_deg_rad = $request->DEF_f_deg_rad;
		$DEF_s = $request->DEF_s;
		$DEF_s_unit = $request->DEF_s_unit;
		$DEF_s_deg_rad = $request->DEF_s_deg_rad;
		$DEF_t = $request->DEF_t;
		$DEF_t_unit = $request->DEF_t_unit;
		$DEF_t_deg_rad = $request->DEF_t_deg_rad;
		$DEF_corresponding = $request->DEF_corresponding;
		$DEF_corresponding_unit = $request->DEF_corresponding_unit;
		function imp_unit($a,$b){
			if($b === "mm"){
				$imp_ans = $a / 10;
			}else if($b === "cm"){
				$imp_ans = $a * 1;
			}else if($b === "m"){
				$imp_ans = $a * 100;
			}else if($b === "km"){
				$imp_ans = $a * 100000;
			}else if($b === "in"){
				$imp_ans = $a * 2.54;
			}else if($b === "ft"){
				$imp_ans = $a * 30.48;
			}else if($b === "yd"){
				$imp_ans = $a * 91.44;
			}else{
				$imp_ans = $a * 160900;
			}
			return $imp_ans;
		}
		function ang_unit($a,$b){
			if($b === "rad"){
				$ang_ans = $a * 114.592;
			}else{
				$ang_ans = $a * 1;
			}
			return $ang_ans;
		}
		if ($type === "1") {
			if ($similarity === "SSS"){
				if(is_numeric($ABC_f) && is_numeric($ABC_s) && is_numeric($ABC_t) && is_numeric($DEF_f) && is_numeric($DEF_s) && is_numeric	($DEF_t)){
					$ABC_f = imp_unit($ABC_f,$ABC_f_unit);
					$ABC_s = imp_unit($ABC_s,$ABC_s_unit);
					$ABC_t = imp_unit($ABC_t,$ABC_t_unit);
					$DEF_f = imp_unit($DEF_f,$DEF_f_unit);
					$DEF_s = imp_unit($DEF_s,$DEF_s_unit);
					$DEF_t = imp_unit($DEF_t,$DEF_t_unit);
					if(($ABC_f === $DEF_f) && ($ABC_s === $DEF_s) && ($ABC_t === $DEF_t)){
						$symbol = "∼";
						$jawab = "equal";
					}else{
						$jawab = "notequal";
						$symbol = "≁";
					}
					$this->param['jawab'] = $jawab;
					$this->param['symbol'] = $symbol;
				}else{
					$this->param['error'] = 'Please Check Your Input.';
					return $this->param;
				}
			}elseif ($similarity === "SAS"){
				if(is_numeric($ABC_f) && is_numeric($ABC_s) && is_numeric($ABC_t) && is_numeric($DEF_f) && is_numeric($DEF_s) && is_numeric($DEF_t)){
					$ABC_f = imp_unit($ABC_f,$ABC_f_unit);
					$ABC_s = imp_unit($ABC_s,$ABC_s_unit);
					$ABC_t = ang_unit($ABC_t,$ABC_t_deg_rad);
					$DEF_f = imp_unit($DEF_f,$DEF_f_unit);
					$DEF_s = imp_unit($DEF_s,$DEF_s_unit);
					$DEF_t = ang_unit($DEF_t,$DEF_t_deg_rad);
					if(($ABC_f === $DEF_f) && ($ABC_s === $DEF_s) && ($ABC_t === $DEF_t)){
						$symbol = "∼";
						$jawab = "equal";
					}else{
						$jawab = "notequal";
						$symbol = "≁";
					}
					$this->param['jawab'] = $jawab;
					$this->param['symbol'] = $symbol;
				}else{
					$this->param['error'] = 'Please Check Your Input.';
					return $this->param;
				}
			}else{
				if(is_numeric($ABC_f) && is_numeric($ABC_s) && is_numeric($ABC_corresponding) && is_numeric($DEF_f) && is_numeric($DEF_s) && is_numeric($DEF_corresponding)){
					$ABC_f = ang_unit($ABC_f,$ABC_f_deg_rad);
					$ABC_s = ang_unit($ABC_s,$ABC_s_deg_rad);
					$ABC_corresponding = imp_unit($ABC_corresponding,$ABC_corresponding_unit);
					$DEF_f = ang_unit($DEF_f,$DEF_f_deg_rad);
					$DEF_s = ang_unit($DEF_s,$DEF_s_deg_rad);
					$DEF_corresponding = imp_unit($DEF_corresponding,$DEF_corresponding_unit);
					$ACB_jawab = 180 - ($ABC_f + $ABC_s);
					$DEF_jawab = 180 - ($DEF_f + $DEF_s);
					$scale_ans = $DEF_corresponding / $ABC_corresponding;
					if(($ABC_f === $DEF_f) && ($ABC_s === $DEF_s)){
						$symbol = "∼";
						$jawab = "equal";
					}else{
						$jawab = "notequal";
						$symbol = "≁";
					}
					$this->param['jawab'] = $jawab;
					$this->param['symbol'] = $symbol;
					$this->param['ACB_jawab'] = $ACB_jawab;
					$this->param['DEF_jawab'] = $DEF_jawab;
					$this->param['scale_ans'] = $scale_ans;
				}else{
					$this->param['error'] = 'Please Check Your Input.';
					return $this->param;
				}
			}
		}else{
			if(is_numeric($ABC_f) && is_numeric($ABC_s) && is_numeric($ABC_t) && is_numeric($scale_factor)){
				$ABC_f = imp_unit($ABC_f,$ABC_f_unit);
				$ABC_s = imp_unit($ABC_s,$ABC_s_unit);
				$ABC_t = imp_unit($ABC_t,$ABC_t_unit);
				$ABC_perimeter_ans = $ABC_f + $ABC_s + $ABC_t;
				$ABC_semi = $ABC_perimeter_ans / 2;
				$ABC_area_ans = sqrt($ABC_semi * (($ABC_semi - $ABC_f) * ($ABC_semi - $ABC_s) * ($ABC_semi - $ABC_t)));
				
				$DEF_f_ans = $ABC_f * $scale_factor;
				$DEF_s_ans = $ABC_s * $scale_factor;
				$DEF_t_ans = $ABC_t * $scale_factor;
				$DEF_perimeter_ans = $DEF_f_ans + $DEF_s_ans + $DEF_t_ans;
				$DEF_semi = $DEF_perimeter_ans / 2;
				$DEF_area_ans = sqrt($DEF_semi * (($DEF_semi - $DEF_f_ans) * ($DEF_semi - $DEF_s_ans) * ($DEF_semi - $DEF_t_ans)));
				$this->param['ABC_perimeter_ans'] = round($ABC_perimeter_ans, 2);
				$this->param['ABC_semi'] = $ABC_semi;
				$this->param['ABC_area_ans'] = round($ABC_area_ans, 2);
				$this->param['DEF_f_ans'] = $DEF_f_ans;
				$this->param['DEF_s_ans'] = $DEF_s_ans;
				$this->param['DEF_t_ans'] = $DEF_t_ans;
				$this->param['DEF_perimeter_ans'] = round($DEF_perimeter_ans, 2);
				$this->param['DEF_semi'] = $DEF_semi;
				$this->param['DEF_area_ans'] = round($DEF_area_ans, 2);
			}else{
				$this->param['error'] = 'Please Check Your Input.';
				return $this->param;
			}
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	// equivalent fraction calculator
	public function equivalent($request){

		$want_to=trim($request->input('want_to'));
		$is_frac=trim($request->input('is_frac'));
		$s1=trim($request->input('s1'));
		$n1=trim($request->input('n1'));
		$d1=trim($request->input('d1'));
		$s2=trim($request->input('s2'));
		$n2=trim($request->input('n2'));
		$d2=trim($request->input('d2'));
		$s3=trim($request->input('s3'));
		$n3=trim($request->input('n3'));
		$d3=trim($request->input('d3'));
		$no=trim($request->input('no'));

			if ($want_to==1) {
			if (is_numeric($n1) && is_numeric($d1)) {
				if ($is_frac==2 && is_numeric($s1)) {
					if ($n1<0) {
						$this->param['error'] = 'Numerator and denominator must be positive';
						return $this->param;	
					}
					if ($s1<1) {
						$up=($d1*$s1)-$n1;
					}else{
						$up=($d1*$s1)+$n1;
					}
				}else{
					$up=$n1;
				}
				if ($no>100) {
					$no=100;
				}
				$upper=[];
				$bottom=[];
				for ($i=1; $i <= $no; $i++) { 
					$upper[]=$up*$i;
					$bottom[]=$d1*$i;
				}
				$this->param['upper'] = $upper;
				$this->param['bottom'] = $bottom;
				$this->param['RESULT'] = 1;

				return $this->param;
			}else{
				$this->param['error'] = 'Please Check Your Input';
				return $this->param;	
			}
			}else{
				if (is_numeric($n2) && is_numeric($d2) && is_numeric($n3) && is_numeric($d3)) {
				function gcd($a,$b) 
				{
					$a = abs($a); $b = abs($b);

					if( $a < $b)
					{ 
						list($b,$a) = Array($a,$b);
					}
					if( $b == 0){
						return 1;
					}
					$r = $a % $b;
					while($r > 0): 
						$a = $b;
						$b = $r;
						$r = $a % $b;
					endwhile;
					return $b;
			
				}

				function reduce($num,$den) 
				{
					$g = gcd($num,$den);
					return array($num/$g,$den/$g);
				}
					if ($is_frac==2 && is_numeric($s2)) {
						if ($n2<0) {
						$this->param['error'] = 'Numerator and denominator must be positive';
						return $this->param;	
					}
					if ($s2<1) {
						$up1=($d2*$s2)-$n2;
					}else{
						$up1=($d2*$s2)+$n2;
					}
					$input1=$s2.' '.$n2.'/'.$d2;
				}else{
					$input1=$n2.'/'.$d2;
					$up1=$n2;
				}
				if ($is_frac==2 && is_numeric($s3)) {
					if ($n3<0) {
						$this->param['error'] = 'Numerator and denominator must be positive';
						return $this->param;	
					}
					if ($s3<1) {
						$up2=($d3*$s3)-$n3;
					}else{
						$up2=($d3*$s3)+$n3;
					}
					$input2=$s3.' '.$n3.'/'.$d3;
				}else{
					$input2=$n3.'/'.$d3;
					$up2=$n3;
				}
				list($fupr,$fbtm) = reduce($up1,$d2);
				list($fupr1,$fbtm1) = reduce($up2,$d3);
				if ($fupr1==$fupr && $fbtm1==$fbtm) {
					$same='yes';
					$sign='=';
				}else{
					$same='no';
					$sign='≠';
				}
				$this->param['same'] = $same;
				$this->param['sign'] = $sign;
				$this->param['input1'] = $input1;
				$this->param['input2'] = $input2;
				$this->param['RESULT'] = 1;

				return $this->param;
				}else{
				$this->param['error'] = 'Please Check Your Input';
				return $this->param;	
			}
			}
	}

	// Marks Percentage Calculator
    public function marks($request){
		$type = $request->input('type');
		$first = $request->input('first');
		$second = $request->input('second');
		$sub_name = $request->input('sub_name');
		$s_marks = $request->input('s_marks');
		$a_marks = $request->input('a_marks');
        
        if ($type == "first") {
			if (is_numeric($first) && is_numeric($second)) {
				if ($first <= $second) {
					$percent= ($first / $second) * 100;

                }else{
                    $this->param['error']='Total scored marks should be less than out of marks.';
                    return $this->param;
                }
            }else{
                $this->param['error']='Please! Check Your Input';
                return $this->param;
            }
        }else if ($type == "second") {
            $y = 0;
            while($y < count($sub_name) && $y < count($s_marks) && $y < count($a_marks)){
                if(!empty($sub_name[$y]) &&  is_numeric($s_marks[$y]) &&  is_numeric($a_marks[$y])){
                    $name_array[] = $sub_name[$y];
                    $s_array[] = $s_marks[$y];
                    $a_array[] = $a_marks[$y];
                }else{
                    $this->param['error']='Please! Check Your Input';
                    return $this->param;       
                }
                $y++;
            }
            $total_scored = array_sum($s_array);
            $total_marks = array_sum($a_array);
            $percent = ($total_scored / $total_marks) * 100;
            $this->param['name_array'] = $name_array;
            $this->param['s_array'] = $s_array;
            $this->param['a_array'] = $a_array;
            $this->param['total_scored'] = $total_scored;
            $this->param['total_marks'] = $total_marks;
        }
		$this->param['type'] = $type;
		$this->param['percent'] = $percent;
		$this->param['RESULT'] = 1;
		return $this->param;
    }

	// Two's Complement Calculator
	public function twos($request){
		$selection=$request->input('selection');
		$cal=$request->input('cal');
		$dec=$request->input('dec');
		$bnry=$request->input('bnry');
		$hex=$request->input('hex');
		$bits=$request->input('bits');
		$no_of_bits=$request->input('no_of_bits');
		// second
		$no=$request->input('no');
		$no1=$request->input('no1');
		$action=$request->input('action');

		// dd($dec);
		if($selection === 'distance'){
			$check=true;
			if ($cal === 'bnry_cal') {
				if (!is_numeric($dec)) {
					$check = false;
				}
			} elseif ($cal === 'dec_cal') {
				if (!is_numeric($dec)) {
					$check = false;
				}
			} elseif ($cal === 'hex_cal') {
				if ($hex === '') {
					$check = false;
				}
			}

			function flip($c) {
				return ($c == '0') ? '1' : '0';
			}
			
			function onesComplement($str) {
				// Returns '0' for '1' and '1' for '0'
				$n = strlen($str);
				$ones = '';
				
				// For ones complement, flip every bit
				for ($i = 0; $i < $n; $i++) {
					$ones .= flip($str[$i]);
				}
				
				return $ones;
			}
			
			function twosComplement($str) {
				$n = strlen($str);
				
				// Traverse the string to get first '1' from the last of string
				for ($i = $n - 1; $i >= 0; $i--) {
					if ($str[$i] === '1') break;
				}
				
				// If there exists no '1', concatenate 1 at the starting of string
				if ($i == -1) return '1' . $str;
				
				// Continue traversal after the position of first '1'
				for ($k = $i - 1; $k >= 0; $k--) {
					// Just flip the values
					$str[$k] = ($str[$k] === '1') ? '0' : '1';
				}
				
				// Return the modified string
				return $str;
			}
			
			function addspace($binary) {
				$bit_len = strlen($binary);
				$s1 = floor($bit_len / 4);
				$s2 = $s1 * 4;
				$s3 = $bit_len - $s2;
				$res = '';
				$rem = $bit_len % 4;
				$len = ($rem != 0) ? $s1 + 1 : $s1;
				$space = 0;
				
				for ($i = 0; $i < $len; $i++) {
					if ($i == 0 && $s3 != 0) {
						for ($j = 0; $j <= $s3; $j++) {
							if ($j != $s3) {
								$res .= $binary[$j];
							} else {
								$res .= ' ';
								$space++;
							}
						}
					} else {
						$s4 = strlen($res) - $space;
						for ($j = 0; $j <= 4; $j++) {
							if ($j != 4) {
								$res .= $binary[$s4 + $j];
							} else {
								$res .= ' ';
								$space++;
							}
						}
					}
				}
				
				return $res;
			}
				
			function bnry_cal($bnry, $bits) {
				// Ensure the input is treated as a binary string
				$binary = (string)$bnry;
				$dec = bindec($binary);  // Convert binary to decimal
				$hex = base_convert($binary, 2, 16);  // Convert binary to hexadecimal
				$bit_len = strlen($binary);
				$bits = (int)$bits;
				$n = $bits - $bit_len;
			
				// Padding binary to the specified bit length
				if ($dec < 0) {
					for ($i = 0; $i < $n; $i++) {
						if ($n < $bits) {
							$binary = '1' . $binary;
						}
					}
				} else {
					for ($i = 0; $i < $n; $i++) {
						if ($n < $bits) {
							$binary = '0' . $binary;
						}
					}
				}
			
				$binary = substr($binary, -$bits);
				$_1s = onesComplement($binary);
				$_1s = addspace($_1s);
			
				if ($dec == 0) {
					$_2s = '0';
					for ($i = 0; $i < $n; $i++) {
						$_2s = '0' . $_2s;
					}
					$_2s = addspace($_2s);
				} else {
					$_2s = twosComplement($binary);
					$_2s = addspace($_2s);
				}
			
				$binary = addspace($binary);
				$result = array(
					'bits' => $bits,
					'dec' => $dec,
					'binary' => $binary,
					'hex' => $hex,
					'_1s' => $_1s,
					'_2s' => $_2s
				);
				return $result;
			}

			function dec_cal($dec, $bits) {
				// Convert decimal to binary
				// dd('s');
				$bnry = decbin($dec);
				$bits = (int)$bits;
				
				// Pad binary to the specified bit length
				$padded_bnry = str_pad($bnry, $bits, '0', STR_PAD_LEFT);
				
				$hex = base_convert($padded_bnry, 2, 16);
				$_1s = onesComplement($padded_bnry);
				$_2s = twosComplement($padded_bnry);
			
				// Add space for readability
				$binary_with_space = addspace($padded_bnry);
				$_1s_with_space = addspace($_1s);
				$_2s_with_space = addspace($_2s);
			
				$result = array(
					'bits' => $bits,
					'dec' => $dec,
					'binary' => $binary_with_space,
					'hex' => $hex,
					'_1s' => $_1s_with_space,
					'_2s' => $_2s_with_space
				);
				return $result;
			}

			// new
			function hex_cal($hex, $bits) {
				// Convert hex to binary
				$binary = base_convert($hex, 16, 2);
				
				// Calculate the bit length of the binary representation
				$bit_len = strlen($binary);
				$bits = (int)$bits;
				$n = $bits - $bit_len;
				
				// Padding the binary string to the specified bit length
				for ($i = 0; $i < $n; $i++) {
					$binary = '0' . $binary;
				}
				
				// Ensure the binary string is exactly the specified bit length
				$binary = substr($binary, -$bits);
				
				// Calculate one's complement
				$_1s = onesComplement($binary);
				
				// Calculate two's complement
				$_2s = twosComplement($binary);
				
				// Add spaces for readability
				$binary_with_space = addspace($binary);
				$_1s_with_space = addspace($_1s);
				$_2s_with_space = addspace($_2s);
				
				// Prepare the result array
				$result = array(
					'bits' => $bits,
					'dec' => bindec($binary),  // Convert binary to decimal
					'binary' => $binary_with_space,
					'hex' => strtoupper($hex),
					'_1s' => $_1s_with_space,
					'_2s' => $_2s_with_space
				);
				return $result;
			}
			if ($bits === "other") {
				if (is_numeric($no_of_bits)) {
					$bits = $no_of_bits;
				}else{
					$this->param['error'] = 'Please! Check Your Input';
					return $this->param;
				}
			} else {
				$bits = $bits;
			}
			
			if ($check) {
				if ($cal === 'dec_cal') {
					$result = dec_cal($dec, $bits);
				}
				if ($cal === 'bnry_cal') {
					$result = bnry_cal($bnry, $bits);
				}
				if ($cal === 'hex_cal') {
					$result = hex_cal($hex, $bits);
				}
				// Add more conditions for 'bnry_cal' and 'hex_cal' if needed
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}


			if($check===true){
				$this->param['bit']=$result['bits'];
				$this->param['dec']=$result['dec'];
				$this->param['binary']=$result['binary'];
				$this->param['hex']=$result['hex'];
				$this->param['_1s']=$result['_1s'];
				$this->param['_2s']=$result['_2s'];
			}else{
				$this->param['error'] = 'Please! Enter Number in Range';
				return $this->param;
			}
			// dd($this->param);

			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
			if (is_numeric($no) && is_numeric($no1)) {
				if ($action=='+') {
					$ans=bindec($no)+bindec($no1);
				}else{
					$ans=bindec($no)-bindec($no1);
				}
				if ($ans<0) {
					$ans='-'.decbin(abs($ans));
				}else{
					$ans=decbin(abs($ans));
				}
				$this->param['add_sub'] = $ans;
				$this->param['no'] = $no;
				$this->param['no1'] = $no1;
				$this->param['action'] = $action;
				$this->param['RESULT'] = 1;
				return $this->param;
			}
		}
	}

