	// Area Under The Curve Calculator
	function area_under($request){
		$EnterEq1=$request['EnterEq1'];
		$with=$request['with'];
		$ub=trim($request['upper']);
		$lb=trim($request['lower']);
		if (!empty($EnterEq1)) {
			$parem=$EnterEq1;
			$parem=str_replace(' ', '', $parem);
			$parem=str_replace('+', 'plus', $parem);
			$parem=str_replace('%20', '', $parem);
			$parem=str_replace('{', '(', $parem);
			$parem=str_replace('}', ')', $parem);
			$parem=str_replace('e^x', 'exp(x)', $parem);
			$parem=str_replace('e^y', 'exp(y)', $parem);
			$parem=str_replace('e^', 'exp', $parem);
			$parem=str_replace('exp^', 'exp', $parem);
			$parem=str_replace('^', '**', $parem);
			$parem=str_replace('e^sqrt(x)', 'exp(2*x)', $parem);
			$ub=str_replace('inf', 'oo', $ub);
			$ub=str_replace('∞', 'oo', $ub);
			if ($ub=='e') {
				$ub=2.71828;
			}
			$lb=str_replace('inf', 'oo', $lb);
			$lb=str_replace('∞', 'oo', $lb);
			if ($lb=='e') {
				$lb=2.71828;
			}
		    try {
				$client = new Client();
				$r = $client->post("http://167.172.134.148/new-area", [
					'form_params' => [
						'equ' => $parem,
						'wrt' => $with,
						'ub' => $ub,
						'lb' => $lb,
					],
					'timeout' => 120,
				]);
				$buffer = $r->getBody();
				$buffer = json_decode($buffer, true);
		    	$parem=str_replace('"', '', $parem);
		    	$parem=str_replace('plus', '+', $parem);
				$this->param['enter'] = str_replace('**', '^', $parem);
				$this->param['with'] = $with;
				$this->param['ub'] = $ub;
				$this->param['lb'] = $lb;
				$this->param['ans'] = $buffer[0];
				$this->param['ans1'] = $buffer[1];
				$this->param['steps'] = $buffer[2];
				$this->param['RESULT'] = 1;
            	return $this->param;
            }
            catch(\Exception $r) {
            	echo $r->getMessage();die;
                $this->param['error'] = 'Please enter any one value.';
            	return $this->param;
            }
		} else {
			$this->param['error'] = 'Please enter any one value.';
            return $this->param;
		}
	}

    // Fraction Calculator
	public function old_fraction($request){
		// dd($request->all());
        $submit = $request->submit;
		if($submit == 'calculate_fraction'){
			$fraction_types = $request->fraction_types;
			$a1 = $request->a1;
			$b1 = $request->b1;
			$N1 = $request->N1;
			$N2 = $request->N2;
			$N3 = $request->N3;
			$N4 = $request->N4;
			$D1 = $request->D1;
			$D2 = $request->D2;
			$D3 = $request->D3;
			$D4 = $request->D4;
			$action = $request->action;
			$action1 = $request->action1;
			$action2 = $request->action2;
			function gcd($a,$b) {
				$a = abs($a); $b = abs($b);
	
				if( $a < $b)
				{ 
					list($b,$a) = Array($a,$b);
				}
				if( $b == 0){
					return 1;
				}
				$r = $a % $b;
				while($r > 0): 
					$a = $b;
					$b = $r;
					$r = $a % $b;
				endwhile;
				return $b;
		
			}
			function lcmofn($numbers, $n){
				$ans = $numbers[0];
				for ($i = 1; $i < $n; $i++)
				$ans = ((($numbers[$i] * $ans)) / (gcd($numbers[$i], $ans)));
				return $ans;
			}
			function reduce($num,$den){
				$g = gcd($num,$den);
				return array($num/$g,$den/$g);
			}
			if ($fraction_types === "simple_frac") {
				if (is_numeric($N1) && is_numeric($D1) && is_numeric($N2) && is_numeric($D2) && $D1!=0 && $D2!=0) {
					if($action == '+'){
						$totalN = ($N1 * $D2)+($N2 * $D1);
						$totalD = ($D1 * $D2);
						$done = 1;
					}elseif($action == '-'){
						$totalN = ($N1 * $D2)-($N2 * $D1);
						$totalD = ($D1 * $D2);
						$done = 1;
					}elseif($action == '÷'){
						$totalN = ($N1 * $D2);
						$totalD = ($N2 * $D1);
						$done = 1;
					}elseif($action == '×' || $action=='of'){
						$totalN = ($N1 *$N2);
						$totalD = ($D1 * $D2);
						$done = 1;
						
					}elseif($action=='^') {
						$totalN = pow($N1,($N2/$D2));
						$totalD = pow($D1,($N2/$D2));
						$done = 1;
					}
					$g = gcd($totalN,$totalD);
					list ($upr  , $btm) = reduce($totalN,$totalD);
					$lcd = lcmofn([$D1,$D2],2);
					$this->param['lcd'] =$lcd;
					$this->param['upr'] =$upr;
					$this->param['btm'] =$btm;
					$this->param['totalN'] =$totalN;
					$this->param['totalD'] =$totalD;
					$this->param['g'] =$g;
					$this->param['RESULT'] =1;
					// dd($this->param);
					return $this->param;
				}else{
					$this->param['error'] = 'Please! Enter valid Input.';
					return $this->param;
				}
			}else if ($fraction_types === "three_frac") {
				if (is_numeric($N1) && is_numeric($D1) && is_numeric($N2) && is_numeric($D2) && is_numeric($N3) && is_numeric($D3) && $D1!=0 && $D2!=0 && $D3!=0) {
					if (($action=='+' || $action=='-') && ($action1=='+' || $action1=='-')) {
						$arr = array($D1,$D2,$D3); 
						$lcm = lcmofn($arr, 3);
						if ($action=='+') {
							$first = ($N1*($lcm/$D1)) + ($N2*($lcm/$D2));
						}else{
							$first = ($N1*($lcm/$D1)) - ($N2*($lcm/$D2));
						}
						if ($action1=='+') {
							$second = $first + ($N3*($lcm/$D3));
						}else{
							$second = $first - ($N3*($lcm/$D3));
						}
						$totalN = $second;
						$totalD = $lcm;
					}elseif (($action=='÷' || $action=='×') && ($action1=='÷' || $action1=='×')) {
						if ($action=='÷') {
							list($N2,$D2) = array($D2,$N2);
						}
						if ($action1=='÷') {
							list($N3,$D3) = array($D3,$N3);
						}
						$totalN = $N1*$N2*$N3;
						$totalD = $D1*$D2*$D3;
