				if( $b == 0){
					return 1;
				}
				$r = $a % $b;
				while($r > 0): 
					$a = $b;
					$b = $r;
					$r = $a % $b;
				endwhile;
				return $b;
		
			}
			function lcmofn($numbers, $n){
				$ans = $numbers[0];
				for ($i = 1; $i < $n; $i++)
				$ans = ((($numbers[$i] * $ans)) / (new_gcd($numbers[$i], $ans)));
				return $ans;
			}
			if (is_numeric($request->nu1) && is_numeric($request->de1) && is_numeric($request->nu2) && is_numeric($request->de2)) {
				$N1 = $request->nu1;
				$D1 = $request->de1;
				$N2 =$request->nu2;
				$D2 = $request->de2;
				if($D1 == 0 || $D2 == 0){
					$this->param['error'] = 'Denominator can not be 0';
					return $this->param;
				}
				if (is_numeric($request->s1)) {
					$val1=$request->s1;
					if($val1<0 && $N1>0){
						$N1 = $N1 * (-1);
					}
					$N1=($D1 * $val1) + $N1;
				}
				if (is_numeric($request->s2)) {
					$val2=$request->s2;
					if($val2<0 && $N2>0){
						$N2 = $N2 * (-1);
					}
					$N2=($D2 * $val2) + $N2;
				}
				$action = $request->actions;
				if($action == '+')
				{
					$totalN = ($N1 * $D2)+($N2 * $D1);
					$totalD = ($D1 * $D2);
					$done = 1;
				}
				if($action == '-')
				{
					$totalN = ($N1 * $D2)-($N2 * $D1);
					$totalD = ($D1 * $D2);
					$done = 1;
				}
				if($action == '÷')
				{
					$totalN = ($N1 * $D2);
					$totalD = ($N2 * $D1);
					$done = 1;
				}
				if($action == '×')
				{
					$totalN = ($N1 *$N2);
					$totalD = ($D1 * $D2);
					$done = 1;
					
				}
				/****
				** Reduce value
				****/
				function gcd($a22,$b22) 
				{
					$a22 = abs($a22); $b22 = abs($b22);
	
					if( $a22 < $b22)
					{ 
						list($b22,$a22) = Array($a22,$b22);
					}
					if( $b22 == 0){
						return 1;
					}
					$r = $a22 % $b22;
					while($r > 0): 
						$a22 = $b22;
						$b22 = $r;
						$r = $a22 % $b22;
					endwhile;
					return $b22;
			
				}
	
				function reduce($num1,$den1) 
				{
					$g = gcd($num1,$den1);
					return array($num1/$g,$den1/$g);
				}
				$g = gcd($totalN,$totalD);
				list ($upr  , $btm) = reduce($totalN,$totalD);
				// return Values
				$lcd = lcmofn([$D1,$D2],2);
				$this->param['upr'] =$upr;
				$this->param['N1'] =$N1;
				$this->param['N2'] =$N2;
				$this->param['D1'] =$D1;
				$this->param['D2'] =$D2;
				$this->param['totalN'] =$totalN;
				$this->param['totalD'] =$totalD;
				$this->param['g'] =$g;
				$this->param['btm'] =$btm;
				$this->param['lcd'] =$lcd;
				return $this->param;
			}else{
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
	}




	// slope calculator
	function slope($request){
	
		$type=$request->input('type');
		$x1=$request->input('x1');
		$x2=$request->input('x2');
		$y1=$request->input('y1');
		$y2=$request->input('y2');
		$dis=$request->input('dis');
		$m=$request->input('m');
		$angle=$request->input('angle');
		$x=$request->input('x');
		$y=$request->input('y');
		$b=$request->input('b');

		if ($type=='2') {
			if (!empty($x1) && !empty($x2) && !empty($y1) && !empty($y2)) {
				$x1=$x1;
				$x2=$x2;
				$y1=$y1;
				$y2=$y2;
				$x=$x2 - $x1;
				$y=$y2 - $y1;
				$slope=round($y / $x,4);
				$angle=round(atan($slope) * (180 / pi()),4);
				$distance=round(sqrt(pow($x, 2) + pow($y, 2)),4);
				$b=round($y1 - ($slope*$x1),2);
				$this->param['x'] = $x;
				$this->param['y'] = $y;
				$this->param['b'] = $b;
				$this->param['slope'] = $slope;
				$this->param['angle'] = $angle." deg";
				$this->param['distance'] = $distance;
				$this->param['RESULT'] = 1;

				return $this->param;
			} else {
				$this->param ['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		if ($type=='1') {
			if (is_numeric($x1)  && is_numeric($y1) && is_numeric($dis)) {
				if ($m=='' && $angle=='') {
					$this->param ['error'] = 'Please fill all fields.';
					return $this->param;
				}
				$x1=$x1;
				$y1=$y1;
				$dis=$dis;
				if (is_numeric($m)) {
					$slope=$m;
					$x2r=round($x1 + ($dis / sqrt((1 + pow($slope, 2)))),4);
					$y2r=round($y1 + $slope * ($dis / sqrt((1 + pow($slope, 2)))),4);
					$x2l=round($x1 + ($dis*(-1) / sqrt((1 + pow($slope, 2)))),4);
					$y2l=round($y1 + $slope * ($dis*(-1) / sqrt((1 + pow($slope, 2)))),4);
					$angle=round(atan($slope) * (180 / pi()),4);
				}else{
					$angle=$angle;
					$a=deg2rad($angle);
					$slope=round(tan($a),4);
					$x2r=round($x1 + ($dis / sqrt((1 + pow($slope, 2)))),4);
					$y2r=round($y1 + $slope * ($dis / sqrt((1 + pow($slope, 2)))),4);
					$x2l=round($x1 + ($dis*(-1) / sqrt((1 + pow($slope, 2)))),4);
					$y2l=round($y1 + $slope * ($dis*(-1) / sqrt((1 + pow($slope, 2)))),4);
				}
				$xr=$x2r - $x1;
				$yr=$y2r - $y1;
				$xl=$x2l - $x1;
				$yl=$y2l - $y1;
				$b=round($y1 - ($slope*$x1),2);
				$this->param['xr'] = $xr;
				$this->param['yr'] = $yr;
				$this->param['xl'] = $xl;
				$this->param['yl'] = $yl;
				$this->param['x2r'] = $x2r;
				$this->param['y2r'] = $y2r;
				$this->param['x2l'] = $x2l;
				$this->param['y2l'] = $y2l;
				$this->param['b'] = $b;
				$this->param['slope'] = $slope;
				$this->param['angle'] = $angle." deg";
				$this->param['distance'] = $dis;
				$this->param['RESULT'] = 1;
				return $this->param;

			} else {
				$this->param ['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		if ($type=='3') {
			if (is_numeric($x1) && is_numeric($y1)) {
				$x1=$x1;
				$y1=$y1;
				if ($m=='' && $angle=='') {
					$this->param ['error'] = 'Please fill all fields.';
					return $this->param;
				}
				if ($x2=='' && $y2=='') {
					$this->param ['error'] = 'Please fill all fields.';
					return $this->param;
				}
				if (is_numeric($m)) {
					$slope=$m;
					$angle=round(atan($slope) * (180 / pi()),4);
				}else{
					$angle=$angle;
					$a=deg2rad($angle);
					$slope=round(tan($a),4);
				}
				if (is_numeric($x2)) {
					$x2=$x2;
					$y2=round(($slope * ($x2-$x1)) + $y1,4);
				}else{
					$y2=$y2;
					$x2=round((($y2-$y1)/$slope)+$x1,4);
				}
				$x=$x2 - $x1;
				$y=$y2 - $y1;
				$distance=round(sqrt(pow($x, 2) + pow($y, 2)),4);
				$b=round($y1 - ($slope*$x1),2);
				$this->param['x'] = $x;
				$this->param['y'] = $y;
				$this->param['x2'] = $x2;
				$this->param['y2'] = $y2;
				$this->param['b'] = $b;
				$this->param['slope'] = $slope;
				$this->param['angle'] = $angle." deg";
				$this->param['distance'] = $distance;
				$this->param['RESULT'] = 1;

				return $this->param;

			} else {
				$this->param ['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		if ($type=='4') {
			if (is_numeric($x1) && is_numeric($y1)) {
				if ($m=='' && $angle=='') {
					$this->param ['error'] = 'Please fill all fields.';
					return $this->param;
				}
				if (is_numeric($m)) {
					$slope=$m;
					$angle=round(atan($slope) * (180 / pi()),4);
				}else{
					$angle=$angle;
					$a=deg2rad($angle);
					$slope=round(tan($a),4);
				}
				$b=round($y1 - ($slope*$x1),4);
				$this->param['b'] = $b;
				$this->param['slope'] = $slope;
				$this->param['angle'] = $angle." deg";
				$this->param['RESULT'] = 1;

				return $this->param;

			} else {
				$this->param ['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		if ($type=='line') {
			if (is_numeric($x) && is_numeric($y) && is_numeric($b)) {
				$x=$x*(-1);
				$y=$y*(-1);
				$slope=round($x / $y,4);
				$angle=round(atan($slope) * (180 / pi()),4);
				$b=round($b / $y,2);
				$this->param['b'] = $b;
				$this->param['slope'] = $slope;
				$this->param['angle'] = $angle." deg";
				$this->param['RESULT'] = 1;

				return $this->param;

			} else {
				$this->param ['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		
	}

	// square root calculator
	public function square($request){
		$n=$request->input('n');
		$n1=$request->input('n1');
		$rt=$request->input('rt');
		$selection=$request->input('selection');
		
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $n)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $n1)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if (preg_match("/\<|\>|\&|php|print_r|print|echo|script|=|&|%/i", $rt)) {
			$this->param['error'] = 'Please Enter Valid Input.';
			return $this->param;
		}
		if($selection =='1'){
			if(!empty($n)){
				$num=eval('return '.$n.';');
				if($num<0){
					$num=abs($num);
					$this->param['iota'] = 'iota';
				}
				$result=sqrt($num);
				$this->param['check'] = 'sr';
			}else{
				$this->param['error'] = 'Please Enter Numbers';
				return $this->param;
			}
		}
		if($selection =='2'){
			if(!empty($n1) && !empty($rt)){
				$num=eval('return '.$n1.';');
				$root=eval('return '.$rt.';');
				if($num<0 && $root<0){
					$this->param['error'] = 'Please Enter Positive Numbers';
					return $this->param;
				}elseif($num<0 && $root==2){
					$num=abs($num);
					$this->param['iota'] = 'iota';
				}elseif($num<0 && $root%2==0){
					$this->param['error'] = 'Please Enter Positive Numbers';
					return $this->param;
				}else{
					$num=abs($num);
				}
				$result=pow($num,1/$root);
				$this->param['check'] = 'gr';
				$this->param['root'] = $root;
			}else{
				$this->param['error'] = 'Please Enter Numbers';
				return $this->param;
			}
		}

		if (!gmp_perfect_square($num)) {
			function primefactor($num) {
				$sqrt = sqrt($num);
				for ($i = 2; $i <= $sqrt; $i++) {
					if ($num % $i == 0) {
						// Recursively build the array ensuring integers
						$factors = primefactor($num / $i);
						$factors[] = (int)$i; // Cast to integer
						return $factors;
					}
				}
				return array((int)$num); // Cast to integer
			}
		
			$factors = primefactor($num);
		
			// Ensure all elements in $factors are integers
			$factors = array_map('intval', $factors);
		
			// Count the values in $factors
			$array = array_count_values($factors);
		
			$val = array();
			foreach ($array as $key => $value) {
				if ($value == 1) {
					$val[] = $key;
				} elseif ($value % 2 == 0) {
					$val[] = pow($key, $value);
				} else {
					$value--;
					$val[] = pow($key, $value);
					$val[] = $key;
				}
			}
		
			$product = 1;
			$final = array();
			$val_show = array();
			foreach ($val as $key => $value) {
				if (!gmp_perfect_square($value)) {
					$product *= $value;
				} else {
					$final[] = $value;
					$val_show[] = $value;
				}
			}
		
			$sqr_show = array() || null; // Initialize $sqr_show as an array
			$c = count($val_show);
			for ($i = 0; $i < $c; $i++) {
				$sqr_show[] = sqrt($val_show[$i]); // Store each square root in the array
			}
		
			$final[] = $product;
			$count = count($final);
			$factor = '';
			$factor1 = '';
		
			for ($i = 0; $i < $count; $i++) {
				$mul = '*';
				$sqr = '√';
				if ($i + 1 == $count) {
					$mul = '';
					$sqr = '';
				}
				$factor .= "$final[$i] $mul ";
				$factor1 .= "$final[$i] $mul $sqr";
			}
		
			$this->param['factor'] = $factor;
			$this->param['factor1'] = $factor1;
			$this->param['product'] = $product;
			$this->param['sqr_show'] = $sqr_show; // Store the array of square roots
		}
		$this->param['result'] = $result;
		$this->param['num'] = $num;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

