	public function sum($request)
	{
		$check = true;
		if (empty($request->x)) {
			$check = false;
		}
		$seprate = $request->seprate;
		if (empty($seprate)) {
			$seprate = ' ';
		}
		$numbers = array_map('trim', array_filter(explode($seprate, $request->x)));
		foreach ($numbers as $value) {
			if (!is_numeric($value)) {
				$check = false;
			}
		}
		if ($check == true) {
			$ns = $numbers;
			$s = array_sum($ns) / count($ns);
			$n = count($ns);
			$sa = 0;
			foreach ($ns as $key => $value) {
				$sa += pow(($value - $s), 2);
			}
			$su = 0;
			foreach ($ns as $key => $value) {
				$su += pow($value, 2);
			}
			$so = 0;
			foreach ($ns as $key => $value) {
				$so += $value;
			}
			$sns = '';
			foreach ($ns as $key => $value) {
				if ($key == (count($ns) - 1)) {
					$sns .= "($value - $s)<sup>2</sup>";
				} else {
					$sns .= "($value - $s)<sup>2</sup> + ";
				}
			}
			$snns = '';
			foreach ($ns as $key => $value) {
				if ($key == (count($ns) - 1)) {
					$a = pow($value - $s, 2);
					$snns .= "$a";
				} else {
					$a = pow($value - $s, 2);
					$snns .= " $a+ ";
				}
			}
			$soa = '';
			foreach ($ns as $key => $value) {
				if ($key == (count($ns) - 1)) {
					$soa .= "($value)<sup>2</sup>";
				} else {
					$soa .= "($value)<sup>2</sup> + ";
				}
			}
			$soas = '';
			foreach ($ns as $key => $value) {
				if ($key == (count($ns) - 1)) {
					$a = pow($value, 2);
					$soas .= "$a";
				} else {
					$a = pow($value, 2);
					$soas .= " $a+ ";
				}
			}
			$this->param['soas'] = $soas;
			$this->param['soa'] = $soa;
			$this->param['snns'] = $snns;
			$this->param['sns'] = $sns;
			$this->param['s'] = $s;
			$this->param['so'] = $so;
			$this->param['n'] = $n;
			$this->param['su'] = $su;
			$this->param['ss'] = $sa;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = "Please! Check Your Input";
			return $this->param;
		}
	}
