					$z_url = 'z_score_2.5';
				} elseif ($rz > 2.624 && $rz < 2.875) {
					$z_url = 'z_score_2.75';
				} elseif ($rz > 2.874 && $rz < 3.125) {
					$z_url = 'z_score_3';
				} elseif ($rz > 3.124 && $rz < 3.375) {
					$z_url = 'z_score_3.25';
				} elseif ($rz > 3.374 && $rz < 3.625) {
					$z_url = 'z_score_3.5';
				} elseif ($rz > 3.624 && $rz < 3.875) {
					$z_url = 'z_score_3.75';
				} elseif ($rz > 3.874 && $rz < 4.125) {
					$z_url = 'z_score_4';
				} elseif ($rz > 4.124) {
					$z_url = 'z_score_4.25';
				}
				$this->param['z_url'] = $z_url;
				$this->param['ltpv'] = abs($ltpv);
				$this->param['rtpv'] = abs($rtpv);
				$this->param['ttpv'] = abs($ttpv);
				$this->param['ttcl'] = abs($ttcl);
				$this->param['ms'] = $ms;
				$this->param['rz'] = round($rz, 4);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = "Please fill all fields.";
				return $this->param;
			}
		}
		if ($request->to_calculate == 'sm') {
			if (is_numeric($request->snvalue) && is_numeric($request->pmvalue) && is_numeric($request->psdvalue) && is_numeric($request->smvalue)) {
				$x = $request->smvalue;
				$n = $request->snvalue;
				$u = $request->pmvalue;
				$o = $request->psdvalue;
				$rz = ($x - $u) / ($o / sqrt($n));
				$ms = $x - $u;
				$sq = sqrt($n);
				$mv = $o / $sq;
				$this->param['ms'] = $ms;
				$this->param['mv'] = $mv;
				$this->param['sq'] = $sq;
				$this->param['rz'] = round($rz, 4);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = "Please fill all fields.";
				return $this->param;
			}
		}
		if ($request->to_calculate == 'ds') {
			$check = true;
			if (empty($request->x) && empty($request->pmvalue) && empty($request->psdvalue)) {
				$check = false;
			}
			$numbers = array_map('trim', array_filter(explode(',', $request->x)));
			foreach ($numbers as $value) {
				if (!is_numeric($value)) {
					$check = false;
				}
			}
			if ($check == true) {
				$a = '';
				$n = count($numbers);
				$arr = $numbers;
				$sum = array_sum($arr);
				$avg = $sum / $n;
				$u = $request->pmvalue;
				$o = $request->psdvalue;
				$rz = ($avg - $u) / ($o / sqrt($n));
				foreach ($arr as $key => $value) {
					if ($key != (count($arr) - 1)) {
						$a .= " $value +";
					} else {
						$a .= " $value ";
					}
				}
				$sm = $avg - $u;
				$sq = sqrt($n);
				$dv = $o / $sq;
				$this->param['avg'] = $avg;
				$this->param['n'] = $n;
				$this->param['a'] = $a;
				$this->param['sum'] = $sum;
				$this->param['sm'] = $sm;
				$this->param['sq'] = $sq;
				$this->param['dv'] = $dv;
				$this->param['rz'] = round($rz, 4);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = "Please fill all fields.";
				return $this->param;
			}
		}
		if ($request->to_calculate == 'p') {
			if (is_numeric($request->pvalue)) {
				$pva = $request->pvalue;
				if ($pva > 0 && $pva < 1) {
					$this->param['pva'] = $pva;
					$this->param['RESULT'] = 1;
					return $this->param;
				} else {
					$this->param['error'] = "Please Input value from 0 to 1.";
					return $this->param;
				}
			} else {
				$this->param['error'] = "Please Put P Value.";
				return $this->param;
			}
			$this->param['RESULT'] = 1;
			return $this->param;
		}
	}
	public function standerror($request)
	{
		if ($request->form == 'raw') {
			$check = true;
			if (empty($request->x) && empty($request->pmvalue) && empty($request->psdvalue)) {
				$check = false;
			}
			$numbers = array_map('trim', array_filter(explode(',', $request->x)));
			foreach ($numbers as $value) {
				if (!is_numeric($value)) {
					$check = false;
				}
			}
			if ($check == true) {
				$d = '';
				$v = '';
				$v1 = '';
				$v2 = '';
				$v3 = '';
				$v4 = '';
				$v5 = '';
				$rv = '';
				$v6 = '';
				$v7 = '';
				$arr1 = array();
				$arr = $numbers;
				$count = count($arr);
				$sum = array_sum($arr);
				$mean = $sum / $count;
				foreach ($arr as $key => $value) {
					$a = $value - $mean;
					$b = pow($a, 2);
					$arr1[] = $b;
					if ($key != (count($arr) - 1)) {
						$v3 .= " $b +";
						$v1 .= " ($value - $mean)² + ";
						$v .= " ( $a )² +";
					} else {
						$v1 .= " ($value - $mean)²  ";
						$v .= " ( $a )² ";
						$v3 .= " $b ";
					}
				}
				$c = array_sum($arr1);
				$v2 = $count - 1;
				$v4 = 1 / $v2;
				$v5 = $v4 * $c;
				$v6 = sqrt($count);
				$rv = round(sqrt($v5), 4);
				$d = sqrt(1 / ($count - 1) * $c);
				$e = round($d, 4);
				$v7 = round($e / $v6, 4);
				$se = round($d / sqrt($count), 4);
				$this->param['count'] = $count;
				$this->param['sum'] = $sum;
				$this->param['mean'] = $mean;
				$this->param['e'] = $e;
				$this->param['se'] = $se;
				$this->param['v'] = $v;
				$this->param['v1'] = $v1;
				$this->param['v2'] = $v2;
				$this->param['v3'] = $v3;
				$this->param['c'] = $c;
				$this->param['v4'] = $v4;
				$this->param['v5'] = $v5;
				$this->param['rv'] = $rv;
				$this->param['v6'] = $v6;
				$this->param['v7'] = $v7;
				$this->param['form'] = $request->form;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = "Please Input Some Values.";
				return $this->param;
			}
		}
		if ($request->form == 'summary') {
			if (is_numeric($request->deviation) && is_numeric($request->sample)) {
				$de = $request->deviation;
				$n = $request->sample;
				$sn = round(sqrt($n), 4);
				$se = round($de / $sn, 4);
				$this->param['se'] = $se;
				$this->param['sn'] = $sn;
				$this->param['RESULT'] = 1;
				$this->param['form'] = $request->form;
				return $this->param;
			} else {
				$this->param['error'] = "Please! Check Your Input";
				return $this->param;
			}
		}
	}

	public function expected($request)
	{
