		function printDivisors($n)
		{
			for ($i = 1; $i <= $n; $i++) {
				if ($n % $i == 0)
					$divi[] = "$i ";
			}
			return ($divi);
		}
		function np($num)
		{
			$prev = '';
			$i = $num;
			$check_n = 0;
			while ($i < 10000000 && $check_n != 1) {
				$i++;
				$mm = 0;
				for ($j = 2; $j <= $i / 2; $j++) {
					if ($i % $j == 0) {
						$mm++;
						break;
					}
				}
				if ($mm == 0) {
					$next = $i;
					$check_n = 1;
				}
			}
			$i = $num;
			$check_n = 0;
			while ($i > 2 && $check_n != 1) {
				$i--;
				$mm = 0;
				for ($j = 2; $j <= $i / 2; $j++) {
					if ($i % $j == 0) {
						$mm++;
						break;
					}
				}
				if ($mm == 0) {
					$prev = $i;
					$check_n = 1;
				}
			}
			return array($prev, $next);
		}
		function factor($loop_eo)
		{
			$newtext_eo = "";
			$chk_eo = 2;
			$prime_eo = 0;
			while ($chk_eo * $chk_eo <= $loop_eo) : //10 => 4
				if ($loop_eo % $chk_eo == 0) { //10 % 2 = 0
					$newtext_eo = $newtext_eo . $chk_eo; // 0 +2 =2;
					$loop_eo = $loop_eo / $chk_eo; //10/2 = 5
					if ($loop_eo != 1) {   // 
						$newtext_eo = $newtext_eo . " × ";
					}
				} else {
					$chk_eo++;
				}
			endwhile;
			if ($loop_eo != 1) {
				$newtext_eo = $newtext_eo . $loop_eo;
			}
			if ($newtext_eo == "" . $loop_eo) {
				$newtext_eo = "1 " . $newtext_eo;
				$prime_eo = 1;
			}
			return $newtext_eo;
		}
		function total($num)
		{
			$list = '';
			$total = 0;
			for ($i = 2; $i <= $num; $i++) {
				$mm = 0;
				for ($j = 2; $j <= $i / 2; $j++) {
					//only not prime numbers
					if ($i % $j == 0) {
						$mm++;
						break;
					}
				}
				if ($mm == 0) {
					$total++;
					$list .= "$i, ";
				}
			}
			return $total;
		}
