	public function rsd($request)
	{
		$x = $request->x;
		$form = $request->form;
		$mean = $request->mean;
		$deviation = $request->deviation;
		if ($form == 'raw') {
			if (!empty($x)) {
				$numbers = explode(',', $x);
				$values = [];
				foreach ($numbers as $key => $value) {
					$values[] = trim($value);
				}
				sort($values);
				foreach ($values as $key => $value) {
					if (!is_numeric($value)) {
						$this->param['error'] = "Please! Check Your Input";
						return $this->param;
						break;
					}
				}

				$min = min($values);
				$max = max($values);
				$count = count($values);
				$sum = array_sum($values);
				$range = $max - $min;
				$mean = round($sum / $count, 5);

				if (($count % 2) != 0) {
					$center = round($count / 2);
					$median = $values[$center--];
				} else {
					$center = round($count / 2);
					$next = $center - 1;
					$median = ($values[$center] + $values[$next]) / 2;
				}
				$m_array = array_count_values($values);
				$m_max = max($m_array);
				$mode = array();
				foreach ($m_array as $key => $value) {
					if ($value == $m_max) {
						$mode[] = $key;
					}
				}
				$d = 0;
				foreach ($values as $key => $value) {
					$d = $d + pow($value - $mean, 2);
				}
				$s_d = (1 / ($count - 1)) * $d;
				$psd = (1 / ($count)) * $d;
				$pvar = $psd;
				$svar = $s_d;
				$SD = sqrt($s_d);
				$PSD = sqrt($psd);
				$rsd = ($SD / $mean) * 100;
				$this->param['rsd'] = $rsd;
				$this->param['min'] = $min;
				$this->param['max'] = $max;
				$this->param['count'] = $count;
				$this->param['sum'] = $sum;
				$this->param['range'] = $range;
				$this->param['mean'] = $mean;
				$this->param['median'] = $median;
				$this->param['mode'] = $mode;
				$this->param['SD'] = $SD;
				$this->param['PSD'] = $PSD;
				$this->param['svar'] = $svar;
				$this->param['pvar'] = $pvar;
				$this->param['form'] = $form;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = "Please! Check Your Input";
				return $this->param;
			}
		} else {
			if (is_numeric($mean) && is_numeric($deviation)) {
				$rsd = ($deviation / $mean) * 100;
				$this->param['rsd'] = $rsd;
				$this->param['form'] = $form;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = "Please! Check Your Input";
				return $this->param;
			}
		}
	}
	public function chebyshevs($request){
		$operations=$request->operations;
		$first=$request->first;
		$second=$request->second;
		if ($operations==3) {
			if ($first > 1) {
				if ($second > 1) {
					$sq = pow($first, 2);
					$f_ans = $second / $sq;
					$final_fans = number_format($f_ans, 3);
					$s_ans = $f_ans * 100;
					if ($s_ans >= 100) {
						$final_sans = "100";
					}else if ($s_ans < 100) {
						$final_sans = number_format($s_ans, 2);
					}
					$pehla = $first;
				}else{
					$this->param['error'] = "Please variance enter greater than 1";
					return $this->param;
				}
			}else{
				$this->param['error'] = "Please bound enter greater than 1.";
				return $this->param;
			} 
		}else if ($operations==4) {
			if ($first > 1) {
				if ($second > 1) {
					$sq = pow($first, 2);
					$f_ans = $first * 4;
					$aja = 1 / $sq;
					$final_fans = number_format($aja, 3);
					$s_ans = $aja * 100;
					if ($s_ans >= 100) {
						$final_sans = "100";
					}else if ($s_ans < 100) {
						$final_sans = number_format($s_ans, 2);
					}
					$pehla = $f_ans;
				}else{
					$this->param['error'] = "Please variance enter greater than 1";
					return $this->param;
				}
			}else{
				$this->param['error'] = "Please bound enter greater than 1.";
				return $this->param;
			}
		}else if ($operations==5) {
			if ($first > 1) {
				$pehla = pow($first, 2);
				$aja = 1 / $pehla;
				$final_fans = number_format($aja, 3);
				$final_sans = 1 - $final_fans;
			}else{
				$this->param['error'] = "Please bound enter greater than 1.";
				return $this->param;
			}
		}else if ($operations==6) {
			if ($first > 1) {
				$pehla = 1 - $first;
				$aja = 1 / $pehla;
				$final_fans = number_format($aja, 3);
				if ($aja >= 0) {
					$final_sans = sqrt($aja);
				}else if ($aja < 0) {
					$final_sans = "NaN";
				}
			}else{
				$this->param['error'] = "Please bound enter greater than 1.";
				return $this->param;
			}
		}
		$this->param['operations']=$operations;
		$this->param['pehla']=$pehla;
		$this->param['final_fans']=$final_fans;
		$this->param['final_sans']=$final_sans;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	public function box($request)
	{
		$x = $request->x;
		$seprate = $request->seprate;
		function quartil($arr)
		{
			$count = count($arr);
			$middleval = floor(($count - 1) / 2);
			if ($count % 2) {
				$median = $arr[$middleval];
			} else {
				$low = $arr[$middleval];
				$high = $arr[$middleval + 1];
				$median = (($low + $high) / 2);
			}
			return number_format((float)$median, 1, '.', '');
		}
		if (empty($x)) {
			$check = false;
		}
		if (empty($seprate)) {
			$seprate = ' ';
		}
		$check = true;
		$numbers = array_map('trim', array_filter(explode($seprate, $x)));
		foreach ($numbers as $value) {
			if (!is_numeric($value)) {
				$check = false;
			}
		}
		if ($check == true) {
			sort($numbers);
			if (count($numbers) < 2) {
				$this->param['error'] = "Please! enter 2 or more numbers";
				return $this->param;
			}
			$maximum = max($numbers);
			$minimum = min($numbers);
			$second = quartil($numbers);
			$tmp = array();
			foreach ($numbers as $key => $val) {
				if ($val > $second) {
					$tmp['third'][] = $val;
				} else if ($val < $second) {
					$tmp['first'][] = $val;
				}
			}
			$first = quartil($tmp['first']);
			$third = quartil($tmp['third']);
			$count = count($numbers);
			if (($count % 2) != 0) {
				$center = round($count / 2);
				$median = $numbers[$center--];
			} else {
				$center = round($count / 2);
				$next = $center - 1;
				$median = ($numbers[$center] + $numbers[$next]) / 2;
			}
		} else {
			$this->param['error'] = "Please! Check Your Input";
			return $this->param;
		}
		$this->param['numbers'] = $numbers;
		$this->param['count'] = count($numbers);
		$this->param['third'] = $third;
		$this->param['first'] = $first;
		$this->param['median'] = $median;
		$this->param['maximum'] = $maximum;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	public function bin_cof($request)
	{
		$n = $request->n;
		$k = $request->k;
		if (is_numeric($n) && is_numeric($k)) {
			if ($k > $n) {
				$this->param['error'] = "n must be larger than or equal to k";
				return $this->param;
			}
			function factorial($n)
			{
				if ($n <= 1) {
					return 1;
				} else {
					try {
						$fact = gmp_fact($n);
						return gmp_strval($fact);
					} catch (\Exception $r) {
						return false;
					}
				}
			}
			if (factorial($n) && factorial($k)) {
				$ans = factorial($n) / (factorial($k) * factorial($n - $k));
				$this->param['ans'] = $ans;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = "Please! Try a small number";
				return $this->param;
			}
		} else {
			$this->param['error'] = "Please! Check Your Input";
			return $this->param;
		}
	}
	public function per_rank($request){
		$x=$request->x;
		$find=$request->find;
		$method=$request->method;
		if (!empty($x) && is_numeric($find)) {
			$numbers=explode(',',$x);
			$values=[];
			$isNum = true;
			foreach ($numbers as $key => $value) {
				if (is_numeric(trim($value))) {
					$values[]=trim($value);
				} else {
					$isNum = false;
					break;
				}
			}
			if ($isNum==true) {
				$count = 0;
				$same = 0;
				sort($values);
				foreach ($values as $key => $value) {
					if ($value <= $find) {
						$count++;
					}
					if ($value == $find) {
						$same++;
					}
				}
				if ($method==1) {
					$pr = ($count/count($values))*100;
				} else {
					$pr = (($count-0.5 * $same)/count($values))*100;
				}
				$this->param['pr'] = $pr;
				$this->param['same'] = $same;
				$this->param['count'] = $count;
				$this->param['find'] = $find;
				$this->param['values'] = $values;
				$this->param['RESULT'] = 1;
				return $this->param;
			}else{
				$this->param['error'] = "Please! Enter only numbers";
				return $this->param;
			}
		} else {
			$this->param['error'] = "Please! Check Your Input";
			return $this->param;
		}
		
	}
	public function coin($request){
		$flips=$request->flips;
		$heads=$request->heads;
		$probablity=$request->probablity;
		$type=$request->type;
		function factorial($num){
			$factorial = 1;  
			for ($x=$num; $x>=1; $x--)   
				{  
					$factorial = $factorial * $x;  
				}
			return $factorial;
		}
		function total_calculation($flips,$heads,$probablity2){
			$sub2=$flips-$heads;
			$f4=factorial($flips);
			$f5=factorial($heads);
			$f6=factorial($sub2);
			$power=pow($probablity2,$heads);
			$power2=pow(1-$probablity2,$sub2);
			$ans2=($f4/($f5*$f6))*$power*$power2;
			return $ans2;
		}
		if($type=="1"){
			if(is_numeric($flips) && is_numeric($heads) && is_numeric($probablity)){
				if($flips>=$heads){
					if($flips>0 && $heads>0){
						if($probablity>=0 && $probablity<=1){
							$num = $flips;
							$num2=$heads;  
							$sub=$flips-$heads;
							$f1=factorial($num);
							$f2=factorial($num2);
							$f3=factorial($sub);
							$power_p=pow($probablity,$heads);
							$power_p2=pow(1-$probablity,$sub);
							$ans=($f1/($f2*$f3))*$power_p*$power_p2;
						}else{
							$this->param['error'] = "Probablity must be between 0 and 1 inclusive";
							return $this->param;
						}
					}else{
						$this->param['error'] = "Enter Value Greater than zero";
						return $this->param;
					}
				}else{
					$this->param['error'] = "The number of obtained heads cannot be greater than the number of tosses.";
					return $this->param;
				}
			}else{
				$this->param['error'] = "Please! Check Your Input";
				return $this->param;
			}
		}else if($type=="2"){
			if(is_numeric($flips) && is_numeric($heads) && is_numeric($probablity)){
				if($flips>=$heads){
					if($flips>=0 && $heads>=0){
						if($probablity>=0 && $probablity<=1){
							$num = $flips;
							$num2=$heads;  
							$sub=$flips-$heads;
							$f1=factorial($num);
							$f2=factorial($num2);
							$f3=factorial($sub);
							$power_p=pow($probablity,$heads);
							$power_p2=pow(1-$probablity,$sub);
							$ans=($f1/($f2*$f3))*$power_p*$power_p2;
							$heading=$heads+1;
							for($i=$heading;$i<=$flips;$i++){
								$awa[]=total_calculation($flips,$heading,$probablity);
								$heading=$heading+1;
								$summer=array_sum($awa);
							}
							$this->param['array_awa']=$awa;
							$this->param['summer']=$summer;
						}else{
							$this->param['error'] = "Probablity must be between 0 and 1 inclusive";
							return $this->param;
						}
					}else{
						$this->param['error'] = "Enter Value Greater than zero";
						return $this->param;
					}
				}else{
					$this->param['error'] = "The number of obtained heads cannot be greater than the number of tosses.";
					return $this->param;
				}
			}else{
				$this->param['error'] = "Please! Check Your Input";
				return $this->param;
			}
		}else if($type=="3"){
			if(is_numeric($flips) && is_numeric($heads) && is_numeric($probablity)){
				if($flips>=$heads){
					if($flips>=0 && $heads>=0){
						if($probablity>=0 && $probablity<=1){
							$num = $flips;
							$num2=0;  
							$sub=$flips-0;
							$f1=factorial($num);
							$f2=factorial($num2);
							$f3=factorial($sub);
							$power_p=pow($probablity,$num2);
							$power_p2=pow(1-$probablity,$sub);
							$ans=($f1/($f2*$f3))*$power_p*$power_p2;
							$heading=$heads+1;
							for($i=0;$i<=$heads;$i++){
								$awa[]=total_calculation($flips,$i,$probablity);
								$heading=$heading+1;
								$summer=array_sum($awa);
							}
							$this->param['array_awa']=$awa;
							$this->param['summer']=$summer;
						}else{
							$this->param['error'] = "Probablity must be between 0 and 1 inclusive";
							return $this->param;
						}
					}else{
						$this->param['error'] = "Enter Value Greater than zero";
						return $this->param;
					}
				}else{
					$this->param['error'] = "The number of obtained heads cannot be greater than the number of tosses.";
					return $this->param;
				}
			}else{
				$this->param['error'] = "Please! Check Your Input";
				return $this->param;
			}
		}
		$this->param['type']=$type;
		$this->param['flips']=$flips;
		$this->param['heads']=$heads;
		$this->param['probablity']=$probablity;
		$this->param['ans']=$ans;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

