		function zProb($z)
		{
			if ($z < -7) {
				return 0.0;
			}
			if ($z > 7) {
				return 1.0;
			}


			if ($z < 0.0) {
				$flag = true;
			} else {
				$flag = false;
			}

			$z = abs($z);
			$b = 0.0;
			$s = sqrt(2) / 3 * $z;
			$HH = .5;
			for ($i = 0; $i < 12; $i++) {
				$a = exp(((-1) * $HH) * $HH / 9) * sin($HH * $s) / $HH;
				$b = $b + $a;
				$HH = $HH + 1.0;
			}
			$p = .5 - $b / pi();
			if (!$flag) {
				$p = 1.0 - $p;
			}
			return $p;
		}
