					$tmp -= ($x + 0.5) * log($tmp);
					$ser = 1.000000000190015;
					for ($j = 0; $j < 6; $j++) {
						$ser += $cof[$j] / ++$y;
					}
					return -$tmp + log(2.5066282746310005 * $ser / $x);
				}
				$pValue = t_dist($tValue, $df);

				// Store the results
