	public function sample_size($request)
	{
		$population = trim($request->population);
		$given_unit = trim($request->given_unit);
		$confidence_unit = trim($request->confidence_unit);
		$margin = trim($request->margin);
		$standard = trim($request->standard);
		$proportion = trim($request->proportion);
		$n_finite = trim($request->n_finite);
		if ($confidence_unit == "70%") {
			$confidence_unit = 1.04;
		} elseif ($confidence_unit == "75%") {
			$confidence_unit = 1.15;
		} elseif ($confidence_unit == "80%") {
			$confidence_unit = 1.28;
		} elseif ($confidence_unit == "85%") {
			$confidence_unit = 1.44;
		} elseif ($confidence_unit == "90%") {
			$confidence_unit = 1.65;
		} elseif ($confidence_unit == "95%") {
			$confidence_unit = 1.96;
		} elseif ($confidence_unit == "98%") {
			$confidence_unit = 2.33;
		} elseif ($confidence_unit == "99%") {
			$confidence_unit = 2.58;
		} elseif ($confidence_unit == "99.9%") {
			$confidence_unit = 3.29;
		} else {
			$confidence_unit = 4.42;
		}
		if ($margin === "0") {

			$this->param['error'] = "Accepted value cannot be equal to zero.";
			return $this->param;
		}
		if ($proportion === "0") {

			$this->param['error'] = "Accepted value cannot be equal to zero.";
			return $this->param;
		}
		if ($population == "sample") {
			if ($given_unit == "standard") {
				if (is_numeric($margin) && is_numeric($standard)) {
					$margin = $margin / 100;
					$multiply = $confidence_unit * $standard;
					$divide = $multiply / $margin;
					$sub_answer = $divide * $divide;
					$answer = round($sub_answer);

					$this->param['margin'] = $margin;
					$this->param['standard'] = $standard;
					$this->param['confidence_unit'] = $confidence_unit;
					$this->param['multiply'] = $multiply;
					$this->param['divide'] = $divide;
					$this->param['sub_answer'] = $sub_answer;
					$this->param['answer'] = $answer;
				} else {

					$this->param['error'] = "Please! Check Your Input";
					return $this->param;
				}
			} else {
				if (is_numeric($margin) && is_numeric($proportion)) {
					$margin = $margin / 100;
					$proportion = $proportion / 100;
					$con_unit = $confidence_unit * $confidence_unit;
					$minus = (1 - $proportion);
					$marg = $margin * $margin;
					$propro_sub = $con_unit * $proportion;
					$propro = $propro_sub * $minus;
					$propro_answer = $propro / $marg;
					$answer = round($propro_answer);
					$this->param['answer'] = $answer;
					$this->param['confidence_unit'] = $confidence_unit;
					$this->param['proportion'] = $proportion;
					$this->param['margin'] = $margin;
					$this->param['minus'] = $minus;
					$this->param['marg'] = $marg;
					$this->param['con_unit'] = $con_unit;
					$this->param['propro'] = $propro;
					$this->param['propro_answer'] = $propro_answer;
				} else {

					$this->param['error'] = "Please! Check Your Input";
					return $this->param;
				}
			}
		} else {
			if ($given_unit == "standard") {
				if (is_numeric($margin) && is_numeric($standard) && is_numeric($n_finite)) {
					$margin = $margin / 100;
					$multiply = $confidence_unit * $standard;
					$divide = $multiply / $margin;
					$sub_answer = $divide * $divide;
					$n_answer = round($sub_answer);
					$a_answer = ($n_answer * $n_finite);
					$b_answer = ($n_answer + $n_finite - 1);
					$answer_s = $a_answer / $b_answer;
					$answer = round($answer_s);
					$this->param['n_finite'] = $n_finite;
					$this->param['margin'] = $margin;
					$this->param['standard'] = $standard;
					$this->param['confidence_unit'] = $confidence_unit;
					$this->param['multiply'] = $multiply;
					$this->param['divide'] = $divide;
					$this->param['sub_answer'] = $sub_answer;
					$this->param['a_answer'] = $a_answer;
					$this->param['b_answer'] = $b_answer;
					$this->param['answer'] = $answer;
				} else {

					$this->param['error'] = "Please! Check Your Input";
					return $this->param;
				}
			} else {
				if (is_numeric($margin) && is_numeric($proportion) && is_numeric($n_finite)) {
					$margin = $margin / 100;
					$proportion = $proportion / 100;
					$con_unit = $confidence_unit * $confidence_unit;
					$minus = (1 - $proportion);
					$marg = $margin * $margin;
					$propro_sub = $con_unit * $proportion;
					$propro = $propro_sub * $minus;
					$propro_answer = $propro / $marg;
					$sub_answer = round($propro_answer);
					$a_answer = ($sub_answer * $n_finite);
					$b_answer = ($sub_answer + $n_finite - 1);
					$answer_s = $a_answer / $b_answer;
					$answer = round($answer_s);
					$this->param['n_finite'] = $n_finite;
					$this->param['confidence_unit'] = $confidence_unit;
					$this->param['proportion'] = $proportion;
					$this->param['margin'] = $margin;
					$this->param['minus'] = $minus;
					$this->param['marg'] = $marg;
					$this->param['con_unit'] = $con_unit;
					$this->param['propro'] = $propro;
					$this->param['propro_answer'] = $propro_answer;
					$this->param['sub_answer'] = $sub_answer;
					$this->param['a_answer'] = $a_answer;
					$this->param['b_answer'] = $b_answer;
					$this->param['answer'] = $answer;
				} else {

					$this->param['error'] = "Please! Check Your Input";
					return $this->param;
				}
			}
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	public function pert($request)
	{
		$optimistic = trim($request->optimistic);
		$optimistic_one = trim($request->optimistic_one);
		$optimistic_sec = trim($request->optimistic_sec);
		$optimistic_unit = trim($request->optimistic_unit);
		$pessimistic = trim($request->pessimistic);
		$pessimistic_one = trim($request->pessimistic_one);
		$pessimistic_sec = trim($request->pessimistic_sec);
		$pessimistic_unit = trim($request->pessimistic_unit);
		$most = trim($request->most);
		$most_one = trim($request->most_one);
		$most_sec = trim($request->most_sec);
		$most_unit = trim($request->most_unit);
		$desired = trim($request->desired);
		$desired_one = trim($request->desired_one);
		$desired_sec = trim($request->desired_sec);
		$desired_unit = trim($request->desired_unit);
		$output_unit = trim($request->output_unit);
		$deviation_unit = trim($request->deviation_unit);
		function time_unit($optimistic, $optimistic_unit)
		{
			if ($optimistic_unit == "hrs") {
				$optimistic = $optimistic * 24;
			} elseif ($optimistic_unit == "days") {
				$optimistic = $optimistic * 1;
			} elseif ($optimistic_unit == "wks") {
				$optimistic = $optimistic / 7;
			} elseif ($optimistic_unit == "mos") {
				$optimistic = $optimistic / 30.417;
			} elseif ($optimistic_unit == "yrs") {
				$optimistic = $optimistic / 365;
			}
			return $optimistic;
		}
		function other_time($optimistic_one, $optimistic_sec, $optimistic_unit)
		{
			if ($optimistic_unit === "yrs/mos") {
				$optimistic = ($optimistic_one * 365) + ($optimistic_sec * 30.417);
			} elseif ($optimistic_unit === "wks/days") {
				$optimistic = ($optimistic_one * 7) + $optimistic_sec;
			} elseif ($optimistic_unit === "days/hrs") {
				$optimistic = $optimistic_one + ($optimistic_sec / 24);
			}
			return $optimistic;
		}
		function secore($x)
		{
			$pi = 3.1415927;
			$a = (8 * ($pi - 3)) / (3 * $pi * (4 - $pi));
			$x2 = $x * $x;
			$ax2 = $a * $x2;
			$num = (4 / $pi) + $ax2;
			$denom = 1 + $ax2;
			$inner = (-$x2) * $num / $denom;
			$secore2 = 1 - exp($inner);
			return sqrt($secore2);
		}
		function cdf($n)
		{
			if ($n < 0) {
				return (1 - secore($n / sqrt(2))) / 2;
			} else {
				return (1 + secore($n / sqrt(2))) / 2;
			}
		}
		if (is_numeric($optimistic) && is_numeric($pessimistic) && is_numeric($most) && is_numeric($desired)) {

			if ($optimistic_unit === "yrs/mos" || $optimistic_unit === "wks/days" || $optimistic_unit === "days/hrs") {
				if (is_numeric($optimistic_one) && is_numeric($optimistic_sec)) {
					$optimistic = other_time($optimistic_one, $optimistic_sec, $optimistic_unit);
					$this->param['optimistic'] = $optimistic;
				} else {
					$this->param['error'] = "Please! Check Your Input";
					return $this->param;
				}
			} else {
				$optimistic = time_unit($optimistic, $optimistic_unit);
			}

			if ($pessimistic_unit === "yrs/mos" || $pessimistic_unit === "wks/days" || $pessimistic_unit === "days/hrs") {
				if (is_numeric($pessimistic_one) && is_numeric($pessimistic_sec)) {
					$pessimistic = other_time($pessimistic_one, $pessimistic_sec, $pessimistic_unit);
					$this->param['pessimistic'] = $pessimistic;
				} else {
					$this->param['error'] = "Please! Check Your Input";
					return $this->param;
				}
			} else {
				$pessimistic = time_unit($pessimistic, $pessimistic_unit);
			}

			if ($most_unit === "yrs/mos" || $most_unit === "wks/days" || $most_unit === "days/hrs") {
				if (is_numeric($most_one) && is_numeric($most_sec)) {
					$most = other_time($most_one, $most_sec, $most_unit);
					$this->param['most'] = $most;
				} else {
					$this->param['error'] = "Please! Check Your Input";
					return $this->param;
				}
			} else {
				$most = time_unit($most, $most_unit);
			}

			if ($desired_unit === "yrs/mos" || $desired_unit === "wks/days" || $desired_unit === "days/hrs") {
				if (is_numeric($desired_one) && is_numeric($desired_sec)) {
					$desired = other_time($desired_one, $desired_sec, $desired_unit);
					$this->param['desired'] = $desired;
				} else {
					$this->param['error'] = "Please! Check Your Input";
					return $this->param;
				}
			} else {
				$desired = time_unit($desired, $desired_unit);
			}

			$multi = 4 * $most;
			$add = $optimistic + $multi + $pessimistic;
			$sub = $add / 6;
			$main_answer = time_unit($sub, $output_unit);

			$standard = $pessimistic - $optimistic;
			if ($standard == 0) {
				$this->param['error'] = "Optimistic or Pessimistic value note same";
				return $this->param;
			} else {
				$sta_answer = $standard / 6;
				$sub_answer = time_unit($sta_answer, $deviation_unit);
				$score = $desired - $main_answer;
				$main_score = $score / $sub_answer;
				$ans = cdf($main_score) * 100;
			}
		} else {
			$this->param['error'] = "Please! Check Your Input";
			return $this->param;
		}
		$this->param['add'] = $add;
		$this->param['main_answer'] = $main_answer;
		$this->param['sub_answer'] = $sub_answer;
		$this->param['ans'] = $ans;
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	public function pie($request)
	{
		$choices = $request->choices;
		$i = 0;
		if (is_numeric($choices[$i])) {
			// ==============Sum==========
			$sum = 0;
			foreach ($choices as $key => $value) {
				$sum = $value + $sum;
			}
			// ==========percentage===============
			$percentage = array();
			foreach ($choices as $value) {
				$per = round(($value / $sum) * 100, 2);
				array_push($percentage, $per);
			}
			// ==========angle===============
			$degree = array();
			foreach ($percentage as $key => $value) {
				$deg = round(($value / 100) * 360);
				array_push($degree, $deg);
			}
			$values = [];
			foreach ($choices as $value) {
				array_push($values, $value);
			}
			// =========letters=============
			$length = count($values) - 1;
			$letters = [];
			for ($i = 65; $i <= 65 + $length; $i++) {
				$letters[] = chr($i);
			}
			// Initialize an empty array to store the converted data
			$dataPoints = [];
			// Assuming both arrays have the same length
			for ($i = 0; $i < count($letters); $i++) {
				$dataPoints[] = [
					'y' => $values[$i],
					'label' => $letters[$i]
				];
			}
			$dataPoints = json_encode($dataPoints);
			$this->param['letters'] =  $letters;
			$this->param['values'] =  $values;
			$this->param['percentage'] =  $percentage;
			$this->param['degree'] =  $degree;
			$this->param['new_combine'] =  $dataPoints;
		} else {
			$this->param['error'] = "Please! Check Your Input";
			return $this->param;
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	public function anova($request)
	{
		$submit = $request->type;
		if ($submit === 'one_way') {
			$k = $request->k;
			$check = true;
			for ($x = 1; $x <= $k; $x++) {
				$group = $_POST["group$x"];
				$groups = array_map("trim", explode(",", $group));
				foreach ($groups as $value) {
					if (!is_numeric($value)) {
						$check = false;
					}
				}
			}
			if ($check === true) {
				$alph = '';
				$alph2 = '';
				$alph_sum = '';
				$alph_sum2 = '';
				for ($i = 1; $i <= $k; $i++) {
					$alph .= "<th class='p-2 border text-center text-blue'>Group $i</th>";
					$alph2 .= "<th class='p-2 border text-center text-blue'>(Group " . $i . ")²</th>";
				}
				$table = "<table class='w-100' style='border-collapse: collapse'><thead><tr class='bg-gray'>$alph</tr></thead><tbody>";
				$table1 = "<table class='w-100' style='border-collapse: collapse'><thead><tr class='bg-gray'>" . $alph2 . "</tr></thead><tbody>";
				$table2 = "<table class='w-100' style='border-collapse: collapse'><thead><tr class='bg-gray'><th colspan='7' class='bb_1 p-2 border text-center text-blue'>Data Summary</th></tr></thead><thead><tr class='bg-gray'><th class='p-2 border text-center text-blue'>Groups</th><th class='p-2 border text-center text-blue'>N</th><th class='p-2 border text-center text-blue'>∑x</th><th class='p-2 border text-center text-blue'>Mean</th><th class='p-2 border text-center text-blue'>∑x²</th><th class='p-2 border text-center text-blue'>Std. Dev.</th><th class='p-2 border text-center text-blue'>Std. Error</th></tr></thead><tbody>";
				$v = 0;
				$std_dev = 0;
				$n_sum = 0;
				$mean_sum = 0;
				$total_sum = 0;
				$total_sum2 = 0;
				$trs[0] = '';
				$trs1[0] = '';
				for ($i = 1; $i <= $k; $i++) {
					$group = $_POST["group$i"];
					$groups = array_map("trim", explode(",", $group));
					$n = count($groups);
					$sum = array_sum($groups);
					$sum2 = 0;
					$mean = $sum / $n;
					foreach ($groups as $key => $value) {
						$v += pow($value - $mean, 2);
						$sum2 += pow($value, 2);
						if (isset($trs[$key])) {
							$td = $trs[$key];
						}else{
							$td = '';
						}
						$td .= "<td class='p-2 border text-center'>" . $value . "</td>";
						$trs[$key] = $td;
						if (isset($trs1[$key])) {
							$td1 = $trs1[$key];
						}else{
							$td1 = '';
						}
						$td1 .= "<td class='p-2 border text-center text-blue'>" . pow($value, 2) . "</td>";
						$trs1[$key] = $td1;
					}
					$std_dev = sqrt($v / ($n - 1));
					$std_error = $std_dev / sqrt($n);
					$table2 .= "<tr class='bg-white'><td class='p-2 border text-center'>Group $i</td><td class='p-2 border text-center'>$n</td><td class='p-2 border text-center'>$sum</td><td class='p-2 border text-center'>$mean</td><td class='p-2 border text-center'>$sum2</td><td class='p-2 border text-center'>" . round($std_dev, 4) . "</td><td class='p-2 border text-center'>" . round($std_error, 4) . "</td></tr>";
					$v = 0;
					$n_sum += $n;
					$mean_sum += $mean;
					$total_sum += $sum;
					$total_sum2 += $sum2;
					$alph_sum .= "<th class='p-2 border text-center text-blue'>∑Group $i = $sum</th>";
					$alph_sum2 .= "<th class='p-2 border text-center text-blue'>∑(Group" . $i . ")² = $sum2</th>";
				}
				for ($i = 0; $i < $n; $i++) {
					$table .= "<tr class='bg-white'>" . $trs[$i] . "</tr>";
					$table1 .= "<tr class='bg-white'>" . $trs1[$i] . "</tr>";
				}
				$mean_sum = $mean_sum / $k;
				$table .= "<tr class='bg-gray'>" . $alph_sum . "</tr></tbody></table>";
				$table1 .= "<tr class='bg-gray'>$alph_sum2</tr></tbody></table>";
				$table2 .= "<tr class='bg-gray'><th class='p-2 border text-center text-blue'>Total</th><th class='p-2 border text-center text-blue'>$n_sum</th><th class='p-2 border text-center text-blue'>$total_sum</th><th class='p-2 border text-center text-blue'>$mean_sum</th><th class='p-2 border text-center text-blue'>$total_sum2</th><th class='p-2 border text-center text-blue'>&nbsp;</th><th class='p-2 border text-center text-blue'>&nbsp;</th></tr></tbody></table>";

				$s1 = '';
				$s2 = '';
				$ssb = 0;
				$ssw = 0;
				for ($i = 1; $i <= $k; $i++) {
					$group = $_POST["group$i"];
					$groups = array_map("trim", explode(",", $group));
					$n = count($groups);
					$sum = array_sum($groups);
					$mean = $sum / $n;
					foreach ($groups as $key => $value) {
						$v += pow($value - $mean, 2);
					}
					$std_dev = sqrt($v / ($n - 1));
					if ($i < $k) {
						$s1 .= "$n * ($mean - $mean_sum)^2 + ";
						$s2 .= "($n - 1) * (" . round($std_dev, 4) . ")^2 + ";
					} else {
						$s1 .= "$n * ($mean - $mean_sum)^2";
						$s2 .= "$n * ($mean - $mean_sum)^2";
					}
					$ssb += $n * pow(($mean - $mean_sum), 2);
				}
				$ssw += ($n - 1) * pow($std_dev, 2);

				$this->param["k"] = $k;
				$this->param["N"] = $n_sum;
				$this->param["table"] = $table;
				$this->param["table1"] = $table1;
				$this->param["table2"] = $table2;
				$this->param["s1"] = $s1;
				$this->param["s2"] = $s2;
				$this->param["ssb"] = round($ssb, 4);
				$this->param["ssw"] = round($ssw, 4);
				$this->param["RESULT"] = 1;
				return $this->param;
			} else {
				$this->param['error'] = "Please! Check Your Input";
				return $this->param;
			}
		} elseif ($submit === 'two_way') {
			$rows = $_POST['rows'];
			$columns = $_POST['columns'];

			$check = true;
			for ($i = 0; $i < $rows; $i++) {
				for ($j = 0; $j < $columns; $j++) {
					$input = $_POST['td_' . $i . '_' . $j];
					$inputs = array_map("trim", explode(",", $input));
					foreach ($inputs as $key => $values) {
						if (!is_numeric($values)) {
							$check = false;
						}
					}
				}
			}
			if ($check === true) {
				$head = '';
				$head2 = '';
				$head2 = '';
				$p3_s1 = '';
				$p3_s2 = '';
				$p3_s3 = '';
				$C = 0;
				$p4_s1 = '';
				$p4_s2 = '';
				$p4_s3 = '';
				$D = 0;
				$n = 0;
				$summ = 0;
				$sumxa = array();
				$table = "<table class='w-100' style='border-collapse: collapse'><thead><tr class='bg-gray'><th class='p-2 border text-center text-blue'>Observation</th>";
				$table1 = "<table class='w-100' style='border-collapse: collapse'><thead><tr class='bg-gray'><th class='p-2 border text-center text-blue'>Observation</th>";
				for ($i = 0; $i < $columns; $i++) {
					$table .= "<th class='p-2 border text-center text-blue'>Group " . ($i + 1) . "</th>";
					$table1 .= "<th class='p-2 border text-center text-blue'>Group " . ($i + 1) . "</th>";
				}
				$table .= "</tr></thead><tbody>";
				$table1 .= "<th class='p-2 border text-center text-blue'>Row Total</th></tr></thead><tbody>";
				$p5_s1 ='';
				$p5_s2 = '';
				$E = 0;
				for ($i = 0; $i < $rows; $i++) {
					$table .= "<tr class='bg-white'><td class='p-2 border text-center'>" . ($i + 1) . "</td>";
					$table1 .= "<tr class='bg-white'><td class='p-2 border text-center'>" . ($i + 1) . "</td>";
					$sum1 = 0;
					$nr = 0;
					$nc = 0;
					for ($j = 0; $j <= $columns; $j++) {
						if ($j != $columns) {
							$input = $_POST['td_' . $i . '_' . $j];
							$table .= "<td class='p-2 border text-center'>$input</td>";
							$inputs = array_map("trim", explode(",", $input));
							$sum = array_sum($inputs);
							$table1 .= "<td class='p-2 border text-center'>" . $sum  . "</td>";
							$sum1 += $sum;
							if(isset($sumxa[$j])){
								$sumx = $sumxa[$j];
							}else{
								$sumx = 0;
							}
							$sumxa[$j] = $sumx + $sum;
							$nr += count($inputs);
							$nc = count($inputs);
							$n += count($inputs);
							$summ += $sum;
							if ($i === $rows - 1 && $j === $columns - 1) {
								$p4_s1 .= '\dfrac {(' . $sum . ')^2}{' . $nc . '}';
								$p4_s2 .= '\dfrac {' . pow($sum, 2) . '}{' . $nc . '}';
								$p4_s3 .= round(((pow($sum, 2)) / $nc), 4);
							} else {
								$p4_s1 .= '\dfrac {(' . $sum . ')^2}{' . $nc . '} + ';
								$p4_s2 .= '\dfrac {' . pow($sum, 2) . '}{' . $nc . '} + ';
								$p4_s3 .= round(((pow($sum, 2)) / $nc), 4) . ' + ';
							}
							$D += (pow($sum, 2)) / $nc;
						} else {
							if(isset($sumxa[$j])){
								$sumx = $sumxa[$j];
							}else{
								$sumx = 0;
							}
							$sumxa[$j] = $sumx + $sum1;
							$table1 .= "<td class='p-2 border text-center'><b>$sum1</b></td>";
						}
					}
					if ($i === $rows - 1) {
						$p3_s1 .= '\dfrac {(' . $sum1 . ')^2}{' . $nr . '}';
						$p3_s2 .= '\dfrac {' . pow($sum1, 2) . '}{' . $nr . '}';
						$p3_s3 .= round(((pow($sum1, 2)) / $nr), 4);
					} else {
						$p3_s1 .= '\dfrac {(' . $sum1 . ')^2}{' . $nr . '} + ';
						$p3_s2 .= '\dfrac {' . pow($sum1, 2) . '}{' . $nr . '} + ';
						$p3_s3 .= round(((pow($sum1, 2)) / $nr), 4) . ' + ';
					}
					$C += (pow($sum1, 2)) / $nr;

					$table .= "</tr>";
					$table1 .= "</tr>";
				}

				$p5_s1 .= '\dfrac {(' . $summ . ')^2}{' . $n . '}';
				$p5_s2 .= '\dfrac {' . pow($summ, 2) . '}{' . $n . '}';
				$E += round(((pow($summ, 2)) / $n), 4);
				$table .= "</tbody></table>";
				$table1 .= "<tr class='bg-white'><td class='p-2 border text-center'><b>Col Total</b></td>";
				foreach ($sumxa as $key => $value) {
					$table1 .= "<td class='p-2 border text-center'><b>$value</b></td>";
				}
				$table1 .= "</tr></tbody></table>";

				$p1 = '';
				$p2_s1 = '';
				$p2_s2 = '';
				$p2_s3 = '';
				$A = 0;
				$B = 0;
				$plus = ' + ';
				for ($i = 0; $i < $columns; $i++) {
					$nc = 0;
					for ($j = 0; $j < $rows; $j++) {
						$input = $_POST['td_' . $j . '_' . $i];
						$inputs = array_map("trim", explode(",", $input));
						$nc += count($inputs);
					}
					if ($i === $columns - 1) {
						$p2_s1 .= '\dfrac {(' . $sumxa[$i] . ')^2}{' . $nc . '}';
						$p2_s2 .= '\dfrac {' . pow($sumxa[$i], 2) . '}{' . $nc . '}';
						$p2_s3 .= round(((pow($sumxa[$i], 2)) / $nc), 4);
					} else {
						$p2_s1 .= '\dfrac {(' . $sumxa[$i] . ')^2}{' . $nc . '} + ';
						$p2_s2 .= '\dfrac {' . pow($sumxa[$i], 2) . '}{' . $nc . '} + ';
						$p2_s3 .= round(((pow($sumxa[$i], 2)) / $nc), 4) . ' + ';
					}
					$B += (pow($sumxa[$i], 2)) / $nc;
				}
				for ($i = 0; $i < $rows; $i++) {
					for ($j = 0; $j < $columns; $j++) {
						$input = $_POST['td_' . $i . '_' . $j];
						$inputs = array_map("trim", explode(",", $input));
						foreach ($inputs as $key => $value) {
							$A += pow($value, 2);
							if ($i === $rows - 1 && $j === $columns - 1 && count($inputs) === $key + 1) {
								$plus = '';
							}
							if ($i === 0 && $j === 0) {
								$p1 .= $value . '^2' . $plus;
							}
							if ($i === $rows - 1 && $j === $columns - 1 && count($inputs) === $key + $rows) {
								$p1 .= '...' . $plus;
							}
							if ($i === $rows - 1 && $j === $columns - 1) {
								$p1 .= $value . '^2' . $plus;
							}
						}
					}
				}
				$this->param["rows"] = $rows;
				$this->param["columns"] = $columns;
				$this->param["table"] = $table;
				$this->param["table1"] = $table1;
				$this->param["p1"] = $p1;
				$this->param["A"] = $A;
				$this->param["p2_s1"] = $p2_s1;
				$this->param["p2_s2"] = $p2_s2;
				$this->param["p2_s3"] = $p2_s3;
				$this->param["B"] = $B;
				$this->param["p3_s1"] = $p3_s1;
				$this->param["p3_s2"] = $p3_s2;
				$this->param["p3_s3"] = $p3_s3;
				$this->param["C"] = $C;
				$this->param["p4_s1"] = $p4_s1;
				$this->param["p4_s2"] = $p4_s2;
				$this->param["p4_s3"] = $p4_s3;
				$this->param["D"] = $D;
				$this->param["p5_s1"] = $p5_s1;
				$this->param["p5_s2"] = $p5_s2;
				$this->param["E"] = $E;
				$this->param["n"] = $n;
				$this->param["RESULT"] = 1;
				return $this->param;
			} else {
				$this->param['error'] = "Please! Check Your Input";
				return $this->param;
			}
		} else {
			$this->param['error'] = "Please! Check Your Input";
			return $this->param;
		}
	}

	// Algebra Calculator
	function algebra($request){
		$EnterEq = $request->EnterEq;
		function convert_latex_to_python($equation) {
			// Replace LaTeX ^ with Python **
			$equation = str_replace('^', '**', $equation);
		
			// Replace LaTeX \sqrt{} with Python sqrt function
			$equation = preg_replace('/\\\\sqrt{(.*?)}/', 'sqrt($1)', $equation);
		
			// Replace LaTeX fractions and add parentheses around the numerator and denominator
			$equation = preg_replace('/\\\\frac{(.*?)}{(.*?)}/', '($1) / ($2)', $equation);
		
			// Replace LaTeX for logarithms
			$equation = preg_replace('/\\\\log{(.*?)}/', 'log($1)', $equation);
			$equation = preg_replace('/\\\\ln{(.*?)}/', 'log($1)', $equation); // natural log
		
			// Replace LaTeX trigonometric functions
			$equation = preg_replace('/\\\\sin\{?(.*?)\}?/', 'sin($1)', $equation);
			$equation = preg_replace('/\\\\cos\{?(.*?)\}?/', 'cos($1)', $equation);
			$equation = preg_replace('/\\\\tan\{?(.*?)\}?/', 'tan($1)', $equation);
			$equation = preg_replace('/\\\\cot\{?(.*?)\}?/', 'cot($1)', $equation);
		
			// Replace LaTeX inverse trigonometric functions
			$equation = preg_replace('/\\\\arcsin\{?(.*?)\}?/', 'asin($1)', $equation);
			$equation = preg_replace('/\\\\arccos\{?(.*?)\}?/', 'acos($1)', $equation);
			$equation = preg_replace('/\\\\arctan\{?(.*?)\}?/', 'atan($1)', $equation);
			$equation = preg_replace('/\\\\arccot\{?(.*?)\}?/', 'acot($1)', $equation);
		
			// Replace LaTeX hyperbolic functions
			$equation = preg_replace('/\\\\sinh\{?(.*?)\}?/', 'sinh($1)', $equation);
			$equation = preg_replace('/\\\\cosh\{?(.*?)\}?/', 'cosh($1)', $equation);
			$equation = preg_replace('/\\\\tanh\{?(.*?)\}?/', 'tanh($1)', $equation);
			$equation = preg_replace('/\\\\coth\{?(.*?)\}?/', 'coth($1)', $equation);
		
			// Replace LaTeX exponentials
			$equation = preg_replace('/\\\\exp\{(.*?)\}/', 'exp($1)', $equation);
		
			// Replace LaTeX absolute value
			$equation = preg_replace('/\\\\left\|(.+?)\\\\right\|/', 'abs($1)', $equation);
		
			// Handle pi symbol
			$equation = str_replace('\\pi', 'pi', $equation);
		
			// Handle infinity
			$equation = str_replace('\\infty', 'float("inf")', $equation);
		
			// Handle Euler's number
			$equation = str_replace('\\mathrm{e}', 'exp(1)', $equation); // or just 'e' if you define e as a constant
		
			// Handle limits (e.g., \lim_{x \to 0}\left( ... \right) )
			$equation = preg_replace('/\\\\lim_{(.*?)\\\\to(.*?)}(.*?)\\\\left\((.*?)\\\\right\)/', 'limit($3, $1, $2)', $equation);
		
			// Handle derivatives (e.g., \frac{d}{dx}\left( ... \right) )
			$equation = preg_replace('/\\\\frac{d}{d(.*?)}\\\\left\((.*?)\\\\right\)/', 'diff($2, $1)', $equation);
			$equation = preg_replace('/\\\\frac{d^{(.*?)}}{d(.*?)^{(.*?)}}\\\\left\((.*?)\\\\right\)/', 'diff($4, $2, $3)', $equation);
		
			// Replace multiplication sign
			$equation = str_replace('\\cdot', '*', $equation); // handle dot multiplication
			$equation = str_replace('\\times', '*', $equation); // handle cross multiplication
		
			// Handle parentheses and grouping
			$equation = preg_replace('/\\\\left\((.*?)\\\\right\)/', '($1)', $equation);
			$equation = preg_replace('/\\\\left\{(.*?)\\\\right\}/', '($1)', $equation);
		
			// Handle integrals (e.g., \int\left( ... \right) )
			$equation = preg_replace('/\\\\int\\\\left\((.*?)\\\\right\)/', 'integrate($1)', $equation);
		
			// Handle the equal sign
			$equation = str_replace('=', '==', $equation); // replace single equal with double equal for Python
		
			// Clean up excess parentheses
			$equation = preg_replace('/\)+/', ')', $equation); // remove extra closing parentheses
			$equation = preg_replace('/\(+/', '(', $equation); // remove extra opening parentheses
		
			// Handle spaces (\qquad)
			$equation = str_replace('\\qquad', '', $equation); // remove \qquad as Python doesn't need it
		
			// Handle subscript notation (e.g., _{})
			$equation = preg_replace('/_(\{.*?\})/', '', $equation); // remove subscripts (specific handling can be added if needed)
			
			// Handle integrals with limits and dx
			$equation = preg_replace('/\\\\int_{(.*?)}\\^{(.*?)}\\\\left\((.*?)\\\\right\)dx/', 'integrate($3, ($1, $2))', $equation);
		
			// Handle secant and inverse secant functions
			$equation = preg_replace('/\\\\sec{(.*?)}/', 'sec($1)', $equation);
			$equation = preg_replace('/\\\\arcsec{(.*?)}/', 'asec($1)', $equation);
			$equation = preg_replace('/\\\\sec\\^{(.*?)}{(.*?)}/', 'sec($2)**$1', $equation);
			$equation = preg_replace('/\\\\sech{(.*?)}/', 'sech($1)', $equation);
		
			// Handle logarithms with base
			$equation = preg_replace('/\\\\log_{(.*?)}\\\\left\((.*?)\\\\right\)/', 'log($2, $1)', $equation);
		
			// Handle cosecant and inverse cosecant functions
			$equation = preg_replace('/\\\\csc{(.*?)}/', 'csc($1)', $equation);
			$equation = preg_replace('/\\\\arccsc{(.*?)}/', 'acsc($1)', $equation);
			$equation = preg_replace('/\\\\csc\\^{(.*?)}{(.*?)}/', 'csc($2)**$1', $equation);
			$equation = preg_replace('/\\\\csch{(.*?)}/', 'csch($1)', $equation);
		
			// Handle additional symbols
			$equation = preg_replace('/\\\\geq/', '>=', $equation);
			$equation = preg_replace('/\\\\leq/', '<=', $equation);
			$equation = str_replace('\\%', '%', $equation);
		
			// Handle square root with degree
			$equation = preg_replace('/\\\\sqrt\[(.*?)\]{(.*?)}/', '($2)**(1/$1)', $equation);
		
			return $equation;
		}
		$with = "x";
		$python_equation = convert_latex_to_python($EnterEq);
		$parem = $python_equation;
		$parem1 = str_replace($with, "($with + h)", $parem);
		$final = '(('.$parem1.') - ('.$parem.'))/h';
		try{
			$response = Http::timeout(120)->get('http://167.172.134.148/difference', [
				'equ' => $parem,
				'wrt' => $with,
				'equ1' => $parem1,
				'final' => $final,
			]);
			if ($response->failed()) {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
			$buffer = $response->body();
			$buffer=explode("@@@", $buffer);
			$this->param['with'] = $with;
			$this->param['enter'] = $buffer[0];
			$this->param['equ1'] = $buffer[1];
			$this->param['final'] = $buffer[2];
			$this->param['res'] = $buffer[3];
			$this->param['RESULT'] = 1;
			return $this->param;
		} catch (\Exception $response) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}
	public function ai_answer($request){
		$input_name = $request->input_name;
		$language = $request->language;
		$tone = $request->tone;
		$answer_length = $request->answer_length;
		if (!isset($input_name) || !isset($language) || !isset($tone) || !isset($answer_length)) {
			$this->param['error'] = 'Please enter something.';
			return $this->param;
		}
		$this->param['disable'] = "disable";
		return $this->param;
	}
	public function question($request){
		$input_name = $request->input_name;
		$fileNames = $request->fileNames;
		if (!isset($input_name) && !isset($fileNames)) {
			$this->param['error'] = 'Please enter something.';
			return $this->param;
		}
		$this->param['input_name'] = $input_name;
		$this->param['disable'] = "disable";
		return $this->param;
	}
